\set ON_ERROR_STOP on

-- Phan 1: Extensions (idempotent CREATE IF NOT EXISTS)
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE EXTENSION IF NOT EXISTS "pgcrypto";
CREATE EXTENSION IF NOT EXISTS "unaccent";
CREATE EXTENSION IF NOT EXISTS "pg_trgm";

-- Phan 2: Schemas (idempotent)
CREATE SCHEMA IF NOT EXISTS edoc;
CREATE SCHEMA IF NOT EXISTS esto;
CREATE SCHEMA IF NOT EXISTS cont;
CREATE SCHEMA IF NOT EXISTS iso;

-- Phan 3: DROP ALL OLD FUNCTIONS (idempotent guard chong SP overload)
-- DROP het SPs fn_* trong 5 schemas TRUOC khi CREATE lai
DO $cleanup$
DECLARE r RECORD;
BEGIN
  FOR r IN
    SELECT n.nspname, p.proname, pg_get_function_identity_arguments(p.oid) AS args
    FROM pg_proc p
    JOIN pg_namespace n ON n.oid = p.pronamespace
    WHERE n.nspname IN ('public', 'edoc', 'esto', 'cont', 'iso')
      AND p.proname LIKE 'fn_%'
  LOOP
    EXECUTE format('DROP FUNCTION IF EXISTS %I.%I(%s) CASCADE', r.nspname, r.proname, r.args);
  END LOOP;
END $cleanup$;

-- Phan 4: Drop ALL triggers (idempotent)
DROP TRIGGER IF EXISTS trg_doc_flows_updated_at ON edoc.doc_flows;
DROP TRIGGER IF EXISTS trg_drafting_docs_updated_at ON edoc.drafting_docs;
DROP TRIGGER IF EXISTS trg_handling_docs_updated_at ON edoc.handling_docs;
DROP TRIGGER IF EXISTS trg_incoming_docs_updated_at ON edoc.incoming_docs;
DROP TRIGGER IF EXISTS trg_outgoing_docs_updated_at ON edoc.outgoing_docs;
DROP TRIGGER IF EXISTS trg_departments_updated_at ON public.departments;
DROP TRIGGER IF EXISTS trg_positions_updated_at ON public.positions;
DROP TRIGGER IF EXISTS trg_roles_updated_at ON public.roles;
DROP TRIGGER IF EXISTS trg_staff_updated_at ON public.staff;

