--
-- Name: fn_contract_create(integer, integer, integer, integer, integer, character varying, integer, character varying, date, date, date, character varying, character varying, integer, character varying, character varying, character varying, character varying, character varying, integer, text, integer, character varying, numeric, integer); Type: FUNCTION; Schema: cont; Owner: -
--

CREATE OR REPLACE FUNCTION cont.fn_contract_create(p_code_index integer, p_contract_type_id integer, p_department_id integer, p_type_of_contract integer, p_contact_id integer, p_contact_name character varying, p_unit_id integer, p_code character varying, p_sign_date date, p_input_date date, p_receive_date date, p_name character varying, p_signer character varying, p_number integer, p_ballot character varying, p_marker character varying, p_curator_name character varying, p_currency character varying, p_transporter character varying, p_staff_id integer, p_note text, p_status integer, p_amount character varying, p_payment_amount numeric, p_created_user_id integer) RETURNS TABLE(success boolean, message text, id integer)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_id INT;
BEGIN
  IF TRIM(COALESCE(p_name, '')) = '' THEN
    RETURN QUERY SELECT false, 'Tên hợp đồng không được để trống'::TEXT, NULL::INT;
    RETURN;
  END IF;

  INSERT INTO cont.contracts (
    code_index, contract_type_id, department_id, type_of_contract, contact_id,
    contact_name, unit_id, code, sign_date, input_date, receive_date, name,
    signer, number, ballot, marker, curator_name, currency, transporter,
    staff_id, note, status, amount, payment_amount, created_user_id
  ) VALUES (
    p_code_index, p_contract_type_id, p_department_id, COALESCE(p_type_of_contract, 0),
    p_contact_id, p_contact_name, p_unit_id, p_code, p_sign_date, p_input_date,
    p_receive_date, p_name, p_signer, p_number, p_ballot, p_marker, p_curator_name,
    p_currency, p_transporter, p_staff_id, p_note, COALESCE(p_status, 0),
    p_amount, p_payment_amount, p_created_user_id
  ) RETURNING cont.contracts.id INTO v_id;

  RETURN QUERY SELECT true, 'Tạo hợp đồng thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_contract_delete(integer); Type: FUNCTION; Schema: cont; Owner: -
--

CREATE OR REPLACE FUNCTION cont.fn_contract_delete(p_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_status INT;
BEGIN
  SELECT status INTO v_status FROM cont.contracts WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy hợp đồng'::TEXT;
    RETURN;
  END IF;

  IF v_status <> 0 THEN
    RETURN QUERY SELECT false, 'Chỉ có thể xóa hợp đồng ở trạng thái Mới'::TEXT;
    RETURN;
  END IF;

  DELETE FROM cont.contracts WHERE id = p_id;

  RETURN QUERY SELECT true, 'Xóa hợp đồng thành công'::TEXT;
END;
$$;


--
-- Name: fn_contract_get_attachments(integer); Type: FUNCTION; Schema: cont; Owner: -
--

CREATE OR REPLACE FUNCTION cont.fn_contract_get_attachments(p_contract_id integer) RETURNS TABLE(id bigint, contract_id integer, file_name character varying, file_path character varying, file_size bigint, mime_type character varying, created_user_id integer, created_date timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    ca.id, ca.contract_id, ca.file_name, ca.file_path,
    ca.file_size, ca.mime_type, ca.created_user_id, ca.created_date
  FROM cont.contract_attachments ca
  WHERE ca.contract_id = p_contract_id
  ORDER BY ca.created_date DESC;
END;
$$;


--
-- Name: fn_contract_get_by_id(integer); Type: FUNCTION; Schema: cont; Owner: -
--

CREATE OR REPLACE FUNCTION cont.fn_contract_get_by_id(p_id integer) RETURNS TABLE(id integer, code_index integer, contract_type_id integer, type_name character varying, department_id integer, type_of_contract integer, contact_id integer, contact_name character varying, unit_id integer, code character varying, sign_date date, input_date date, receive_date date, name character varying, signer character varying, number integer, ballot character varying, marker character varying, curator_name character varying, currency character varying, transporter character varying, staff_id integer, note text, status integer, amount character varying, payment_amount numeric, created_user_id integer, created_date timestamp with time zone, modified_user_id integer, modified_date timestamp with time zone, attachment_count bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    c.id, c.code_index, c.contract_type_id, ct.name AS type_name,
    c.department_id, c.type_of_contract, c.contact_id, c.contact_name,
    c.unit_id, c.code, c.sign_date, c.input_date, c.receive_date,
    c.name, c.signer, c.number, c.ballot, c.marker, c.curator_name,
    c.currency, c.transporter, c.staff_id, c.note, c.status,
    c.amount, c.payment_amount, c.created_user_id, c.created_date,
    c.modified_user_id, c.modified_date,
    (SELECT COUNT(*) FROM cont.contract_attachments ca WHERE ca.contract_id = c.id) AS attachment_count
  FROM cont.contracts c
  LEFT JOIN cont.contract_types ct ON ct.id = c.contract_type_id
  WHERE c.id = p_id;
END;
$$;


--
-- Name: fn_contract_get_list(integer, integer, integer, text, integer, integer); Type: FUNCTION; Schema: cont; Owner: -
--

CREATE OR REPLACE FUNCTION cont.fn_contract_get_list(p_unit_id integer, p_contract_type_id integer, p_status integer, p_keyword text, p_page integer DEFAULT 1, p_page_size integer DEFAULT 20) RETURNS TABLE(id integer, code_index integer, contract_type_id integer, type_name character varying, unit_id integer, code character varying, name character varying, sign_date date, signer character varying, contact_name character varying, staff_id integer, status integer, amount character varying, payment_amount numeric, created_date timestamp with time zone, attachment_count bigint, total_count bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_offset INT := (COALESCE(p_page, 1) - 1) * COALESCE(p_page_size, 20);
BEGIN
  RETURN QUERY
  WITH filtered AS (
    SELECT
      c.id,
      c.code_index,
      c.contract_type_id,
      ct.name AS type_name,
      c.unit_id,
      c.code,
      c.name,
      c.sign_date,
      c.signer,
      c.contact_name,
      c.staff_id,
      c.status,
      c.amount,
      c.payment_amount,
      c.created_date,
      (SELECT COUNT(*) FROM cont.contract_attachments ca WHERE ca.contract_id = c.id) AS attachment_count
    FROM cont.contracts c
    LEFT JOIN cont.contract_types ct ON ct.id = c.contract_type_id
    WHERE c.unit_id = p_unit_id
      AND (p_contract_type_id IS NULL OR c.contract_type_id = p_contract_type_id)
      AND (p_status IS NULL OR p_status = -99 OR c.status = p_status)
      AND (p_keyword IS NULL OR TRIM(p_keyword) = '' OR
           c.name ILIKE '%' || p_keyword || '%' OR
           c.code ILIKE '%' || p_keyword || '%' OR
           c.contact_name ILIKE '%' || p_keyword || '%')
  )
  SELECT
    flt.*,
    COUNT(*) OVER() AS total_count
  FROM filtered flt
  ORDER BY flt.created_date DESC
  LIMIT p_page_size OFFSET v_offset;
END;
$$;


--
-- Name: fn_contract_type_create(integer, integer, character varying, character varying, text, integer, integer); Type: FUNCTION; Schema: cont; Owner: -
--

CREATE OR REPLACE FUNCTION cont.fn_contract_type_create(p_unit_id integer, p_parent_id integer, p_code character varying, p_name character varying, p_note text, p_sort_order integer, p_created_user_id integer) RETURNS TABLE(success boolean, message text, id integer)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_id INT;
BEGIN
  IF TRIM(COALESCE(p_name, '')) = '' THEN
    RETURN QUERY SELECT false, 'Tên loại hợp đồng không được để trống'::TEXT, NULL::INT;
    RETURN;
  END IF;

  INSERT INTO cont.contract_types (unit_id, parent_id, code, name, note, sort_order, created_user_id)
  VALUES (p_unit_id, COALESCE(p_parent_id, 0), NULLIF(TRIM(p_code),''), p_name, p_note, COALESCE(p_sort_order, 0), p_created_user_id)
  RETURNING cont.contract_types.id INTO v_id;

  RETURN QUERY SELECT true, 'Tạo loại hợp đồng thành công'::TEXT, v_id;
EXCEPTION
  WHEN unique_violation THEN
    RETURN QUERY SELECT false, 'Mã loại hợp đồng đã tồn tại'::TEXT, NULL::INT;
END;
$$;


--
-- Name: fn_contract_type_delete(integer); Type: FUNCTION; Schema: cont; Owner: -
--

CREATE OR REPLACE FUNCTION cont.fn_contract_type_delete(p_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_count INT;
BEGIN
  SELECT COUNT(*) INTO v_count FROM cont.contracts WHERE contract_type_id = p_id;
  IF v_count > 0 THEN
    RETURN QUERY SELECT false, 'Loại hợp đồng đang được sử dụng, không thể xóa'::TEXT;
    RETURN;
  END IF;

  DELETE FROM cont.contract_types WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy loại hợp đồng'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT true, 'Xóa loại hợp đồng thành công'::TEXT;
END;
$$;


--
-- Name: fn_contract_type_get_list(integer); Type: FUNCTION; Schema: cont; Owner: -
--

CREATE OR REPLACE FUNCTION cont.fn_contract_type_get_list(p_unit_id integer) RETURNS TABLE(id integer, unit_id integer, parent_id integer, code character varying, name character varying, note text, sort_order integer, created_date timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    ct.id, ct.unit_id, ct.parent_id, ct.code, ct.name, ct.note,
    ct.sort_order, ct.created_date
  FROM cont.contract_types ct
  WHERE (ct.unit_id IS NULL OR ct.unit_id = p_unit_id)
  ORDER BY ct.sort_order, ct.name;
END;
$$;


--
-- Name: fn_contract_type_update(integer, integer, character varying, character varying, text, integer, integer); Type: FUNCTION; Schema: cont; Owner: -
--

CREATE OR REPLACE FUNCTION cont.fn_contract_type_update(p_id integer, p_parent_id integer, p_code character varying, p_name character varying, p_note text, p_sort_order integer, p_modified_user_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  IF TRIM(COALESCE(p_name, '')) = '' THEN
    RETURN QUERY SELECT false, 'Tên loại hợp đồng không được để trống'::TEXT;
    RETURN;
  END IF;

  UPDATE cont.contract_types SET
    parent_id        = COALESCE(p_parent_id, 0),
    code             = NULLIF(TRIM(p_code),''),
    name             = p_name,
    note             = p_note,
    sort_order       = COALESCE(p_sort_order, 0),
    modified_user_id = p_modified_user_id,
    modified_date    = NOW()
  WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy loại hợp đồng'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT true, 'Cập nhật thành công'::TEXT;
EXCEPTION
  WHEN unique_violation THEN
    RETURN QUERY SELECT false, 'Mã loại hợp đồng đã tồn tại'::TEXT;
END;
$$;


--
-- Name: fn_contract_update(integer, integer, integer, integer, integer, integer, character varying, character varying, date, date, date, character varying, character varying, integer, character varying, character varying, character varying, character varying, character varying, integer, text, integer, character varying, numeric, integer); Type: FUNCTION; Schema: cont; Owner: -
--

CREATE OR REPLACE FUNCTION cont.fn_contract_update(p_id integer, p_code_index integer, p_contract_type_id integer, p_department_id integer, p_type_of_contract integer, p_contact_id integer, p_contact_name character varying, p_code character varying, p_sign_date date, p_input_date date, p_receive_date date, p_name character varying, p_signer character varying, p_number integer, p_ballot character varying, p_marker character varying, p_curator_name character varying, p_currency character varying, p_transporter character varying, p_staff_id integer, p_note text, p_status integer, p_amount character varying, p_payment_amount numeric, p_modified_user_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  IF TRIM(COALESCE(p_name, '')) = '' THEN
    RETURN QUERY SELECT false, 'Tên hợp đồng không được để trống'::TEXT;
    RETURN;
  END IF;

  UPDATE cont.contracts SET
    code_index        = p_code_index,
    contract_type_id  = p_contract_type_id,
    department_id     = p_department_id,
    type_of_contract  = COALESCE(p_type_of_contract, 0),
    contact_id        = p_contact_id,
    contact_name      = p_contact_name,
    code              = p_code,
    sign_date         = p_sign_date,
    input_date        = p_input_date,
    receive_date      = p_receive_date,
    name              = p_name,
    signer            = p_signer,
    number            = p_number,
    ballot            = p_ballot,
    marker            = p_marker,
    curator_name      = p_curator_name,
    currency          = p_currency,
    transporter       = p_transporter,
    staff_id          = p_staff_id,
    note              = p_note,
    status            = COALESCE(p_status, status),
    amount            = p_amount,
    payment_amount    = p_payment_amount,
    modified_user_id  = p_modified_user_id,
    modified_date     = NOW()
  WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy hợp đồng'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT true, 'Cập nhật thành công'::TEXT;
END;
$$;


--
-- Name: fn_attachment_can_sign(bigint, character varying, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_attachment_can_sign(p_attachment_id bigint, p_attachment_type character varying, p_staff_id integer) RETURNS TABLE(can_sign boolean, reason text, file_path character varying, file_name character varying)
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
  v_is_ca         BOOLEAN;
  v_file_path     VARCHAR(1000);
  v_file_name     VARCHAR(500);
  v_doc_id        BIGINT;
  v_signer_name   VARCHAR(200);
  v_signer_int    INT;
  v_approver_name VARCHAR(200);
  v_created_by    INT;
  v_staff_name    VARCHAR(100);
  v_is_admin      BOOLEAN;
BEGIN
  -- Lấy staff info (full_name + admin check 1 lần)
  SELECT s.full_name,
         EXISTS (
           SELECT 1
           FROM public.role_of_staff ros
           JOIN public.roles r ON r.id = ros.role_id
           WHERE ros.staff_id = p_staff_id
             AND r.name = 'Quản trị hệ thống'
         ) OR COALESCE(s.is_admin, FALSE)
    INTO v_staff_name, v_is_admin
    FROM public.staff s
    WHERE s.id = p_staff_id;

  IF v_staff_name IS NULL THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy người dùng'::TEXT,
                         NULL::VARCHAR(1000), NULL::VARCHAR(500);
    RETURN;
  END IF;

  -- Incoming: không được ký (VB đến là input, không phát sinh chữ ký số)
  IF p_attachment_type = 'incoming' THEN
    RETURN QUERY SELECT FALSE, 'Không được ký số văn bản đến'::TEXT,
                         NULL::VARCHAR(1000), NULL::VARCHAR(500);
    RETURN;
  END IF;

  IF p_attachment_type = 'outgoing' THEN
    SELECT att.is_ca, att.file_path, att.file_name, att.outgoing_doc_id
      INTO v_is_ca, v_file_path, v_file_name, v_doc_id
      FROM edoc.attachment_outgoing_docs att
      WHERE att.id = p_attachment_id;

    IF v_file_path IS NULL THEN
      RETURN QUERY SELECT FALSE, 'Không tìm thấy file đính kèm'::TEXT,
                           NULL::VARCHAR(1000), NULL::VARCHAR(500);
      RETURN;
    END IF;
    IF COALESCE(v_is_ca, FALSE) THEN
      RETURN QUERY SELECT FALSE, 'File đã được ký số'::TEXT, v_file_path, v_file_name;
      RETURN;
    END IF;

    SELECT od.signer, od.approver, od.created_by
      INTO v_signer_name, v_approver_name, v_created_by
      FROM edoc.outgoing_docs od
      WHERE od.id = v_doc_id;

    IF v_is_admin
       OR (v_created_by IS NOT NULL AND v_created_by = p_staff_id)
       OR (v_signer_name IS NOT NULL
           AND LOWER(unaccent(v_signer_name)) = LOWER(unaccent(v_staff_name)))
       OR (v_approver_name IS NOT NULL
           AND LOWER(unaccent(v_approver_name)) = LOWER(unaccent(v_staff_name))) THEN
      RETURN QUERY SELECT TRUE, NULL::TEXT, v_file_path, v_file_name;
    ELSE
      RETURN QUERY SELECT FALSE,
                         'Bạn không có quyền ký văn bản này (không phải người tạo/người ký)'::TEXT,
                         v_file_path, v_file_name;
    END IF;
    RETURN;
  END IF;

  IF p_attachment_type = 'drafting' THEN
    SELECT att.is_ca, att.file_path, att.file_name, att.drafting_doc_id
      INTO v_is_ca, v_file_path, v_file_name, v_doc_id
      FROM edoc.attachment_drafting_docs att
      WHERE att.id = p_attachment_id;

    IF v_file_path IS NULL THEN
      RETURN QUERY SELECT FALSE, 'Không tìm thấy file đính kèm'::TEXT,
                           NULL::VARCHAR(1000), NULL::VARCHAR(500);
      RETURN;
    END IF;
    IF COALESCE(v_is_ca, FALSE) THEN
      RETURN QUERY SELECT FALSE, 'File đã được ký số'::TEXT, v_file_path, v_file_name;
      RETURN;
    END IF;

    SELECT dd.signer, dd.approver, dd.created_by
      INTO v_signer_name, v_approver_name, v_created_by
      FROM edoc.drafting_docs dd
      WHERE dd.id = v_doc_id;

    IF v_is_admin
       OR (v_created_by IS NOT NULL AND v_created_by = p_staff_id)
       OR (v_signer_name IS NOT NULL
           AND LOWER(unaccent(v_signer_name)) = LOWER(unaccent(v_staff_name)))
       OR (v_approver_name IS NOT NULL
           AND LOWER(unaccent(v_approver_name)) = LOWER(unaccent(v_staff_name))) THEN
      RETURN QUERY SELECT TRUE, NULL::TEXT, v_file_path, v_file_name;
    ELSE
      RETURN QUERY SELECT FALSE,
                         'Bạn không có quyền ký văn bản này (không phải người tạo/người ký)'::TEXT,
                         v_file_path, v_file_name;
    END IF;
    RETURN;
  END IF;

  IF p_attachment_type = 'handling' THEN
    SELECT att.is_ca, att.file_path, att.file_name, att.handling_doc_id
      INTO v_is_ca, v_file_path, v_file_name, v_doc_id
      FROM edoc.attachment_handling_docs att
      WHERE att.id = p_attachment_id;

    IF v_file_path IS NULL THEN
      RETURN QUERY SELECT FALSE, 'Không tìm thấy file đính kèm'::TEXT,
                           NULL::VARCHAR(1000), NULL::VARCHAR(500);
      RETURN;
    END IF;
    IF COALESCE(v_is_ca, FALSE) THEN
      RETURN QUERY SELECT FALSE, 'File đã được ký số'::TEXT, v_file_path, v_file_name;
      RETURN;
    END IF;

    -- handling_docs.signer là INT FK (KHÔNG phải VARCHAR như outgoing/drafting)
    SELECT hd.signer INTO v_signer_int
      FROM edoc.handling_docs hd
      WHERE hd.id = v_doc_id;

    IF v_is_admin OR (v_signer_int IS NOT NULL AND v_signer_int = p_staff_id) THEN
      RETURN QUERY SELECT TRUE, NULL::TEXT, v_file_path, v_file_name;
    ELSE
      RETURN QUERY SELECT FALSE,
                         'Chỉ người được giao ký HSCV mới ký được'::TEXT,
                         v_file_path, v_file_name;
    END IF;
    RETURN;
  END IF;

  -- Fallback: attachment_type lạ
  RETURN QUERY SELECT FALSE, 'Loại file đính kèm không hợp lệ'::TEXT,
                       NULL::VARCHAR(1000), NULL::VARCHAR(500);
END;
$$;


