--
-- Name: fn_dashboard_get_stats(integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_dashboard_get_stats(p_staff_id integer, p_unit_id integer) RETURNS TABLE(incoming_unread bigint, outgoing_pending bigint, handling_total bigint, handling_overdue bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    (
      SELECT COUNT(*)
      FROM edoc.user_incoming_docs uid
      INNER JOIN edoc.incoming_docs ind ON ind.id = uid.incoming_doc_id
      WHERE uid.staff_id = p_staff_id
        AND uid.is_read = FALSE
    ) AS incoming_unread,

    (
      SELECT COUNT(*)
      FROM edoc.outgoing_docs
      WHERE unit_id = p_unit_id
        AND approved = FALSE
    ) AS outgoing_pending,

    (
      SELECT COUNT(*)
      FROM edoc.handling_docs
      WHERE unit_id = p_unit_id
    ) AS handling_total,

    (
      SELECT COUNT(*)
      FROM edoc.handling_docs
      WHERE unit_id = p_unit_id
        AND end_date IS NOT NULL
        AND end_date < NOW()
        AND status != 4
    ) AS handling_overdue;
END;
$$;


--
-- Name: fn_dashboard_recent_incoming(integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_dashboard_recent_incoming(p_unit_id integer, p_limit integer DEFAULT 10) RETURNS TABLE(id bigint, doc_code character varying, abstract text, received_date timestamp with time zone, urgency_name character varying, sender_name character varying)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    d.id,
    COALESCE(NULLIF(d.notation, ''), d.document_code, '')::VARCHAR AS doc_code,
    d.abstract,
    d.received_date,
    CASE d.urgent_id
      WHEN 1 THEN 'Thường'
      WHEN 2 THEN 'Khẩn'
      WHEN 3 THEN 'Hỏa tốc'
      ELSE 'Thường'
    END::VARCHAR AS urgency_name,
    COALESCE(d.publish_unit, '')::VARCHAR AS sender_name
  FROM edoc.incoming_docs d
  WHERE d.unit_id = p_unit_id
  ORDER BY d.received_date DESC NULLS LAST, d.created_at DESC
  LIMIT COALESCE(p_limit, 10);
END;
$$;


--
-- Name: fn_dashboard_recent_outgoing(integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_dashboard_recent_outgoing(p_unit_id integer, p_limit integer DEFAULT 10) RETURNS TABLE(id bigint, doc_code character varying, abstract text, sent_date timestamp with time zone, doc_type_name character varying)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    d.id,
    COALESCE(NULLIF(d.notation, ''), d.document_code, '')::VARCHAR AS doc_code,
    d.abstract,
    COALESCE(d.publish_date, d.received_date, d.created_at) AS sent_date,
    COALESCE(dt.name, '')::VARCHAR AS doc_type_name
  FROM edoc.outgoing_docs d
  LEFT JOIN edoc.doc_types dt ON dt.id = d.doc_type_id
  WHERE d.unit_id = p_unit_id
  ORDER BY COALESCE(d.publish_date, d.received_date, d.created_at) DESC
  LIMIT COALESCE(p_limit, 10);
END;
$$;


--
-- Name: fn_dashboard_upcoming_tasks(integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_dashboard_upcoming_tasks(p_staff_id integer, p_limit integer DEFAULT 10) RETURNS TABLE(id bigint, title character varying, open_date timestamp with time zone, status smallint, progress_percent smallint, deadline timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT DISTINCT
    hd.id,
    hd.name::VARCHAR AS title,
    hd.start_date AS open_date,
    hd.status,
    COALESCE(hd.progress, 0::SMALLINT) AS progress_percent,
    hd.end_date AS deadline
  FROM edoc.handling_docs hd
  WHERE hd.status != 4
    AND hd.end_date >= NOW()
    AND (
      hd.curator = p_staff_id
      OR EXISTS (
        SELECT 1 FROM edoc.staff_handling_docs shd
        WHERE shd.handling_doc_id = hd.id
          AND shd.staff_id = p_staff_id
      )
    )
  ORDER BY hd.end_date ASC
  LIMIT COALESCE(p_limit, 10);
END;
$$;


--
-- Name: fn_delegation_create(integer, integer, date, date, text); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_delegation_create(p_from_staff_id integer, p_to_staff_id integer, p_start_date date, p_end_date date, p_note text DEFAULT NULL::text) RETURNS TABLE(success boolean, message text, id integer)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id INT;
BEGIN
  IF p_from_staff_id IS NULL OR p_to_staff_id IS NULL THEN
    RETURN QUERY SELECT FALSE, 'Vui lòng chọn người ủy quyền và người nhận ủy quyền'::TEXT, 0;
    RETURN;
  END IF;
  IF p_from_staff_id = p_to_staff_id THEN
    RETURN QUERY SELECT FALSE, 'Không thể ủy quyền cho chính mình'::TEXT, 0;
    RETURN;
  END IF;
  IF p_start_date IS NULL OR p_end_date IS NULL THEN
    RETURN QUERY SELECT FALSE, 'Ngày bắt đầu và ngày kết thúc không được để trống'::TEXT, 0;
    RETURN;
  END IF;
  IF p_end_date < p_start_date THEN
    RETURN QUERY SELECT FALSE, 'Ngày kết thúc phải lớn hơn hoặc bằng ngày bắt đầu'::TEXT, 0;
    RETURN;
  END IF;

  -- Check staff exists
  IF NOT EXISTS(SELECT 1 FROM public.staff s WHERE s.id = p_from_staff_id AND s.is_deleted = FALSE) THEN
    RETURN QUERY SELECT FALSE, 'Người ủy quyền không tồn tại'::TEXT, 0;
    RETURN;
  END IF;
  IF NOT EXISTS(SELECT 1 FROM public.staff s WHERE s.id = p_to_staff_id AND s.is_deleted = FALSE) THEN
    RETURN QUERY SELECT FALSE, 'Người nhận ủy quyền không tồn tại'::TEXT, 0;
    RETURN;
  END IF;

  -- Check overlap: same from_staff, active, date range overlaps
  IF EXISTS(
    SELECT 1 FROM edoc.delegations d
    WHERE d.from_staff_id = p_from_staff_id
      AND d.is_revoked = FALSE
      AND d.start_date <= p_end_date
      AND d.end_date >= p_start_date
  ) THEN
    RETURN QUERY SELECT FALSE, 'Đã tồn tại ủy quyền trong khoảng thời gian này'::TEXT, 0;
    RETURN;
  END IF;

  INSERT INTO edoc.delegations (from_staff_id, to_staff_id, start_date, end_date, note)
  VALUES (p_from_staff_id, p_to_staff_id, p_start_date, p_end_date, p_note)
  RETURNING edoc.delegations.id INTO v_id;

  RETURN QUERY SELECT TRUE, 'Tao uy quyen thanh cong'::TEXT, v_id;
END;
$$;


--
-- Name: fn_delegation_get_list(integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_delegation_get_list(p_unit_id integer DEFAULT NULL::integer, p_staff_id integer DEFAULT NULL::integer) RETURNS TABLE(id integer, from_staff_id integer, from_staff_name character varying, to_staff_id integer, to_staff_name character varying, start_date date, end_date date, note text, is_revoked boolean, revoked_at timestamp with time zone, created_at timestamp with time zone)
    LANGUAGE sql STABLE
    AS $$
  SELECT dl.id, dl.from_staff_id,
         sf.full_name::VARCHAR AS from_staff_name,
         dl.to_staff_id,
         st.full_name::VARCHAR AS to_staff_name,
         dl.start_date, dl.end_date, dl.note,
         dl.is_revoked, dl.revoked_at, dl.created_at
  FROM edoc.delegations dl
    JOIN public.staff sf ON sf.id = dl.from_staff_id
    JOIN public.staff st ON st.id = dl.to_staff_id
  WHERE (p_unit_id IS NULL OR sf.unit_id = p_unit_id)
    AND (p_staff_id IS NULL OR dl.from_staff_id = p_staff_id OR dl.to_staff_id = p_staff_id)
  ORDER BY dl.created_at DESC;
$$;


--
-- Name: fn_delegation_revoke(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_delegation_revoke(p_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NOT EXISTS(SELECT 1 FROM edoc.delegations WHERE id = p_id AND is_revoked = FALSE) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy ủy quyền hoặc đã thu hồi'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.delegations SET is_revoked = TRUE, revoked_at = NOW()
  WHERE id = p_id;

  RETURN QUERY SELECT TRUE, 'Thu hoi uy quyen thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_device_token_delete(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_device_token_delete(p_id bigint, p_staff_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  DELETE FROM edoc.device_tokens
  WHERE id = p_id AND staff_id = p_staff_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Khong tim thay device token'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT true, 'Xoa device token thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_device_token_get_by_staff(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_device_token_get_by_staff(p_staff_id integer) RETURNS TABLE(id bigint, device_token character varying, device_type character varying, is_active boolean, created_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    dt.id,
    dt.device_token,
    dt.device_type,
    dt.is_active,
    dt.created_at
  FROM edoc.device_tokens dt
  WHERE dt.staff_id = p_staff_id
    AND dt.is_active = true
  ORDER BY dt.created_at DESC;
END;
$$;


--
-- Name: fn_device_token_upsert(integer, character varying, character varying); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_device_token_upsert(p_staff_id integer, p_device_token character varying, p_device_type character varying DEFAULT 'web'::character varying) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_id BIGINT;
BEGIN
  INSERT INTO edoc.device_tokens (staff_id, device_token, device_type, updated_at)
  VALUES (p_staff_id, p_device_token, p_device_type, NOW())
  ON CONFLICT (device_token) DO UPDATE SET
    staff_id    = EXCLUDED.staff_id,
    device_type = EXCLUDED.device_type,
    is_active   = true,
    updated_at  = NOW()
  RETURNING edoc.device_tokens.id INTO v_id;

  RETURN QUERY SELECT true, 'Luu device token thanh cong'::TEXT, v_id;
END;
$$;


--
-- Name: fn_digital_signature_create(bigint, character varying, integer, character varying, character varying); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_digital_signature_create(p_doc_id bigint, p_doc_type character varying, p_staff_id integer, p_sign_method character varying, p_original_file_path character varying DEFAULT NULL::character varying) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_id BIGINT;
BEGIN
  -- Validate doc_type
  IF p_doc_type NOT IN ('outgoing', 'drafting') THEN
    RETURN QUERY SELECT false, 'Loai van ban khong hop le'::TEXT, NULL::BIGINT;
    RETURN;
  END IF;

  -- Validate sign_method
  IF p_sign_method NOT IN ('smart_ca', 'esign_neac', 'usb_token') THEN
    RETURN QUERY SELECT false, 'Phuong thuc ky khong hop le'::TEXT, NULL::BIGINT;
    RETURN;
  END IF;

  INSERT INTO edoc.digital_signatures (
    doc_id, doc_type, staff_id, sign_method, original_file_path
  )
  VALUES (
    p_doc_id, p_doc_type, p_staff_id, p_sign_method, p_original_file_path
  )
  RETURNING edoc.digital_signatures.id INTO v_id;

  RETURN QUERY SELECT true, 'Tao yeu cau ky so thanh cong'::TEXT, v_id;
END;
$$;


--
-- Name: fn_digital_signature_get_by_doc(bigint, character varying); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_digital_signature_get_by_doc(p_doc_id bigint, p_doc_type character varying) RETURNS TABLE(id bigint, doc_id bigint, doc_type character varying, staff_id integer, staff_name character varying, sign_method character varying, certificate_serial character varying, certificate_subject character varying, certificate_issuer character varying, signed_file_path character varying, original_file_path character varying, sign_status character varying, error_message text, signed_at timestamp with time zone, created_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    ds.id,
    ds.doc_id,
    ds.doc_type,
    ds.staff_id,
    s.full_name::VARCHAR AS staff_name,
    ds.sign_method,
    ds.certificate_serial,
    ds.certificate_subject,
    ds.certificate_issuer,
    ds.signed_file_path,
    ds.original_file_path,
    ds.sign_status,
    ds.error_message,
    ds.signed_at,
    ds.created_at
  FROM edoc.digital_signatures ds
  JOIN public.staff s ON s.id = ds.staff_id
  WHERE ds.doc_id = p_doc_id
    AND ds.doc_type = p_doc_type
  ORDER BY ds.created_at DESC;
END;
$$;


--
-- Name: fn_digital_signature_get_by_id(bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_digital_signature_get_by_id(p_id bigint) RETURNS TABLE(id bigint, doc_id bigint, doc_type character varying, staff_id integer, staff_name character varying, sign_method character varying, certificate_serial character varying, certificate_subject character varying, certificate_issuer character varying, signed_file_path character varying, original_file_path character varying, sign_status character varying, error_message text, signed_at timestamp with time zone, created_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    ds.id,
    ds.doc_id,
    ds.doc_type,
    ds.staff_id,
    s.full_name::VARCHAR AS staff_name,
    ds.sign_method,
    ds.certificate_serial,
    ds.certificate_subject,
    ds.certificate_issuer,
    ds.signed_file_path,
    ds.original_file_path,
    ds.sign_status,
    ds.error_message,
    ds.signed_at,
    ds.created_at
  FROM edoc.digital_signatures ds
  JOIN public.staff s ON s.id = ds.staff_id
  WHERE ds.id = p_id;
END;
$$;


--
-- Name: fn_digital_signature_update_status(bigint, character varying, character varying, character varying, character varying, character varying, text); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_digital_signature_update_status(p_id bigint, p_sign_status character varying, p_certificate_serial character varying DEFAULT NULL::character varying, p_certificate_subject character varying DEFAULT NULL::character varying, p_certificate_issuer character varying DEFAULT NULL::character varying, p_signed_file_path character varying DEFAULT NULL::character varying, p_error_message text DEFAULT NULL::text) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE edoc.digital_signatures
  SET sign_status         = p_sign_status,
      certificate_serial  = COALESCE(p_certificate_serial, certificate_serial),
      certificate_subject = COALESCE(p_certificate_subject, certificate_subject),
      certificate_issuer  = COALESCE(p_certificate_issuer, certificate_issuer),
      signed_file_path    = COALESCE(p_signed_file_path, signed_file_path),
      error_message       = p_error_message,
      signed_at           = CASE WHEN p_sign_status = 'signed' THEN NOW() ELSE signed_at END
  WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Khong tim thay ban ghi ky so'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT true, 'Cap nhat trang thai ky so thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_doc_book_create(smallint, integer, character varying, boolean, text, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_book_create(p_type_id smallint, p_unit_id integer, p_name character varying, p_is_default boolean DEFAULT false, p_description text DEFAULT NULL::text, p_created_by integer DEFAULT NULL::integer) RETURNS TABLE(success boolean, message text, id integer)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id INT; v_exists BOOLEAN;
BEGIN
  -- Validate
  IF p_name IS NULL OR TRIM(p_name) = '' THEN
    RETURN QUERY SELECT FALSE, 'Tên sổ văn bản không được để trống'::TEXT, 0;
    RETURN;
  END IF;
  IF LENGTH(p_name) > 200 THEN
    RETURN QUERY SELECT FALSE, 'Tên sổ văn bản không được vượt quá 200 ký tự'::TEXT, 0;
    RETURN;
  END IF;

  -- Check unique name per type + unit
  SELECT EXISTS(
    SELECT 1 FROM edoc.doc_books
    WHERE type_id = p_type_id AND unit_id = p_unit_id
      AND LOWER(TRIM(name)) = LOWER(TRIM(p_name))
      AND is_deleted = FALSE
  ) INTO v_exists;

  IF v_exists THEN
    RETURN QUERY SELECT FALSE, 'Tên sổ văn bản đã tồn tại trong đơn vị'::TEXT, 0;
    RETURN;
  END IF;

  -- If setting as default, unset others
  IF p_is_default THEN
    UPDATE edoc.doc_books SET is_default = FALSE
    WHERE type_id = p_type_id AND unit_id = p_unit_id AND is_deleted = FALSE;
  END IF;

  INSERT INTO edoc.doc_books (type_id, unit_id, name, is_default, description, created_by)
  VALUES (p_type_id, p_unit_id, TRIM(p_name), COALESCE(p_is_default, FALSE), p_description, p_created_by)
  RETURNING doc_books.id INTO v_id;

  RETURN QUERY SELECT TRUE, 'Tao so van ban thanh cong'::TEXT, v_id;
END;
$$;


--
-- Name: fn_doc_book_delete(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_book_delete(p_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NOT EXISTS(SELECT 1 FROM edoc.doc_books WHERE id = p_id AND is_deleted = FALSE) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy sổ văn bản'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.doc_books SET is_deleted = TRUE WHERE id = p_id;
  RETURN QUERY SELECT TRUE, 'Xoa so van ban thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_doc_book_get_by_id(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_book_get_by_id(p_id integer) RETURNS TABLE(id integer, unit_id integer, type_id smallint, name character varying, description text, sort_order integer, is_default boolean, created_by integer, created_at timestamp with time zone)
    LANGUAGE sql STABLE
    AS $$
  SELECT b.id, b.unit_id, b.type_id, b.name::VARCHAR,
         b.description, b.sort_order, b.is_default,
         b.created_by, b.created_at
  FROM edoc.doc_books b
  WHERE b.id = p_id AND b.is_deleted = FALSE;
$$;


--
-- Name: fn_doc_book_get_list(smallint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_book_get_list(p_type_id smallint DEFAULT NULL::smallint, p_unit_id integer DEFAULT NULL::integer) RETURNS TABLE(id integer, unit_id integer, type_id smallint, name character varying, description text, sort_order integer, is_default boolean, created_by integer, created_at timestamp with time zone)
    LANGUAGE sql STABLE
    AS $$
  SELECT b.id, b.unit_id, b.type_id, b.name::VARCHAR,
         b.description, b.sort_order, b.is_default,
         b.created_by, b.created_at
  FROM edoc.doc_books b
  WHERE b.is_deleted = FALSE
    AND (p_type_id IS NULL OR b.type_id = p_type_id)
    AND (p_unit_id IS NULL OR b.unit_id = p_unit_id)
  ORDER BY b.sort_order, b.name;
$$;


--
-- Name: fn_doc_book_set_default(integer, smallint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_book_set_default(p_id integer, p_type_id smallint, p_unit_id integer) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- Unset all defaults for this type + unit
  UPDATE edoc.doc_books SET is_default = FALSE
  WHERE type_id = p_type_id AND unit_id = p_unit_id AND is_deleted = FALSE;

  -- Set the selected one
  UPDATE edoc.doc_books SET is_default = TRUE
  WHERE id = p_id AND is_deleted = FALSE;

  RETURN FOUND;
END;
$$;


--
-- Name: fn_doc_book_update(integer, character varying, boolean, text, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_book_update(p_id integer, p_name character varying, p_is_default boolean DEFAULT NULL::boolean, p_description text DEFAULT NULL::text, p_sort_order integer DEFAULT NULL::integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_rec edoc.doc_books%ROWTYPE;
BEGIN
  SELECT * INTO v_rec FROM edoc.doc_books WHERE id = p_id AND is_deleted = FALSE;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy sổ văn bản'::TEXT;
    RETURN;
  END IF;

  IF p_name IS NULL OR TRIM(p_name) = '' THEN
    RETURN QUERY SELECT FALSE, 'Tên sổ văn bản không được để trống'::TEXT;
    RETURN;
  END IF;
  IF LENGTH(p_name) > 200 THEN
    RETURN QUERY SELECT FALSE, 'Tên sổ văn bản không được vượt quá 200 ký tự'::TEXT;
    RETURN;
  END IF;

  -- Check unique name (exclude self)
  IF EXISTS(
    SELECT 1 FROM edoc.doc_books
    WHERE type_id = v_rec.type_id AND unit_id = v_rec.unit_id
      AND LOWER(TRIM(name)) = LOWER(TRIM(p_name))
      AND id <> p_id AND is_deleted = FALSE
  ) THEN
    RETURN QUERY SELECT FALSE, 'Tên sổ văn bản đã tồn tại trong đơn vị'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.doc_books SET
    name        = TRIM(p_name),
    is_default  = COALESCE(p_is_default, is_default),
    description = COALESCE(p_description, description),
    sort_order  = COALESCE(p_sort_order, sort_order)
  WHERE id = p_id;

  RETURN QUERY SELECT TRUE, 'Cap nhat thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_doc_column_delete(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_column_delete(p_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  DELETE FROM edoc.doc_columns WHERE id = p_id AND is_system = false;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy hoặc không thể xóa trường hệ thống'::TEXT; RETURN;
  END IF;
  RETURN QUERY SELECT TRUE, 'Đã xóa'::TEXT;
END;
$$;


--
-- Name: fn_doc_column_get_all(); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_column_get_all() RETURNS TABLE(id integer, type_id smallint, doc_type_name character varying, column_name character varying, label character varying, data_type character varying, max_length integer, sort_order integer, is_mandatory boolean, is_system boolean)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
  RETURN QUERY
  SELECT c.id, c.type_id, dt.name, c.column_name, c.label, c.data_type,
         c.max_length, c.sort_order, c.is_mandatory, c.is_system
  FROM edoc.doc_columns c
  JOIN edoc.doc_types dt ON dt.id = c.type_id
  ORDER BY dt.name, c.sort_order;
END;
$$;


--
-- Name: fn_doc_column_get_by_type(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_column_get_by_type(p_type_id integer) RETURNS TABLE(id integer, column_name character varying, label character varying, data_type character varying, max_length integer, sort_order integer, is_mandatory boolean, is_system boolean, description text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT c.id, c.column_name, c.label, c.data_type, c.max_length,
         c.sort_order, c.is_mandatory, c.is_system, c.description
  FROM edoc.doc_columns c
  WHERE c.type_id = p_type_id
  ORDER BY c.sort_order, c.id;
END;
$$;


--
-- Name: fn_doc_column_get_list(smallint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_column_get_list(p_type_id smallint) RETURNS TABLE(id integer, type_id smallint, column_name character varying, label character varying, is_mandatory boolean, is_show_all boolean, sort_order integer, description text)
    LANGUAGE sql STABLE
    AS $$
  SELECT c.id, c.type_id, c.column_name::VARCHAR, c.label::VARCHAR,
         c.is_mandatory, c.is_show_all, c.sort_order, c.description
  FROM edoc.doc_columns c
  WHERE c.type_id = p_type_id
  ORDER BY c.sort_order;
$$;


--
-- Name: fn_doc_column_save(integer, integer, character varying, character varying, character varying, integer, integer, boolean, text); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_column_save(p_id integer DEFAULT NULL::integer, p_type_id integer DEFAULT NULL::integer, p_column_name character varying DEFAULT NULL::character varying, p_label character varying DEFAULT NULL::character varying, p_data_type character varying DEFAULT 'text'::character varying, p_max_length integer DEFAULT NULL::integer, p_sort_order integer DEFAULT 0, p_is_mandatory boolean DEFAULT false, p_description text DEFAULT NULL::text) RETURNS TABLE(success boolean, message text, id integer)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id INT;
BEGIN
  IF p_label IS NULL OR TRIM(p_label) = '' THEN
    RETURN QUERY SELECT FALSE, 'Nhãn hiển thị là bắt buộc'::TEXT, 0; RETURN;
  END IF;

  IF p_id IS NOT NULL AND p_id > 0 THEN
    -- Update
    UPDATE edoc.doc_columns SET
      column_name = COALESCE(p_column_name, column_name),
      label = TRIM(p_label),
      data_type = COALESCE(p_data_type, data_type),
      max_length = p_max_length,
      sort_order = COALESCE(p_sort_order, sort_order),
      is_mandatory = COALESCE(p_is_mandatory, is_mandatory),
      description = NULLIF(TRIM(p_description), '')
    WHERE edoc.doc_columns.id = p_id AND is_system = false;

    IF NOT FOUND THEN
      RETURN QUERY SELECT FALSE, 'Không tìm thấy hoặc không thể sửa trường hệ thống'::TEXT, 0; RETURN;
    END IF;
    v_id := p_id;
  ELSE
    -- Insert
    INSERT INTO edoc.doc_columns (type_id, column_name, label, data_type, max_length, sort_order, is_mandatory, description)
    VALUES (p_type_id, p_column_name, TRIM(p_label), COALESCE(p_data_type, 'text'), p_max_length, COALESCE(p_sort_order, 0), COALESCE(p_is_mandatory, false), NULLIF(TRIM(p_description), ''))
    RETURNING edoc.doc_columns.id INTO v_id;
  END IF;

  RETURN QUERY SELECT TRUE, 'Lưu thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_doc_column_toggle_visibility(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_column_toggle_visibility(p_id integer) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE edoc.doc_columns SET is_show_all = NOT is_show_all WHERE id = p_id;
  RETURN FOUND;
END;
$$;


--
-- Name: fn_doc_column_update(integer, character varying, boolean, boolean, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_column_update(p_id integer, p_label character varying DEFAULT NULL::character varying, p_is_mandatory boolean DEFAULT NULL::boolean, p_is_show_all boolean DEFAULT NULL::boolean, p_sort_order integer DEFAULT NULL::integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NOT EXISTS(SELECT 1 FROM edoc.doc_columns WHERE id = p_id) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy thuộc tính'::TEXT;
    RETURN;
  END IF;

  IF p_label IS NOT NULL AND LENGTH(p_label) > 200 THEN
    RETURN QUERY SELECT FALSE, 'Nhãn hiển thị không được vượt quá 200 ký tự'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.doc_columns SET
    label        = COALESCE(NULLIF(TRIM(p_label), ''), label),
    is_mandatory = COALESCE(p_is_mandatory, is_mandatory),
    is_show_all  = COALESCE(p_is_show_all, is_show_all),
    sort_order   = COALESCE(p_sort_order, sort_order)
  WHERE id = p_id;

  RETURN QUERY SELECT TRUE, 'Cap nhat thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_doc_field_create(integer, character varying, character varying); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_field_create(p_unit_id integer, p_code character varying, p_name character varying) RETURNS TABLE(success boolean, message text, id integer)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id INT;
BEGIN
  IF p_code IS NULL OR TRIM(p_code) = '' THEN
    RETURN QUERY SELECT FALSE, 'Mã lĩnh vực không được để trống'::TEXT, 0;
    RETURN;
  END IF;
  IF p_name IS NULL OR TRIM(p_name) = '' THEN
    RETURN QUERY SELECT FALSE, 'Tên lĩnh vực không được để trống'::TEXT, 0;
    RETURN;
  END IF;
  IF LENGTH(p_code) > 20 THEN
    RETURN QUERY SELECT FALSE, 'Mã lĩnh vực không được vượt quá 20 ký tự'::TEXT, 0;
    RETURN;
  END IF;
  IF LENGTH(p_name) > 200 THEN
    RETURN QUERY SELECT FALSE, 'Tên lĩnh vực không được vượt quá 200 ký tự'::TEXT, 0;
    RETURN;
  END IF;

  -- Check unique code per unit
  IF EXISTS(
    SELECT 1 FROM edoc.doc_fields
    WHERE unit_id = p_unit_id AND LOWER(TRIM(code)) = LOWER(TRIM(p_code))
  ) THEN
    RETURN QUERY SELECT FALSE, 'Mã lĩnh vực đã tồn tại trong đơn vị'::TEXT, 0;
    RETURN;
  END IF;

  INSERT INTO edoc.doc_fields (unit_id, code, name)
  VALUES (p_unit_id, TRIM(p_code), TRIM(p_name))
  RETURNING doc_fields.id INTO v_id;

  RETURN QUERY SELECT TRUE, 'Tao linh vuc thanh cong'::TEXT, v_id;
END;
$$;


--
-- Name: fn_doc_field_delete(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_field_delete(p_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NOT EXISTS(SELECT 1 FROM edoc.doc_fields WHERE id = p_id) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy lĩnh vực'::TEXT;
    RETURN;
  END IF;

  DELETE FROM edoc.doc_fields WHERE id = p_id;
  RETURN QUERY SELECT TRUE, 'Xoa linh vuc thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_doc_field_get_by_id(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_field_get_by_id(p_id integer) RETURNS TABLE(id integer, unit_id integer, code character varying, name character varying, sort_order integer, is_active boolean, created_at timestamp with time zone)
    LANGUAGE sql STABLE
    AS $$
  SELECT f.id, f.unit_id, f.code::VARCHAR, f.name::VARCHAR,
         f.sort_order, f.is_active, f.created_at
  FROM edoc.doc_fields f WHERE f.id = p_id;
$$;


--
-- Name: fn_doc_field_get_list(integer, character varying); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_field_get_list(p_unit_id integer DEFAULT NULL::integer, p_keyword character varying DEFAULT NULL::character varying) RETURNS TABLE(id integer, unit_id integer, code character varying, name character varying, sort_order integer, is_active boolean, created_at timestamp with time zone)
    LANGUAGE sql STABLE
    AS $$
  SELECT f.id, f.unit_id, f.code::VARCHAR, f.name::VARCHAR,
         f.sort_order, f.is_active, f.created_at
  FROM edoc.doc_fields f
  WHERE (p_unit_id IS NULL OR f.unit_id = p_unit_id)
    AND (p_keyword IS NULL OR f.name ILIKE '%' || p_keyword || '%'
         OR f.code ILIKE '%' || p_keyword || '%')
  ORDER BY f.sort_order, f.name;
$$;


--
-- Name: fn_doc_field_update(integer, character varying, character varying, integer, boolean); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_field_update(p_id integer, p_code character varying DEFAULT NULL::character varying, p_name character varying DEFAULT NULL::character varying, p_sort_order integer DEFAULT NULL::integer, p_is_active boolean DEFAULT NULL::boolean) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_unit_id INT;
BEGIN
  SELECT unit_id INTO v_unit_id FROM edoc.doc_fields WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy lĩnh vực'::TEXT;
    RETURN;
  END IF;

  IF p_code IS NULL OR TRIM(p_code) = '' THEN
    RETURN QUERY SELECT FALSE, 'Mã lĩnh vực không được để trống'::TEXT;
    RETURN;
  END IF;
  IF p_name IS NULL OR TRIM(p_name) = '' THEN
    RETURN QUERY SELECT FALSE, 'Tên lĩnh vực không được để trống'::TEXT;
    RETURN;
  END IF;
  IF LENGTH(p_code) > 20 THEN
    RETURN QUERY SELECT FALSE, 'Mã lĩnh vực không được vượt quá 20 ký tự'::TEXT;
    RETURN;
  END IF;

  -- Check unique code (exclude self)
  IF EXISTS(
    SELECT 1 FROM edoc.doc_fields
    WHERE unit_id = v_unit_id AND LOWER(TRIM(code)) = LOWER(TRIM(p_code))
      AND id <> p_id
  ) THEN
    RETURN QUERY SELECT FALSE, 'Mã lĩnh vực đã tồn tại trong đơn vị'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.doc_fields SET
    code       = TRIM(p_code),
    name       = TRIM(p_name),
    sort_order = COALESCE(p_sort_order, sort_order),
    is_active  = COALESCE(p_is_active, is_active)
  WHERE id = p_id;

  RETURN QUERY SELECT TRUE, 'Cap nhat thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_doc_flow_create(integer, character varying, character varying, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_flow_create(p_unit_id integer, p_name character varying, p_version character varying, p_doc_field_id integer, p_created_by integer) RETURNS TABLE(success boolean, message text, id integer)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id INT;
BEGIN
  IF p_name IS NULL OR TRIM(p_name) = '' THEN
    RETURN QUERY SELECT FALSE, 'Tên quy trình không được để trống'::TEXT, 0::INT;
    RETURN;
  END IF;

  IF EXISTS (
    SELECT 1 FROM edoc.doc_flows
    WHERE unit_id = p_unit_id AND name = TRIM(p_name)
      AND (version = p_version OR (version IS NULL AND p_version IS NULL))
  ) THEN
    RETURN QUERY SELECT FALSE, 'Quy trình với tên và phiên bản này đã tồn tại'::TEXT, 0::INT;
    RETURN;
  END IF;

  INSERT INTO edoc.doc_flows (unit_id, name, version, doc_field_id, is_active, created_by)
  VALUES (p_unit_id, TRIM(p_name), NULLIF(TRIM(COALESCE(p_version, '')), ''), p_doc_field_id, TRUE, p_created_by)
  RETURNING edoc.doc_flows.id INTO v_id;

  RETURN QUERY SELECT TRUE, 'Tạo quy trình thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_doc_flow_delete(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_flow_delete(p_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- Không xóa nếu đang được sử dụng bởi HSCV
  IF EXISTS (SELECT 1 FROM edoc.handling_docs WHERE workflow_id = p_id) THEN
    RETURN QUERY SELECT FALSE, 'Không thể xóa quy trình đang được sử dụng bởi hồ sơ công việc'::TEXT;
    RETURN;
  END IF;

  DELETE FROM edoc.doc_flows WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Quy trình không tồn tại'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT TRUE, 'Xóa quy trình thành công'::TEXT;
END;
$$;


--
-- Name: fn_doc_flow_get_by_id(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_flow_get_by_id(p_id integer) RETURNS TABLE(id integer, unit_id integer, name character varying, version character varying, doc_field_id integer, doc_field_name character varying, is_active boolean, created_by integer, created_at timestamp with time zone, updated_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    f.id,
    f.unit_id,
    f.name,
    f.version,
    f.doc_field_id,
    df.name  AS doc_field_name,
    f.is_active,
    f.created_by,
    f.created_at,
    f.updated_at
  FROM edoc.doc_flows f
  LEFT JOIN edoc.doc_fields df ON df.id = f.doc_field_id
  WHERE f.id = p_id;
END;
$$;


--
-- Name: fn_doc_flow_get_list(integer, integer, boolean); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_flow_get_list(p_unit_id integer, p_doc_field_id integer DEFAULT NULL::integer, p_is_active boolean DEFAULT NULL::boolean) RETURNS TABLE(id integer, name character varying, version character varying, doc_field_id integer, doc_field_name character varying, is_active boolean, step_count bigint, created_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    f.id,
    f.name,
    f.version,
    f.doc_field_id,
    df.name                                  AS doc_field_name,
    f.is_active,
    COUNT(s.id)                              AS step_count,
    f.created_at
  FROM edoc.doc_flows f
  LEFT JOIN edoc.doc_fields df ON df.id = f.doc_field_id
  LEFT JOIN edoc.doc_flow_steps s ON s.flow_id = f.id
  WHERE
    f.unit_id = p_unit_id
    AND (p_doc_field_id IS NULL OR f.doc_field_id = p_doc_field_id)
    AND (p_is_active IS NULL OR f.is_active = p_is_active)
  GROUP BY f.id, f.name, f.version, f.doc_field_id, df.name, f.is_active, f.created_at
  ORDER BY f.name, f.version;
END;
$$;


--
-- Name: fn_doc_flow_step_assign_staff(integer, integer[]); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_flow_step_assign_staff(p_step_id integer, p_staff_ids integer[]) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_staff_id INT;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM edoc.doc_flow_steps WHERE id = p_step_id) THEN
    RETURN QUERY SELECT FALSE, 'Bước quy trình không tồn tại'::TEXT;
    RETURN;
  END IF;

  -- Xóa toàn bộ cán bộ cũ của bước
  DELETE FROM edoc.doc_flow_step_staff WHERE step_id = p_step_id;

  -- Gán mới nếu có danh sách
  IF p_staff_ids IS NOT NULL AND ARRAY_LENGTH(p_staff_ids, 1) > 0 THEN
    FOREACH v_staff_id IN ARRAY p_staff_ids LOOP
      INSERT INTO edoc.doc_flow_step_staff (step_id, staff_id)
      VALUES (p_step_id, v_staff_id)
      ON CONFLICT DO NOTHING;
    END LOOP;
  END IF;

  RETURN QUERY SELECT TRUE, 'Cập nhật cán bộ thực hiện bước thành công'::TEXT;
END;
$$;


--
-- Name: fn_doc_flow_step_create(integer, character varying, integer, character varying, boolean, integer, double precision, double precision); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_flow_step_create(p_flow_id integer, p_step_name character varying, p_step_order integer, p_step_type character varying, p_allow_sign boolean, p_deadline_days integer, p_position_x double precision, p_position_y double precision) RETURNS TABLE(success boolean, message text, id integer)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id INT;
BEGIN
  IF p_step_name IS NULL OR TRIM(p_step_name) = '' THEN
    RETURN QUERY SELECT FALSE, 'Tên bước không được để trống'::TEXT, 0::INT;
    RETURN;
  END IF;

  IF p_step_type NOT IN ('start', 'process', 'end') THEN
    RETURN QUERY SELECT FALSE, 'Loại bước không hợp lệ (start/process/end)'::TEXT, 0::INT;
    RETURN;
  END IF;

  IF NOT EXISTS (SELECT 1 FROM edoc.doc_flows WHERE id = p_flow_id) THEN
    RETURN QUERY SELECT FALSE, 'Quy trình không tồn tại'::TEXT, 0::INT;
    RETURN;
  END IF;

  INSERT INTO edoc.doc_flow_steps (
    flow_id, step_name, step_order, step_type,
    allow_sign, deadline_days, position_x, position_y
  ) VALUES (
    p_flow_id, TRIM(p_step_name), COALESCE(p_step_order, 0),
    COALESCE(p_step_type, 'process'), COALESCE(p_allow_sign, FALSE),
    COALESCE(p_deadline_days, 0), COALESCE(p_position_x, 0), COALESCE(p_position_y, 0)
  )
  RETURNING edoc.doc_flow_steps.id INTO v_id;

  RETURN QUERY SELECT TRUE, 'Tạo bước quy trình thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_doc_flow_step_delete(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_flow_step_delete(p_step_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  DELETE FROM edoc.doc_flow_steps WHERE id = p_step_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Bước quy trình không tồn tại'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT TRUE, 'Xóa bước quy trình thành công'::TEXT;
END;
$$;


--
-- Name: fn_doc_flow_step_get_list(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_flow_step_get_list(p_flow_id integer) RETURNS TABLE(id integer, step_name character varying, step_order integer, step_type character varying, allow_sign boolean, deadline_days integer, position_x double precision, position_y double precision)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    s.id,
    s.step_name,
    s.step_order,
    s.step_type,
    s.allow_sign,
    s.deadline_days,
    s.position_x,
    s.position_y
  FROM edoc.doc_flow_steps s
  WHERE s.flow_id = p_flow_id
  ORDER BY s.step_order, s.id;
END;
$$;


--
-- Name: fn_doc_flow_step_get_staff(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_flow_step_get_staff(p_step_id integer) RETURNS TABLE(id integer, staff_id integer, staff_name text, position_name character varying, department_name character varying)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    ss.id,
    ss.staff_id,
    CONCAT(s.last_name, ' ', s.first_name)::TEXT AS staff_name,
    p.name                                        AS position_name,
    d.name                                        AS department_name
  FROM edoc.doc_flow_step_staff ss
  JOIN public.staff s ON s.id = ss.staff_id
  LEFT JOIN public.positions p ON p.id = s.position_id
  LEFT JOIN public.departments d ON d.id = s.department_id
  WHERE ss.step_id = p_step_id
  ORDER BY s.last_name, s.first_name;
END;
$$;


--
-- Name: fn_doc_flow_step_link_create(integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_flow_step_link_create(p_from_step_id integer, p_to_step_id integer) RETURNS TABLE(success boolean, message text, id integer)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id INT;
BEGIN
  IF p_from_step_id = p_to_step_id THEN
    RETURN QUERY SELECT FALSE, 'Không thể tạo liên kết vòng lặp cùng bước'::TEXT, 0::INT;
    RETURN;
  END IF;

  IF EXISTS (
    SELECT 1 FROM edoc.doc_flow_step_links
    WHERE from_step_id = p_from_step_id AND to_step_id = p_to_step_id
  ) THEN
    RETURN QUERY SELECT FALSE, 'Liên kết giữa hai bước này đã tồn tại'::TEXT, 0::INT;
    RETURN;
  END IF;

  INSERT INTO edoc.doc_flow_step_links (from_step_id, to_step_id)
  VALUES (p_from_step_id, p_to_step_id)
  RETURNING edoc.doc_flow_step_links.id INTO v_id;

  RETURN QUERY SELECT TRUE, 'Tạo liên kết bước thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_doc_flow_step_link_delete(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_flow_step_link_delete(p_link_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  DELETE FROM edoc.doc_flow_step_links WHERE id = p_link_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Liên kết không tồn tại'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT TRUE, 'Xóa liên kết bước thành công'::TEXT;
END;
$$;


--
-- Name: fn_doc_flow_step_update(integer, character varying, integer, character varying, boolean, integer, double precision, double precision); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_flow_step_update(p_step_id integer, p_step_name character varying, p_step_order integer, p_step_type character varying, p_allow_sign boolean, p_deadline_days integer, p_position_x double precision, p_position_y double precision) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF p_step_name IS NULL OR TRIM(p_step_name) = '' THEN
    RETURN QUERY SELECT FALSE, 'Tên bước không được để trống'::TEXT;
    RETURN;
  END IF;

  IF p_step_type NOT IN ('start', 'process', 'end') THEN
    RETURN QUERY SELECT FALSE, 'Loại bước không hợp lệ (start/process/end)'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.doc_flow_steps SET
    step_name     = TRIM(p_step_name),
    step_order    = COALESCE(p_step_order, step_order),
    step_type     = COALESCE(p_step_type, step_type),
    allow_sign    = COALESCE(p_allow_sign, allow_sign),
    deadline_days = COALESCE(p_deadline_days, deadline_days),
    position_x    = COALESCE(p_position_x, position_x),
    position_y    = COALESCE(p_position_y, position_y)
  WHERE id = p_step_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Bước quy trình không tồn tại'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT TRUE, 'Cập nhật bước quy trình thành công'::TEXT;
END;
$$;


--
-- Name: fn_doc_flow_update(integer, character varying, character varying, integer, boolean); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_flow_update(p_id integer, p_name character varying, p_version character varying, p_doc_field_id integer, p_is_active boolean) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF p_name IS NULL OR TRIM(p_name) = '' THEN
    RETURN QUERY SELECT FALSE, 'Tên quy trình không được để trống'::TEXT;
    RETURN;
  END IF;

  IF NOT EXISTS (SELECT 1 FROM edoc.doc_flows WHERE id = p_id) THEN
    RETURN QUERY SELECT FALSE, 'Quy trình không tồn tại'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.doc_flows SET
    name          = TRIM(p_name),
    version       = NULLIF(TRIM(COALESCE(p_version, '')), ''),
    doc_field_id  = p_doc_field_id,
    is_active     = COALESCE(p_is_active, is_active),
    updated_at    = NOW()
  WHERE id = p_id;

  RETURN QUERY SELECT TRUE, 'Cập nhật quy trình thành công'::TEXT;
END;
$$;


--
-- Name: fn_doc_save_extra_fields(character varying, bigint, jsonb); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_save_extra_fields(p_doc_type character varying, p_doc_id bigint, p_extra jsonb) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF p_doc_type = 'incoming' THEN
    UPDATE edoc.incoming_docs SET extra_fields = COALESCE(p_extra, '{}') WHERE id = p_doc_id;
  ELSIF p_doc_type = 'outgoing' THEN
    UPDATE edoc.outgoing_docs SET extra_fields = COALESCE(p_extra, '{}') WHERE id = p_doc_id;
  ELSIF p_doc_type = 'drafting' THEN
    UPDATE edoc.drafting_docs SET extra_fields = COALESCE(p_extra, '{}') WHERE id = p_doc_id;
  ELSE
    RETURN QUERY SELECT FALSE, 'Loại VB không hợp lệ'::TEXT; RETURN;
  END IF;

  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản'::TEXT; RETURN;
  END IF;

  RETURN QUERY SELECT TRUE, 'Lưu trường bổ sung thành công'::TEXT;
END;
$$;


--
-- Name: fn_doc_type_create(smallint, integer, character varying, character varying, smallint, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_type_create(p_type_id smallint, p_parent_id integer DEFAULT NULL::integer, p_name character varying DEFAULT NULL::character varying, p_code character varying DEFAULT NULL::character varying, p_notation_type smallint DEFAULT 0, p_sort_order integer DEFAULT 0, p_created_by integer DEFAULT NULL::integer) RETURNS TABLE(success boolean, message text, id integer)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id INT;
BEGIN
  -- Validate required
  IF p_name IS NULL OR TRIM(p_name) = '' THEN
    RETURN QUERY SELECT FALSE, 'Tên loại văn bản không được để trống'::TEXT, 0;
    RETURN;
  END IF;
  IF p_code IS NULL OR TRIM(p_code) = '' THEN
    RETURN QUERY SELECT FALSE, 'Mã loại văn bản không được để trống'::TEXT, 0;
    RETURN;
  END IF;
  IF LENGTH(p_code) > 20 THEN
    RETURN QUERY SELECT FALSE, 'Mã loại văn bản không được vượt quá 20 ký tự'::TEXT, 0;
    RETURN;
  END IF;
  IF LENGTH(p_name) > 200 THEN
    RETURN QUERY SELECT FALSE, 'Tên loại văn bản không được vượt quá 200 ký tự'::TEXT, 0;
    RETURN;
  END IF;

  -- Check unique code
  IF EXISTS(
    SELECT 1 FROM edoc.doc_types
    WHERE LOWER(TRIM(code)) = LOWER(TRIM(p_code)) AND is_deleted = FALSE
  ) THEN
    RETURN QUERY SELECT FALSE, 'Mã loại văn bản đã tồn tại'::TEXT, 0;
    RETURN;
  END IF;

  -- Check parent exists
  IF p_parent_id IS NOT NULL THEN
    IF NOT EXISTS(SELECT 1 FROM edoc.doc_types dt WHERE dt.id = p_parent_id AND dt.is_deleted = FALSE) THEN
      RETURN QUERY SELECT FALSE, 'Loại văn bản cha không tồn tại'::TEXT, 0;
      RETURN;
    END IF;
  END IF;

  INSERT INTO edoc.doc_types (type_id, parent_id, code, name, notation_type, sort_order, created_by)
  VALUES (p_type_id, p_parent_id, TRIM(p_code), TRIM(p_name), p_notation_type, p_sort_order, p_created_by)
  RETURNING doc_types.id INTO v_id;

  RETURN QUERY SELECT TRUE, 'Tao loai van ban thanh cong'::TEXT, v_id;
END;
$$;


--
-- Name: fn_doc_type_delete(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_type_delete(p_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_child_count INT;
BEGIN
  IF NOT EXISTS(SELECT 1 FROM edoc.doc_types WHERE id = p_id AND is_deleted = FALSE) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy loại văn bản'::TEXT;
    RETURN;
  END IF;

  SELECT COUNT(*) INTO v_child_count
  FROM edoc.doc_types WHERE parent_id = p_id AND is_deleted = FALSE;

  IF v_child_count > 0 THEN
    RETURN QUERY SELECT FALSE, ('Không thể xóa: còn '|| v_child_count ||' loại văn bản con')::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.doc_types SET is_deleted = TRUE WHERE id = p_id;
  RETURN QUERY SELECT TRUE, 'Xoa loai van ban thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_doc_type_get_by_id(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_type_get_by_id(p_id integer) RETURNS TABLE(id integer, type_id smallint, parent_id integer, code character varying, name character varying, description text, sort_order integer, notation_type smallint, is_default boolean, created_at timestamp with time zone)
    LANGUAGE sql STABLE
    AS $$
  SELECT t.id, t.type_id, t.parent_id, t.code::VARCHAR, t.name::VARCHAR,
         t.description, t.sort_order, t.notation_type,
         t.is_default, t.created_at
  FROM edoc.doc_types t
  WHERE t.id = p_id AND t.is_deleted = FALSE;
$$;


--
-- Name: fn_doc_type_get_tree(smallint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_type_get_tree(p_type_id smallint DEFAULT NULL::smallint) RETURNS TABLE(id integer, type_id smallint, parent_id integer, code character varying, name character varying, description text, sort_order integer, notation_type smallint, is_default boolean, created_at timestamp with time zone)
    LANGUAGE sql STABLE
    AS $$
  SELECT t.id, t.type_id, t.parent_id, t.code::VARCHAR, t.name::VARCHAR,
         t.description, t.sort_order, t.notation_type,
         t.is_default, t.created_at
  FROM edoc.doc_types t
  WHERE t.is_deleted = FALSE
    AND (p_type_id IS NULL OR t.type_id = p_type_id)
  ORDER BY t.sort_order, t.name;
$$;


--
-- Name: fn_doc_type_update(integer, integer, character varying, character varying, smallint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_doc_type_update(p_id integer, p_parent_id integer DEFAULT NULL::integer, p_name character varying DEFAULT NULL::character varying, p_code character varying DEFAULT NULL::character varying, p_notation_type smallint DEFAULT NULL::smallint, p_sort_order integer DEFAULT NULL::integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NOT EXISTS(SELECT 1 FROM edoc.doc_types WHERE id = p_id AND is_deleted = FALSE) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy loại văn bản'::TEXT;
    RETURN;
  END IF;

  IF p_name IS NULL OR TRIM(p_name) = '' THEN
    RETURN QUERY SELECT FALSE, 'Tên loại văn bản không được để trống'::TEXT;
    RETURN;
  END IF;
  IF p_code IS NULL OR TRIM(p_code) = '' THEN
    RETURN QUERY SELECT FALSE, 'Mã loại văn bản không được để trống'::TEXT;
    RETURN;
  END IF;
  IF LENGTH(p_code) > 20 THEN
    RETURN QUERY SELECT FALSE, 'Mã loại văn bản không được vượt quá 20 ký tự'::TEXT;
    RETURN;
  END IF;

  -- Check unique code (exclude self)
  IF EXISTS(
    SELECT 1 FROM edoc.doc_types
    WHERE LOWER(TRIM(code)) = LOWER(TRIM(p_code))
      AND id <> p_id AND is_deleted = FALSE
  ) THEN
    RETURN QUERY SELECT FALSE, 'Mã loại văn bản đã tồn tại'::TEXT;
    RETURN;
  END IF;

  -- Prevent self-referencing
  IF p_parent_id = p_id THEN
    RETURN QUERY SELECT FALSE, 'Không thể chọn chính mình làm cha'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.doc_types SET
    parent_id     = p_parent_id,
    name          = TRIM(p_name),
    code          = TRIM(p_code),
    notation_type = COALESCE(p_notation_type, notation_type),
    sort_order    = COALESCE(p_sort_order, sort_order)
  WHERE id = p_id;

  RETURN QUERY SELECT TRUE, 'Cap nhat thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_drafting_doc_approve(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_drafting_doc_approve(p_id bigint, p_staff_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_staff_name VARCHAR;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM edoc.drafting_docs WHERE edoc.drafting_docs.id = p_id) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản dự thảo'::TEXT;
    RETURN;
  END IF;

  IF (SELECT is_released FROM edoc.drafting_docs WHERE edoc.drafting_docs.id = p_id) = TRUE THEN
    RETURN QUERY SELECT FALSE, 'Văn bản đã phát hành, không cần duyệt'::TEXT;
    RETURN;
  END IF;

  SELECT full_name INTO v_staff_name FROM public.staff WHERE public.staff.id = p_staff_id;

  UPDATE edoc.drafting_docs SET
    approved = TRUE,
    approver = v_staff_name,
    updated_by = p_staff_id,
    updated_at = NOW()
  WHERE edoc.drafting_docs.id = p_id;

  RETURN QUERY SELECT TRUE, 'Duyệt văn bản dự thảo thành công'::TEXT;
END;
$$;


--
-- Name: fn_drafting_doc_count_unread(integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_drafting_doc_count_unread(p_unit_id integer, p_staff_id integer) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE v_count INT;
BEGIN
  SELECT COUNT(*)::INT INTO v_count
  FROM edoc.drafting_docs d
  LEFT JOIN edoc.user_drafting_docs ud ON ud.drafting_doc_id = d.id AND ud.staff_id = p_staff_id
  WHERE d.unit_id = p_unit_id
    AND (ud.is_read IS NULL OR ud.is_read = FALSE);
  RETURN v_count;
END;
$$;


--
-- Name: fn_drafting_doc_create(integer, timestamp with time zone, integer, character varying, character varying, character varying, text, integer, integer, integer, timestamp with time zone, character varying, timestamp with time zone, integer, integer, integer, smallint, smallint, integer, integer, timestamp with time zone, text, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_drafting_doc_create(p_unit_id integer, p_received_date timestamp with time zone, p_number integer, p_sub_number character varying, p_notation character varying, p_document_code character varying, p_abstract text, p_drafting_unit_id integer DEFAULT NULL::integer, p_drafting_user_id integer DEFAULT NULL::integer, p_publish_unit_id integer DEFAULT NULL::integer, p_publish_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_signer character varying DEFAULT NULL::character varying, p_sign_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_doc_book_id integer DEFAULT NULL::integer, p_doc_type_id integer DEFAULT NULL::integer, p_doc_field_id integer DEFAULT NULL::integer, p_secret_id smallint DEFAULT 1, p_urgent_id smallint DEFAULT 1, p_number_paper integer DEFAULT 1, p_number_copies integer DEFAULT 1, p_expired_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_recipients text DEFAULT NULL::text, p_created_by integer DEFAULT NULL::integer) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id BIGINT;
BEGIN
  -- Validate
  IF p_abstract IS NULL OR TRIM(p_abstract) = '' THEN
    RETURN QUERY SELECT FALSE, 'Trích yếu nội dung không được để trống'::TEXT, 0::BIGINT;
    RETURN;
  END IF;

  IF p_doc_book_id IS NULL THEN
    RETURN QUERY SELECT FALSE, 'Sổ văn bản là bắt buộc'::TEXT, 0::BIGINT;
    RETURN;
  END IF;

  -- Auto number nếu không truyền
  IF p_number IS NULL OR p_number = 0 THEN
    p_number := edoc.fn_drafting_doc_get_next_number(p_doc_book_id, p_unit_id);
  END IF;

  INSERT INTO edoc.drafting_docs (
    unit_id, received_date, number, sub_number, notation, document_code,
    abstract, drafting_unit_id, drafting_user_id, publish_unit_id, publish_date,
    signer, sign_date, doc_book_id, doc_type_id, doc_field_id,
    secret_id, urgent_id, number_paper, number_copies, expired_date,
    recipients, created_by, updated_by
  ) VALUES (
    p_unit_id, COALESCE(p_received_date, NOW()), p_number,
    NULLIF(TRIM(p_sub_number), ''), NULLIF(TRIM(p_notation), ''), NULLIF(TRIM(p_document_code), ''),
    TRIM(p_abstract), p_drafting_unit_id, p_drafting_user_id, p_publish_unit_id, p_publish_date,
    NULLIF(TRIM(p_signer), ''), p_sign_date, p_doc_book_id, p_doc_type_id, p_doc_field_id,
    COALESCE(p_secret_id, 1), COALESCE(p_urgent_id, 1),
    COALESCE(p_number_paper, 1), COALESCE(p_number_copies, 1), p_expired_date,
    NULLIF(TRIM(p_recipients), ''), p_created_by, p_created_by
  )
  RETURNING edoc.drafting_docs.id INTO v_id;

  RETURN QUERY SELECT TRUE, 'Tạo văn bản dự thảo thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_drafting_doc_delete(bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_drafting_doc_delete(p_id bigint) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_approved BOOLEAN;
  v_released BOOLEAN;
BEGIN
  SELECT approved, is_released INTO v_approved, v_released
  FROM edoc.drafting_docs WHERE edoc.drafting_docs.id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản dự thảo'::TEXT;
    RETURN;
  END IF;
  IF v_approved = TRUE THEN
    RETURN QUERY SELECT FALSE, 'Không thể xóa văn bản đã được duyệt'::TEXT;
    RETURN;
  END IF;
  IF v_released = TRUE THEN
    RETURN QUERY SELECT FALSE, 'Không thể xóa văn bản đã phát hành'::TEXT;
    RETURN;
  END IF;

  DELETE FROM edoc.drafting_docs WHERE edoc.drafting_docs.id = p_id;
  RETURN QUERY SELECT TRUE, 'Xóa văn bản dự thảo thành công'::TEXT;
END;
$$;


--
-- Name: fn_drafting_doc_get_by_id(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_drafting_doc_get_by_id(p_id bigint, p_staff_id integer) RETURNS TABLE(id bigint, unit_id integer, received_date timestamp with time zone, number integer, sub_number character varying, notation character varying, document_code character varying, abstract text, drafting_unit_id integer, drafting_user_id integer, publish_unit_id integer, publish_date timestamp with time zone, signer character varying, sign_date timestamp with time zone, doc_book_id integer, doc_type_id integer, doc_field_id integer, secret_id smallint, urgent_id smallint, number_paper integer, number_copies integer, expired_date timestamp with time zone, recipients text, approver character varying, approved boolean, is_released boolean, released_date timestamp with time zone, reject_reason text, created_by integer, created_at timestamp with time zone, updated_by integer, updated_at timestamp with time zone, doc_book_name character varying, doc_type_name character varying, doc_type_code character varying, doc_field_name character varying, drafting_unit_name character varying, drafting_user_name character varying, publish_unit_name character varying, created_by_name character varying, is_read boolean)
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- Đánh dấu đã đọc
  INSERT INTO edoc.user_drafting_docs (drafting_doc_id, staff_id, is_read, read_at)
  VALUES (p_id, p_staff_id, TRUE, NOW())
  ON CONFLICT (drafting_doc_id, staff_id)
  DO UPDATE SET is_read = TRUE, read_at = COALESCE(edoc.user_drafting_docs.read_at, NOW());

  RETURN QUERY
  SELECT
    d.id, d.unit_id, d.received_date, d.number, d.sub_number,
    d.notation, d.document_code, d.abstract,
    d.drafting_unit_id, d.drafting_user_id, d.publish_unit_id, d.publish_date,
    d.signer, d.sign_date, d.doc_book_id, d.doc_type_id, d.doc_field_id,
    d.secret_id, d.urgent_id, d.number_paper, d.number_copies,
    d.expired_date, d.recipients, d.approver, d.approved,
    d.is_released, d.released_date,
    d.reject_reason,                                -- MỚI
    d.created_by, d.created_at, d.updated_by, d.updated_at,
    db.name, dt.name, dt.code, df.name,
    du.name, ds.full_name,
    pu.name,                                        -- MỚI: publish_unit_name
    s.full_name,
    TRUE
  FROM edoc.drafting_docs d
  LEFT JOIN edoc.doc_books db ON db.id = d.doc_book_id
  LEFT JOIN edoc.doc_types dt ON dt.id = d.doc_type_id
  LEFT JOIN edoc.doc_fields df ON df.id = d.doc_field_id
  LEFT JOIN public.departments du ON du.id = d.drafting_unit_id
  LEFT JOIN public.staff ds ON ds.id = d.drafting_user_id
  LEFT JOIN public.departments pu ON pu.id = d.publish_unit_id    -- MỚI
  LEFT JOIN public.staff s ON s.id = d.created_by
  WHERE d.id = p_id;
END;
$$;


--
-- Name: fn_drafting_doc_get_history(bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_drafting_doc_get_history(p_doc_id bigint) RETURNS TABLE(event_type character varying, event_time timestamp with time zone, staff_name character varying, content text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT * FROM (
    -- Tạo
    SELECT 'created'::VARCHAR AS evt, d.created_at AS etime, s.full_name AS sname,
           ('Tạo văn bản dự thảo, số: ' || d.number)::TEXT AS econtent
    FROM edoc.drafting_docs d
    JOIN public.staff s ON s.id = d.created_by
    WHERE d.id = p_doc_id

    UNION ALL
    -- Duyệt
    SELECT 'approved'::VARCHAR, d.updated_at, d.approver::VARCHAR, 'Duyệt văn bản dự thảo'::TEXT
    FROM edoc.drafting_docs d
    WHERE d.id = p_doc_id AND d.approved = TRUE

    UNION ALL
    -- Phát hành
    SELECT 'released'::VARCHAR, d.released_date, s.full_name, 'Phát hành thành văn bản đi'::TEXT
    FROM edoc.drafting_docs d
    JOIN public.staff s ON s.id = d.updated_by
    WHERE d.id = p_doc_id AND d.is_released = TRUE

    UNION ALL
    -- Gửi
    SELECT 'sent'::VARCHAR, ud.created_at, s.full_name, 'Nhận văn bản'::TEXT
    FROM edoc.user_drafting_docs ud
    JOIN public.staff s ON s.id = ud.staff_id
    WHERE ud.drafting_doc_id = p_doc_id
  ) sub
  ORDER BY sub.etime DESC;
END;
$$;


--
-- Name: fn_drafting_doc_get_list(integer, integer, integer, integer, integer, smallint, boolean, boolean, timestamp with time zone, timestamp with time zone, text, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_drafting_doc_get_list(p_unit_id integer, p_staff_id integer, p_doc_book_id integer DEFAULT NULL::integer, p_doc_type_id integer DEFAULT NULL::integer, p_doc_field_id integer DEFAULT NULL::integer, p_urgent_id smallint DEFAULT NULL::smallint, p_is_released boolean DEFAULT NULL::boolean, p_approved boolean DEFAULT NULL::boolean, p_from_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_to_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_keyword text DEFAULT NULL::text, p_page integer DEFAULT 1, p_page_size integer DEFAULT 20) RETURNS TABLE(id bigint, unit_id integer, received_date timestamp with time zone, number integer, sub_number character varying, notation character varying, document_code character varying, abstract text, drafting_unit_id integer, drafting_user_id integer, publish_unit_id integer, publish_date timestamp with time zone, signer character varying, sign_date timestamp with time zone, doc_book_id integer, doc_type_id integer, doc_field_id integer, secret_id smallint, urgent_id smallint, number_paper integer, number_copies integer, expired_date timestamp with time zone, recipients text, approver character varying, approved boolean, is_released boolean, released_date timestamp with time zone, created_by integer, created_at timestamp with time zone, doc_book_name character varying, doc_type_name character varying, doc_type_code character varying, doc_field_name character varying, drafting_unit_name character varying, drafting_user_name character varying, created_by_name character varying, is_read boolean, read_at timestamp with time zone, attachment_count bigint, total_count bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_offset INT;
  v_keyword TEXT;
BEGIN
  v_offset := (GREATEST(p_page, 1) - 1) * p_page_size;
  v_keyword := NULLIF(TRIM(p_keyword), '');

  RETURN QUERY
  WITH filtered AS (
    SELECT
      d.id AS doc_id,
      d.*,
      db.name AS _doc_book_name,
      dt.name AS _doc_type_name,
      dt.code AS _doc_type_code,
      df.name AS _doc_field_name,
      du.name AS _drafting_unit_name,
      ds.full_name AS _drafting_user_name,
      s.full_name AS _created_by_name,
      ud.is_read AS _is_read,
      ud.read_at AS _read_at,
      (SELECT COUNT(*) FROM edoc.attachment_drafting_docs a WHERE a.drafting_doc_id = d.id) AS _attachment_count,
      COUNT(*) OVER() AS _total_count
    FROM edoc.drafting_docs d
    LEFT JOIN edoc.doc_books db ON db.id = d.doc_book_id
    LEFT JOIN edoc.doc_types dt ON dt.id = d.doc_type_id
    LEFT JOIN edoc.doc_fields df ON df.id = d.doc_field_id
    LEFT JOIN public.departments du ON du.id = d.drafting_unit_id
    LEFT JOIN public.staff ds ON ds.id = d.drafting_user_id
    LEFT JOIN public.staff s ON s.id = d.created_by
    LEFT JOIN edoc.user_drafting_docs ud ON ud.drafting_doc_id = d.id AND ud.staff_id = p_staff_id
    WHERE d.unit_id = p_unit_id
      AND (p_doc_book_id IS NULL OR d.doc_book_id = p_doc_book_id)
      AND (p_doc_type_id IS NULL OR d.doc_type_id = p_doc_type_id)
      AND (p_doc_field_id IS NULL OR d.doc_field_id = p_doc_field_id)
      AND (p_urgent_id IS NULL OR d.urgent_id = p_urgent_id)
      AND (p_approved IS NULL OR d.approved = p_approved)
      AND (p_is_released IS NULL OR d.is_released = p_is_released)
      AND (p_from_date IS NULL OR d.received_date >= p_from_date)
      AND (p_to_date IS NULL OR d.received_date <= p_to_date)
      AND (v_keyword IS NULL OR
           d.abstract ILIKE '%' || v_keyword || '%' OR
           d.notation ILIKE '%' || v_keyword || '%' OR
           d.signer ILIKE '%' || v_keyword || '%' OR
           d.recipients ILIKE '%' || v_keyword || '%'
      )
    ORDER BY d.received_date DESC, d.number DESC
    LIMIT p_page_size OFFSET v_offset
  )
  SELECT
    f.doc_id, f.unit_id, f.received_date, f.number, f.sub_number,
    f.notation, f.document_code, f.abstract,
    f.drafting_unit_id, f.drafting_user_id, f.publish_unit_id, f.publish_date,
    f.signer, f.sign_date, f.doc_book_id, f.doc_type_id, f.doc_field_id,
    f.secret_id, f.urgent_id, f.number_paper, f.number_copies,
    f.expired_date, f.recipients, f.approver, f.approved,
    f.is_released, f.released_date, f.created_by, f.created_at,
    f._doc_book_name, f._doc_type_name, f._doc_type_code, f._doc_field_name,
    f._drafting_unit_name, f._drafting_user_name, f._created_by_name,
    COALESCE(f._is_read, FALSE), f._read_at,
    f._attachment_count, f._total_count
  FROM filtered f;
END;
$$;


--
-- Name: fn_drafting_doc_get_next_number(integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_drafting_doc_get_next_number(p_doc_book_id integer, p_unit_id integer) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE v_max INT;
BEGIN
  SELECT COALESCE(MAX(number), 0) INTO v_max
  FROM edoc.drafting_docs
  WHERE doc_book_id = p_doc_book_id
    AND unit_id = p_unit_id
    AND EXTRACT(YEAR FROM received_date) = EXTRACT(YEAR FROM NOW());
  RETURN v_max + 1;
END;
$$;


--
-- Name: fn_drafting_doc_get_recipients(bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_drafting_doc_get_recipients(p_doc_id bigint) RETURNS TABLE(id bigint, staff_id integer, staff_name character varying, position_name character varying, department_name character varying, is_read boolean, read_at timestamp with time zone, created_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    ud.id, ud.staff_id,
    s.full_name,
    p.name AS position_name,
    dep.name AS department_name,
    ud.is_read, ud.read_at, ud.created_at
  FROM edoc.user_drafting_docs ud
  JOIN public.staff s ON s.id = ud.staff_id
  LEFT JOIN public.positions p ON p.id = s.position_id
  LEFT JOIN public.departments dep ON dep.id = s.department_id
  WHERE ud.drafting_doc_id = p_doc_id
  ORDER BY ud.created_at DESC;
END;
$$;


--
-- Name: fn_drafting_doc_mark_read_bulk(bigint[], integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_drafting_doc_mark_read_bulk(p_doc_ids bigint[], p_staff_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  INSERT INTO edoc.user_drafting_docs (drafting_doc_id, staff_id, is_read, read_at)
  SELECT unnest(p_doc_ids), p_staff_id, TRUE, NOW()
  ON CONFLICT (drafting_doc_id, staff_id)
  DO UPDATE SET is_read = TRUE, read_at = COALESCE(edoc.user_drafting_docs.read_at, NOW());

  RETURN QUERY SELECT TRUE, 'Đã đánh dấu đọc thành công'::TEXT;
END;
$$;


--
-- Name: fn_drafting_doc_reject(bigint, integer, text); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_drafting_doc_reject(p_id bigint, p_staff_id integer, p_reason text DEFAULT NULL::text) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_staff_name VARCHAR;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM edoc.drafting_docs WHERE edoc.drafting_docs.id = p_id) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản dự thảo'::TEXT;
    RETURN;
  END IF;

  IF (SELECT is_released FROM edoc.drafting_docs WHERE edoc.drafting_docs.id = p_id) = TRUE THEN
    RETURN QUERY SELECT FALSE, 'Không thể từ chối: văn bản đã phát hành'::TEXT;
    RETURN;
  END IF;

  SELECT full_name INTO v_staff_name FROM public.staff WHERE public.staff.id = p_staff_id;

  UPDATE edoc.drafting_docs SET
    approved = FALSE,
    approver = NULL,
    reject_reason = NULLIF(TRIM(p_reason), ''),    -- MỚI: lưu lý do
    updated_by = p_staff_id,
    updated_at = NOW()
  WHERE edoc.drafting_docs.id = p_id;

  RETURN QUERY SELECT TRUE, 'Đã từ chối văn bản dự thảo'::TEXT;
END;
$$;


--
-- Name: fn_drafting_doc_release(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_drafting_doc_release(p_id bigint, p_released_by integer) RETURNS TABLE(success boolean, message text, outgoing_doc_id bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_draft   edoc.drafting_docs%ROWTYPE;
  v_out_id  BIGINT;
BEGIN
  SELECT * INTO v_draft FROM edoc.drafting_docs WHERE edoc.drafting_docs.id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản dự thảo'::TEXT, 0::BIGINT;
    RETURN;
  END IF;

  IF v_draft.approved IS NULL OR v_draft.approved = FALSE THEN
    RETURN QUERY SELECT FALSE, 'Văn bản chưa được duyệt, không thể phát hành'::TEXT, 0::BIGINT;
    RETURN;
  END IF;

  IF v_draft.is_released = TRUE THEN
    RETURN QUERY SELECT FALSE, 'Văn bản đã được phát hành trước đó'::TEXT, 0::BIGINT;
    RETURN;
  END IF;

  -- Tạo VB đi từ dự thảo
  INSERT INTO edoc.outgoing_docs (
    unit_id, received_date, number, sub_number, notation, document_code,
    abstract, drafting_unit_id, drafting_user_id, publish_unit_id, publish_date,
    signer, sign_date, expired_date,
    number_paper, number_copies, secret_id, urgent_id,
    recipients, doc_book_id, doc_type_id, doc_field_id,
    approved, approver, created_by, updated_by
  ) VALUES (
    v_draft.unit_id, v_draft.received_date, v_draft.number, v_draft.sub_number,
    v_draft.notation, v_draft.document_code, v_draft.abstract,
    v_draft.drafting_unit_id, v_draft.drafting_user_id, v_draft.publish_unit_id, v_draft.publish_date,
    v_draft.signer, v_draft.sign_date, v_draft.expired_date,
    v_draft.number_paper, v_draft.number_copies, v_draft.secret_id, v_draft.urgent_id,
    v_draft.recipients, v_draft.doc_book_id, v_draft.doc_type_id, v_draft.doc_field_id,
    TRUE, v_draft.approver, p_released_by, p_released_by
  )
  RETURNING edoc.outgoing_docs.id INTO v_out_id;

  -- Copy đính kèm từ dự thảo sang VB đi
  INSERT INTO edoc.attachment_outgoing_docs (outgoing_doc_id, file_name, file_path, file_size, content_type, sort_order, created_by)
  SELECT v_out_id, file_name, file_path, file_size, content_type, sort_order, created_by
  FROM edoc.attachment_drafting_docs
  WHERE drafting_doc_id = p_id;

  -- Đánh dấu dự thảo đã phát hành
  UPDATE edoc.drafting_docs SET
    is_released = TRUE,
    released_date = NOW(),
    updated_by = p_released_by,
    updated_at = NOW()
  WHERE edoc.drafting_docs.id = p_id;

  RETURN QUERY SELECT TRUE, 'Phát hành thành công, đã tạo văn bản đi'::TEXT, v_out_id;
END;
$$;


--
-- Name: fn_drafting_doc_retract(bigint, integer, integer[]); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_drafting_doc_retract(p_id bigint, p_staff_id integer, p_staff_ids integer[] DEFAULT NULL::integer[]) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_is_released BOOLEAN;
  v_deleted_count INT;
BEGIN
  SELECT d.is_released INTO v_is_released
  FROM edoc.drafting_docs d WHERE d.id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản dự thảo'::TEXT; RETURN;
  END IF;

  IF v_is_released THEN
    RETURN QUERY SELECT FALSE, 'Không thể thu hồi — văn bản đã phát hành'::TEXT; RETURN;
  END IF;

  IF p_staff_ids IS NULL THEN
    DELETE FROM edoc.user_drafting_docs WHERE drafting_doc_id = p_id;
    GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
    UPDATE edoc.drafting_docs SET approved = FALSE, updated_by = p_staff_id, updated_at = NOW() WHERE id = p_id;
  ELSE
    DELETE FROM edoc.user_drafting_docs WHERE drafting_doc_id = p_id AND staff_id = ANY(p_staff_ids);
    GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
    UPDATE edoc.drafting_docs SET updated_by = p_staff_id, updated_at = NOW() WHERE id = p_id;
  END IF;

  RETURN QUERY SELECT TRUE, ('Thu hồi thành công — đã xóa ' || v_deleted_count || ' người nhận')::TEXT;
END;
$$;


--
-- Name: fn_drafting_doc_send(bigint, integer[], integer, timestamp with time zone); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_drafting_doc_send(p_doc_id bigint, p_staff_ids integer[], p_sent_by integer, p_expired_date timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_approved BOOLEAN;
  v_count INT;
BEGIN
  SELECT approved INTO v_approved FROM edoc.drafting_docs WHERE edoc.drafting_docs.id = p_doc_id;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản dự thảo'::TEXT;
    RETURN;
  END IF;
  IF v_approved IS NULL OR v_approved = FALSE THEN
    RETURN QUERY SELECT FALSE, 'Văn bản chưa được duyệt, không thể gửi'::TEXT;
    RETURN;
  END IF;

  IF p_staff_ids IS NULL OR array_length(p_staff_ids, 1) IS NULL THEN
    RETURN QUERY SELECT FALSE, 'Vui lòng chọn ít nhất một người nhận'::TEXT;
    RETURN;
  END IF;

  INSERT INTO edoc.user_drafting_docs (drafting_doc_id, staff_id, sent_by, expired_date, is_read, created_at)
  SELECT p_doc_id, unnest(p_staff_ids), p_sent_by, p_expired_date, FALSE, NOW()
  ON CONFLICT (drafting_doc_id, staff_id) DO NOTHING;

  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN QUERY SELECT TRUE, ('Đã gửi cho ' || v_count || ' người nhận')::TEXT;
END;
$$;


--
-- Name: fn_drafting_doc_unapprove(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_drafting_doc_unapprove(p_id bigint, p_staff_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM edoc.drafting_docs WHERE edoc.drafting_docs.id = p_id) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản dự thảo'::TEXT;
    RETURN;
  END IF;

  IF (SELECT is_released FROM edoc.drafting_docs WHERE edoc.drafting_docs.id = p_id) = TRUE THEN
    RETURN QUERY SELECT FALSE, 'Không thể hủy duyệt: văn bản đã phát hành'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.drafting_docs SET
    approved = FALSE,
    approver = NULL,
    updated_by = p_staff_id,
    updated_at = NOW()
  WHERE edoc.drafting_docs.id = p_id;

  RETURN QUERY SELECT TRUE, 'Hủy duyệt thành công'::TEXT;
END;
$$;


--
-- Name: fn_drafting_doc_update(bigint, timestamp with time zone, integer, character varying, character varying, character varying, text, integer, integer, integer, timestamp with time zone, character varying, timestamp with time zone, integer, integer, integer, smallint, smallint, integer, integer, timestamp with time zone, text, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_drafting_doc_update(p_id bigint, p_received_date timestamp with time zone, p_number integer, p_sub_number character varying, p_notation character varying, p_document_code character varying, p_abstract text, p_drafting_unit_id integer DEFAULT NULL::integer, p_drafting_user_id integer DEFAULT NULL::integer, p_publish_unit_id integer DEFAULT NULL::integer, p_publish_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_signer character varying DEFAULT NULL::character varying, p_sign_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_doc_book_id integer DEFAULT NULL::integer, p_doc_type_id integer DEFAULT NULL::integer, p_doc_field_id integer DEFAULT NULL::integer, p_secret_id smallint DEFAULT 1, p_urgent_id smallint DEFAULT 1, p_number_paper integer DEFAULT 1, p_number_copies integer DEFAULT 1, p_expired_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_recipients text DEFAULT NULL::text, p_updated_by integer DEFAULT NULL::integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_approved BOOLEAN;
  v_released BOOLEAN;
BEGIN
  SELECT approved, is_released INTO v_approved, v_released
  FROM edoc.drafting_docs WHERE edoc.drafting_docs.id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản dự thảo'::TEXT;
    RETURN;
  END IF;
  IF v_approved = TRUE THEN
    RETURN QUERY SELECT FALSE, 'Không thể sửa văn bản đã được duyệt'::TEXT;
    RETURN;
  END IF;
  IF v_released = TRUE THEN
    RETURN QUERY SELECT FALSE, 'Không thể sửa văn bản đã phát hành'::TEXT;
    RETURN;
  END IF;

  IF p_abstract IS NULL OR TRIM(p_abstract) = '' THEN
    RETURN QUERY SELECT FALSE, 'Trích yếu nội dung không được để trống'::TEXT;
    RETURN;
  END IF;
  IF p_doc_book_id IS NULL THEN
    RETURN QUERY SELECT FALSE, 'Sổ văn bản là bắt buộc'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.drafting_docs SET
    received_date     = COALESCE(p_received_date, received_date),
    number            = COALESCE(p_number, number),
    sub_number        = NULLIF(TRIM(p_sub_number), ''),
    notation          = NULLIF(TRIM(p_notation), ''),
    document_code     = NULLIF(TRIM(p_document_code), ''),
    abstract          = TRIM(p_abstract),
    drafting_unit_id  = p_drafting_unit_id,
    drafting_user_id  = p_drafting_user_id,
    publish_unit_id   = p_publish_unit_id,
    publish_date      = p_publish_date,
    signer            = NULLIF(TRIM(p_signer), ''),
    sign_date         = p_sign_date,
    doc_book_id       = p_doc_book_id,
    doc_type_id       = p_doc_type_id,
    doc_field_id      = p_doc_field_id,
    secret_id         = COALESCE(p_secret_id, 1),
    urgent_id         = COALESCE(p_urgent_id, 1),
    number_paper      = COALESCE(p_number_paper, 1),
    number_copies     = COALESCE(p_number_copies, 1),
    expired_date      = p_expired_date,
    recipients        = NULLIF(TRIM(p_recipients), ''),
    updated_by        = p_updated_by,
    updated_at        = NOW()
  WHERE edoc.drafting_docs.id = p_id;

  RETURN QUERY SELECT TRUE, 'Cập nhật văn bản dự thảo thành công'::TEXT;
END;
$$;


--
-- Name: fn_email_template_create(integer, character varying, character varying, text, text, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_email_template_create(p_unit_id integer, p_name character varying, p_subject character varying DEFAULT NULL::character varying, p_content text DEFAULT NULL::text, p_description text DEFAULT NULL::text, p_created_by integer DEFAULT NULL::integer) RETURNS TABLE(success boolean, message text, id integer)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id INT;
BEGIN
  IF p_name IS NULL OR TRIM(p_name) = '' THEN
    RETURN QUERY SELECT FALSE, 'Tên mẫu email không được để trống'::TEXT, 0;
    RETURN;
  END IF;
  IF p_content IS NULL OR TRIM(p_content) = '' THEN
    RETURN QUERY SELECT FALSE, 'Nội dung mẫu email không được để trống'::TEXT, 0;
    RETURN;
  END IF;
  IF LENGTH(p_name) > 200 THEN
    RETURN QUERY SELECT FALSE, 'Tên mẫu email không được vượt quá 200 ký tự'::TEXT, 0;
    RETURN;
  END IF;
  IF p_subject IS NOT NULL AND LENGTH(p_subject) > 500 THEN
    RETURN QUERY SELECT FALSE, 'Tiêu đề email không được vượt quá 500 ký tự'::TEXT, 0;
    RETURN;
  END IF;

  INSERT INTO edoc.email_templates (unit_id, name, subject, content, description, created_by)
  VALUES (p_unit_id, TRIM(p_name), TRIM(p_subject), TRIM(p_content), p_description, p_created_by)
  RETURNING email_templates.id INTO v_id;

  RETURN QUERY SELECT TRUE, 'Tao mau email thanh cong'::TEXT, v_id;
END;
$$;


--
-- Name: fn_email_template_delete(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_email_template_delete(p_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NOT EXISTS(SELECT 1 FROM edoc.email_templates WHERE id = p_id) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy mẫu email'::TEXT;
    RETURN;
  END IF;

  DELETE FROM edoc.email_templates WHERE id = p_id;
  RETURN QUERY SELECT TRUE, 'Xoa mau email thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_email_template_get_list(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_email_template_get_list(p_unit_id integer) RETURNS TABLE(id integer, unit_id integer, name character varying, subject character varying, content text, description text, is_active boolean, created_by integer, created_at timestamp with time zone)
    LANGUAGE sql STABLE
    AS $$
  SELECT t.id, t.unit_id, t.name::VARCHAR, t.subject::VARCHAR,
         t.content, t.description, t.is_active, t.created_by, t.created_at
  FROM edoc.email_templates t
  WHERE t.unit_id = p_unit_id
  ORDER BY t.name;
$$;


--
-- Name: fn_email_template_update(integer, character varying, character varying, text, text, boolean); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_email_template_update(p_id integer, p_name character varying DEFAULT NULL::character varying, p_subject character varying DEFAULT NULL::character varying, p_content text DEFAULT NULL::text, p_description text DEFAULT NULL::text, p_is_active boolean DEFAULT NULL::boolean) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NOT EXISTS(SELECT 1 FROM edoc.email_templates WHERE id = p_id) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy mẫu email'::TEXT;
    RETURN;
  END IF;
  IF p_name IS NULL OR TRIM(p_name) = '' THEN
    RETURN QUERY SELECT FALSE, 'Tên mẫu email không được để trống'::TEXT;
    RETURN;
  END IF;
  IF p_content IS NULL OR TRIM(p_content) = '' THEN
    RETURN QUERY SELECT FALSE, 'Nội dung mẫu email không được để trống'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.email_templates SET
    name        = TRIM(p_name),
    subject     = COALESCE(TRIM(p_subject), subject),
    content     = TRIM(p_content),
    description = COALESCE(p_description, description),
    is_active   = COALESCE(p_is_active, is_active)
  WHERE id = p_id;

  RETURN QUERY SELECT TRUE, 'Cap nhat mau email thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_handling_doc_approve(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_approve(p_id bigint, p_approved_by integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_status SMALLINT;
BEGIN
  -- T-02-01: validate current status before transition
  SELECT status INTO v_status FROM edoc.handling_docs WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Hồ sơ công việc không tồn tại'::TEXT;
    RETURN;
  END IF;

  -- 5-step flow: chỉ duyệt khi đã trình ký (status=3) → set Hoàn thành (status=4)
  IF v_status <> 3 THEN
    RETURN QUERY SELECT FALSE, 'Chỉ được duyệt khi hồ sơ ở trạng thái Đã trình ký'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.handling_docs SET
    status           = 4,    -- Hoàn thành
    progress         = 100,
    complete_user_id = p_approved_by,
    complete_date    = NOW(),
    updated_by       = p_approved_by,
    updated_at       = NOW()
  WHERE id = p_id;

  INSERT INTO edoc.handling_doc_history (handling_doc_id, action_type, from_staff_id, created_by)
  VALUES (p_id, 'approve', p_approved_by, p_approved_by);

  RETURN QUERY SELECT TRUE, 'Duyệt hồ sơ công việc thành công'::TEXT;
END;
$$;


--
-- Name: fn_handling_doc_assign_staff(bigint, integer[], smallint, timestamp with time zone, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_assign_staff(p_doc_id bigint, p_staff_ids integer[], p_role_type smallint, p_deadline timestamp with time zone, p_assigned_by integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_staff_id INT;
BEGIN
  IF p_staff_ids IS NULL OR ARRAY_LENGTH(p_staff_ids, 1) = 0 THEN
    RETURN QUERY SELECT FALSE, 'Danh sách cán bộ không được để trống'::TEXT;
    RETURN;
  END IF;

  IF NOT EXISTS (SELECT 1 FROM edoc.handling_docs WHERE id = p_doc_id) THEN
    RETURN QUERY SELECT FALSE, 'Hồ sơ công việc không tồn tại'::TEXT;
    RETURN;
  END IF;

  FOREACH v_staff_id IN ARRAY p_staff_ids LOOP
    INSERT INTO edoc.staff_handling_docs (handling_doc_id, staff_id, role, assigned_at)
    VALUES (p_doc_id, v_staff_id, COALESCE(p_role_type, 1), NOW())
    ON CONFLICT DO NOTHING;
  END LOOP;

  RETURN QUERY SELECT TRUE, 'Phân công cán bộ thành công'::TEXT;
END;
$$;


--
-- Name: fn_handling_doc_change_status(bigint, smallint, integer, text); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_change_status(p_id bigint, p_new_status smallint, p_changed_by integer, p_reason text DEFAULT NULL::text) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_status SMALLINT;
BEGIN
  SELECT status INTO v_status FROM edoc.handling_docs WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Hồ sơ công việc không tồn tại'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.handling_docs SET
    status     = p_new_status,
    updated_by = p_changed_by,
    updated_at = NOW()
  WHERE id = p_id;

  INSERT INTO edoc.handling_doc_history (handling_doc_id, action_type, from_staff_id, note, created_by)
  VALUES (p_id, 'change_status:' || p_new_status, p_changed_by, p_reason, p_changed_by);

  RETURN QUERY SELECT TRUE, 'Cập nhật trạng thái thành công'::TEXT;
END;
$$;


--
-- Name: fn_handling_doc_complete(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_complete(p_id bigint, p_completed_by integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_status SMALLINT;
BEGIN
  -- T-02-01: validate current status before transition
  SELECT status INTO v_status FROM edoc.handling_docs WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Hồ sơ công việc không tồn tại'::TEXT;
    RETURN;
  END IF;

  IF v_status <> 3 THEN
    RETURN QUERY SELECT FALSE, 'Chỉ được hoàn thành khi hồ sơ ở trạng thái Đã duyệt'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.handling_docs SET
    status           = 4,  -- Hoàn thành
    complete_user_id = p_completed_by,
    complete_date    = NOW(),
    progress         = 100,
    updated_by       = p_completed_by,
    updated_at       = NOW()
  WHERE id = p_id;

  INSERT INTO edoc.handling_doc_history (handling_doc_id, action_type, from_staff_id, created_by)
  VALUES (p_id, 'complete', p_completed_by, p_completed_by);

  RETURN QUERY SELECT TRUE, 'Hoàn thành hồ sơ công việc thành công'::TEXT;
END;
$$;


--
-- Name: fn_handling_doc_count_by_status(integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_count_by_status(p_unit_id integer, p_staff_id integer) RETURNS TABLE(filter_type text, count bigint)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT 'all'::TEXT,               COUNT(*)::BIGINT FROM edoc.handling_docs WHERE unit_id = p_unit_id
  UNION ALL
  SELECT 'created_by_me'::TEXT,     COUNT(*)::BIGINT FROM edoc.handling_docs WHERE unit_id = p_unit_id AND created_by = p_staff_id
  UNION ALL
  SELECT 'rejected'::TEXT,          COUNT(*)::BIGINT FROM edoc.handling_docs WHERE unit_id = p_unit_id AND status = -1 AND created_by = p_staff_id
  UNION ALL
  SELECT 'returned'::TEXT,          COUNT(*)::BIGINT FROM edoc.handling_docs WHERE unit_id = p_unit_id AND status = -2
  UNION ALL
  SELECT 'pending_primary'::TEXT,   COUNT(*)::BIGINT
    FROM edoc.handling_docs h
    WHERE h.unit_id = p_unit_id AND h.status = 0
      AND EXISTS (SELECT 1 FROM edoc.staff_handling_docs shd WHERE shd.handling_doc_id = h.id AND shd.staff_id = p_staff_id AND shd.role = 1)
  UNION ALL
  SELECT 'pending_coord'::TEXT,     COUNT(*)::BIGINT
    FROM edoc.handling_docs h
    WHERE h.unit_id = p_unit_id AND h.status IN (0, 1)
      AND EXISTS (SELECT 1 FROM edoc.staff_handling_docs shd WHERE shd.handling_doc_id = h.id AND shd.staff_id = p_staff_id AND shd.role = 2)
  UNION ALL
  SELECT 'submitting'::TEXT,        COUNT(*)::BIGINT FROM edoc.handling_docs WHERE unit_id = p_unit_id AND status = 3
  UNION ALL
  SELECT 'in_progress'::TEXT,       COUNT(*)::BIGINT FROM edoc.handling_docs WHERE unit_id = p_unit_id AND status = 1
  UNION ALL
  SELECT 'proposed_complete'::TEXT, COUNT(*)::BIGINT FROM edoc.handling_docs WHERE unit_id = p_unit_id AND status = 3
  UNION ALL
  SELECT 'completed'::TEXT,         COUNT(*)::BIGINT FROM edoc.handling_docs WHERE unit_id = p_unit_id AND status = 4;
END;
$$;


--
-- Name: fn_handling_doc_create(integer, integer, integer, integer, character varying, text, timestamp with time zone, timestamp with time zone, integer, integer, integer, boolean, bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_create(p_unit_id integer, p_department_id integer, p_doc_type_id integer, p_doc_field_id integer, p_name character varying, p_comments text, p_start_date timestamp with time zone, p_end_date timestamp with time zone, p_curator_id integer, p_signer_id integer, p_workflow_id integer, p_is_from_doc boolean, p_parent_id bigint, p_created_by integer) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id BIGINT;
BEGIN
  -- Validate: tên bắt buộc
  IF p_name IS NULL OR TRIM(p_name) = '' THEN
    RETURN QUERY SELECT FALSE, 'Tên hồ sơ công việc không được để trống'::TEXT, 0::BIGINT;
    RETURN;
  END IF;

  -- Validate: hạn giải quyết >= ngày mở
  IF p_start_date IS NOT NULL AND p_end_date IS NOT NULL AND p_end_date < p_start_date THEN
    RETURN QUERY SELECT FALSE, 'Hạn giải quyết phải sau hoặc bằng ngày mở'::TEXT, 0::BIGINT;
    RETURN;
  END IF;

  INSERT INTO edoc.handling_docs (
    unit_id, department_id, doc_type_id, doc_field_id, name, comments,
    start_date, end_date, curator, signer, workflow_id, is_from_doc,
    parent_id, created_by, updated_by
  ) VALUES (
    p_unit_id, p_department_id, p_doc_type_id, p_doc_field_id,
    TRIM(p_name), NULLIF(TRIM(COALESCE(p_comments, '')), ''),
    COALESCE(p_start_date, NOW()), p_end_date, p_curator_id, p_signer_id,
    p_workflow_id, COALESCE(p_is_from_doc, FALSE), p_parent_id,
    p_created_by, p_created_by
  )
  RETURNING edoc.handling_docs.id INTO v_id;

  INSERT INTO edoc.handling_doc_history (handling_doc_id, action_type, from_staff_id, created_by)
  VALUES (v_id, 'create', p_created_by, p_created_by);

  RETURN QUERY SELECT TRUE, 'Tạo hồ sơ công việc thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_handling_doc_create_from_doc(bigint, character varying, text, date, date, integer[], text, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_create_from_doc(p_doc_id bigint, p_doc_type character varying, p_name text, p_start_date date, p_end_date date, p_curator_ids integer[], p_note text, p_created_by integer) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_id      BIGINT;
  v_unit_id INT;
  v_curator_id INT;
  v_cid     INT;
BEGIN
  -- Lấy unit_id từ văn bản gốc
  IF p_doc_type = 'incoming' THEN
    SELECT ind.unit_id INTO v_unit_id FROM edoc.incoming_docs ind WHERE ind.id = p_doc_id;
  ELSIF p_doc_type = 'outgoing' THEN
    SELECT od.unit_id INTO v_unit_id FROM edoc.outgoing_docs od WHERE od.id = p_doc_id;
  ELSIF p_doc_type = 'drafting' THEN
    SELECT dd.unit_id INTO v_unit_id FROM edoc.drafting_docs dd WHERE dd.id = p_doc_id;
  END IF;

  IF v_unit_id IS NULL THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản nguồn'::TEXT, NULL::BIGINT;
    RETURN;
  END IF;

  -- Lấy người phụ trách đầu tiên (primary curator)
  IF p_curator_ids IS NOT NULL AND array_length(p_curator_ids, 1) > 0 THEN
    v_curator_id := p_curator_ids[1];
  END IF;

  -- Tạo hồ sơ công việc
  INSERT INTO edoc.handling_docs (
    unit_id, name, comments, start_date, end_date,
    curator, status, is_from_doc, created_by, created_at, updated_at
  ) VALUES (
    v_unit_id, p_name, p_note, p_start_date, p_end_date,
    v_curator_id, 0, TRUE, p_created_by, NOW(), NOW()
  )
  RETURNING edoc.handling_docs.id INTO v_id;

  -- Liên kết văn bản với HSCV
  INSERT INTO edoc.handling_doc_links (handling_doc_id, doc_type, doc_id)
  VALUES (v_id, p_doc_type, p_doc_id)
  ON CONFLICT DO NOTHING;

  -- Thêm các người phụ trách vào staff_handling_docs
  IF p_curator_ids IS NOT NULL THEN
    FOREACH v_cid IN ARRAY p_curator_ids LOOP
      INSERT INTO edoc.staff_handling_docs (handling_doc_id, staff_id, role, assigned_at)
      VALUES (v_id, v_cid, 1, NOW())
      ON CONFLICT DO NOTHING;
    END LOOP;
  END IF;

  RETURN QUERY SELECT TRUE, 'Tạo hồ sơ công việc thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_handling_doc_delete(bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_delete(p_id bigint) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_status SMALLINT;
BEGIN
  SELECT status INTO v_status FROM edoc.handling_docs WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Hồ sơ công việc không tồn tại'::TEXT;
    RETURN;
  END IF;

  -- Chỉ xóa khi trạng thái = 0 (Mới) — T-02-02 threat mitigation
  IF v_status <> 0 THEN
    RETURN QUERY SELECT FALSE, 'Chỉ được xóa hồ sơ công việc ở trạng thái Mới'::TEXT;
    RETURN;
  END IF;

  DELETE FROM edoc.handling_docs WHERE id = p_id;
  RETURN QUERY SELECT TRUE, 'Xóa hồ sơ công việc thành công'::TEXT;
END;
$$;


--
-- Name: fn_handling_doc_get_attachments(bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_get_attachments(p_doc_id bigint) RETURNS TABLE(id bigint, file_name character varying, file_path character varying, file_size bigint, content_type character varying, sort_order integer, created_by integer, created_by_name text, created_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    a.id,
    a.file_name,
    a.file_path,
    a.file_size,
    a.content_type,
    a.sort_order,
    a.created_by,
    CONCAT(s.last_name, ' ', s.first_name)::TEXT AS created_by_name,
    a.created_at
  FROM edoc.attachment_handling_docs a
  LEFT JOIN public.staff s ON s.id = a.created_by
  WHERE a.handling_doc_id = p_doc_id
  ORDER BY a.sort_order, a.created_at;
END;
$$;


--
-- Name: fn_handling_doc_get_by_id(bigint); Type: FUNCTION; Schema: edoc; Owner: -
-- 36 cột: 28 cũ + 4 cột số (number, sub_number, doc_book_id, doc_book_name) + JOIN doc_books
--          + 3 cột cancel (cancel_reason, cancelled_at, cancelled_by) — Gap D
--

DROP FUNCTION IF EXISTS edoc.fn_handling_doc_get_by_id(bigint) CASCADE;

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_get_by_id(p_id bigint)
RETURNS TABLE(
    id bigint,
    unit_id integer,
    unit_name character varying,
    department_id integer,
    department_name character varying,
    name character varying,
    abstract text,
    comments text,
    doc_notation character varying,
    doc_type_id integer,
    doc_type_name character varying,
    doc_field_id integer,
    doc_field_name character varying,
    start_date timestamp with time zone,
    end_date timestamp with time zone,
    curator_id integer,
    curator_name text,
    signer_id integer,
    signer_name text,
    status smallint,
    progress smallint,
    workflow_id integer,
    workflow_name character varying,
    parent_id bigint,
    parent_name character varying,
    is_from_doc boolean,
    created_by integer,
    created_at timestamp with time zone,
    updated_at timestamp with time zone,
    "number" integer,
    sub_number character varying,
    doc_book_id integer,
    doc_book_name character varying,
    cancel_reason text,
    cancelled_at timestamp with time zone,
    cancelled_by integer
)
LANGUAGE plpgsql
AS $$
BEGIN
  RETURN QUERY
  SELECT
    h.id,
    h.unit_id,
    du.name                                     AS unit_name,
    h.department_id,
    dd.name                                     AS department_name,
    h.name,
    h.abstract,
    h.comments,
    h.doc_notation,
    h.doc_type_id,
    dt.name                                     AS doc_type_name,
    h.doc_field_id,
    df.name                                     AS doc_field_name,
    h.start_date,
    h.end_date,
    h.curator                                   AS curator_id,
    CONCAT(sc.last_name, ' ', sc.first_name)    AS curator_name,
    h.signer                                    AS signer_id,
    CONCAT(ss.last_name, ' ', ss.first_name)    AS signer_name,
    h.status,
    h.progress,
    h.workflow_id,
    NULL::VARCHAR                               AS workflow_name,
    h.parent_id,
    hp.name                                     AS parent_name,
    h.is_from_doc,
    h.created_by,
    h.created_at,
    h.updated_at,
    h.number,
    h.sub_number,
    h.doc_book_id,
    db.name::VARCHAR                            AS doc_book_name,
    h.cancel_reason,
    h.cancelled_at,
    h.cancelled_by
  FROM edoc.handling_docs h
  LEFT JOIN public.departments du ON du.id = h.unit_id
  LEFT JOIN public.departments dd ON dd.id = h.department_id
  LEFT JOIN edoc.doc_types     dt ON dt.id = h.doc_type_id
  LEFT JOIN edoc.doc_fields    df ON df.id = h.doc_field_id
  LEFT JOIN public.staff       sc ON sc.id = h.curator
  LEFT JOIN public.staff       ss ON ss.id = h.signer
  LEFT JOIN edoc.handling_docs hp ON hp.id = h.parent_id
  LEFT JOIN edoc.doc_books     db ON db.id = h.doc_book_id AND db.is_deleted = FALSE
  WHERE h.id = p_id;
END;
$$;


--
-- Name: fn_handling_doc_get_children(bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_get_children(p_id bigint) RETURNS TABLE(id bigint, name character varying, start_date timestamp with time zone, end_date timestamp with time zone, status smallint, curator_id integer, curator_name text, signer_id integer, signer_name text, progress smallint, doc_field_name character varying, doc_type_name character varying, created_at timestamp with time zone, total_count bigint)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    h.id,
    h.name,
    h.start_date,
    h.end_date,
    h.status,
    h.curator                                  AS curator_id,
    CONCAT(sc.last_name, ' ', sc.first_name)   AS curator_name,
    h.signer                                   AS signer_id,
    CONCAT(ss.last_name, ' ', ss.first_name)   AS signer_name,
    h.progress,
    df.name                                    AS doc_field_name,
    dt.name                                    AS doc_type_name,
    h.created_at,
    COUNT(*) OVER()::BIGINT                    AS total_count
  FROM edoc.handling_docs h
  LEFT JOIN public.staff sc ON sc.id = h.curator
  LEFT JOIN public.staff ss ON ss.id = h.signer
  LEFT JOIN edoc.doc_fields df ON df.id = h.doc_field_id
  LEFT JOIN edoc.doc_types dt ON dt.id = h.doc_type_id
  WHERE h.parent_id = p_id
  ORDER BY h.created_at DESC;
END;
$$;


--
-- Name: fn_handling_doc_get_for_link(integer, text); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_get_for_link(p_unit_id integer, p_keyword text DEFAULT NULL::text) RETURNS TABLE(id bigint, name character varying, abstract text, status smallint, start_date timestamp with time zone, end_date timestamp with time zone, curator_name character varying)
    LANGUAGE plpgsql
    AS $$
DECLARE v_kw TEXT := NULLIF(TRIM(p_keyword), '');
BEGIN
  RETURN QUERY
  SELECT h.id, h.name::VARCHAR, h.abstract, h.status, h.start_date, h.end_date,
         s.full_name
  FROM edoc.handling_docs h
  LEFT JOIN public.staff s ON s.id = h.curator
  WHERE h.unit_id = p_unit_id
    AND h.status < 3  -- chưa hoàn thành (0=mới, 1=đang xử lý, 2=trình duyệt)
    AND (v_kw IS NULL OR h.name ILIKE '%' || v_kw || '%' OR h.abstract ILIKE '%' || v_kw || '%')
  ORDER BY h.created_at DESC
  LIMIT 50;
END;
$$;


--
-- Name: fn_handling_doc_get_linked_docs(bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_get_linked_docs(p_id bigint) RETURNS TABLE(link_id bigint, doc_id bigint, doc_type character varying, doc_number integer, doc_notation character varying, doc_abstract text, doc_date timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    l.id       AS link_id,
    l.doc_id,
    l.doc_type,
    CASE l.doc_type
      WHEN 'incoming' THEN (SELECT d.number FROM edoc.incoming_docs d WHERE d.id = l.doc_id)
      ELSE NULL
    END        AS doc_number,
    CASE l.doc_type
      WHEN 'incoming' THEN (SELECT d.notation FROM edoc.incoming_docs d WHERE d.id = l.doc_id)
      ELSE NULL
    END        AS doc_notation,
    CASE l.doc_type
      WHEN 'incoming' THEN (SELECT d.abstract FROM edoc.incoming_docs d WHERE d.id = l.doc_id)
      ELSE NULL
    END        AS doc_abstract,
    CASE l.doc_type
      WHEN 'incoming' THEN (SELECT d.received_date FROM edoc.incoming_docs d WHERE d.id = l.doc_id)
      ELSE NULL
    END        AS doc_date
  FROM edoc.handling_doc_links l
  WHERE l.handling_doc_id = p_id
  ORDER BY l.created_at DESC;
END;
$$;


--
-- Name: fn_handling_doc_get_list(integer, integer, integer, integer, text, text, timestamp with time zone, timestamp with time zone, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_get_list(p_unit_id integer, p_department_id integer, p_staff_id integer, p_status integer, p_filter_type text, p_keyword text, p_from_date timestamp with time zone, p_to_date timestamp with time zone, p_page integer DEFAULT 1, p_page_size integer DEFAULT 20) RETURNS TABLE(id bigint, name character varying, start_date timestamp with time zone, end_date timestamp with time zone, status smallint, curator_id integer, curator_name text, signer_id integer, signer_name text, progress smallint, doc_field_name character varying, doc_type_name character varying, created_at timestamp with time zone, total_count bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_offset INT := (COALESCE(p_page, 1) - 1) * COALESCE(p_page_size, 20);
BEGIN
  RETURN QUERY
  WITH filtered AS (
    SELECT
      h.id,
      h.name,
      h.start_date,
      h.end_date,
      h.status,
      h.curator       AS curator_id,
      CONCAT(sc.last_name, ' ', sc.first_name) AS curator_name,
      h.signer        AS signer_id,
      CONCAT(ss.last_name, ' ', ss.first_name) AS signer_name,
      h.progress,
      df.name         AS doc_field_name,
      dt.name         AS doc_type_name,
      h.created_at
    FROM edoc.handling_docs h
    LEFT JOIN public.staff sc ON sc.id = h.curator
    LEFT JOIN public.staff ss ON ss.id = h.signer
    LEFT JOIN edoc.doc_fields df ON df.id = h.doc_field_id
    LEFT JOIN edoc.doc_types dt ON dt.id = h.doc_type_id
    WHERE
      h.unit_id = p_unit_id
      -- status filter (-1=all statuses)
      AND (p_status IS NULL OR p_status = -99 OR h.status = p_status)
      -- department filter
      AND (p_department_id IS NULL OR h.department_id = p_department_id)
      -- filter_type logic
      AND (
        p_filter_type IS NULL OR p_filter_type = 'all' OR
        (p_filter_type = 'created_by_me'    AND h.created_by = p_staff_id) OR
        (p_filter_type = 'rejected'         AND h.status = -1 AND h.created_by = p_staff_id) OR
        (p_filter_type = 'returned'         AND h.status = -2) OR
        (p_filter_type = 'pending_primary'  AND h.status = 0 AND EXISTS (
          SELECT 1 FROM edoc.staff_handling_docs shd WHERE shd.handling_doc_id = h.id AND shd.staff_id = p_staff_id AND shd.role = 1
        )) OR
        (p_filter_type = 'pending_coord'    AND h.status IN (0, 1) AND EXISTS (
          SELECT 1 FROM edoc.staff_handling_docs shd WHERE shd.handling_doc_id = h.id AND shd.staff_id = p_staff_id AND shd.role = 2
        )) OR
        (p_filter_type = 'submitting'       AND h.status = 3) OR
        (p_filter_type = 'in_progress'      AND h.status = 1) OR
        (p_filter_type = 'proposed_complete' AND h.status = 3) OR
        (p_filter_type = 'completed'        AND h.status = 4)
      )
      -- keyword search
      AND (p_keyword IS NULL OR TRIM(p_keyword) = '' OR h.name ILIKE '%' || p_keyword || '%')
      -- date range
      AND (p_from_date IS NULL OR h.start_date >= p_from_date)
      AND (p_to_date IS NULL OR h.start_date <= p_to_date)
  )
  SELECT
    f.id,
    f.name,
    f.start_date,
    f.end_date,
    f.status,
    f.curator_id,
    f.curator_name,
    f.signer_id,
    f.signer_name,
    f.progress,
    f.doc_field_name,
    f.doc_type_name,
    f.created_at,
    COUNT(*) OVER()::BIGINT AS total_count
  FROM filtered f
  ORDER BY f.created_at DESC
  LIMIT COALESCE(p_page_size, 20)
  OFFSET v_offset;
END;
$$;


--
-- Name: fn_handling_doc_get_staff(bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_get_staff(p_doc_id bigint) RETURNS TABLE(id bigint, staff_id integer, staff_name text, position_name character varying, department_name character varying, role smallint, step character varying, assigned_at timestamp with time zone, completed_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    shd.id,
    shd.staff_id,
    CONCAT(s.last_name, ' ', s.first_name)::TEXT AS staff_name,
    p.name                                        AS position_name,
    d.name                                        AS department_name,
    shd.role,
    shd.step,
    shd.assigned_at,
    shd.completed_at
  FROM edoc.staff_handling_docs shd
  JOIN public.staff s ON s.id = shd.staff_id
  LEFT JOIN public.positions p ON p.id = s.position_id
  LEFT JOIN public.departments d ON d.id = s.department_id
  WHERE shd.handling_doc_id = p_doc_id
  ORDER BY shd.role, shd.assigned_at;
END;
$$;


--
-- Name: fn_handling_doc_kpi(integer, timestamp with time zone, timestamp with time zone); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_kpi(p_unit_id integer, p_from_date timestamp with time zone, p_to_date timestamp with time zone) RETURNS TABLE(total bigint, prev_period bigint, current_period bigint, completed bigint, in_progress bigint, overdue bigint, overdue_percent numeric)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_total         BIGINT;
  v_prev          BIGINT;
  v_current       BIGINT;
  v_completed     BIGINT;
  v_in_progress   BIGINT;
  v_overdue       BIGINT;
  v_percent       NUMERIC;
BEGIN
  -- Tổng HSCV thuộc đơn vị
  SELECT COUNT(*) INTO v_total
  FROM edoc.handling_docs
  WHERE unit_id = p_unit_id;

  -- Chuyển kỳ trước: tạo trước p_from_date và chưa hoàn thành/từ chối
  SELECT COUNT(*) INTO v_prev
  FROM edoc.handling_docs
  WHERE unit_id = p_unit_id
    AND created_at < p_from_date
    AND status NOT IN (4, -1);

  -- Kỳ này: tạo trong khoảng from-to
  SELECT COUNT(*) INTO v_current
  FROM edoc.handling_docs
  WHERE unit_id = p_unit_id
    AND (p_from_date IS NULL OR created_at >= p_from_date)
    AND (p_to_date IS NULL OR created_at <= p_to_date);

  -- Hoàn thành trong kỳ
  SELECT COUNT(*) INTO v_completed
  FROM edoc.handling_docs
  WHERE unit_id = p_unit_id
    AND status = 4
    AND (p_from_date IS NULL OR complete_date >= p_from_date)
    AND (p_to_date IS NULL OR complete_date <= p_to_date);

  -- Đang thực hiện (kỳ này, chưa hoàn thành)
  SELECT COUNT(*) INTO v_in_progress
  FROM edoc.handling_docs
  WHERE unit_id = p_unit_id
    AND status IN (0, 1, 2, 3)
    AND (p_from_date IS NULL OR created_at >= p_from_date)
    AND (p_to_date IS NULL OR created_at <= p_to_date);

  -- Quá hạn: end_date < NOW() và chưa hoàn thành/từ chối
  SELECT COUNT(*) INTO v_overdue
  FROM edoc.handling_docs
  WHERE unit_id = p_unit_id
    AND end_date < NOW()
    AND status NOT IN (4, -1)
    AND (p_from_date IS NULL OR created_at >= p_from_date)
    AND (p_to_date IS NULL OR created_at <= p_to_date);

  -- % quá hạn
  IF v_current > 0 THEN
    v_percent := ROUND((v_overdue::NUMERIC / v_current::NUMERIC) * 100, 2);
  ELSE
    v_percent := 0;
  END IF;

  RETURN QUERY SELECT v_total, v_prev, v_current, v_completed, v_in_progress, v_overdue, v_percent;
END;
$$;


--
-- Name: fn_handling_doc_link_doc(bigint, bigint, character varying, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_link_doc(p_handling_doc_id bigint, p_doc_id bigint, p_doc_type character varying, p_linked_by integer) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id BIGINT;
BEGIN
  IF p_doc_type NOT IN ('incoming', 'outgoing', 'drafting') THEN
    RETURN QUERY SELECT FALSE, 'Loại văn bản không hợp lệ'::TEXT, 0::BIGINT;
    RETURN;
  END IF;

  IF EXISTS (
    SELECT 1 FROM edoc.handling_doc_links
    WHERE handling_doc_id = p_handling_doc_id AND doc_id = p_doc_id AND doc_type = p_doc_type
  ) THEN
    RETURN QUERY SELECT FALSE, 'Văn bản này đã được liên kết'::TEXT, 0::BIGINT;
    RETURN;
  END IF;

  INSERT INTO edoc.handling_doc_links (handling_doc_id, doc_type, doc_id)
  VALUES (p_handling_doc_id, p_doc_type, p_doc_id)
  RETURNING edoc.handling_doc_links.id INTO v_id;

  RETURN QUERY SELECT TRUE, 'Liên kết văn bản thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_handling_doc_reject(bigint, integer, text); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_reject(p_id bigint, p_rejected_by integer, p_reason text) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_status SMALLINT;
BEGIN
  -- T-02-01: validate current status before transition
  IF p_reason IS NULL OR TRIM(p_reason) = '' THEN
    RETURN QUERY SELECT FALSE, 'Lý do từ chối không được để trống'::TEXT;
    RETURN;
  END IF;

  SELECT status INTO v_status FROM edoc.handling_docs WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Hồ sơ công việc không tồn tại'::TEXT;
    RETURN;
  END IF;

  -- 5-step flow: chỉ từ chối khi đã trình ký (status=3)
  IF v_status <> 3 THEN
    RETURN QUERY SELECT FALSE, 'Chỉ được từ chối khi hồ sơ ở trạng thái Đã trình ký'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.handling_docs SET
    status     = -1,  -- Từ chối
    comments   = COALESCE(comments, '') || E'\n[Từ chối] ' || TRIM(p_reason),
    updated_by = p_rejected_by,
    updated_at = NOW()
  WHERE id = p_id;

  INSERT INTO edoc.handling_doc_history (handling_doc_id, action_type, from_staff_id, note, created_by)
  VALUES (p_id, 'reject', p_rejected_by, TRIM(p_reason), p_rejected_by);

  RETURN QUERY SELECT TRUE, 'Từ chối hồ sơ công việc thành công'::TEXT;
END;
$$;


--
-- Name: fn_handling_doc_remove_staff(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_remove_staff(p_doc_id bigint, p_staff_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  DELETE FROM edoc.staff_handling_docs
  WHERE handling_doc_id = p_doc_id AND staff_id = p_staff_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Cán bộ không có trong danh sách xử lý'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT TRUE, 'Hủy phân công thành công'::TEXT;
END;
$$;


--
-- Name: fn_handling_doc_return(bigint, integer, text); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_return(p_id bigint, p_returned_by integer, p_reason text) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_status SMALLINT;
BEGIN
  -- T-02-01: validate current status before transition
  IF p_reason IS NULL OR TRIM(p_reason) = '' THEN
    RETURN QUERY SELECT FALSE, 'Lý do trả về không được để trống'::TEXT;
    RETURN;
  END IF;

  SELECT status INTO v_status FROM edoc.handling_docs WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Hồ sơ công việc không tồn tại'::TEXT;
    RETURN;
  END IF;

  IF v_status NOT IN (1, 3) THEN
    RETURN QUERY SELECT FALSE, 'Chỉ được trả về khi hồ sơ ở trạng thái Đang xử lý hoặc Đã trình ký'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.handling_docs SET
    status     = -2,  -- Trả về
    comments   = COALESCE(comments, '') || E'\n[Trả về] ' || TRIM(p_reason),
    updated_by = p_returned_by,
    updated_at = NOW()
  WHERE id = p_id;

  INSERT INTO edoc.handling_doc_history (handling_doc_id, action_type, from_staff_id, note, created_by)
  VALUES (p_id, 'return', p_returned_by, TRIM(p_reason), p_returned_by);

  RETURN QUERY SELECT TRUE, 'Trả về hồ sơ công việc thành công'::TEXT;
END;
$$;


--
-- Name: fn_handling_doc_submit(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_submit(p_id bigint, p_submitted_by integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_status SMALLINT;
BEGIN
  -- T-02-01: validate current status before transition
  SELECT status INTO v_status FROM edoc.handling_docs WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Hồ sơ công việc không tồn tại'::TEXT;
    RETURN;
  END IF;

  IF v_status NOT IN (0, 1) THEN
    RETURN QUERY SELECT FALSE, 'Chỉ được trình ký khi hồ sơ ở trạng thái Mới hoặc Đang xử lý'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.handling_docs SET
    status     = 3,  -- Đã trình ký (gộp 2 bước: status 2 intermediate đã loại bỏ — bấm "Trình ký" 1 lần đẩy thẳng lên lãnh đạo)
    updated_by = p_submitted_by,
    updated_at = NOW()
  WHERE id = p_id;

  INSERT INTO edoc.handling_doc_history (handling_doc_id, action_type, from_staff_id, created_by)
  VALUES (p_id, 'submit', p_submitted_by, p_submitted_by);

  RETURN QUERY SELECT TRUE, 'Trình ký thành công'::TEXT;
END;
$$;


--
-- Name: fn_handling_doc_unlink_doc(bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_unlink_doc(p_link_id bigint) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  DELETE FROM edoc.handling_doc_links WHERE id = p_link_id;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Liên kết không tồn tại'::TEXT;
    RETURN;
  END IF;
  RETURN QUERY SELECT TRUE, 'Hủy liên kết thành công'::TEXT;
END;
$$;


--
-- Name: fn_handling_doc_update(bigint, integer, integer, character varying, text, timestamp with time zone, timestamp with time zone, integer, integer, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_update(p_id bigint, p_doc_type_id integer, p_doc_field_id integer, p_name character varying, p_comments text, p_start_date timestamp with time zone, p_end_date timestamp with time zone, p_curator_id integer, p_signer_id integer, p_workflow_id integer, p_updated_by integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_status SMALLINT;
BEGIN
  -- Validate: tên bắt buộc
  IF p_name IS NULL OR TRIM(p_name) = '' THEN
    RETURN QUERY SELECT FALSE, 'Tên hồ sơ công việc không được để trống'::TEXT;
    RETURN;
  END IF;

  -- Validate: hạn giải quyết >= ngày mở
  IF p_start_date IS NOT NULL AND p_end_date IS NOT NULL AND p_end_date < p_start_date THEN
    RETURN QUERY SELECT FALSE, 'Hạn giải quyết phải sau hoặc bằng ngày mở'::TEXT;
    RETURN;
  END IF;

  -- Kiểm tra tồn tại và trạng thái
  SELECT status INTO v_status FROM edoc.handling_docs WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Hồ sơ công việc không tồn tại'::TEXT;
    RETURN;
  END IF;

  -- Chỉ cập nhật khi trạng thái = 0 (Mới)
  IF v_status <> 0 THEN
    RETURN QUERY SELECT FALSE, 'Chỉ được cập nhật hồ sơ công việc ở trạng thái Mới'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.handling_docs SET
    doc_type_id  = p_doc_type_id,
    doc_field_id = p_doc_field_id,
    name         = TRIM(p_name),
    comments     = NULLIF(TRIM(COALESCE(p_comments, '')), ''),
    start_date   = p_start_date,
    end_date     = p_end_date,
    curator      = p_curator_id,
    signer       = p_signer_id,
    workflow_id  = p_workflow_id,
    updated_by   = p_updated_by,
    updated_at   = NOW()
  WHERE id = p_id;

  RETURN QUERY SELECT TRUE, 'Cập nhật hồ sơ công việc thành công'::TEXT;
END;
$$;


--
-- Name: fn_handling_doc_update_progress(bigint, smallint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_update_progress(p_id bigint, p_progress smallint) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- T-02-04: validate progress range 0-100
  IF p_progress < 0 OR p_progress > 100 THEN
    RETURN QUERY SELECT FALSE, 'Tiến độ phải trong khoảng 0-100%'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.handling_docs SET
    progress   = p_progress,
    updated_at = NOW()
  WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Hồ sơ công việc không tồn tại'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT TRUE, 'Cập nhật tiến độ thành công'::TEXT;
END;
$$;


--
-- ============================================================================
-- HSCV Advanced SPs — consolidated từ archive/v1.0-migrations/quick_260418_*
-- (HDSD III.2.5 Hủy + III.2.6 Forward ý kiến + III.2.7 Transfer + Lấy số / Mở lại)
-- ============================================================================
--

--
-- Name: fn_handling_doc_reopen(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
-- Mở lại HSCV (status 4 → 1). GIỮ NGUYÊN progress per A2.
--

DROP FUNCTION IF EXISTS edoc.fn_handling_doc_reopen(bigint, integer) CASCADE;

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_reopen(
    p_id      bigint,
    p_user_id integer
)
RETURNS TABLE(success boolean, message text)
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_status SMALLINT;
BEGIN
    SELECT status INTO v_status
      FROM edoc.handling_docs
      WHERE id = p_id;

    IF NOT FOUND THEN
        RETURN QUERY SELECT FALSE, 'Không tìm thấy hồ sơ công việc'::TEXT;
        RETURN;
    END IF;

    IF v_status <> 4 THEN
        RETURN QUERY SELECT FALSE,
            ('Chỉ có thể mở lại HSCV đã hoàn thành. Trạng thái hiện tại: ' || v_status)::TEXT;
        RETURN;
    END IF;

    -- A2: status 4 → 1, GIỮ NGUYÊN progress, clear complete_date / complete_user_id
    UPDATE edoc.handling_docs
    SET status           = 1,
        complete_date    = NULL,
        complete_user_id = NULL,
        updated_by       = p_user_id,
        updated_at       = NOW()
    WHERE id = p_id;

    INSERT INTO edoc.handling_doc_history (handling_doc_id, action_type, from_staff_id, created_by)
    VALUES (p_id, 'reopen', p_user_id, p_user_id);

    RETURN QUERY SELECT TRUE, 'Đã mở lại hồ sơ công việc'::TEXT;
END;
$$;


--
-- Name: fn_handling_doc_get_next_number(integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
-- Tính số HSCV kế tiếp = MAX(number)+1 theo năm created_at + doc_book_id + unit_id (A3).
--

DROP FUNCTION IF EXISTS edoc.fn_handling_doc_get_next_number(integer, integer) CASCADE;

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_get_next_number(
    p_doc_book_id integer,
    p_unit_id     integer
)
RETURNS integer
LANGUAGE plpgsql
AS $$
DECLARE
    v_next INT;
BEGIN
    SELECT COALESCE(MAX(number), 0) + 1
      INTO v_next
      FROM edoc.handling_docs
      WHERE doc_book_id = p_doc_book_id
        AND unit_id = p_unit_id
        AND number IS NOT NULL
        AND EXTRACT(YEAR FROM created_at) = EXTRACT(YEAR FROM NOW());
    RETURN v_next;
END;
$$;


--
-- Name: fn_handling_doc_assign_number(bigint, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
-- Gán số HSCV: kiểm tra chưa có số → tính MAX+1 theo năm + sổ → UPDATE row.
--

DROP FUNCTION IF EXISTS edoc.fn_handling_doc_assign_number(bigint, integer, integer) CASCADE;

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_assign_number(
    p_id          bigint,
    p_user_id     integer,
    p_doc_book_id integer
)
RETURNS TABLE(success boolean, message text, "number" integer)
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_unit_id          INT;
    v_existing_number  INT;
    v_next             INT;
BEGIN
    SELECT h.unit_id, h.number
      INTO v_unit_id, v_existing_number
      FROM edoc.handling_docs h
      WHERE h.id = p_id;

    IF NOT FOUND THEN
        RETURN QUERY SELECT FALSE, 'Không tìm thấy hồ sơ công việc'::TEXT, NULL::INT;
        RETURN;
    END IF;

    IF v_existing_number IS NOT NULL THEN
        RETURN QUERY SELECT FALSE,
            ('HSCV đã có số ' || v_existing_number)::TEXT,
            v_existing_number;
        RETURN;
    END IF;

    IF p_doc_book_id IS NULL THEN
        RETURN QUERY SELECT FALSE, 'Vui lòng chọn sổ văn bản'::TEXT, NULL::INT;
        RETURN;
    END IF;

    -- A3: Tính số kế tiếp theo năm created_at + doc_book_id + unit_id
    v_next := edoc.fn_handling_doc_get_next_number(p_doc_book_id, v_unit_id);

    UPDATE edoc.handling_docs
    SET number      = v_next,
        doc_book_id = p_doc_book_id,
        updated_by  = p_user_id,
        updated_at  = NOW()
    WHERE id = p_id;

    INSERT INTO edoc.handling_doc_history (handling_doc_id, action_type, from_staff_id, note, created_by)
    VALUES (p_id, 'assign_number', p_user_id, ('Số: ' || v_next)::TEXT, p_user_id);

    RETURN QUERY SELECT TRUE, ('Đã lấy số ' || v_next)::TEXT, v_next;
END;
$$;


--
-- Name: fn_handling_doc_cancel(bigint, integer, text); Type: FUNCTION; Schema: edoc; Owner: -
-- Hủy HSCV với lý do (Gap D / TC-066).
-- Bug B fix: chỉ cho phép hủy khi status IN (-1, -2) (Từ chối/Trả về).
--

DROP FUNCTION IF EXISTS edoc.fn_handling_doc_cancel(bigint, integer, text) CASCADE;

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_cancel(
    p_id bigint,
    p_user_id integer,
    p_reason text
)
RETURNS TABLE(success boolean, message text)
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_status SMALLINT;
BEGIN
    IF p_reason IS NULL OR LENGTH(TRIM(p_reason)) = 0 THEN
        RETURN QUERY SELECT FALSE, 'Vui lòng nhập lý do hủy'::TEXT;
        RETURN;
    END IF;

    SELECT h.status INTO v_status FROM edoc.handling_docs h WHERE h.id = p_id;
    IF NOT FOUND THEN
        RETURN QUERY SELECT FALSE, 'Không tìm thấy hồ sơ công việc'::TEXT;
        RETURN;
    END IF;

    -- Bug B fix: chỉ cho phép hủy khi đã từ chối (-1) hoặc trả về (-2)
    IF v_status NOT IN (-1, -2) THEN
        RETURN QUERY SELECT FALSE,
            ('Chỉ được hủy HSCV ở trạng thái Từ chối (-1) hoặc Trả về (-2). Trạng thái hiện tại: ' || v_status::TEXT)::TEXT;
        RETURN;
    END IF;

    UPDATE edoc.handling_docs
    SET status = -3,
        cancel_reason = p_reason,
        cancelled_at = NOW(),
        cancelled_by = p_user_id,
        updated_at = NOW()
    WHERE id = p_id;

    RETURN QUERY SELECT TRUE, 'Đã hủy hồ sơ công việc'::TEXT;
END;
$$;


--
-- Name: fn_handling_doc_transfer(bigint, integer, integer, text, integer); Type: FUNCTION; Schema: edoc; Owner: -
-- Chuyển tiếp HSCV (transfer ownership) — Gap F / TC-068.
--

DROP FUNCTION IF EXISTS edoc.fn_handling_doc_transfer(bigint, integer, integer, text, integer) CASCADE;

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_transfer(
    p_id bigint,
    p_from_staff_id integer,
    p_to_staff_id integer,
    p_note text,
    p_by integer
)
RETURNS TABLE(success boolean, message text)
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_current_curator INT;
    v_doc_unit INT;
    v_to_unit INT;
    v_to_locked BOOLEAN;
    v_to_deleted BOOLEAN;
BEGIN
    IF p_to_staff_id IS NULL OR p_to_staff_id <= 0 THEN
        RETURN QUERY SELECT FALSE, 'Vui lòng chọn người nhận'::TEXT;
        RETURN;
    END IF;
    IF p_from_staff_id = p_to_staff_id THEN
        RETURN QUERY SELECT FALSE, 'Không thể chuyển cho chính mình'::TEXT;
        RETURN;
    END IF;

    SELECT h.curator, h.unit_id INTO v_current_curator, v_doc_unit
      FROM edoc.handling_docs h WHERE h.id = p_id;
    IF NOT FOUND THEN
        RETURN QUERY SELECT FALSE, 'Không tìm thấy hồ sơ công việc'::TEXT;
        RETURN;
    END IF;

    SELECT s.unit_id, COALESCE(s.is_locked, FALSE), COALESCE(s.is_deleted, FALSE)
      INTO v_to_unit, v_to_locked, v_to_deleted
      FROM public.staff s WHERE s.id = p_to_staff_id;
    IF NOT FOUND THEN
        RETURN QUERY SELECT FALSE, 'Không tìm thấy người nhận'::TEXT;
        RETURN;
    END IF;
    IF v_to_locked THEN
        RETURN QUERY SELECT FALSE, 'Người nhận đã khóa tài khoản'::TEXT;
        RETURN;
    END IF;
    IF v_to_deleted THEN
        RETURN QUERY SELECT FALSE, 'Người nhận đã bị xoá'::TEXT;
        RETURN;
    END IF;
    IF v_to_unit <> v_doc_unit THEN
        RETURN QUERY SELECT FALSE, 'Chỉ có thể chuyển HSCV cho người cùng đơn vị'::TEXT;
        RETURN;
    END IF;

    UPDATE edoc.handling_docs
    SET curator = p_to_staff_id,
        updated_at = NOW()
    WHERE id = p_id;

    INSERT INTO edoc.handling_doc_history(
        handling_doc_id, action_type, from_staff_id, to_staff_id, note, created_by, created_at
    )
    VALUES (p_id, 'transfer', v_current_curator, p_to_staff_id, p_note, p_by, NOW());

    RETURN QUERY SELECT TRUE, 'Đã chuyển tiếp hồ sơ công việc'::TEXT;
END;
$$;


--
-- Name: fn_handling_doc_history_list(bigint); Type: FUNCTION; Schema: edoc; Owner: -
-- Lịch sử transfer/cancel HSCV — Gap F.
--

DROP FUNCTION IF EXISTS edoc.fn_handling_doc_history_list(bigint) CASCADE;

CREATE OR REPLACE FUNCTION edoc.fn_handling_doc_history_list(p_id bigint)
RETURNS TABLE(
    id bigint,
    handling_doc_id bigint,
    action_type character varying,
    from_staff_id integer,
    from_staff_name text,
    to_staff_id integer,
    to_staff_name text,
    note text,
    created_by integer,
    created_by_name text,
    created_at timestamp with time zone
)
LANGUAGE plpgsql
AS $$
BEGIN
    RETURN QUERY
    SELECT
        h.id,
        h.handling_doc_id,
        h.action_type,
        h.from_staff_id,
        CASE WHEN fs.id IS NOT NULL THEN CONCAT(fs.last_name, ' ', fs.first_name)::TEXT ELSE NULL::TEXT END AS from_staff_name,
        h.to_staff_id,
        CASE WHEN ts.id IS NOT NULL THEN CONCAT(ts.last_name, ' ', ts.first_name)::TEXT ELSE NULL::TEXT END AS to_staff_name,
        h.note,
        h.created_by,
        CASE WHEN cs.id IS NOT NULL THEN CONCAT(cs.last_name, ' ', cs.first_name)::TEXT ELSE NULL::TEXT END AS created_by_name,
        h.created_at
    FROM edoc.handling_doc_history h
    LEFT JOIN public.staff fs ON fs.id = h.from_staff_id
    LEFT JOIN public.staff ts ON ts.id = h.to_staff_id
    LEFT JOIN public.staff cs ON cs.id = h.created_by
    WHERE h.handling_doc_id = p_id
    ORDER BY h.created_at DESC;
END;
$$;


--
-- Name: fn_opinion_forward(bigint, integer, integer, text); Type: FUNCTION; Schema: edoc; Owner: -
-- Chuyển tiếp ý kiến HSCV — Gap E / TC-067.
--

DROP FUNCTION IF EXISTS edoc.fn_opinion_forward(bigint, integer, integer, text) CASCADE;

CREATE OR REPLACE FUNCTION edoc.fn_opinion_forward(
    p_opinion_id bigint,
    p_from_staff_id integer,
    p_to_staff_id integer,
    p_note text
)
RETURNS TABLE(success boolean, message text, id bigint)
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_handling_doc_id BIGINT;
    v_to_exists BOOLEAN;
    v_new_id BIGINT;
BEGIN
    IF p_note IS NULL OR LENGTH(TRIM(p_note)) = 0 THEN
        RETURN QUERY SELECT FALSE, 'Vui lòng nhập nội dung chuyển tiếp'::TEXT, NULL::BIGINT;
        RETURN;
    END IF;

    SELECT o.handling_doc_id INTO v_handling_doc_id
      FROM edoc.opinion_handling_docs o
      WHERE o.id = p_opinion_id;
    IF NOT FOUND THEN
        RETURN QUERY SELECT FALSE, 'Không tìm thấy ý kiến gốc'::TEXT, NULL::BIGINT;
        RETURN;
    END IF;

    SELECT EXISTS(
        SELECT 1 FROM public.staff s
        WHERE s.id = p_to_staff_id
          AND COALESCE(s.is_locked, FALSE) = FALSE
          AND COALESCE(s.is_deleted, FALSE) = FALSE
    ) INTO v_to_exists;
    IF NOT v_to_exists THEN
        RETURN QUERY SELECT FALSE, 'Không tìm thấy người nhận hoặc đã khóa/xoá'::TEXT, NULL::BIGINT;
        RETURN;
    END IF;

    INSERT INTO edoc.opinion_handling_docs(
        handling_doc_id, staff_id, content, created_at,
        forwarded_to_staff_id, forwarded_at, forward_note, parent_opinion_id
    )
    VALUES (
        v_handling_doc_id, p_from_staff_id, p_note, NOW(),
        p_to_staff_id, NOW(), p_note, p_opinion_id
    )
    RETURNING edoc.opinion_handling_docs.id INTO v_new_id;

    RETURN QUERY SELECT TRUE, 'Đã chuyển tiếp ý kiến'::TEXT, v_new_id;
END;
$$;


--
-- Name: fn_incoming_doc_approve(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_approve(p_id bigint, p_staff_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_staff_name VARCHAR;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM edoc.incoming_docs WHERE edoc.incoming_docs.id = p_id) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản đến'::TEXT;
    RETURN;
  END IF;

  SELECT full_name INTO v_staff_name FROM public.staff WHERE public.staff.id = p_staff_id;

  UPDATE edoc.incoming_docs SET
    approved = TRUE,
    approver = v_staff_name,
    updated_by = p_staff_id,
    updated_at = NOW()
  WHERE edoc.incoming_docs.id = p_id;

  RETURN QUERY SELECT TRUE, 'Duyệt văn bản thành công'::TEXT;
END;
$$;


--
-- Name: fn_incoming_doc_cancel_approve(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_cancel_approve(p_doc_id bigint, p_cancelled_by integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_approved BOOLEAN;
BEGIN
  -- Kiểm tra văn bản tồn tại và đã được duyệt
  SELECT approved INTO v_approved FROM edoc.incoming_docs WHERE id = p_doc_id;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản'::TEXT;
    RETURN;
  END IF;

  IF NOT COALESCE(v_approved, FALSE) THEN
    RETURN QUERY SELECT FALSE, 'Văn bản chưa được duyệt, không thể hủy duyệt'::TEXT;
    RETURN;
  END IF;

  -- Hủy duyệt
  UPDATE edoc.incoming_docs
  SET
    approved = FALSE,
    updated_by = p_cancelled_by,
    updated_at = NOW()
  WHERE id = p_doc_id;

  RETURN QUERY SELECT TRUE, 'Hủy duyệt văn bản thành công'::TEXT;
END;
$$;


--
-- Name: fn_incoming_doc_count_unread(integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_count_unread(p_unit_id integer, p_staff_id integer) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE v_count INT;
BEGIN
  SELECT COUNT(*)::INT INTO v_count
  FROM edoc.incoming_docs d
  LEFT JOIN edoc.user_incoming_docs uid ON uid.incoming_doc_id = d.id AND uid.staff_id = p_staff_id
  WHERE d.unit_id = p_unit_id
    AND (uid.is_read IS NULL OR uid.is_read = FALSE);
  RETURN v_count;
END;
$$;


--
-- Name: fn_incoming_doc_create(integer, timestamp with time zone, integer, character varying, character varying, text, character varying, timestamp with time zone, character varying, timestamp with time zone, integer, integer, integer, smallint, smallint, integer, integer, timestamp with time zone, text, text, boolean, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_create(p_unit_id integer, p_received_date timestamp with time zone, p_number integer, p_notation character varying, p_document_code character varying, p_abstract text, p_publish_unit character varying, p_publish_date timestamp with time zone, p_signer character varying, p_sign_date timestamp with time zone, p_doc_book_id integer, p_doc_type_id integer, p_doc_field_id integer, p_secret_id smallint DEFAULT 1, p_urgent_id smallint DEFAULT 1, p_number_paper integer DEFAULT 1, p_number_copies integer DEFAULT 1, p_expired_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_recipients text DEFAULT NULL::text, p_sents text DEFAULT NULL::text, p_is_received_paper boolean DEFAULT false, p_created_by integer DEFAULT NULL::integer) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id BIGINT;
BEGIN
  IF p_abstract IS NULL OR TRIM(p_abstract) = '' THEN
    RETURN QUERY SELECT FALSE, 'Trích yếu nội dung không được để trống'::TEXT, 0::BIGINT;
    RETURN;
  END IF;

  IF p_doc_book_id IS NULL THEN
    RETURN QUERY SELECT FALSE, 'Sổ văn bản là bắt buộc'::TEXT, 0::BIGINT;
    RETURN;
  END IF;

  IF p_number IS NULL OR p_number = 0 THEN
    p_number := edoc.fn_incoming_doc_get_next_number(p_doc_book_id, p_unit_id);
  END IF;

  INSERT INTO edoc.incoming_docs (
    unit_id, received_date, number, notation, document_code,
    abstract, publish_unit, publish_date, signer, sign_date,
    doc_book_id, doc_type_id, doc_field_id, secret_id, urgent_id,
    number_paper, number_copies, expired_date, recipients, sents,
    is_received_paper, created_by, updated_by
  ) VALUES (
    p_unit_id, COALESCE(p_received_date, NOW()), p_number, NULLIF(TRIM(p_notation), ''), NULLIF(TRIM(p_document_code), ''),
    TRIM(p_abstract), NULLIF(TRIM(p_publish_unit), ''), p_publish_date, NULLIF(TRIM(p_signer), ''), p_sign_date,
    p_doc_book_id, p_doc_type_id, p_doc_field_id, COALESCE(p_secret_id, 1), COALESCE(p_urgent_id, 1),
    COALESCE(p_number_paper, 1), COALESCE(p_number_copies, 1), p_expired_date, NULLIF(TRIM(p_recipients), ''),
    NULLIF(TRIM(p_sents), ''),
    COALESCE(p_is_received_paper, FALSE), p_created_by, p_created_by
  )
  RETURNING edoc.incoming_docs.id INTO v_id;

  RETURN QUERY SELECT TRUE, 'Tạo văn bản đến thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_incoming_doc_delete(bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_delete(p_id bigint) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_approved BOOLEAN;
BEGIN
  SELECT approved INTO v_approved FROM edoc.incoming_docs WHERE edoc.incoming_docs.id = p_id;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản đến'::TEXT;
    RETURN;
  END IF;
  IF v_approved = TRUE THEN
    RETURN QUERY SELECT FALSE, 'Không thể xóa văn bản đã được duyệt'::TEXT;
    RETURN;
  END IF;

  -- CASCADE sẽ xóa user_incoming_docs, attachments, leader_notes
  DELETE FROM edoc.incoming_docs WHERE edoc.incoming_docs.id = p_id;
  RETURN QUERY SELECT TRUE, 'Xóa văn bản đến thành công'::TEXT;
END;
$$;


--
-- Name: fn_incoming_doc_get_by_id(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_get_by_id(p_id bigint, p_staff_id integer) RETURNS TABLE(id bigint, unit_id integer, received_date timestamp with time zone, number integer, notation character varying, document_code character varying, abstract text, publish_unit character varying, publish_date timestamp with time zone, signer character varying, sign_date timestamp with time zone, doc_book_id integer, doc_type_id integer, doc_field_id integer, secret_id smallint, urgent_id smallint, number_paper integer, number_copies integer, expired_date timestamp with time zone, recipients text, sents text, approver character varying, approved boolean, is_handling boolean, is_received_paper boolean, received_paper_date timestamp with time zone, archive_status boolean, is_inter_doc boolean, inter_doc_id integer, created_by integer, created_at timestamp with time zone, updated_by integer, updated_at timestamp with time zone, doc_book_name character varying, doc_type_name character varying, doc_type_code character varying, doc_field_name character varying, created_by_name character varying, is_read boolean)
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- Đánh dấu đã đọc
  PERFORM edoc.fn_incoming_doc_mark_read(p_id, p_staff_id);

  RETURN QUERY
  SELECT
    d.id, d.unit_id, d.received_date, d.number, d.notation, d.document_code,
    d.abstract, d.publish_unit, d.publish_date, d.signer, d.sign_date,
    d.doc_book_id, d.doc_type_id, d.doc_field_id, d.secret_id, d.urgent_id,
    d.number_paper, d.number_copies, d.expired_date, d.recipients,
    d.sents,                                    -- MỚI
    d.approver, d.approved, d.is_handling, d.is_received_paper,
    d.received_paper_date,                      -- MỚI
    d.archive_status,
    d.is_inter_doc,                             -- MỚI
    d.inter_doc_id,                             -- MỚI
    d.created_by, d.created_at, d.updated_by, d.updated_at,
    db.name, dt.name, dt.code, df.name, s.full_name,
    TRUE  -- đã mark read ở trên
  FROM edoc.incoming_docs d
  LEFT JOIN edoc.doc_books db ON db.id = d.doc_book_id
  LEFT JOIN edoc.doc_types dt ON dt.id = d.doc_type_id
  LEFT JOIN edoc.doc_fields df ON df.id = d.doc_field_id
  LEFT JOIN public.staff s ON s.id = d.created_by
  WHERE d.id = p_id;
END;
$$;


--
-- Name: fn_incoming_doc_get_history(bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_get_history(p_doc_id bigint) RETURNS TABLE(event_type character varying, event_time timestamp with time zone, staff_name character varying, content text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT * FROM (
    -- Tạo VB
    SELECT 'created'::VARCHAR AS evt, d.created_at AS etime, s.full_name AS sname, ('Tạo văn bản đến, số đến: ' || d.number)::TEXT AS econtent
    FROM edoc.incoming_docs d
    JOIN public.staff s ON s.id = d.created_by
    WHERE d.id = p_doc_id

    UNION ALL
    -- Duyệt
    SELECT 'approved'::VARCHAR, d.updated_at, d.approver::VARCHAR, 'Duyệt văn bản'::TEXT
    FROM edoc.incoming_docs d
    WHERE d.id = p_doc_id AND d.approved = TRUE

    UNION ALL
    -- Gửi cho cán bộ
    SELECT 'sent'::VARCHAR, uid.created_at, s.full_name, ('Nhận văn bản')::TEXT
    FROM edoc.user_incoming_docs uid
    JOIN public.staff s ON s.id = uid.staff_id
    WHERE uid.incoming_doc_id = p_doc_id

    UNION ALL
    -- Bút phê
    SELECT 'leader_note'::VARCHAR, ln.created_at, s.full_name, ln.content
    FROM edoc.leader_notes ln
    JOIN public.staff s ON s.id = ln.staff_id
    WHERE ln.incoming_doc_id = p_doc_id
  ) sub
  ORDER BY sub.etime DESC;
END;
$$;


--
-- Name: fn_incoming_doc_get_list(integer, integer, integer, integer, integer, smallint, boolean, boolean, timestamp with time zone, timestamp with time zone, text, text, integer, integer, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_get_list(p_unit_id integer, p_staff_id integer, p_doc_book_id integer DEFAULT NULL::integer, p_doc_type_id integer DEFAULT NULL::integer, p_doc_field_id integer DEFAULT NULL::integer, p_urgent_id smallint DEFAULT NULL::smallint, p_is_read boolean DEFAULT NULL::boolean, p_approved boolean DEFAULT NULL::boolean, p_from_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_to_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_keyword text DEFAULT NULL::text, p_signer text DEFAULT NULL::text, p_from_number integer DEFAULT NULL::integer, p_to_number integer DEFAULT NULL::integer, p_page integer DEFAULT 1, p_page_size integer DEFAULT 20) RETURNS TABLE(id bigint, unit_id integer, received_date timestamp with time zone, number integer, notation character varying, document_code character varying, abstract text, publish_unit character varying, publish_date timestamp with time zone, signer character varying, sign_date timestamp with time zone, doc_book_id integer, doc_type_id integer, doc_field_id integer, secret_id smallint, urgent_id smallint, number_paper integer, number_copies integer, expired_date timestamp with time zone, recipients text, sents text, approver character varying, approved boolean, is_handling boolean, is_received_paper boolean, archive_status boolean, created_by integer, created_at timestamp with time zone, doc_book_name character varying, doc_type_name character varying, doc_type_code character varying, doc_field_name character varying, created_by_name character varying, is_read boolean, read_at timestamp with time zone, attachment_count bigint, total_count bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_offset INT;
  v_keyword TEXT;
  v_signer TEXT;
BEGIN
  v_offset := (GREATEST(p_page, 1) - 1) * p_page_size;
  v_keyword := NULLIF(TRIM(p_keyword), '');
  v_signer := NULLIF(TRIM(p_signer), '');

  RETURN QUERY
  WITH filtered AS (
    SELECT
      d.id AS doc_id,
      d.*,
      db.name AS _doc_book_name,
      dt.name AS _doc_type_name,
      dt.code AS _doc_type_code,
      df.name AS _doc_field_name,
      s.full_name AS _created_by_name,
      uid.is_read AS _is_read,
      uid.read_at AS _read_at,
      (SELECT COUNT(*) FROM edoc.attachment_incoming_docs a WHERE a.incoming_doc_id = d.id) AS _attachment_count,
      COUNT(*) OVER() AS _total_count
    FROM edoc.incoming_docs d
    LEFT JOIN edoc.doc_books db ON db.id = d.doc_book_id
    LEFT JOIN edoc.doc_types dt ON dt.id = d.doc_type_id
    LEFT JOIN edoc.doc_fields df ON df.id = d.doc_field_id
    LEFT JOIN public.staff s ON s.id = d.created_by
    LEFT JOIN edoc.user_incoming_docs uid ON uid.incoming_doc_id = d.id AND uid.staff_id = p_staff_id
    WHERE d.unit_id = p_unit_id
      AND (p_doc_book_id IS NULL OR d.doc_book_id = p_doc_book_id)
      AND (p_doc_type_id IS NULL OR d.doc_type_id = p_doc_type_id)
      AND (p_doc_field_id IS NULL OR d.doc_field_id = p_doc_field_id)
      AND (p_urgent_id IS NULL OR d.urgent_id = p_urgent_id)
      AND (p_approved IS NULL OR d.approved = p_approved)
      AND (p_from_date IS NULL OR d.received_date >= p_from_date)
      AND (p_to_date IS NULL OR d.received_date <= p_to_date)
      AND (p_is_read IS NULL OR (p_is_read = TRUE AND uid.is_read = TRUE) OR (p_is_read = FALSE AND (uid.is_read IS NULL OR uid.is_read = FALSE)))
      AND (v_signer IS NULL OR d.signer ILIKE '%' || v_signer || '%')                  -- MỚI
      AND (p_from_number IS NULL OR d.number >= p_from_number)                          -- MỚI
      AND (p_to_number IS NULL OR d.number <= p_to_number)                              -- MỚI
      AND (v_keyword IS NULL OR
           d.abstract ILIKE '%' || v_keyword || '%' OR
           d.notation ILIKE '%' || v_keyword || '%' OR
           d.publish_unit ILIKE '%' || v_keyword || '%' OR
           d.signer ILIKE '%' || v_keyword || '%' OR
           d.document_code ILIKE '%' || v_keyword || '%'
      )
    ORDER BY d.received_date DESC, d.number DESC
    LIMIT p_page_size OFFSET v_offset
  )
  SELECT
    f.doc_id,
    f.unit_id,
    f.received_date,
    f.number,
    f.notation,
    f.document_code,
    f.abstract,
    f.publish_unit,
    f.publish_date,
    f.signer,
    f.sign_date,
    f.doc_book_id,
    f.doc_type_id,
    f.doc_field_id,
    f.secret_id,
    f.urgent_id,
    f.number_paper,
    f.number_copies,
    f.expired_date,
    f.recipients,
    f.sents,                            -- MỚI
    f.approver,
    f.approved,
    f.is_handling,
    f.is_received_paper,
    f.archive_status,
    f.created_by,
    f.created_at,
    f._doc_book_name,
    f._doc_type_name,
    f._doc_type_code,
    f._doc_field_name,
    f._created_by_name,
    COALESCE(f._is_read, FALSE),
    f._read_at,
    f._attachment_count,
    f._total_count
  FROM filtered f;
END;
$$;


--
-- Name: fn_incoming_doc_get_next_number(integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_get_next_number(p_doc_book_id integer, p_unit_id integer) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE v_max INT;
BEGIN
  SELECT COALESCE(MAX(number), 0) INTO v_max
  FROM edoc.incoming_docs
  WHERE doc_book_id = p_doc_book_id
    AND unit_id = p_unit_id
    AND EXTRACT(YEAR FROM received_date) = EXTRACT(YEAR FROM NOW());
  RETURN v_max + 1;
END;
$$;


--
-- Name: fn_incoming_doc_get_recipients(bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_get_recipients(p_doc_id bigint) RETURNS TABLE(id bigint, staff_id integer, staff_name character varying, position_name character varying, department_name character varying, is_read boolean, read_at timestamp with time zone, created_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    uid.id, uid.staff_id,
    s.full_name,
    p.name AS position_name,
    dep.name AS department_name,
    uid.is_read, uid.read_at, uid.created_at
  FROM edoc.user_incoming_docs uid
  JOIN public.staff s ON s.id = uid.staff_id
  LEFT JOIN public.positions p ON p.id = s.position_id
  LEFT JOIN public.departments dep ON dep.id = s.department_id
  WHERE uid.incoming_doc_id = p_doc_id
  ORDER BY uid.created_at DESC;
END;
$$;


--
-- Name: fn_incoming_doc_get_sendable_staff(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_get_sendable_staff(p_unit_id integer) RETURNS TABLE(staff_id integer, full_name character varying, position_name character varying, department_id integer, department_name character varying)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT s.id, s.full_name, p.name, s.department_id, d.name
  FROM public.staff s
  LEFT JOIN public.positions p ON p.id = s.position_id
  LEFT JOIN public.departments d ON d.id = s.department_id
  WHERE s.department_id IN (
    SELECT dep.id FROM public.departments dep
    WHERE dep.id = p_unit_id OR dep.parent_id = p_unit_id
  )
  AND s.is_locked = FALSE AND s.is_deleted = FALSE
  ORDER BY d.sort_order, d.name, s.full_name;
END;
$$;


--
-- Name: fn_incoming_doc_handover(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_handover(p_doc_id bigint, p_staff_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_count INT;
BEGIN
  -- Kiểm tra văn bản tồn tại
  SELECT COUNT(*) INTO v_count FROM edoc.incoming_docs WHERE id = p_doc_id;
  IF v_count = 0 THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản'::TEXT;
    RETURN;
  END IF;

  -- Đánh dấu nhân viên đã nhận bàn giao (ghi nhận user nhận VB)
  INSERT INTO edoc.user_incoming_docs (incoming_doc_id, staff_id, is_read, read_at)
  VALUES (p_doc_id, p_staff_id, TRUE, NOW())
  ON CONFLICT (incoming_doc_id, staff_id)
  DO UPDATE SET is_read = TRUE, read_at = NOW();

  RETURN QUERY SELECT TRUE, 'Nhận bàn giao thành công'::TEXT;
END;
$$;


--
-- Name: fn_incoming_doc_mark_read(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_mark_read(p_doc_id bigint, p_staff_id integer) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
  INSERT INTO edoc.user_incoming_docs (incoming_doc_id, staff_id, is_read, read_at)
  VALUES (p_doc_id, p_staff_id, TRUE, NOW())
  ON CONFLICT (incoming_doc_id, staff_id)
  DO UPDATE SET is_read = TRUE, read_at = COALESCE(edoc.user_incoming_docs.read_at, NOW());
END;
$$;


--
-- Name: fn_incoming_doc_mark_read_bulk(bigint[], integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_mark_read_bulk(p_doc_ids bigint[], p_staff_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  INSERT INTO edoc.user_incoming_docs (incoming_doc_id, staff_id, is_read, read_at)
  SELECT unnest(p_doc_ids), p_staff_id, TRUE, NOW()
  ON CONFLICT (incoming_doc_id, staff_id)
  DO UPDATE SET is_read = TRUE, read_at = COALESCE(edoc.user_incoming_docs.read_at, NOW());

  RETURN QUERY SELECT TRUE, 'Đã đánh dấu đọc thành công'::TEXT;
END;
$$;


--
-- Name: fn_incoming_doc_receive_paper(bigint, integer, timestamp with time zone); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_receive_paper(p_id bigint, p_staff_id integer, p_received_paper_date timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE edoc.incoming_docs SET
    is_received_paper = TRUE,
    received_paper_date = COALESCE(p_received_paper_date, NOW()),  -- MỚI
    updated_by = p_staff_id,
    updated_at = NOW()
  WHERE edoc.incoming_docs.id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản đến'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT TRUE, 'Đã xác nhận nhận bản giấy'::TEXT;
END;
$$;


--
-- Name: fn_incoming_doc_retract(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_retract(p_id bigint, p_staff_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_deleted_count INT;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM edoc.incoming_docs WHERE id = p_id) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản đến'::TEXT; RETURN;
  END IF;

  DELETE FROM edoc.user_incoming_docs
  WHERE incoming_doc_id = p_id AND staff_id != p_staff_id;
  GET DIAGNOSTICS v_deleted_count = ROW_COUNT;

  UPDATE edoc.incoming_docs
  SET approved = FALSE, updated_by = p_staff_id, updated_at = NOW()
  WHERE id = p_id;

  RETURN QUERY SELECT TRUE, ('Thu hồi thành công — đã xóa ' || v_deleted_count || ' người nhận')::TEXT;
END;
$$;


--
-- Name: fn_incoming_doc_return(bigint, integer, text); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_return(p_doc_id bigint, p_returned_by integer, p_reason text) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_count INT;
BEGIN
  -- Kiểm tra lý do không được rỗng
  IF p_reason IS NULL OR TRIM(p_reason) = '' THEN
    RETURN QUERY SELECT FALSE, 'Lý do chuyển lại không được để trống'::TEXT;
    RETURN;
  END IF;

  -- Kiểm tra văn bản tồn tại
  SELECT COUNT(*) INTO v_count FROM edoc.incoming_docs WHERE id = p_doc_id;
  IF v_count = 0 THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản'::TEXT;
    RETURN;
  END IF;

  -- Ghi nhận bút phê lý do chuyển lại
  INSERT INTO edoc.leader_notes (incoming_doc_id, staff_id, content, created_at)
  VALUES (p_doc_id, p_returned_by, '[Chuyển lại] ' || TRIM(p_reason), NOW());

  -- Cập nhật trạng thái văn bản về chờ xử lý
  UPDATE edoc.incoming_docs
  SET
    approved = FALSE,
    updated_by = p_returned_by,
    updated_at = NOW()
  WHERE id = p_doc_id;

  RETURN QUERY SELECT TRUE, 'Chuyển lại văn bản thành công'::TEXT;
END;
$$;


--
-- Name: fn_incoming_doc_send(bigint, integer[], integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_send(p_doc_id bigint, p_staff_ids integer[], p_sent_by integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_approved BOOLEAN;
  v_count INT;
BEGIN
  -- Check approved
  SELECT approved INTO v_approved FROM edoc.incoming_docs WHERE edoc.incoming_docs.id = p_doc_id;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản đến'::TEXT;
    RETURN;
  END IF;
  IF v_approved IS NULL OR v_approved = FALSE THEN
    RETURN QUERY SELECT FALSE, 'Văn bản chưa được duyệt, không thể gửi'::TEXT;
    RETURN;
  END IF;

  IF p_staff_ids IS NULL OR array_length(p_staff_ids, 1) IS NULL THEN
    RETURN QUERY SELECT FALSE, 'Vui lòng chọn ít nhất một người nhận'::TEXT;
    RETURN;
  END IF;

  -- Insert, skip duplicates — lưu sent_by để render badge "Gửi bởi ..." ở list
  INSERT INTO edoc.user_incoming_docs (incoming_doc_id, staff_id, sent_by, is_read, created_at)
  SELECT p_doc_id, unnest(p_staff_ids), p_sent_by, FALSE, NOW()
  ON CONFLICT (incoming_doc_id, staff_id) DO NOTHING;

  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN QUERY SELECT TRUE, ('Đã gửi cho ' || v_count || ' người nhận')::TEXT;
END;
$$;


--
-- Name: fn_incoming_doc_unapprove(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_unapprove(p_id bigint, p_staff_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_has_sent BOOLEAN;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM edoc.incoming_docs WHERE edoc.incoming_docs.id = p_id) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản đến'::TEXT;
    RETURN;
  END IF;

  -- Không cho hủy duyệt nếu đã gửi
  SELECT EXISTS(SELECT 1 FROM edoc.user_incoming_docs WHERE incoming_doc_id = p_id) INTO v_has_sent;
  IF v_has_sent THEN
    RETURN QUERY SELECT FALSE, 'Không thể hủy duyệt: văn bản đã được gửi cho cán bộ'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.incoming_docs SET
    approved = FALSE,
    approver = NULL,
    updated_by = p_staff_id,
    updated_at = NOW()
  WHERE edoc.incoming_docs.id = p_id;

  RETURN QUERY SELECT TRUE, 'Hủy duyệt thành công'::TEXT;
END;
$$;


--
-- Name: fn_incoming_doc_update(bigint, timestamp with time zone, integer, character varying, character varying, text, character varying, timestamp with time zone, character varying, timestamp with time zone, integer, integer, integer, smallint, smallint, integer, integer, timestamp with time zone, text, text, boolean, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_update(p_id bigint, p_received_date timestamp with time zone, p_number integer, p_notation character varying, p_document_code character varying, p_abstract text, p_publish_unit character varying, p_publish_date timestamp with time zone, p_signer character varying, p_sign_date timestamp with time zone, p_doc_book_id integer, p_doc_type_id integer, p_doc_field_id integer, p_secret_id smallint DEFAULT 1, p_urgent_id smallint DEFAULT 1, p_number_paper integer DEFAULT 1, p_number_copies integer DEFAULT 1, p_expired_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_recipients text DEFAULT NULL::text, p_sents text DEFAULT NULL::text, p_is_received_paper boolean DEFAULT false, p_updated_by integer DEFAULT NULL::integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_approved BOOLEAN;
BEGIN
  SELECT approved INTO v_approved FROM edoc.incoming_docs WHERE edoc.incoming_docs.id = p_id;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản đến'::TEXT;
    RETURN;
  END IF;
  IF v_approved = TRUE THEN
    RETURN QUERY SELECT FALSE, 'Không thể sửa văn bản đã được duyệt'::TEXT;
    RETURN;
  END IF;

  IF p_abstract IS NULL OR TRIM(p_abstract) = '' THEN
    RETURN QUERY SELECT FALSE, 'Trích yếu nội dung không được để trống'::TEXT;
    RETURN;
  END IF;

  IF p_doc_book_id IS NULL THEN
    RETURN QUERY SELECT FALSE, 'Sổ văn bản là bắt buộc'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.incoming_docs SET
    received_date   = COALESCE(p_received_date, received_date),
    number          = COALESCE(p_number, number),
    notation        = NULLIF(TRIM(p_notation), ''),
    document_code   = NULLIF(TRIM(p_document_code), ''),
    abstract        = TRIM(p_abstract),
    publish_unit    = NULLIF(TRIM(p_publish_unit), ''),
    publish_date    = p_publish_date,
    signer          = NULLIF(TRIM(p_signer), ''),
    sign_date       = p_sign_date,
    doc_book_id     = p_doc_book_id,
    doc_type_id     = p_doc_type_id,
    doc_field_id    = p_doc_field_id,
    secret_id       = COALESCE(p_secret_id, 1),
    urgent_id       = COALESCE(p_urgent_id, 1),
    number_paper    = COALESCE(p_number_paper, 1),
    number_copies   = COALESCE(p_number_copies, 1),
    expired_date    = p_expired_date,
    recipients      = NULLIF(TRIM(p_recipients), ''),
    sents           = NULLIF(TRIM(p_sents), ''),       -- MỚI
    is_received_paper = COALESCE(p_is_received_paper, FALSE),
    updated_by      = p_updated_by,
    updated_at      = NOW()
  WHERE edoc.incoming_docs.id = p_id;

  RETURN QUERY SELECT TRUE, 'Cập nhật văn bản đến thành công'::TEXT;
END;
$$;


--
-- Name: fn_inter_incoming_complete(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_inter_incoming_complete(p_id bigint, p_staff_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_status VARCHAR;
BEGIN
  SELECT status INTO v_status FROM edoc.inter_incoming_docs WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản liên thông'::TEXT; RETURN;
  END IF;
  IF v_status != 'received' THEN
    RETURN QUERY SELECT FALSE, ('Không thể hoàn thành — trạng thái hiện tại: ' || v_status)::TEXT; RETURN;
  END IF;
  UPDATE edoc.inter_incoming_docs SET status = 'completed', updated_at = NOW() WHERE id = p_id;
  RETURN QUERY SELECT TRUE, 'Hoàn thành xử lý văn bản liên thông'::TEXT;
END;
$$;


--
-- Name: fn_inter_incoming_create(integer, character varying, character varying, text, character varying, date, character varying, date, date, integer, character varying, character varying, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_inter_incoming_create(p_unit_id integer, p_notation character varying, p_document_code character varying, p_abstract text, p_publish_unit character varying, p_publish_date date, p_signer character varying, p_sign_date date, p_expired_date date, p_doc_type_id integer, p_source_system character varying, p_external_doc_id character varying, p_created_by integer) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_id BIGINT;
BEGIN
  -- Kiểm tra đơn vị tồn tại
  IF NOT EXISTS (SELECT 1 FROM public.departments WHERE id = p_unit_id) THEN
    RETURN QUERY SELECT FALSE, 'Đơn vị không tồn tại'::TEXT, NULL::BIGINT;
    RETURN;
  END IF;

  INSERT INTO edoc.inter_incoming_docs (
    unit_id, notation, document_code, abstract,
    publish_unit, publish_date, signer, sign_date,
    expired_date, doc_type_id, source_system, external_doc_id,
    created_by, created_at, updated_at
  ) VALUES (
    p_unit_id, p_notation, p_document_code, p_abstract,
    p_publish_unit, p_publish_date, p_signer, p_sign_date,
    p_expired_date, p_doc_type_id, p_source_system, p_external_doc_id,
    p_created_by, NOW(), NOW()
  )
  RETURNING inter_incoming_docs.id INTO v_id;

  RETURN QUERY SELECT TRUE, 'Tạo văn bản liên thông thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_inter_incoming_get_by_id(bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_inter_incoming_get_by_id(p_id bigint) RETURNS TABLE(id bigint, unit_id integer, received_date timestamp without time zone, notation character varying, document_code character varying, abstract text, publish_unit character varying, publish_date date, signer character varying, sign_date date, expired_date date, doc_type_id integer, doc_field_id integer, secret_id smallint, urgent_id smallint, number_paper integer, number_copies integer, recipients text, status character varying, source_system character varying, external_doc_id character varying, organ_id character varying, from_organ_id character varying, created_by integer, created_at timestamp without time zone, updated_at timestamp without time zone, doc_type_name character varying, doc_field_name character varying, created_by_name character varying)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    d.id, d.unit_id, d.received_date, d.notation, d.document_code,
    d.abstract, d.publish_unit, d.publish_date, d.signer, d.sign_date,
    d.expired_date, d.doc_type_id,
    d.doc_field_id,                                -- MỚI
    d.secret_id,                                   -- MỚI
    d.urgent_id,                                   -- MỚI
    d.number_paper,                                -- MỚI
    d.number_copies,                               -- MỚI
    d.recipients,                                  -- MỚI
    d.status, d.source_system, d.external_doc_id,
    d.organ_id,                                    -- MỚI
    d.from_organ_id,                               -- MỚI
    d.created_by, d.created_at, d.updated_at,
    dt.name,                                       -- MỚI: doc_type_name
    df.name,                                       -- MỚI: doc_field_name
    s.full_name                                    -- MỚI: created_by_name
  FROM edoc.inter_incoming_docs d
  LEFT JOIN edoc.doc_types dt ON dt.id = d.doc_type_id        -- MỚI
  LEFT JOIN edoc.doc_fields df ON df.id = d.doc_field_id      -- MỚI
  LEFT JOIN public.staff s ON s.id = d.created_by             -- MỚI
  WHERE d.id = p_id;
END;
$$;


--
-- Name: fn_inter_incoming_get_list(integer, text, text, date, date, integer, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_inter_incoming_get_list(p_unit_id integer, p_keyword text, p_status text, p_from_date date, p_to_date date, p_doc_type_id integer DEFAULT NULL::integer, p_page integer DEFAULT 1, p_page_size integer DEFAULT 20) RETURNS TABLE(id bigint, unit_id integer, received_date timestamp without time zone, notation character varying, document_code character varying, abstract text, publish_unit character varying, publish_date date, signer character varying, sign_date date, expired_date date, doc_type_id integer, status character varying, source_system character varying, external_doc_id character varying, created_by integer, created_at timestamp without time zone, updated_at timestamp without time zone, doc_type_name character varying, created_by_name character varying, total_count bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_offset INT := (COALESCE(p_page, 1) - 1) * COALESCE(p_page_size, 20);
BEGIN
  RETURN QUERY
  WITH filtered AS (
    SELECT
      d.id, d.unit_id, d.received_date, d.notation, d.document_code,
      d.abstract, d.publish_unit, d.publish_date, d.signer, d.sign_date,
      d.expired_date, d.doc_type_id, d.status, d.source_system, d.external_doc_id,
      d.created_by, d.created_at, d.updated_at,
      dt.name AS _doc_type_name,                  -- MỚI
      s.full_name AS _created_by_name             -- MỚI
    FROM edoc.inter_incoming_docs d
    LEFT JOIN edoc.doc_types dt ON dt.id = d.doc_type_id       -- MỚI
    LEFT JOIN public.staff s ON s.id = d.created_by            -- MỚI
    WHERE
      d.unit_id = p_unit_id
      AND (p_status IS NULL OR p_status = '' OR d.status = p_status)
      AND (p_doc_type_id IS NULL OR d.doc_type_id = p_doc_type_id)  -- MỚI
      AND (p_from_date IS NULL OR d.received_date::DATE >= p_from_date)
      AND (p_to_date IS NULL OR d.received_date::DATE <= p_to_date)
      AND (
        p_keyword IS NULL OR TRIM(p_keyword) = ''
        OR d.notation ILIKE '%' || p_keyword || '%'
        OR d.abstract ILIKE '%' || p_keyword || '%'
        OR d.publish_unit ILIKE '%' || p_keyword || '%'
      )
  )
  SELECT
    f.id, f.unit_id, f.received_date, f.notation, f.document_code,
    f.abstract, f.publish_unit, f.publish_date, f.signer, f.sign_date,
    f.expired_date, f.doc_type_id, f.status, f.source_system, f.external_doc_id,
    f.created_by, f.created_at, f.updated_at,
    f._doc_type_name,                              -- MỚI
    f._created_by_name,                            -- MỚI
    COUNT(*) OVER()::BIGINT AS total_count
  FROM filtered f
  ORDER BY f.received_date DESC NULLS LAST
  LIMIT COALESCE(p_page_size, 20)
  OFFSET v_offset;
END;
$$;


--
-- Name: fn_inter_incoming_receive(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_inter_incoming_receive(p_id bigint, p_staff_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_inter       edoc.inter_incoming_docs%ROWTYPE;
  v_unit_id     INT;
  v_incoming_id BIGINT;
  v_next_number INT;
BEGIN
  -- Lấy thông tin VB liên thông
  SELECT * INTO v_inter FROM edoc.inter_incoming_docs WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản liên thông'::TEXT; RETURN;
  END IF;
  IF v_inter.status != 'pending' THEN
    RETURN QUERY SELECT FALSE, ('Không thể nhận bàn giao — trạng thái hiện tại: ' || v_inter.status)::TEXT; RETURN;
  END IF;

  -- Lấy unit_id từ staff
  SELECT s.unit_id INTO v_unit_id FROM public.staff s WHERE s.id = p_staff_id;
  IF v_unit_id IS NULL THEN v_unit_id := v_inter.unit_id; END IF;

  -- Tính số đến tiếp theo
  SELECT COALESCE(MAX(number), 0) + 1 INTO v_next_number
  FROM edoc.incoming_docs WHERE unit_id = v_unit_id;

  -- Tạo VB đến từ VB liên thông
  INSERT INTO edoc.incoming_docs (
    unit_id, received_date, number, notation, document_code,
    abstract, publish_unit, publish_date, signer, sign_date,
    doc_type_id, expired_date, secret_id, urgent_id,
    is_inter_doc, inter_doc_id,
    approved, is_handling, is_received_paper, archive_status,
    created_by, created_at
  ) VALUES (
    v_unit_id, NOW(), v_next_number, v_inter.notation, v_inter.document_code,
    v_inter.abstract, v_inter.publish_unit, v_inter.publish_date, v_inter.signer, v_inter.sign_date,
    v_inter.doc_type_id, v_inter.expired_date, 1, 1,
    TRUE, p_id::INT,
    FALSE, FALSE, FALSE, FALSE,
    p_staff_id, NOW()
  ) RETURNING id INTO v_incoming_id;

  -- Phân phối VB đến cho người nhận bàn giao
  INSERT INTO edoc.user_incoming_docs (incoming_doc_id, staff_id, is_read, created_at)
  VALUES (v_incoming_id, p_staff_id, FALSE, NOW());

  -- Cập nhật trạng thái VB liên thông
  UPDATE edoc.inter_incoming_docs SET status = 'received', updated_at = NOW() WHERE id = p_id;

  RETURN QUERY SELECT TRUE, ('Nhận bàn giao thành công — đã tạo văn bản đến số ' || v_next_number)::TEXT;
END;
$$;


--
-- Name: fn_inter_incoming_return(bigint, integer, text); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_inter_incoming_return(p_id bigint, p_staff_id integer, p_reason text DEFAULT NULL::text) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_status VARCHAR;
BEGIN
  SELECT status INTO v_status FROM edoc.inter_incoming_docs WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản liên thông'::TEXT; RETURN;
  END IF;
  IF v_status != 'pending' THEN
    RETURN QUERY SELECT FALSE, ('Không thể chuyển lại — trạng thái hiện tại: ' || v_status)::TEXT; RETURN;
  END IF;
  UPDATE edoc.inter_incoming_docs SET status = 'returned', updated_at = NOW() WHERE id = p_id;
  RETURN QUERY SELECT TRUE, 'Chuyển lại văn bản thành công'::TEXT;
END;
$$;


--
-- Name: fn_leader_note_comment_and_assign(bigint, integer, text, timestamp with time zone, integer[], character varying); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_leader_note_comment_and_assign(p_doc_id bigint, p_staff_id integer, p_content text, p_expired_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_staff_ids integer[] DEFAULT NULL::integer[], p_doc_type character varying DEFAULT 'incoming'::character varying) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_id BIGINT;
  v_sent_count INT := 0;
BEGIN
  IF p_content IS NULL OR TRIM(p_content) = '' THEN
    RETURN QUERY SELECT FALSE, 'Nội dung bút phê không được để trống'::TEXT, 0::BIGINT;
    RETURN;
  END IF;

  -- Tạo leader note
  IF p_doc_type = 'incoming' THEN
    INSERT INTO edoc.leader_notes (incoming_doc_id, staff_id, content, expired_date, assigned_staff_ids)
    VALUES (p_doc_id, p_staff_id, TRIM(p_content), p_expired_date, p_staff_ids)
    RETURNING edoc.leader_notes.id INTO v_id;
  ELSIF p_doc_type = 'outgoing' THEN
    INSERT INTO edoc.leader_notes (outgoing_doc_id, staff_id, content, expired_date, assigned_staff_ids)
    VALUES (p_doc_id, p_staff_id, TRIM(p_content), p_expired_date, p_staff_ids)
    RETURNING edoc.leader_notes.id INTO v_id;
  ELSIF p_doc_type = 'drafting' THEN
    INSERT INTO edoc.leader_notes (drafting_doc_id, staff_id, content, expired_date, assigned_staff_ids)
    VALUES (p_doc_id, p_staff_id, TRIM(p_content), p_expired_date, p_staff_ids)
    RETURNING edoc.leader_notes.id INTO v_id;
  END IF;

  -- Gửi VB cho cán bộ được phân công
  IF p_staff_ids IS NOT NULL AND array_length(p_staff_ids, 1) > 0 THEN
    IF p_doc_type = 'incoming' THEN
      INSERT INTO edoc.user_incoming_docs (incoming_doc_id, staff_id, is_read, created_at)
      SELECT p_doc_id, unnest(p_staff_ids), FALSE, NOW()
      ON CONFLICT (incoming_doc_id, staff_id) DO NOTHING;
      GET DIAGNOSTICS v_sent_count = ROW_COUNT;
    ELSIF p_doc_type = 'outgoing' THEN
      INSERT INTO edoc.user_outgoing_docs (outgoing_doc_id, staff_id, sent_by, is_read, created_at)
      SELECT p_doc_id, unnest(p_staff_ids), p_staff_id, FALSE, NOW()
      ON CONFLICT (outgoing_doc_id, staff_id) DO NOTHING;
      GET DIAGNOSTICS v_sent_count = ROW_COUNT;
    ELSIF p_doc_type = 'drafting' THEN
      INSERT INTO edoc.user_drafting_docs (drafting_doc_id, staff_id, sent_by, is_read, created_at)
      SELECT p_doc_id, unnest(p_staff_ids), p_staff_id, FALSE, NOW()
      ON CONFLICT (drafting_doc_id, staff_id) DO NOTHING;
      GET DIAGNOSTICS v_sent_count = ROW_COUNT;
    END IF;
  END IF;

  RETURN QUERY SELECT TRUE,
    ('Bút phê thành công' || CASE WHEN v_sent_count > 0 THEN ', đã phân công ' || v_sent_count || ' cán bộ' ELSE '' END)::TEXT,
    v_id;
END;
$$;


--
-- Name: fn_leader_note_create(bigint, integer, text); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_leader_note_create(p_doc_id bigint, p_staff_id integer, p_content text) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id BIGINT;
BEGIN
