    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT ln.id, ln.staff_id, s.full_name, p.name, ln.content, ln.created_at
  FROM edoc.leader_notes ln
  JOIN public.staff s ON s.id = ln.staff_id
  LEFT JOIN public.positions p ON p.id = s.position_id
  WHERE ln.outgoing_doc_id = p_doc_id
  ORDER BY ln.created_at DESC;
END;
$$;


--
-- Name: fn_leader_note_get_list(bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_leader_note_get_list(p_doc_id bigint) RETURNS TABLE(id bigint, staff_id integer, staff_name character varying, position_name character varying, content text, created_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT ln.id, ln.staff_id, s.full_name, p.name, ln.content, ln.created_at
  FROM edoc.leader_notes ln
  JOIN public.staff s ON s.id = ln.staff_id
  LEFT JOIN public.positions p ON p.id = s.position_id
  WHERE ln.incoming_doc_id = p_doc_id
  ORDER BY ln.created_at DESC;
END;
$$;


--
-- Name: fn_lgsp_mock_receive(integer, character varying, text, character varying, character varying, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_lgsp_mock_receive(p_unit_id integer, p_notation character varying, p_abstract text, p_publish_unit character varying, p_signer character varying, p_doc_type_id integer DEFAULT NULL::integer, p_created_by integer DEFAULT NULL::integer) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id BIGINT;
BEGIN
  INSERT INTO edoc.inter_incoming_docs (
    unit_id, notation, abstract, publish_unit, signer,
    doc_type_id, source_system, status, created_by
  ) VALUES (
    p_unit_id, p_notation, p_abstract, p_publish_unit, p_signer,
    p_doc_type_id, 'LGSP_MOCK', 'pending', p_created_by
  )
  RETURNING inter_incoming_docs.id INTO v_id;

  RETURN QUERY SELECT TRUE, ('[MOCK] Đã nhận VB liên thông #' || v_id)::TEXT, v_id;
END;
$$;


--
-- Name: fn_lgsp_mock_send(bigint, character varying, character varying, character varying, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_lgsp_mock_send(p_doc_id bigint, p_doc_type character varying, p_dest_org_code character varying, p_dest_org_name character varying, p_sent_by integer) RETURNS TABLE(success boolean, message text, tracking_id bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id BIGINT;
BEGIN
  INSERT INTO edoc.lgsp_tracking (
    outgoing_doc_id, incoming_doc_id, direction, dest_org_code, dest_org_name,
    status, sent_at, created_by
  ) VALUES (
    CASE WHEN p_doc_type = 'outgoing' THEN p_doc_id ELSE NULL END,
    CASE WHEN p_doc_type = 'incoming' THEN p_doc_id ELSE NULL END,
    'send', p_dest_org_code, p_dest_org_name,
    'success', NOW(), p_sent_by  -- Mock: luôn success
  )
  RETURNING edoc.lgsp_tracking.id INTO v_id;

  RETURN QUERY SELECT TRUE, ('[MOCK] Gửi liên thông thành công → ' || p_dest_org_name)::TEXT, v_id;
END;
$$;


--
-- Name: fn_lgsp_org_get_list(text, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

-- Phase 260424-wve follow-up: unify về inter_organizations (bảng duy nhất quản lý cơ quan
-- liên thông). lgsp_organizations giữ để không phá schema nhưng không dùng trong workflow.
-- Phase 2 sẽ làm sync từ LGSP API vào inter_organizations trực tiếp.
CREATE OR REPLACE FUNCTION edoc.fn_lgsp_org_get_list(p_search text DEFAULT NULL::text, p_page integer DEFAULT 1, p_page_size integer DEFAULT 20) RETURNS TABLE(id bigint, org_code character varying, org_name character varying, parent_code character varying, address character varying, email character varying, phone character varying, is_active boolean, synced_at timestamp with time zone, total_count bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_offset INT := (p_page - 1) * p_page_size;
  v_total  BIGINT;
BEGIN
  SELECT COUNT(*) INTO v_total
  FROM edoc.inter_organizations o
  WHERE COALESCE(o.is_active, true) = true
    AND (p_search IS NULL OR p_search = ''
      OR o.code ILIKE '%' || p_search || '%'
      OR o.name ILIKE '%' || p_search || '%');

  RETURN QUERY
  SELECT
    o.id::bigint,
    o.code AS org_code,
    o.name AS org_name,
    NULL::varchar AS parent_code,
    NULL::varchar AS address,
    NULL::varchar AS email,
    NULL::varchar AS phone,
    COALESCE(o.is_active, true) AS is_active,
    o.created_at AS synced_at,
    v_total
  FROM edoc.inter_organizations o
  WHERE COALESCE(o.is_active, true) = true
    AND (p_search IS NULL OR p_search = ''
      OR o.code ILIKE '%' || p_search || '%'
      OR o.name ILIKE '%' || p_search || '%')
  ORDER BY o.name
  LIMIT p_page_size OFFSET v_offset;
END;
$$;


--
-- Name: fn_lgsp_org_sync(character varying, character varying, character varying, character varying, character varying, character varying); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_lgsp_org_sync(p_org_code character varying, p_org_name character varying, p_parent_code character varying DEFAULT NULL::character varying, p_address character varying DEFAULT NULL::character varying, p_email character varying DEFAULT NULL::character varying, p_phone character varying DEFAULT NULL::character varying) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_id BIGINT;
BEGIN
  INSERT INTO edoc.lgsp_organizations (org_code, org_name, parent_code, address, email, phone, synced_at)
  VALUES (p_org_code, p_org_name, p_parent_code, p_address, p_email, p_phone, NOW())
  ON CONFLICT (org_code) DO UPDATE SET
    org_name    = EXCLUDED.org_name,
    parent_code = EXCLUDED.parent_code,
    address     = EXCLUDED.address,
    email       = EXCLUDED.email,
    phone       = EXCLUDED.phone,
    synced_at   = NOW()
  RETURNING edoc.lgsp_organizations.id INTO v_id;

  RETURN QUERY SELECT true, 'Dong bo co quan thanh cong'::TEXT, v_id;
END;
$$;


--
-- Name: fn_lgsp_tracking_create(bigint, bigint, character varying, character varying, character varying, text, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_lgsp_tracking_create(p_outgoing_doc_id bigint DEFAULT NULL::bigint, p_incoming_doc_id bigint DEFAULT NULL::bigint, p_direction character varying DEFAULT 'send'::character varying, p_dest_org_code character varying DEFAULT NULL::character varying, p_dest_org_name character varying DEFAULT NULL::character varying, p_edxml_content text DEFAULT NULL::text, p_created_by integer DEFAULT NULL::integer) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_id BIGINT;
BEGIN
  INSERT INTO edoc.lgsp_tracking (
    outgoing_doc_id, incoming_doc_id, direction, dest_org_code, dest_org_name,
    edxml_content, status, created_by
  )
  VALUES (
    p_outgoing_doc_id, p_incoming_doc_id, p_direction, p_dest_org_code, p_dest_org_name,
    p_edxml_content, 'pending', p_created_by
  )
  RETURNING edoc.lgsp_tracking.id INTO v_id;

  RETURN QUERY SELECT true, 'Tạo tracking liên thông thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_lgsp_tracking_get_by_doc(bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_lgsp_tracking_get_by_doc(p_outgoing_doc_id bigint) RETURNS TABLE(id bigint, direction character varying, lgsp_doc_id character varying, dest_org_code character varying, dest_org_name character varying, status character varying, error_message text, sent_at timestamp with time zone, created_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    t.id,
    t.direction,
    t.lgsp_doc_id,
    t.dest_org_code,
    t.dest_org_name,
    t.status,
    t.error_message,
    t.sent_at,
    t.created_at
  FROM edoc.lgsp_tracking t
  WHERE t.outgoing_doc_id = p_outgoing_doc_id
  ORDER BY t.created_at DESC;
END;
$$;


--
-- Name: fn_lgsp_tracking_get_list(character varying, character varying, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_lgsp_tracking_get_list(p_direction character varying DEFAULT NULL::character varying, p_status character varying DEFAULT NULL::character varying, p_page integer DEFAULT 1, p_page_size integer DEFAULT 20) RETURNS TABLE(id bigint, outgoing_doc_id bigint, incoming_doc_id bigint, direction character varying, lgsp_doc_id character varying, dest_org_code character varying, dest_org_name character varying, status character varying, error_message text, sent_at timestamp with time zone, received_at timestamp with time zone, created_at timestamp with time zone, total_count bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_offset INT := (p_page - 1) * p_page_size;
  v_total  BIGINT;
BEGIN
  SELECT COUNT(*) INTO v_total
  FROM edoc.lgsp_tracking t
  WHERE (p_direction IS NULL OR p_direction = '' OR t.direction = p_direction)
    AND (p_status IS NULL OR p_status = '' OR t.status = p_status);

  RETURN QUERY
  SELECT
    t.id,
    t.outgoing_doc_id,
    t.incoming_doc_id,
    t.direction,
    t.lgsp_doc_id,
    t.dest_org_code,
    t.dest_org_name,
    t.status,
    t.error_message,
    t.sent_at,
    t.received_at,
    t.created_at,
    v_total
  FROM edoc.lgsp_tracking t
  WHERE (p_direction IS NULL OR p_direction = '' OR t.direction = p_direction)
    AND (p_status IS NULL OR p_status = '' OR t.status = p_status)
  ORDER BY t.created_at DESC
  LIMIT p_page_size OFFSET v_offset;
END;
$$;


--
-- Name: fn_lgsp_tracking_update_status(bigint, character varying, character varying, text); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_lgsp_tracking_update_status(p_id bigint, p_status character varying, p_lgsp_doc_id character varying DEFAULT NULL::character varying, p_error_message text DEFAULT NULL::text) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE edoc.lgsp_tracking
  SET status        = p_status,
      lgsp_doc_id   = COALESCE(p_lgsp_doc_id, lgsp_doc_id),
      error_message = p_error_message,
      sent_at       = CASE WHEN p_status = 'success' THEN NOW() ELSE sent_at END,
      received_at   = CASE WHEN p_status = 'success' AND direction = 'receive' THEN NOW() ELSE received_at END
  WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Khong tim thay tracking'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT true, 'Cap nhat trang thai thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_meeting_type_create(integer, character varying, text, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_meeting_type_create(p_unit_id integer, p_name character varying, p_description text, p_sort_order integer, p_created_user_id integer) RETURNS TABLE(success boolean, message text, id integer)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_id INT;
BEGIN
  IF TRIM(COALESCE(p_name, '')) = '' THEN
    RETURN QUERY SELECT false, 'Tên loại cuộc họp không được để trống'::TEXT, NULL::INT;
    RETURN;
  END IF;

  INSERT INTO edoc.meeting_types (unit_id, name, description, sort_order, created_user_id)
  VALUES (p_unit_id, p_name, p_description, COALESCE(p_sort_order, 0), p_created_user_id)
  RETURNING edoc.meeting_types.id INTO v_id;

  RETURN QUERY SELECT true, 'Tạo loại cuộc họp thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_meeting_type_delete(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_meeting_type_delete(p_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  UPDATE edoc.meeting_types SET is_deleted = true WHERE id = p_id AND is_deleted = false;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy loại cuộc họp'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT true, 'Xóa loại cuộc họp thành công'::TEXT;
END;
$$;


--
-- Name: fn_meeting_type_get_list(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_meeting_type_get_list(p_unit_id integer) RETURNS TABLE(id integer, unit_id integer, name character varying, description text, sort_order integer, created_date timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    mt.id, mt.unit_id, mt.name, mt.description, mt.sort_order, mt.created_date
  FROM edoc.meeting_types mt
  WHERE mt.unit_id = p_unit_id AND mt.is_deleted = false
  ORDER BY mt.sort_order, mt.name;
END;
$$;


--
-- Name: fn_meeting_type_update(integer, character varying, text, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_meeting_type_update(p_id integer, p_name character varying, p_description text, p_sort_order integer, p_modified_user_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  IF TRIM(COALESCE(p_name, '')) = '' THEN
    RETURN QUERY SELECT false, 'Tên loại cuộc họp không được để trống'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.meeting_types SET
    name             = p_name,
    description      = p_description,
    sort_order       = COALESCE(p_sort_order, 0),
    modified_user_id = p_modified_user_id,
    modified_date    = NOW()
  WHERE id = p_id AND is_deleted = false;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy loại cuộc họp'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT true, 'Cập nhật thành công'::TEXT;
END;
$$;


--
-- Name: fn_message_count_unread(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_message_count_unread(p_staff_id integer) RETURNS TABLE(count bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT COUNT(*)::BIGINT
  FROM edoc.message_recipients mr
  WHERE mr.staff_id = p_staff_id
    AND mr.is_read = FALSE
    AND mr.is_deleted = FALSE;
END;
$$;


--
-- Name: fn_message_create(integer, integer[], character varying, text, bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_message_create(p_from_staff_id integer, p_to_staff_ids integer[], p_subject character varying, p_content text, p_parent_id bigint DEFAULT NULL::bigint) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_id          BIGINT;
  v_staff_id    INT;
BEGIN
  -- Kiểm tra người nhận
  IF p_to_staff_ids IS NULL OR array_length(p_to_staff_ids, 1) = 0 THEN
    RETURN QUERY SELECT FALSE, 'Phải có ít nhất một người nhận'::TEXT, NULL::BIGINT;
    RETURN;
  END IF;

  -- Kiểm tra tiêu đề
  IF p_subject IS NULL OR TRIM(p_subject) = '' THEN
    RETURN QUERY SELECT FALSE, 'Tiêu đề tin nhắn không được để trống'::TEXT, NULL::BIGINT;
    RETURN;
  END IF;

  -- Kiểm tra nội dung
  IF p_content IS NULL OR TRIM(p_content) = '' THEN
    RETURN QUERY SELECT FALSE, 'Nội dung tin nhắn không được để trống'::TEXT, NULL::BIGINT;
    RETURN;
  END IF;

  -- Tạo tin nhắn
  INSERT INTO edoc.messages (from_staff_id, subject, content, parent_id, created_at)
  VALUES (p_from_staff_id, p_subject, p_content, p_parent_id, NOW())
  RETURNING messages.id INTO v_id;

  -- Thêm người nhận
  FOREACH v_staff_id IN ARRAY p_to_staff_ids LOOP
    INSERT INTO edoc.message_recipients (message_id, staff_id, is_read, is_deleted)
    VALUES (v_id, v_staff_id, FALSE, FALSE)
    ON CONFLICT (message_id, staff_id) DO NOTHING;
  END LOOP;

  RETURN QUERY SELECT TRUE, 'Gửi tin nhắn thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_message_delete(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_message_delete(p_id bigint, p_staff_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_count INT;
BEGIN
  -- Kiểm tra người dùng có quyền xóa (là người nhận)
  SELECT COUNT(*) INTO v_count
  FROM edoc.message_recipients
  WHERE message_id = p_id AND staff_id = p_staff_id AND is_deleted = FALSE;

  IF v_count = 0 THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy tin nhắn hoặc đã bị xóa'::TEXT;
    RETURN;
  END IF;

  -- Soft delete: chỉ xóa bản copy của người dùng này
  UPDATE edoc.message_recipients
  SET is_deleted = TRUE, deleted_at = NOW()
  WHERE message_id = p_id AND staff_id = p_staff_id;

  RETURN QUERY SELECT TRUE, 'Xóa tin nhắn thành công'::TEXT;
END;
$$;


--
-- Name: fn_message_get_by_id(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_message_get_by_id(p_id bigint, p_staff_id integer) RETURNS TABLE(id bigint, from_staff_id integer, from_staff_name text, subject character varying, content text, parent_id bigint, created_at timestamp without time zone, is_read boolean, recipient_names text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  -- Đánh dấu đã đọc nếu là người nhận
  UPDATE edoc.message_recipients
  SET is_read = TRUE, read_at = NOW()
  WHERE message_id = p_id AND staff_id = p_staff_id AND is_read = FALSE;

  -- Trả về chi tiết tin nhắn
  RETURN QUERY
  SELECT
    m.id,
    m.from_staff_id,
    CONCAT(s.last_name, ' ', s.first_name) AS from_staff_name,
    m.subject,
    m.content,
    m.parent_id,
    m.created_at,
    COALESCE(mr.is_read, FALSE) AS is_read,
    (
      SELECT STRING_AGG(CONCAT(sr.last_name, ' ', sr.first_name), ', ' ORDER BY sr.last_name)
      FROM edoc.message_recipients mr2
      JOIN public.staff sr ON sr.id = mr2.staff_id
      WHERE mr2.message_id = m.id
    ) AS recipient_names
  FROM edoc.messages m
  JOIN public.staff s ON s.id = m.from_staff_id
  LEFT JOIN edoc.message_recipients mr ON mr.message_id = m.id AND mr.staff_id = p_staff_id
  WHERE
    m.id = p_id
    AND (
      m.from_staff_id = p_staff_id
      OR EXISTS (
        SELECT 1 FROM edoc.message_recipients mr3
        WHERE mr3.message_id = m.id AND mr3.staff_id = p_staff_id
      )
    );
END;
$$;


--
-- Name: fn_message_get_inbox(integer, text, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_message_get_inbox(p_staff_id integer, p_keyword text, p_page integer DEFAULT 1, p_page_size integer DEFAULT 20) RETURNS TABLE(id bigint, from_staff_id integer, from_staff_name text, subject character varying, content text, parent_id bigint, created_at timestamp without time zone, is_read boolean, total_count bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_offset INT := (COALESCE(p_page, 1) - 1) * COALESCE(p_page_size, 20);
BEGIN
  RETURN QUERY
  WITH filtered AS (
    SELECT
      m.id,
      m.from_staff_id,
      CONCAT(s.last_name, ' ', s.first_name) AS from_staff_name,
      m.subject,
      m.content,
      m.parent_id,
      m.created_at,
      mr.is_read
    FROM edoc.messages m
    JOIN edoc.message_recipients mr ON mr.message_id = m.id AND mr.staff_id = p_staff_id
    JOIN public.staff s ON s.id = m.from_staff_id
    WHERE
      mr.is_deleted = FALSE
      AND m.parent_id IS NULL
      AND (
        p_keyword IS NULL OR TRIM(p_keyword) = ''
        OR m.subject ILIKE '%' || p_keyword || '%'
        OR m.content ILIKE '%' || p_keyword || '%'
      )
  )
  SELECT
    f.id,
    f.from_staff_id,
    f.from_staff_name,
    f.subject,
    f.content,
    f.parent_id,
    f.created_at,
    f.is_read,
    COUNT(*) OVER()::BIGINT AS total_count
  FROM filtered f
  ORDER BY f.created_at DESC
  LIMIT COALESCE(p_page_size, 20)
  OFFSET v_offset;
END;
$$;


--
-- Name: fn_message_get_sent(integer, text, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_message_get_sent(p_staff_id integer, p_keyword text, p_page integer DEFAULT 1, p_page_size integer DEFAULT 20) RETURNS TABLE(id bigint, subject character varying, content text, parent_id bigint, created_at timestamp without time zone, recipient_names text, total_count bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_offset INT := (COALESCE(p_page, 1) - 1) * COALESCE(p_page_size, 20);
BEGIN
  RETURN QUERY
  WITH filtered AS (
    SELECT
      m.id,
      m.subject,
      m.content,
      m.parent_id,
      m.created_at,
      (
        SELECT STRING_AGG(CONCAT(sr.last_name, ' ', sr.first_name), ', ' ORDER BY sr.last_name)
        FROM edoc.message_recipients mr2
        JOIN public.staff sr ON sr.id = mr2.staff_id
        WHERE mr2.message_id = m.id
      ) AS recipient_names
    FROM edoc.messages m
    WHERE
      m.from_staff_id = p_staff_id
      AND m.parent_id IS NULL
      AND (
        p_keyword IS NULL OR TRIM(p_keyword) = ''
        OR m.subject ILIKE '%' || p_keyword || '%'
        OR m.content ILIKE '%' || p_keyword || '%'
      )
  )
  SELECT
    f.id,
    f.subject,
    f.content,
    f.parent_id,
    f.created_at,
    f.recipient_names,
    COUNT(*) OVER()::BIGINT AS total_count
  FROM filtered f
  ORDER BY f.created_at DESC
  LIMIT COALESCE(p_page_size, 20)
  OFFSET v_offset;
END;
$$;


--
-- Name: fn_message_get_trash(integer, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_message_get_trash(p_staff_id integer, p_page integer DEFAULT 1, p_page_size integer DEFAULT 20) RETURNS TABLE(id bigint, from_staff_id integer, from_staff_name text, subject character varying, content text, parent_id bigint, created_at timestamp without time zone, deleted_at timestamp without time zone, total_count bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_offset INT := (COALESCE(p_page, 1) - 1) * COALESCE(p_page_size, 20);
BEGIN
  RETURN QUERY
  WITH filtered AS (
    SELECT
      m.id,
      m.from_staff_id,
      CONCAT(s.last_name, ' ', s.first_name) AS from_staff_name,
      m.subject,
      m.content,
      m.parent_id,
      m.created_at,
      mr.deleted_at
    FROM edoc.messages m
    JOIN edoc.message_recipients mr ON mr.message_id = m.id AND mr.staff_id = p_staff_id
    JOIN public.staff s ON s.id = m.from_staff_id
    WHERE mr.is_deleted = TRUE
  )
  SELECT
    f.id,
    f.from_staff_id,
    f.from_staff_name,
    f.subject,
    f.content,
    f.parent_id,
    f.created_at,
    f.deleted_at,
    COUNT(*) OVER()::BIGINT AS total_count
  FROM filtered f
  ORDER BY f.deleted_at DESC NULLS LAST
  LIMIT COALESCE(p_page_size, 20)
  OFFSET v_offset;
END;
$$;


--
-- Name: fn_message_reply(bigint, integer, text); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_message_reply(p_message_id bigint, p_staff_id integer, p_content text) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_reply_id      BIGINT;
  v_original      edoc.messages%ROWTYPE;
  v_subject       VARCHAR(200);
  v_staff_id      INT;
  v_recipient_ids INT[];
BEGIN
  -- Kiểm tra nội dung
  IF p_content IS NULL OR TRIM(p_content) = '' THEN
    RETURN QUERY SELECT FALSE, 'Nội dung trả lời không được để trống'::TEXT, NULL::BIGINT;
    RETURN;
  END IF;

  -- Lấy tin nhắn gốc
  SELECT * INTO v_original FROM edoc.messages WHERE id = p_message_id;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy tin nhắn gốc'::TEXT, NULL::BIGINT;
    RETURN;
  END IF;

  -- Xây dựng tiêu đề trả lời
  v_subject := 'Re: ' || v_original.subject;

  -- Tạo tin nhắn trả lời với parent_id = tin nhắn gốc
  INSERT INTO edoc.messages (from_staff_id, subject, content, parent_id, created_at)
  VALUES (p_staff_id, v_subject, p_content, p_message_id, NOW())
  RETURNING messages.id INTO v_reply_id;

  -- Thêm người gửi gốc làm người nhận
  INSERT INTO edoc.message_recipients (message_id, staff_id, is_read, is_deleted)
  VALUES (v_reply_id, v_original.from_staff_id, FALSE, FALSE)
  ON CONFLICT (message_id, staff_id) DO NOTHING;

  -- Thêm tất cả người nhận tin nhắn gốc (trừ người đang reply)
  FOR v_staff_id IN
    SELECT mr.staff_id FROM edoc.message_recipients mr
    WHERE mr.message_id = p_message_id AND mr.staff_id <> p_staff_id
  LOOP
    INSERT INTO edoc.message_recipients (message_id, staff_id, is_read, is_deleted)
    VALUES (v_reply_id, v_staff_id, FALSE, FALSE)
    ON CONFLICT (message_id, staff_id) DO NOTHING;
  END LOOP;

  RETURN QUERY SELECT TRUE, 'Trả lời tin nhắn thành công'::TEXT, v_reply_id;
END;
$$;


--
-- Name: fn_notice_count_unread(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

-- Phase 260424-wve follow-up: thêm p_unit_id để sync filter với fn_notice_get_list
-- (bug: badge sidebar count 30 nhưng list trống vì notice thuộc unit khác)
DROP FUNCTION IF EXISTS edoc.fn_notice_count_unread(integer);
CREATE OR REPLACE FUNCTION edoc.fn_notice_count_unread(p_staff_id integer, p_unit_id integer DEFAULT NULL) RETURNS TABLE(count bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT COUNT(*)::BIGINT
  FROM edoc.notices n
  WHERE (p_unit_id IS NULL OR n.unit_id = p_unit_id OR n.unit_id IS NULL)
    AND NOT EXISTS (
      SELECT 1 FROM edoc.notice_reads nr
      WHERE nr.notice_id = n.id AND nr.staff_id = p_staff_id
    );
END;
$$;


--
-- Name: fn_notice_create(integer, character varying, text, character varying, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_notice_create(p_unit_id integer, p_title character varying, p_content text, p_notice_type character varying, p_created_by integer) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_id BIGINT;
BEGIN
  -- Kiểm tra tiêu đề
  IF p_title IS NULL OR TRIM(p_title) = '' THEN
    RETURN QUERY SELECT FALSE, 'Tiêu đề thông báo không được để trống'::TEXT, NULL::BIGINT;
    RETURN;
  END IF;

  -- Kiểm tra nội dung
  IF p_content IS NULL OR TRIM(p_content) = '' THEN
    RETURN QUERY SELECT FALSE, 'Nội dung thông báo không được để trống'::TEXT, NULL::BIGINT;
    RETURN;
  END IF;

  INSERT INTO edoc.notices (unit_id, title, content, notice_type, created_by, created_at)
  VALUES (p_unit_id, p_title, p_content, COALESCE(p_notice_type, 'system'), p_created_by, NOW())
  RETURNING notices.id INTO v_id;

  RETURN QUERY SELECT TRUE, 'Tạo thông báo thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_notice_get_list(integer, integer, text, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_notice_get_list(p_unit_id integer, p_staff_id integer, p_is_read text, p_page integer DEFAULT 1, p_page_size integer DEFAULT 20) RETURNS TABLE(id bigint, unit_id integer, title character varying, content text, notice_type character varying, created_by integer, created_at timestamp without time zone, is_read boolean, total_count bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_offset INT := (COALESCE(p_page, 1) - 1) * COALESCE(p_page_size, 20);
BEGIN
  RETURN QUERY
  WITH filtered AS (
    SELECT
      n.id,
      n.unit_id,
      n.title,
      n.content,
      n.notice_type,
      n.created_by,
      n.created_at,
      CASE WHEN nr.id IS NOT NULL THEN TRUE ELSE FALSE END AS is_read
    FROM edoc.notices n
    LEFT JOIN edoc.notice_reads nr ON nr.notice_id = n.id AND nr.staff_id = p_staff_id
    WHERE
      (p_unit_id IS NULL OR n.unit_id = p_unit_id OR n.unit_id IS NULL)
      AND (
        p_is_read IS NULL OR p_is_read = ''
        OR (p_is_read = 'true' AND nr.id IS NOT NULL)
        OR (p_is_read = 'false' AND nr.id IS NULL)
      )
  )
  SELECT
    f.id,
    f.unit_id,
    f.title,
    f.content,
    f.notice_type,
    f.created_by,
    f.created_at,
    f.is_read,
    COUNT(*) OVER()::BIGINT AS total_count
  FROM filtered f
  ORDER BY f.created_at DESC
  LIMIT COALESCE(p_page_size, 20)
  OFFSET v_offset;
END;
$$;


--
-- Name: fn_notice_mark_all_read(integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_notice_mark_all_read(p_staff_id integer, p_unit_id integer) RETURNS TABLE(success boolean, message text, count bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_count BIGINT := 0;
BEGIN
  -- Chèn bản ghi đọc cho tất cả thông báo chưa đọc của staff này
  WITH unread_notices AS (
    SELECT n.id
    FROM edoc.notices n
    WHERE
      (p_unit_id IS NULL OR n.unit_id = p_unit_id OR n.unit_id IS NULL)
      AND NOT EXISTS (
        SELECT 1 FROM edoc.notice_reads nr
        WHERE nr.notice_id = n.id AND nr.staff_id = p_staff_id
      )
  ),
  inserted AS (
    INSERT INTO edoc.notice_reads (notice_id, staff_id, read_at)
    SELECT un.id, p_staff_id, NOW() FROM unread_notices un
    ON CONFLICT (notice_id, staff_id) DO NOTHING
    RETURNING 1
  )
  SELECT COUNT(*) INTO v_count FROM inserted;

  RETURN QUERY SELECT TRUE, 'Đánh dấu tất cả đã đọc thành công'::TEXT, v_count;
END;
$$;


--
-- Name: fn_notice_mark_read(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_notice_mark_read(p_notice_id bigint, p_staff_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  -- Kiểm tra thông báo tồn tại
  IF NOT EXISTS (SELECT 1 FROM edoc.notices WHERE id = p_notice_id) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy thông báo'::TEXT;
    RETURN;
  END IF;

  -- Insert ON CONFLICT DO NOTHING để tránh duplicate
  INSERT INTO edoc.notice_reads (notice_id, staff_id, read_at)
  VALUES (p_notice_id, p_staff_id, NOW())
  ON CONFLICT (notice_id, staff_id) DO NOTHING;

  RETURN QUERY SELECT TRUE, 'Đánh dấu đã đọc thành công'::TEXT;
END;
$$;


--
-- Name: fn_notification_log_create(integer, character varying, character varying, character varying, text, character varying, bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_notification_log_create(p_staff_id integer, p_channel character varying, p_event_type character varying, p_title character varying DEFAULT NULL::character varying, p_body text DEFAULT NULL::text, p_ref_type character varying DEFAULT NULL::character varying, p_ref_id bigint DEFAULT NULL::bigint) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_id BIGINT;
BEGIN
  INSERT INTO edoc.notification_logs (
    staff_id, channel, event_type, title, body, ref_type, ref_id
  )
  VALUES (
    p_staff_id, p_channel, p_event_type, p_title, p_body, p_ref_type, p_ref_id
  )
  RETURNING edoc.notification_logs.id INTO v_id;

  RETURN QUERY SELECT true, 'Tao log thong bao thanh cong'::TEXT, v_id;
END;
$$;


--
-- Name: fn_notification_log_get_list(integer, character varying, character varying, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_notification_log_get_list(p_staff_id integer DEFAULT NULL::integer, p_channel character varying DEFAULT NULL::character varying, p_send_status character varying DEFAULT NULL::character varying, p_page integer DEFAULT 1, p_page_size integer DEFAULT 20) RETURNS TABLE(id bigint, staff_id integer, channel character varying, event_type character varying, title character varying, body text, ref_type character varying, ref_id bigint, send_status character varying, error_message text, sent_at timestamp with time zone, created_at timestamp with time zone, total_count bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_offset INT := (p_page - 1) * p_page_size;
  v_total  BIGINT;
BEGIN
  SELECT COUNT(*) INTO v_total
  FROM edoc.notification_logs nl
  WHERE (p_staff_id IS NULL OR nl.staff_id = p_staff_id)
    AND (p_channel IS NULL OR p_channel = '' OR nl.channel = p_channel)
    AND (p_send_status IS NULL OR p_send_status = '' OR nl.send_status = p_send_status);

  RETURN QUERY
  SELECT
    nl.id,
    nl.staff_id,
    nl.channel,
    nl.event_type,
    nl.title,
    nl.body,
    nl.ref_type,
    nl.ref_id,
    nl.send_status,
    nl.error_message,
    nl.sent_at,
    nl.created_at,
    v_total
  FROM edoc.notification_logs nl
  WHERE (p_staff_id IS NULL OR nl.staff_id = p_staff_id)
    AND (p_channel IS NULL OR p_channel = '' OR nl.channel = p_channel)
    AND (p_send_status IS NULL OR p_send_status = '' OR nl.send_status = p_send_status)
  ORDER BY nl.created_at DESC
  LIMIT p_page_size OFFSET v_offset;
END;
$$;


--
-- Name: fn_notification_log_update_status(bigint, character varying, text); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_notification_log_update_status(p_id bigint, p_send_status character varying, p_error_message text DEFAULT NULL::text) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE edoc.notification_logs
  SET send_status   = p_send_status,
      error_message = p_error_message,
      sent_at       = CASE WHEN p_send_status = 'sent' THEN NOW() ELSE sent_at END
  WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Khong tim thay log thong bao'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT true, 'Cap nhat trang thai thong bao thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_notification_pref_get_by_staff(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_notification_pref_get_by_staff(p_staff_id integer) RETURNS TABLE(id bigint, channel character varying, is_enabled boolean)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    np.id,
    np.channel,
    np.is_enabled
  FROM edoc.notification_preferences np
  WHERE np.staff_id = p_staff_id
  ORDER BY np.channel;
END;
$$;


--
-- Name: fn_notification_pref_upsert(integer, character varying, boolean); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_notification_pref_upsert(p_staff_id integer, p_channel character varying, p_is_enabled boolean DEFAULT true) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_id BIGINT;
BEGIN
  INSERT INTO edoc.notification_preferences (staff_id, channel, is_enabled, updated_at)
  VALUES (p_staff_id, p_channel, p_is_enabled, NOW())
  ON CONFLICT (staff_id, channel) DO UPDATE SET
    is_enabled = EXCLUDED.is_enabled,
    updated_at = NOW()
  RETURNING edoc.notification_preferences.id INTO v_id;

  RETURN QUERY SELECT true, 'Cap nhat cau hinh thong bao thanh cong'::TEXT, v_id;
END;
$$;


--
-- Name: fn_opinion_create(bigint, integer, text, text); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_opinion_create(p_doc_id bigint, p_staff_id integer, p_content text, p_opinion_type text DEFAULT 'general'::text) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id BIGINT;
BEGIN
  IF p_content IS NULL OR TRIM(p_content) = '' THEN
    RETURN QUERY SELECT FALSE, 'Nội dung ý kiến không được để trống'::TEXT, 0::BIGINT;
    RETURN;
  END IF;

  -- Qualify table.id to avoid ambiguous reference with RETURNS TABLE(id) — Rule 3 fix
  IF NOT EXISTS (SELECT 1 FROM edoc.handling_docs hd WHERE hd.id = p_doc_id) THEN
    RETURN QUERY SELECT FALSE, 'Hồ sơ công việc không tồn tại'::TEXT, 0::BIGINT;
    RETURN;
  END IF;

  INSERT INTO edoc.opinion_handling_docs (handling_doc_id, staff_id, content, created_at)
  VALUES (p_doc_id, p_staff_id, TRIM(p_content), NOW())
  RETURNING edoc.opinion_handling_docs.id INTO v_id;

  RETURN QUERY SELECT TRUE, 'Thêm ý kiến thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_opinion_get_list(bigint); Type: FUNCTION; Schema: edoc; Owner: -
-- 11 cột: 6 cũ + 5 forward (forwarded_to_staff_id, forwarded_to_name, forwarded_at, forward_note, parent_opinion_id) — Gap E
--

DROP FUNCTION IF EXISTS edoc.fn_opinion_get_list(bigint) CASCADE;

CREATE OR REPLACE FUNCTION edoc.fn_opinion_get_list(p_doc_id bigint)
RETURNS TABLE(
    id bigint,
    staff_id integer,
    staff_name text,
    content text,
    attachment_path character varying,
    created_at timestamp with time zone,
    forwarded_to_staff_id integer,
    forwarded_to_name text,
    forwarded_at timestamp with time zone,
    forward_note text,
    parent_opinion_id bigint
)
LANGUAGE plpgsql
AS $$
BEGIN
  RETURN QUERY
  SELECT
    o.id,
    o.staff_id,
    CONCAT(s.last_name, ' ', s.first_name)::TEXT AS staff_name,
    o.content,
    o.attachment_path,
    o.created_at,
    o.forwarded_to_staff_id,
    CASE
        WHEN ts.id IS NOT NULL THEN CONCAT(ts.last_name, ' ', ts.first_name)::TEXT
        ELSE NULL::TEXT
    END AS forwarded_to_name,
    o.forwarded_at,
    o.forward_note,
    o.parent_opinion_id
  FROM edoc.opinion_handling_docs o
  JOIN public.staff s ON s.id = o.staff_id
  LEFT JOIN public.staff ts ON ts.id = o.forwarded_to_staff_id
  WHERE o.handling_doc_id = p_doc_id
  ORDER BY o.created_at ASC;
END;
$$;


--
-- Name: fn_organization_get(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_organization_get(p_unit_id integer) RETURNS TABLE(id integer, unit_id integer, code character varying, name character varying, address text, phone character varying, fax character varying, email character varying, email_doc character varying, secretary character varying, chairman_number character varying, level smallint, is_exchange boolean, lgsp_system_id character varying, lgsp_secret_key character varying, updated_by integer, updated_at timestamp with time zone)
    LANGUAGE sql STABLE
    AS $$
  SELECT o.id, o.unit_id, o.code::VARCHAR, o.name::VARCHAR, o.address,
         o.phone::VARCHAR, o.fax::VARCHAR, o.email::VARCHAR, o.email_doc::VARCHAR,
         o.secretary::VARCHAR, o.chairman_number::VARCHAR, o.level,
         o.is_exchange, o.lgsp_system_id::VARCHAR, o.lgsp_secret_key::VARCHAR,
         o.updated_by, o.updated_at
  FROM edoc.organizations o
  WHERE o.unit_id = p_unit_id;
$$;


--
-- Name: fn_organization_upsert(integer, character varying, character varying, text, character varying, character varying, character varying, character varying, character varying, character varying, smallint, boolean, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_organization_upsert(p_unit_id integer, p_code character varying DEFAULT NULL::character varying, p_name character varying DEFAULT NULL::character varying, p_address text DEFAULT NULL::text, p_phone character varying DEFAULT NULL::character varying, p_fax character varying DEFAULT NULL::character varying, p_email character varying DEFAULT NULL::character varying, p_email_doc character varying DEFAULT NULL::character varying, p_secretary character varying DEFAULT NULL::character varying, p_chairman_number character varying DEFAULT NULL::character varying, p_level smallint DEFAULT 1, p_is_exchange boolean DEFAULT false, p_updated_by integer DEFAULT NULL::integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- Validate FK
  IF NOT EXISTS(SELECT 1 FROM public.departments WHERE id = p_unit_id AND is_deleted = FALSE) THEN
    RETURN QUERY SELECT FALSE, 'Đơn vị không tồn tại'::TEXT;
    RETURN;
  END IF;

  -- Validate lengths
  IF p_code IS NOT NULL AND LENGTH(p_code) > 20 THEN
    RETURN QUERY SELECT FALSE, 'Mã cơ quan không được vượt quá 20 ký tự'::TEXT;
    RETURN;
  END IF;
  IF p_email IS NOT NULL AND LENGTH(p_email) > 100 THEN
    RETURN QUERY SELECT FALSE, 'Email không được vượt quá 100 ký tự'::TEXT;
    RETURN;
  END IF;
  IF p_phone IS NOT NULL AND LENGTH(p_phone) > 20 THEN
    RETURN QUERY SELECT FALSE, 'Số điện thoại không được vượt quá 20 ký tự'::TEXT;
    RETURN;
  END IF;

  INSERT INTO edoc.organizations (
    unit_id, code, name, address, phone, fax, email, email_doc,
    secretary, chairman_number, level, is_exchange,
    lgsp_system_id, lgsp_secret_key, updated_by, updated_at
  ) VALUES (
    p_unit_id, p_code, p_name, p_address, p_phone, p_fax, p_email, p_email_doc,
    p_secretary, p_chairman_number, p_level, p_is_exchange,
    NULL, NULL, p_updated_by, NOW()
  )
  ON CONFLICT (unit_id) DO UPDATE SET
    code             = EXCLUDED.code,
    name             = EXCLUDED.name,
    address          = EXCLUDED.address,
    phone            = EXCLUDED.phone,
    fax              = EXCLUDED.fax,
    email            = EXCLUDED.email,
    email_doc        = EXCLUDED.email_doc,
    secretary        = EXCLUDED.secretary,
    chairman_number  = EXCLUDED.chairman_number,
    level            = EXCLUDED.level,
    is_exchange      = EXCLUDED.is_exchange,
    updated_by       = EXCLUDED.updated_by,
    updated_at       = NOW();

  RETURN QUERY SELECT TRUE, 'Cap nhat thong tin co quan thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_outgoing_doc_approve(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_outgoing_doc_approve(p_id bigint, p_staff_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_staff_name VARCHAR;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM edoc.outgoing_docs WHERE edoc.outgoing_docs.id = p_id) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản đi'::TEXT;
    RETURN;
  END IF;

  SELECT full_name INTO v_staff_name FROM public.staff WHERE public.staff.id = p_staff_id;

  UPDATE edoc.outgoing_docs SET
    approved = TRUE,
    approver = v_staff_name,
    updated_by = p_staff_id,
    updated_at = NOW()
  WHERE edoc.outgoing_docs.id = p_id;

  RETURN QUERY SELECT TRUE, 'Duyệt văn bản đi thành công'::TEXT;
END;
$$;


--
-- Name: fn_outgoing_doc_check_number(integer, integer, integer, bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_outgoing_doc_check_number(p_unit_id integer, p_doc_book_id integer, p_number integer, p_exclude_id bigint DEFAULT NULL::bigint) RETURNS TABLE(is_exists boolean)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT EXISTS (
    SELECT 1 FROM edoc.outgoing_docs
    WHERE unit_id = p_unit_id
      AND doc_book_id = p_doc_book_id
      AND number = p_number
      AND EXTRACT(YEAR FROM received_date) = EXTRACT(YEAR FROM NOW())
      AND (p_exclude_id IS NULL OR id != p_exclude_id)
  );
END;
$$;


--
-- Name: fn_outgoing_doc_count_unread(integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_outgoing_doc_count_unread(p_unit_id integer, p_staff_id integer) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE v_count INT;
BEGIN
  SELECT COUNT(*)::INT INTO v_count
  FROM edoc.outgoing_docs d
  LEFT JOIN edoc.user_outgoing_docs uo ON uo.outgoing_doc_id = d.id AND uo.staff_id = p_staff_id
  WHERE d.unit_id = p_unit_id
    AND (uo.is_read IS NULL OR uo.is_read = FALSE);
  RETURN v_count;
END;
$$;


--
-- Name: fn_outgoing_doc_create(integer, timestamp with time zone, integer, character varying, character varying, character varying, text, integer, integer, integer, timestamp with time zone, character varying, timestamp with time zone, integer, integer, integer, smallint, smallint, integer, integer, timestamp with time zone, text, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_outgoing_doc_create(p_unit_id integer, p_received_date timestamp with time zone, p_number integer, p_sub_number character varying, p_notation character varying, p_document_code character varying, p_abstract text, p_drafting_unit_id integer DEFAULT NULL::integer, p_drafting_user_id integer DEFAULT NULL::integer, p_publish_unit_id integer DEFAULT NULL::integer, p_publish_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_signer character varying DEFAULT NULL::character varying, p_sign_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_doc_book_id integer DEFAULT NULL::integer, p_doc_type_id integer DEFAULT NULL::integer, p_doc_field_id integer DEFAULT NULL::integer, p_secret_id smallint DEFAULT 1, p_urgent_id smallint DEFAULT 1, p_number_paper integer DEFAULT 1, p_number_copies integer DEFAULT 1, p_expired_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_recipients text DEFAULT NULL::text, p_created_by integer DEFAULT NULL::integer) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id BIGINT;
BEGIN
  IF p_abstract IS NULL OR TRIM(p_abstract) = '' THEN
    RETURN QUERY SELECT FALSE, 'Trích yếu nội dung không được để trống'::TEXT, 0::BIGINT;
    RETURN;
  END IF;

  IF p_doc_book_id IS NULL THEN
    RETURN QUERY SELECT FALSE, 'Sổ văn bản là bắt buộc'::TEXT, 0::BIGINT;
    RETURN;
  END IF;

  IF p_number IS NULL OR p_number = 0 THEN
    p_number := edoc.fn_outgoing_doc_get_next_number(p_doc_book_id, p_unit_id);
  END IF;

  INSERT INTO edoc.outgoing_docs (
    unit_id, received_date, number, sub_number, notation, document_code,
    abstract, drafting_unit_id, drafting_user_id, publish_unit_id, publish_date,
    signer, sign_date, expired_date,
    number_paper, number_copies, secret_id, urgent_id,
    recipients, doc_book_id, doc_type_id, doc_field_id,
    created_by, updated_by
  ) VALUES (
    p_unit_id, COALESCE(p_received_date, NOW()), p_number,
    NULLIF(TRIM(p_sub_number), ''), NULLIF(TRIM(p_notation), ''), NULLIF(TRIM(p_document_code), ''),
    TRIM(p_abstract), p_drafting_unit_id, p_drafting_user_id, p_publish_unit_id, p_publish_date,
    NULLIF(TRIM(p_signer), ''), p_sign_date, p_expired_date,
    COALESCE(p_number_paper, 1), COALESCE(p_number_copies, 1),
    COALESCE(p_secret_id, 1), COALESCE(p_urgent_id, 1),
    NULLIF(TRIM(p_recipients), ''), p_doc_book_id, p_doc_type_id, p_doc_field_id,
    p_created_by, p_created_by
  )
  RETURNING edoc.outgoing_docs.id INTO v_id;

  RETURN QUERY SELECT TRUE, 'Tạo văn bản đi thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_outgoing_doc_delete(bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_outgoing_doc_delete(p_id bigint) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_approved BOOLEAN;
BEGIN
  SELECT approved INTO v_approved FROM edoc.outgoing_docs WHERE edoc.outgoing_docs.id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản đi'::TEXT;
    RETURN;
  END IF;
  IF v_approved = TRUE THEN
    RETURN QUERY SELECT FALSE, 'Không thể xóa văn bản đã được duyệt'::TEXT;
    RETURN;
  END IF;

  DELETE FROM edoc.outgoing_docs WHERE edoc.outgoing_docs.id = p_id;
  RETURN QUERY SELECT TRUE, 'Xóa văn bản đi thành công'::TEXT;
END;
$$;


--
-- Name: fn_outgoing_doc_get_by_id(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_outgoing_doc_get_by_id(p_id bigint, p_staff_id integer) RETURNS TABLE(id bigint, unit_id integer, received_date timestamp with time zone, number integer, sub_number character varying, notation character varying, document_code character varying, abstract text, drafting_unit_id integer, drafting_user_id integer, publish_unit_id integer, publish_date timestamp with time zone, signer character varying, sign_date timestamp with time zone, expired_date timestamp with time zone, doc_book_id integer, doc_type_id integer, doc_field_id integer, secret_id smallint, urgent_id smallint, number_paper integer, number_copies integer, recipients text, approver character varying, approved boolean, is_handling boolean, archive_status boolean, is_inter_doc boolean, is_digital_signed smallint, created_by integer, created_at timestamp with time zone, updated_by integer, updated_at timestamp with time zone, doc_book_name character varying, doc_type_name character varying, doc_type_code character varying, doc_field_name character varying, drafting_unit_name character varying, drafting_user_name character varying, publish_unit_name character varying, created_by_name character varying, is_read boolean)
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- Đánh dấu đã đọc
  INSERT INTO edoc.user_outgoing_docs (outgoing_doc_id, staff_id, is_read, read_at)
  VALUES (p_id, p_staff_id, TRUE, NOW())
  ON CONFLICT (outgoing_doc_id, staff_id)
  DO UPDATE SET is_read = TRUE, read_at = COALESCE(edoc.user_outgoing_docs.read_at, NOW());

  RETURN QUERY
  SELECT
    d.id, d.unit_id, d.received_date, d.number, d.sub_number,
    d.notation, d.document_code, d.abstract,
    d.drafting_unit_id, d.drafting_user_id, d.publish_unit_id, d.publish_date,
    d.signer, d.sign_date, d.expired_date,
    d.doc_book_id, d.doc_type_id, d.doc_field_id,
    d.secret_id, d.urgent_id, d.number_paper, d.number_copies,
    d.recipients, d.approver, d.approved,
    d.is_handling, d.archive_status, d.is_inter_doc, d.is_digital_signed,
    d.created_by, d.created_at, d.updated_by, d.updated_at,
    db.name, dt.name, dt.code, df.name,
    du.name, ds.full_name,
    pu.name,                                       -- MỚI: publish_unit_name
    s.full_name,
    TRUE
  FROM edoc.outgoing_docs d
  LEFT JOIN edoc.doc_books db ON db.id = d.doc_book_id
  LEFT JOIN edoc.doc_types dt ON dt.id = d.doc_type_id
  LEFT JOIN edoc.doc_fields df ON df.id = d.doc_field_id
  LEFT JOIN public.departments du ON du.id = d.drafting_unit_id
  LEFT JOIN public.staff ds ON ds.id = d.drafting_user_id
  LEFT JOIN public.departments pu ON pu.id = d.publish_unit_id    -- MỚI
  LEFT JOIN public.staff s ON s.id = d.created_by
  WHERE d.id = p_id;
END;
$$;


--
-- Name: fn_outgoing_doc_get_history(bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_outgoing_doc_get_history(p_doc_id bigint) RETURNS TABLE(event_type character varying, event_time timestamp with time zone, staff_name character varying, content text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT * FROM (
    -- Tạo
    SELECT 'created'::VARCHAR AS evt, d.created_at AS etime, s.full_name AS sname,
           ('Tạo văn bản đi, số: ' || d.number)::TEXT AS econtent
    FROM edoc.outgoing_docs d
    JOIN public.staff s ON s.id = d.created_by
    WHERE d.id = p_doc_id

    UNION ALL
    -- Duyệt
    SELECT 'approved'::VARCHAR, d.updated_at, d.approver::VARCHAR, 'Duyệt văn bản đi'::TEXT
    FROM edoc.outgoing_docs d
    WHERE d.id = p_doc_id AND d.approved = TRUE

    UNION ALL
    -- Gửi
    SELECT 'sent'::VARCHAR, uo.created_at, s.full_name, 'Nhận văn bản'::TEXT
    FROM edoc.user_outgoing_docs uo
    JOIN public.staff s ON s.id = uo.staff_id
    WHERE uo.outgoing_doc_id = p_doc_id
  ) sub
  ORDER BY sub.etime DESC;
END;
$$;


--
-- Name: fn_outgoing_doc_get_list(integer, integer, integer, integer, integer, smallint, boolean, timestamp with time zone, timestamp with time zone, text, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_outgoing_doc_get_list(p_unit_id integer, p_staff_id integer, p_doc_book_id integer DEFAULT NULL::integer, p_doc_type_id integer DEFAULT NULL::integer, p_doc_field_id integer DEFAULT NULL::integer, p_urgent_id smallint DEFAULT NULL::smallint, p_approved boolean DEFAULT NULL::boolean, p_from_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_to_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_keyword text DEFAULT NULL::text, p_page integer DEFAULT 1, p_page_size integer DEFAULT 20) RETURNS TABLE(id bigint, unit_id integer, received_date timestamp with time zone, number integer, sub_number character varying, notation character varying, document_code character varying, abstract text, drafting_unit_id integer, drafting_user_id integer, publish_unit_id integer, publish_date timestamp with time zone, signer character varying, sign_date timestamp with time zone, expired_date timestamp with time zone, doc_book_id integer, doc_type_id integer, doc_field_id integer, secret_id smallint, urgent_id smallint, number_paper integer, number_copies integer, recipients text, approver character varying, approved boolean, is_handling boolean, archive_status boolean, created_by integer, created_at timestamp with time zone, doc_book_name character varying, doc_type_name character varying, doc_type_code character varying, doc_field_name character varying, drafting_unit_name character varying, drafting_user_name character varying, created_by_name character varying, is_read boolean, read_at timestamp with time zone, attachment_count bigint, total_count bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_offset INT;
  v_keyword TEXT;
BEGIN
  v_offset := (GREATEST(p_page, 1) - 1) * p_page_size;
  v_keyword := NULLIF(TRIM(p_keyword), '');

  RETURN QUERY
  WITH filtered AS (
    SELECT
      d.id AS doc_id,
      d.*,
      db.name AS _doc_book_name,
      dt.name AS _doc_type_name,
      dt.code AS _doc_type_code,
      df.name AS _doc_field_name,
      du.name AS _drafting_unit_name,
      ds.full_name AS _drafting_user_name,
      s.full_name AS _created_by_name,
      uo.is_read AS _is_read,
      uo.read_at AS _read_at,
      (SELECT COUNT(*) FROM edoc.attachment_outgoing_docs a WHERE a.outgoing_doc_id = d.id) AS _attachment_count,
      COUNT(*) OVER() AS _total_count
    FROM edoc.outgoing_docs d
    LEFT JOIN edoc.doc_books db ON db.id = d.doc_book_id
    LEFT JOIN edoc.doc_types dt ON dt.id = d.doc_type_id
    LEFT JOIN edoc.doc_fields df ON df.id = d.doc_field_id
    LEFT JOIN public.departments du ON du.id = d.drafting_unit_id
    LEFT JOIN public.staff ds ON ds.id = d.drafting_user_id
    LEFT JOIN public.staff s ON s.id = d.created_by
    LEFT JOIN edoc.user_outgoing_docs uo ON uo.outgoing_doc_id = d.id AND uo.staff_id = p_staff_id
    WHERE d.unit_id = p_unit_id
      AND (p_doc_book_id IS NULL OR d.doc_book_id = p_doc_book_id)
      AND (p_doc_type_id IS NULL OR d.doc_type_id = p_doc_type_id)
      AND (p_doc_field_id IS NULL OR d.doc_field_id = p_doc_field_id)
      AND (p_urgent_id IS NULL OR d.urgent_id = p_urgent_id)
      AND (p_approved IS NULL OR d.approved = p_approved)
      AND (p_from_date IS NULL OR d.received_date >= p_from_date)
      AND (p_to_date IS NULL OR d.received_date <= p_to_date)
      AND (v_keyword IS NULL OR
           d.abstract ILIKE '%' || v_keyword || '%' OR
           d.notation ILIKE '%' || v_keyword || '%' OR
           d.signer ILIKE '%' || v_keyword || '%' OR
           d.recipients ILIKE '%' || v_keyword || '%'
      )
    ORDER BY d.received_date DESC, d.number DESC
    LIMIT p_page_size OFFSET v_offset
  )
  SELECT
    f.doc_id, f.unit_id, f.received_date, f.number, f.sub_number,
    f.notation, f.document_code, f.abstract,
    f.drafting_unit_id, f.drafting_user_id, f.publish_unit_id, f.publish_date,
    f.signer, f.sign_date, f.expired_date,
    f.doc_book_id, f.doc_type_id, f.doc_field_id,
    f.secret_id, f.urgent_id, f.number_paper, f.number_copies,
    f.recipients, f.approver, f.approved,
    f.is_handling, f.archive_status, f.created_by, f.created_at,
    f._doc_book_name, f._doc_type_name, f._doc_type_code, f._doc_field_name,
    f._drafting_unit_name, f._drafting_user_name, f._created_by_name,
    COALESCE(f._is_read, FALSE), f._read_at,
    f._attachment_count, f._total_count
  FROM filtered f;
END;
$$;


--
-- Name: fn_outgoing_doc_get_next_number(integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_outgoing_doc_get_next_number(p_doc_book_id integer, p_unit_id integer) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE v_max INT;
BEGIN
  SELECT COALESCE(MAX(number), 0) INTO v_max
  FROM edoc.outgoing_docs
  WHERE doc_book_id = p_doc_book_id
    AND unit_id = p_unit_id
    AND EXTRACT(YEAR FROM received_date) = EXTRACT(YEAR FROM NOW());
  RETURN v_max + 1;
END;
$$;


--
-- Name: fn_outgoing_doc_get_recipients(bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_outgoing_doc_get_recipients(p_doc_id bigint) RETURNS TABLE(id bigint, staff_id integer, staff_name character varying, position_name character varying, department_name character varying, is_read boolean, read_at timestamp with time zone, created_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    uo.id, uo.staff_id,
    s.full_name,
    p.name AS position_name,
    dep.name AS department_name,
    uo.is_read, uo.read_at, uo.created_at
  FROM edoc.user_outgoing_docs uo
  JOIN public.staff s ON s.id = uo.staff_id
  LEFT JOIN public.positions p ON p.id = s.position_id
  LEFT JOIN public.departments dep ON dep.id = s.department_id
  WHERE uo.outgoing_doc_id = p_doc_id
  ORDER BY uo.created_at DESC;
END;
$$;


--
-- Name: fn_outgoing_doc_get_unused_numbers(integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_outgoing_doc_get_unused_numbers(p_unit_id integer, p_doc_book_id integer) RETURNS TABLE(unused_number integer)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_max INT;
BEGIN
  -- Lấy số lớn nhất đã cấp trong năm
  SELECT COALESCE(MAX(number), 0) INTO v_max
  FROM edoc.outgoing_docs
  WHERE unit_id = p_unit_id
    AND doc_book_id = p_doc_book_id
    AND EXTRACT(YEAR FROM received_date) = EXTRACT(YEAR FROM NOW());

  -- Trả về các số bị bỏ qua (gaps)
  RETURN QUERY
  SELECT g.n::INT AS unused_number
  FROM generate_series(1, v_max) AS g(n)
  WHERE NOT EXISTS (
    SELECT 1 FROM edoc.outgoing_docs o
    WHERE o.unit_id = p_unit_id
      AND o.doc_book_id = p_doc_book_id
      AND o.number = g.n
      AND EXTRACT(YEAR FROM o.received_date) = EXTRACT(YEAR FROM NOW())
  )
  ORDER BY g.n;
END;
$$;


--
-- Name: fn_outgoing_doc_mark_read_bulk(bigint[], integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_outgoing_doc_mark_read_bulk(p_doc_ids bigint[], p_staff_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  INSERT INTO edoc.user_outgoing_docs (outgoing_doc_id, staff_id, is_read, read_at)
  SELECT unnest(p_doc_ids), p_staff_id, TRUE, NOW()
  ON CONFLICT (outgoing_doc_id, staff_id)
  DO UPDATE SET is_read = TRUE, read_at = COALESCE(edoc.user_outgoing_docs.read_at, NOW());

  RETURN QUERY SELECT TRUE, 'Đã đánh dấu đọc thành công'::TEXT;
END;
$$;


--
-- Name: fn_outgoing_doc_reject(bigint, integer, text); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_outgoing_doc_reject(p_id bigint, p_staff_id integer, p_reason text DEFAULT NULL::text) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM edoc.outgoing_docs WHERE id = p_id) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản đi'::TEXT; RETURN;
  END IF;
  UPDATE edoc.outgoing_docs SET approved = FALSE, updated_by = p_staff_id, updated_at = NOW() WHERE id = p_id;
  RETURN QUERY SELECT TRUE, 'Đã từ chối văn bản đi'::TEXT;
END; $$;


--
-- Name: fn_outgoing_doc_retract(bigint, integer, integer[]); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_outgoing_doc_retract(p_id bigint, p_staff_id integer, p_staff_ids integer[] DEFAULT NULL::integer[]) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE v_deleted_count INT;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM edoc.outgoing_docs WHERE id = p_id) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản đi'::TEXT; RETURN;
  END IF;

  IF p_staff_ids IS NULL THEN
    -- Thu hồi tất cả (trừ người thu hồi)
    DELETE FROM edoc.user_outgoing_docs WHERE outgoing_doc_id = p_id AND staff_id != p_staff_id;
    GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
    -- Reset approved khi thu hồi toàn bộ
    UPDATE edoc.outgoing_docs SET approved = FALSE, updated_by = p_staff_id, updated_at = NOW() WHERE id = p_id;
  ELSE
    -- Thu hồi từng người cụ thể
    DELETE FROM edoc.user_outgoing_docs WHERE outgoing_doc_id = p_id AND staff_id = ANY(p_staff_ids);
    GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
    UPDATE edoc.outgoing_docs SET updated_by = p_staff_id, updated_at = NOW() WHERE id = p_id;
  END IF;

  RETURN QUERY SELECT TRUE, ('Thu hồi thành công — đã xóa ' || v_deleted_count || ' người nhận')::TEXT;
END;
$$;


--
-- Name: fn_outgoing_doc_send(bigint, integer[], integer, timestamp with time zone); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_outgoing_doc_send(p_doc_id bigint, p_staff_ids integer[], p_sent_by integer, p_expired_date timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_approved BOOLEAN;
  v_count INT;
BEGIN
  SELECT approved INTO v_approved FROM edoc.outgoing_docs WHERE edoc.outgoing_docs.id = p_doc_id;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản đi'::TEXT;
    RETURN;
  END IF;
  IF v_approved IS NULL OR v_approved = FALSE THEN
    RETURN QUERY SELECT FALSE, 'Văn bản chưa được duyệt, không thể gửi'::TEXT;
    RETURN;
  END IF;

  IF p_staff_ids IS NULL OR array_length(p_staff_ids, 1) IS NULL THEN
    RETURN QUERY SELECT FALSE, 'Vui lòng chọn ít nhất một người nhận'::TEXT;
    RETURN;
  END IF;

  INSERT INTO edoc.user_outgoing_docs (outgoing_doc_id, staff_id, sent_by, expired_date, is_read, created_at)
  SELECT p_doc_id, unnest(p_staff_ids), p_sent_by, p_expired_date, FALSE, NOW()
  ON CONFLICT (outgoing_doc_id, staff_id) DO NOTHING;

  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN QUERY SELECT TRUE, ('Đã gửi cho ' || v_count || ' người nhận')::TEXT;
END;
$$;


--
-- Name: fn_outgoing_doc_unapprove(bigint, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_outgoing_doc_unapprove(p_id bigint, p_staff_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_has_sent BOOLEAN;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM edoc.outgoing_docs WHERE edoc.outgoing_docs.id = p_id) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản đi'::TEXT;
    RETURN;
  END IF;

  SELECT EXISTS(SELECT 1 FROM edoc.user_outgoing_docs WHERE outgoing_doc_id = p_id) INTO v_has_sent;
  IF v_has_sent THEN
    RETURN QUERY SELECT FALSE, 'Không thể hủy duyệt: văn bản đã được gửi cho cán bộ'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.outgoing_docs SET
    approved = FALSE,
    approver = NULL,
    updated_by = p_staff_id,
    updated_at = NOW()
  WHERE edoc.outgoing_docs.id = p_id;

  RETURN QUERY SELECT TRUE, 'Hủy duyệt thành công'::TEXT;
END;
$$;


--
-- Name: fn_outgoing_doc_update(bigint, timestamp with time zone, integer, character varying, character varying, character varying, text, integer, integer, integer, timestamp with time zone, character varying, timestamp with time zone, integer, integer, integer, smallint, smallint, integer, integer, timestamp with time zone, text, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_outgoing_doc_update(p_id bigint, p_received_date timestamp with time zone, p_number integer, p_sub_number character varying, p_notation character varying, p_document_code character varying, p_abstract text, p_drafting_unit_id integer DEFAULT NULL::integer, p_drafting_user_id integer DEFAULT NULL::integer, p_publish_unit_id integer DEFAULT NULL::integer, p_publish_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_signer character varying DEFAULT NULL::character varying, p_sign_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_doc_book_id integer DEFAULT NULL::integer, p_doc_type_id integer DEFAULT NULL::integer, p_doc_field_id integer DEFAULT NULL::integer, p_secret_id smallint DEFAULT 1, p_urgent_id smallint DEFAULT 1, p_number_paper integer DEFAULT 1, p_number_copies integer DEFAULT 1, p_expired_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_recipients text DEFAULT NULL::text, p_updated_by integer DEFAULT NULL::integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_approved BOOLEAN;
BEGIN
  SELECT approved INTO v_approved FROM edoc.outgoing_docs WHERE edoc.outgoing_docs.id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản đi'::TEXT;
    RETURN;
  END IF;
  IF v_approved = TRUE THEN
    RETURN QUERY SELECT FALSE, 'Không thể sửa văn bản đã được duyệt'::TEXT;
    RETURN;
  END IF;

  IF p_abstract IS NULL OR TRIM(p_abstract) = '' THEN
    RETURN QUERY SELECT FALSE, 'Trích yếu nội dung không được để trống'::TEXT;
    RETURN;
  END IF;
  IF p_doc_book_id IS NULL THEN
    RETURN QUERY SELECT FALSE, 'Sổ văn bản là bắt buộc'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.outgoing_docs SET
    received_date     = COALESCE(p_received_date, received_date),
    number            = COALESCE(p_number, number),
    sub_number        = NULLIF(TRIM(p_sub_number), ''),
    notation          = NULLIF(TRIM(p_notation), ''),
    document_code     = NULLIF(TRIM(p_document_code), ''),
    abstract          = TRIM(p_abstract),
    drafting_unit_id  = p_drafting_unit_id,
    drafting_user_id  = p_drafting_user_id,
    publish_unit_id   = p_publish_unit_id,
    publish_date      = p_publish_date,
    signer            = NULLIF(TRIM(p_signer), ''),
    sign_date         = p_sign_date,
    doc_book_id       = p_doc_book_id,
    doc_type_id       = p_doc_type_id,
    doc_field_id      = p_doc_field_id,
    secret_id         = COALESCE(p_secret_id, 1),
    urgent_id         = COALESCE(p_urgent_id, 1),
    number_paper      = COALESCE(p_number_paper, 1),
    number_copies     = COALESCE(p_number_copies, 1),
    expired_date      = p_expired_date,
    recipients        = NULLIF(TRIM(p_recipients), ''),
    updated_by        = p_updated_by,
    updated_at        = NOW()
  WHERE edoc.outgoing_docs.id = p_id;

  RETURN QUERY SELECT TRUE, 'Cập nhật văn bản đi thành công'::TEXT;
END;
$$;


--
-- Name: fn_report_handling_by_assigner(integer, timestamp with time zone, timestamp with time zone); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_report_handling_by_assigner(p_unit_id integer, p_from_date timestamp with time zone, p_to_date timestamp with time zone) RETURNS TABLE(staff_id integer, staff_name text, department_name text, total bigint, completed bigint, in_progress bigint, overdue bigint, completion_rate numeric)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    s.id                                                                   AS staff_id,
    CONCAT(s.last_name, ' ', s.first_name)::TEXT                          AS staff_name,
    d.name::TEXT                                                           AS department_name,
    COUNT(h.id)::BIGINT                                                    AS total,
    COUNT(h.id) FILTER (WHERE h.status = 4)::BIGINT                        AS completed,
    COUNT(h.id) FILTER (WHERE h.status IN (0,1,2,3))::BIGINT               AS in_progress,
    COUNT(h.id) FILTER (
      WHERE h.end_date < NOW() AND h.status NOT IN (4, -1)
    )::BIGINT                                                               AS overdue,
    CASE
      WHEN COUNT(h.id) > 0
      THEN ROUND(COUNT(h.id) FILTER (WHERE h.status = 4)::NUMERIC / COUNT(h.id)::NUMERIC * 100, 2)
      ELSE 0
    END                                                                     AS completion_rate
  FROM public.staff s
  LEFT JOIN public.departments d ON d.id = s.department_id
  LEFT JOIN edoc.handling_docs h ON h.created_by = s.id
    AND h.unit_id = p_unit_id
    AND (p_from_date IS NULL OR h.created_at >= p_from_date)
    AND (p_to_date IS NULL OR h.created_at <= p_to_date)
  WHERE s.unit_id = p_unit_id AND s.is_locked = FALSE
  GROUP BY s.id, s.last_name, s.first_name, d.name
  HAVING COUNT(h.id) > 0
  ORDER BY total DESC, s.last_name;
END;
$$;


--
-- Name: fn_report_handling_by_resolver(integer, timestamp with time zone, timestamp with time zone); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_report_handling_by_resolver(p_unit_id integer, p_from_date timestamp with time zone, p_to_date timestamp with time zone) RETURNS TABLE(staff_id integer, staff_name text, department_name text, total bigint, completed bigint, in_progress bigint, overdue bigint, completion_rate numeric)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    s.id                                                                   AS staff_id,
    CONCAT(s.last_name, ' ', s.first_name)::TEXT                          AS staff_name,
    d.name::TEXT                                                           AS department_name,
    COUNT(h.id)::BIGINT                                                    AS total,
    COUNT(h.id) FILTER (WHERE h.status = 4)::BIGINT                        AS completed,
    COUNT(h.id) FILTER (WHERE h.status IN (0,1,2,3))::BIGINT               AS in_progress,
    COUNT(h.id) FILTER (
      WHERE h.end_date < NOW() AND h.status NOT IN (4, -1)
    )::BIGINT                                                               AS overdue,
    CASE
      WHEN COUNT(h.id) > 0
      THEN ROUND(COUNT(h.id) FILTER (WHERE h.status = 4)::NUMERIC / COUNT(h.id)::NUMERIC * 100, 2)
      ELSE 0
    END                                                                     AS completion_rate
  FROM public.staff s
  LEFT JOIN public.departments d ON d.id = s.department_id
  LEFT JOIN edoc.handling_docs h ON h.curator = s.id
    AND h.unit_id = p_unit_id
    AND (p_from_date IS NULL OR h.created_at >= p_from_date)
    AND (p_to_date IS NULL OR h.created_at <= p_to_date)
  WHERE s.unit_id = p_unit_id AND s.is_locked = FALSE
  GROUP BY s.id, s.last_name, s.first_name, d.name
  HAVING COUNT(h.id) > 0
  ORDER BY total DESC, s.last_name;
END;
$$;


--
-- Name: fn_report_handling_by_unit(integer, timestamp with time zone, timestamp with time zone); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_report_handling_by_unit(p_unit_id integer, p_from_date timestamp with time zone, p_to_date timestamp with time zone) RETURNS TABLE(department_id integer, department_name text, total bigint, completed bigint, in_progress bigint, overdue bigint, completion_rate numeric)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    d.id                                                      AS department_id,
    d.name::TEXT                                              AS department_name,
    COUNT(h.id)::BIGINT                                       AS total,
    COUNT(h.id) FILTER (WHERE h.status = 4)::BIGINT           AS completed,
    COUNT(h.id) FILTER (WHERE h.status IN (0,1,2,3))::BIGINT  AS in_progress,
    COUNT(h.id) FILTER (
      WHERE h.end_date < NOW() AND h.status NOT IN (4, -1)
    )::BIGINT                                                  AS overdue,
    CASE
      WHEN COUNT(h.id) > 0
      THEN ROUND(COUNT(h.id) FILTER (WHERE h.status = 4)::NUMERIC / COUNT(h.id)::NUMERIC * 100, 2)
      ELSE 0
    END                                                        AS completion_rate
  FROM public.departments d
  LEFT JOIN edoc.handling_docs h ON h.department_id = d.id
    AND h.unit_id = p_unit_id
    AND (p_from_date IS NULL OR h.created_at >= p_from_date)
    AND (p_to_date IS NULL OR h.created_at <= p_to_date)
  WHERE d.parent_id = p_unit_id AND d.is_unit = FALSE AND d.is_deleted = FALSE
  GROUP BY d.id, d.name
  ORDER BY total DESC, d.name;
END;
$$;


--
-- Name: fn_room_create(integer, character varying, character varying, character varying, text, integer, boolean, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_room_create(p_unit_id integer, p_name character varying, p_code character varying, p_location character varying, p_note text, p_sort_order integer, p_show_in_calendar boolean, p_created_user_id integer) RETURNS TABLE(success boolean, message text, id integer)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_id INT;
BEGIN
  IF TRIM(COALESCE(p_name, '')) = '' THEN
    RETURN QUERY SELECT false, 'Tên phòng họp không được để trống'::TEXT, NULL::INT;
    RETURN;
  END IF;

  INSERT INTO edoc.rooms (unit_id, name, code, location, note, sort_order, show_in_calendar, created_user_id)
  VALUES (p_unit_id, p_name, NULLIF(TRIM(p_code),''), p_location, p_note,
          COALESCE(p_sort_order, 0), COALESCE(p_show_in_calendar, true), p_created_user_id)
  RETURNING edoc.rooms.id INTO v_id;

  RETURN QUERY SELECT true, 'Tạo phòng họp thành công'::TEXT, v_id;
EXCEPTION
  WHEN unique_violation THEN
    RETURN QUERY SELECT false, 'Mã phòng họp đã tồn tại'::TEXT, NULL::INT;
END;
$$;


--
-- Name: fn_room_delete(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_room_delete(p_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_count INT;
BEGIN
  SELECT COUNT(*) INTO v_count FROM edoc.room_schedules WHERE room_id = p_id;
  IF v_count > 0 THEN
    RETURN QUERY SELECT false, 'Phòng họp đang có lịch họp, không thể xóa'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.rooms SET is_deleted = true WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy phòng họp'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT true, 'Xóa phòng họp thành công'::TEXT;
END;
$$;


--
-- Name: fn_room_get_list(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_room_get_list(p_unit_id integer) RETURNS TABLE(id integer, unit_id integer, name character varying, code character varying, location character varying, note text, sort_order integer, show_in_calendar boolean, created_date timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    r.id, r.unit_id, r.name, r.code, r.location, r.note,
    r.sort_order, r.show_in_calendar, r.created_date
  FROM edoc.rooms r
  WHERE r.unit_id = p_unit_id AND r.is_deleted = false
  ORDER BY r.sort_order, r.name;
END;
$$;


--
-- Name: fn_room_schedule_approve(integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_room_schedule_approve(p_id integer, p_approved_staff_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_approved INT;
BEGIN
  SELECT approved INTO v_approved FROM edoc.room_schedules WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy cuộc họp'::TEXT;
    RETURN;
  END IF;

  IF v_approved <> 0 THEN
    RETURN QUERY SELECT false, 'Cuộc họp không ở trạng thái chờ duyệt'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.room_schedules SET
    approved          = 1,
    approved_date     = NOW(),
    approved_staff_id = p_approved_staff_id,
    modified_user_id  = p_approved_staff_id,
    modified_date     = NOW()
  WHERE id = p_id;

  RETURN QUERY SELECT true, 'Duyệt cuộc họp thành công'::TEXT;
END;
$$;


--
-- Name: fn_room_schedule_assign_staff(integer, integer[], integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_room_schedule_assign_staff(p_room_schedule_id integer, p_staff_ids integer[], p_user_type integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_staff_id INT;
BEGIN
  IF p_staff_ids IS NULL OR array_length(p_staff_ids, 1) IS NULL THEN
    RETURN QUERY SELECT false, 'Danh sách nhân sự trống'::TEXT;
    RETURN;
  END IF;

  FOREACH v_staff_id IN ARRAY p_staff_ids LOOP
    INSERT INTO edoc.room_schedule_staff (room_schedule_id, staff_id, user_type)
    VALUES (p_room_schedule_id, v_staff_id, COALESCE(p_user_type, 0))
    ON CONFLICT (room_schedule_id, staff_id) DO NOTHING;
  END LOOP;

  RETURN QUERY SELECT true, 'Phân công thành viên thành công'::TEXT;
END;
$$;


--
-- Name: fn_room_schedule_create(integer, integer, integer, character varying, text, character varying, date, date, character varying, character varying, integer, integer, character varying, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_room_schedule_create(p_unit_id integer, p_room_id integer, p_meeting_type_id integer, p_name character varying, p_content text, p_component character varying, p_start_date date, p_end_date date, p_start_time character varying, p_end_time character varying, p_master_id integer, p_secretary_id integer, p_online_link character varying, p_created_user_id integer) RETURNS TABLE(success boolean, message text, id integer)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_id INT;
BEGIN
  IF TRIM(COALESCE(p_name, '')) = '' THEN
    RETURN QUERY SELECT false, 'Tên cuộc họp không được để trống'::TEXT, NULL::INT;
    RETURN;
  END IF;

  IF p_start_date IS NULL THEN
    RETURN QUERY SELECT false, 'Ngày họp không được để trống'::TEXT, NULL::INT;
    RETURN;
  END IF;

  INSERT INTO edoc.room_schedules (
    unit_id, room_id, meeting_type_id, name, content, component,
    start_date, end_date, start_time, end_time, master_id, secretary_id,
    online_link, created_user_id
  ) VALUES (
    p_unit_id, p_room_id, p_meeting_type_id, p_name, p_content, p_component,
    p_start_date, p_end_date, p_start_time, p_end_time, p_master_id, p_secretary_id,
    p_online_link, p_created_user_id
  ) RETURNING edoc.room_schedules.id INTO v_id;

  RETURN QUERY SELECT true, 'Tạo cuộc họp thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_room_schedule_delete(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_room_schedule_delete(p_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_approved INT;
BEGIN
  SELECT approved INTO v_approved FROM edoc.room_schedules WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy cuộc họp'::TEXT;
    RETURN;
  END IF;

  IF v_approved <> 0 THEN
    RETURN QUERY SELECT false, 'Chỉ có thể xóa cuộc họp chưa được duyệt'::TEXT;
    RETURN;
  END IF;

  DELETE FROM edoc.room_schedules WHERE id = p_id;

  RETURN QUERY SELECT true, 'Xóa cuộc họp thành công'::TEXT;
END;
$$;


--
-- Name: fn_room_schedule_get_by_id(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_room_schedule_get_by_id(p_id integer) RETURNS TABLE(id integer, unit_id integer, room_id integer, room_name character varying, meeting_type_id integer, meeting_type_name character varying, name character varying, content text, component character varying, start_date date, end_date date, start_time character varying, end_time character varying, master_id integer, master_name text, secretary_id integer, approved integer, approved_date timestamp with time zone, approved_staff_id integer, rejection_reason text, meeting_status integer, online_link character varying, is_cancel integer, created_user_id integer, created_date timestamp with time zone, modified_user_id integer, modified_date timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    rs.id, rs.unit_id, rs.room_id, r.name AS room_name,
    rs.meeting_type_id, mt.name AS meeting_type_name,
    rs.name, rs.content, rs.component,
    rs.start_date, rs.end_date, rs.start_time, rs.end_time,
    rs.master_id, (ms.last_name || ' ' || ms.first_name)::TEXT AS master_name,
    rs.secretary_id, rs.approved, rs.approved_date, rs.approved_staff_id,
    rs.rejection_reason, rs.meeting_status, rs.online_link, rs.is_cancel,
    rs.created_user_id, rs.created_date, rs.modified_user_id, rs.modified_date
  FROM edoc.room_schedules rs
  LEFT JOIN edoc.rooms r ON r.id = rs.room_id
  LEFT JOIN edoc.meeting_types mt ON mt.id = rs.meeting_type_id
  LEFT JOIN public.staff ms ON ms.id = rs.master_id
  WHERE rs.id = p_id;
END;
$$;


--
-- Name: fn_room_schedule_get_list(integer, integer, integer, date, date, text, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_room_schedule_get_list(p_unit_id integer, p_room_id integer, p_status integer, p_from_date date, p_to_date date, p_keyword text, p_page integer DEFAULT 1, p_page_size integer DEFAULT 20) RETURNS TABLE(id integer, unit_id integer, room_id integer, room_name character varying, meeting_type_id integer, meeting_type_name character varying, name character varying, content text, start_date date, end_date date, start_time character varying, end_time character varying, master_id integer, master_name text, approved integer, meeting_status integer, online_link character varying, created_date timestamp with time zone, staff_count bigint, total_count bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_offset INT := (COALESCE(p_page, 1) - 1) * COALESCE(p_page_size, 20);
BEGIN
  RETURN QUERY
  WITH filtered AS (
    SELECT
      rs.id,
      rs.unit_id,
      rs.room_id,
      r.name AS room_name,
      rs.meeting_type_id,
      mt.name AS meeting_type_name,
      rs.name,
      rs.content,
      rs.start_date,
      rs.end_date,
      rs.start_time,
      rs.end_time,
      rs.master_id,
      (s.last_name || ' ' || s.first_name)::TEXT AS master_name,
      rs.approved,
      rs.meeting_status,
      rs.online_link,
      rs.created_date,
      (SELECT COUNT(*) FROM edoc.room_schedule_staff rss WHERE rss.room_schedule_id = rs.id) AS staff_count
    FROM edoc.room_schedules rs
    LEFT JOIN edoc.rooms r ON r.id = rs.room_id
    LEFT JOIN edoc.meeting_types mt ON mt.id = rs.meeting_type_id
    LEFT JOIN public.staff s ON s.id = rs.master_id
    WHERE rs.unit_id = p_unit_id
      AND (p_room_id IS NULL OR rs.room_id = p_room_id)
      AND (p_status IS NULL OR p_status = -99 OR rs.meeting_status = p_status)
      AND (p_from_date IS NULL OR rs.start_date >= p_from_date)
      AND (p_to_date IS NULL OR rs.start_date <= p_to_date)
      AND (p_keyword IS NULL OR TRIM(p_keyword) = '' OR rs.name ILIKE '%' || p_keyword || '%')
  )
  SELECT
    flt.*,
    COUNT(*) OVER() AS total_count
  FROM filtered flt
  ORDER BY flt.start_date DESC, flt.start_time
  LIMIT p_page_size OFFSET v_offset;
END;
$$;


--
-- Name: fn_room_schedule_get_staff(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_room_schedule_get_staff(p_room_schedule_id integer) RETURNS TABLE(id integer, room_schedule_id integer, staff_id integer, staff_name text, position_name character varying, user_type integer, is_secretary boolean, is_represent boolean, attendance boolean, attendance_date timestamp with time zone, attendance_note text, received_appointment integer, received_appointment_date timestamp with time zone, view_date timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    rss.id,
    rss.room_schedule_id,
    rss.staff_id,
    (s.last_name || ' ' || s.first_name)::TEXT AS staff_name,
    p.name AS position_name,
    rss.user_type,
    rss.is_secretary,
    rss.is_represent,
    rss.attendance,
    rss.attendance_date,
    rss.attendance_note,
    rss.received_appointment,
    rss.received_appointment_date,
    rss.view_date
  FROM edoc.room_schedule_staff rss
  LEFT JOIN public.staff s ON s.id = rss.staff_id
  LEFT JOIN public.positions p ON p.id = s.position_id
  WHERE rss.room_schedule_id = p_room_schedule_id
  ORDER BY rss.user_type, s.last_name;
END;
$$;


--
-- Name: fn_room_schedule_reject(integer, integer, text); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_room_schedule_reject(p_id integer, p_approved_staff_id integer, p_reason text) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_approved INT;
BEGIN
  SELECT approved INTO v_approved FROM edoc.room_schedules WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy cuộc họp'::TEXT;
    RETURN;
  END IF;

  IF v_approved <> 0 THEN
    RETURN QUERY SELECT false, 'Cuộc họp không ở trạng thái chờ duyệt'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.room_schedules SET
    approved          = -1,
    approved_date     = NOW(),
    approved_staff_id = p_approved_staff_id,
    rejection_reason  = p_reason,
    modified_user_id  = p_approved_staff_id,
    modified_date     = NOW()
  WHERE id = p_id;

  RETURN QUERY SELECT true, 'Từ chối cuộc họp thành công'::TEXT;
END;
$$;


--
-- Name: fn_room_schedule_remove_staff(integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_room_schedule_remove_staff(p_room_schedule_id integer, p_staff_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  DELETE FROM edoc.room_schedule_staff
  WHERE room_schedule_id = p_room_schedule_id AND staff_id = p_staff_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy thành viên trong cuộc họp'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT true, 'Xóa thành viên thành công'::TEXT;
END;
$$;


--
-- Name: fn_room_schedule_stats(integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_room_schedule_stats(p_unit_id integer, p_year integer) RETURNS TABLE(stat_type text, category_id integer, category_name character varying, month_num integer, count bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  -- Thống kê theo tháng
  RETURN QUERY
  SELECT
    'by_month'::TEXT AS stat_type,
    0 AS category_id,
    'Tất cả'::VARCHAR AS category_name,
    EXTRACT(MONTH FROM rs.start_date)::INT AS month_num,
    COUNT(*)::BIGINT AS count
  FROM edoc.room_schedules rs
  WHERE rs.unit_id = p_unit_id
    AND EXTRACT(YEAR FROM rs.start_date) = p_year
    AND rs.is_cancel = 0
  GROUP BY EXTRACT(MONTH FROM rs.start_date)
  ORDER BY month_num;

  -- Thống kê theo phòng
  RETURN QUERY
  SELECT
    'by_room'::TEXT AS stat_type,
    r.id AS category_id,
    r.name AS category_name,
    0 AS month_num,
    COUNT(*)::BIGINT AS count
  FROM edoc.room_schedules rs
  JOIN edoc.rooms r ON r.id = rs.room_id
  WHERE rs.unit_id = p_unit_id
    AND EXTRACT(YEAR FROM rs.start_date) = p_year
    AND rs.is_cancel = 0
  GROUP BY r.id, r.name
  ORDER BY count DESC;

  -- Thống kê theo loại cuộc họp
  RETURN QUERY
  SELECT
    'by_meeting_type'::TEXT AS stat_type,
    mt.id AS category_id,
    mt.name AS category_name,
    0 AS month_num,
    COUNT(*)::BIGINT AS count
  FROM edoc.room_schedules rs
  JOIN edoc.meeting_types mt ON mt.id = rs.meeting_type_id
  WHERE rs.unit_id = p_unit_id
    AND EXTRACT(YEAR FROM rs.start_date) = p_year
    AND rs.is_cancel = 0
  GROUP BY mt.id, mt.name
  ORDER BY count DESC;
END;
$$;


--
-- Name: fn_room_schedule_update(integer, integer, integer, character varying, text, character varying, date, date, character varying, character varying, integer, integer, character varying, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_room_schedule_update(p_id integer, p_room_id integer, p_meeting_type_id integer, p_name character varying, p_content text, p_component character varying, p_start_date date, p_end_date date, p_start_time character varying, p_end_time character varying, p_master_id integer, p_secretary_id integer, p_online_link character varying, p_modified_user_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  IF TRIM(COALESCE(p_name, '')) = '' THEN
    RETURN QUERY SELECT false, 'Tên cuộc họp không được để trống'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.room_schedules SET
    room_id          = p_room_id,
    meeting_type_id  = p_meeting_type_id,
    name             = p_name,
    content          = p_content,
    component        = p_component,
    start_date       = COALESCE(p_start_date, start_date),
    end_date         = p_end_date,
    start_time       = p_start_time,
    end_time         = p_end_time,
    master_id        = p_master_id,
    secretary_id     = p_secretary_id,
    online_link      = p_online_link,
    modified_user_id = p_modified_user_id,
    modified_date    = NOW()
  WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy cuộc họp'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT true, 'Cập nhật thành công'::TEXT;
END;
$$;


--
-- Name: fn_room_update(integer, character varying, character varying, character varying, text, integer, boolean, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_room_update(p_id integer, p_name character varying, p_code character varying, p_location character varying, p_note text, p_sort_order integer, p_show_in_calendar boolean, p_modified_user_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  IF TRIM(COALESCE(p_name, '')) = '' THEN
    RETURN QUERY SELECT false, 'Tên phòng họp không được để trống'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.rooms SET
    name             = p_name,
    code             = NULLIF(TRIM(p_code),''),
    location         = p_location,
    note             = p_note,
    sort_order       = COALESCE(p_sort_order, 0),
    show_in_calendar = COALESCE(p_show_in_calendar, true),
    modified_user_id = p_modified_user_id,
    modified_date    = NOW()
  WHERE id = p_id AND is_deleted = false;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy phòng họp'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT true, 'Cập nhật thành công'::TEXT;
EXCEPTION
  WHEN unique_violation THEN
    RETURN QUERY SELECT false, 'Mã phòng họp đã tồn tại'::TEXT;
END;
$$;


--
-- Name: fn_send_config_get_by_user(integer, character varying); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_send_config_get_by_user(p_user_id integer, p_config_type character varying DEFAULT 'doc'::character varying) RETURNS TABLE(id integer, target_user_id integer, target_name character varying, position_name character varying, department_name character varying)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT c.id, c.target_user_id, s.full_name, p.name, d.name
  FROM edoc.send_doc_user_configs c
  JOIN public.staff s ON s.id = c.target_user_id
  LEFT JOIN public.positions p ON p.id = s.position_id
  LEFT JOIN public.departments d ON d.id = s.department_id
  WHERE c.user_id = p_user_id AND c.config_type = p_config_type
  ORDER BY d.sort_order, s.full_name;
END;
$$;


--
-- Name: fn_send_config_save(integer, character varying, integer[]); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_send_config_save(p_user_id integer, p_config_type character varying, p_target_user_ids integer[]) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_count INT;
BEGIN
  -- Xóa cũ
  DELETE FROM edoc.send_doc_user_configs
  WHERE user_id = p_user_id AND config_type = p_config_type;

  -- Insert mới
  IF p_target_user_ids IS NOT NULL AND array_length(p_target_user_ids, 1) > 0 THEN
    INSERT INTO edoc.send_doc_user_configs (user_id, target_user_id, config_type)
    SELECT p_user_id, unnest(p_target_user_ids), p_config_type
    ON CONFLICT (user_id, target_user_id, config_type) DO NOTHING;
  END IF;

  SELECT COUNT(*) INTO v_count
  FROM edoc.send_doc_user_configs
  WHERE user_id = p_user_id AND config_type = p_config_type;

  RETURN QUERY SELECT TRUE, ('Đã lưu ' || v_count || ' người nhận')::TEXT;
END;
$$;


--
-- Name: fn_sign_need_count_by_staff(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_sign_need_count_by_staff(p_staff_id integer) RETURNS integer
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
  v_count INT;
BEGIN
  -- total_count từ row đầu tiên của list SP; nếu không có row thì 0.
  SELECT COALESCE((SELECT total_count FROM edoc.fn_sign_need_list_by_staff(p_staff_id, 1, 1) LIMIT 1), 0)::INT
    INTO v_count;
  RETURN COALESCE(v_count, 0);
END;
$$;


--
-- Name: fn_sign_need_list_by_staff(integer, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_sign_need_list_by_staff(p_staff_id integer, p_page integer, p_page_size integer) RETURNS TABLE(attachment_id bigint, attachment_type character varying, file_name character varying, doc_id bigint, doc_type character varying, doc_label text, doc_number integer, doc_notation character varying, created_at timestamp with time zone, total_count bigint)
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
  v_staff_name VARCHAR;
  v_is_admin   BOOLEAN := FALSE;
  v_offset     INT;
  v_limit      INT;
BEGIN
  -- Resolve staff name + admin flag once (reused across 3 union branches).
  -- Junction table is `public.role_of_staff` (khớp migration 045 fn_attachment_can_sign).
  SELECT s.full_name,
         (COALESCE(s.is_admin, FALSE) OR EXISTS (
            SELECT 1 FROM public.role_of_staff ros
              JOIN public.roles r ON r.id = ros.role_id
             WHERE ros.staff_id = s.id
               AND r.name = 'Quản trị hệ thống'
         ))
    INTO v_staff_name, v_is_admin
    FROM public.staff s
   WHERE s.id = p_staff_id;

  v_offset := GREATEST(0, (COALESCE(p_page, 1) - 1) * COALESCE(p_page_size, 20));
  v_limit  := GREATEST(1, LEAST(COALESCE(p_page_size, 20), 100));

  RETURN QUERY
  WITH combined AS (
    -- --------------------------------------------------------------------
    -- (1) Outgoing docs — signer/approver VARCHAR name match OR created_by OR admin
    -- --------------------------------------------------------------------
    SELECT aod.id                             AS attachment_id,
           'outgoing'::VARCHAR(20)            AS attachment_type,
           aod.file_name,
           od.id                              AS doc_id,
           'outgoing_doc'::VARCHAR(20)        AS doc_type,
           ('VB đi số ' || COALESCE(od.number::TEXT, '?')
                        || ' — '
                        || COALESCE(od.notation, '?'))::TEXT AS doc_label,
           od.number                          AS doc_number,
           od.notation                        AS doc_notation,
           aod.created_at
      FROM edoc.attachment_outgoing_docs aod
      JOIN edoc.outgoing_docs od ON od.id = aod.outgoing_doc_id
     WHERE COALESCE(aod.is_ca, FALSE) = FALSE
       AND LOWER(aod.file_name) LIKE '%.pdf'
       AND NOT EXISTS (
         SELECT 1 FROM edoc.sign_transactions st
          WHERE st.attachment_id   = aod.id
            AND st.attachment_type = 'outgoing'
            AND st.status          = 'pending'
       )
       AND (
         v_is_admin
         OR od.created_by = p_staff_id
         OR (od.signer   IS NOT NULL AND v_staff_name IS NOT NULL
             AND LOWER(UNACCENT(od.signer))   = LOWER(UNACCENT(v_staff_name)))
         OR (od.approver IS NOT NULL AND v_staff_name IS NOT NULL
             AND LOWER(UNACCENT(od.approver)) = LOWER(UNACCENT(v_staff_name)))
       )

    UNION ALL

    -- --------------------------------------------------------------------
    -- (2) Drafting docs — same permission model as outgoing
    -- --------------------------------------------------------------------
    SELECT add2.id,
           'drafting'::VARCHAR(20),
           add2.file_name,
           dd.id,
           'drafting_doc'::VARCHAR(20),
           ('VB dự thảo số ' || COALESCE(dd.number::TEXT, '?')
                             || ' — '
                             || COALESCE(dd.notation, '?'))::TEXT,
           dd.number,
           dd.notation,
           add2.created_at
      FROM edoc.attachment_drafting_docs add2
      JOIN edoc.drafting_docs dd ON dd.id = add2.drafting_doc_id
     WHERE COALESCE(add2.is_ca, FALSE) = FALSE
       AND LOWER(add2.file_name) LIKE '%.pdf'
       AND NOT EXISTS (
         SELECT 1 FROM edoc.sign_transactions st
          WHERE st.attachment_id   = add2.id
            AND st.attachment_type = 'drafting'
            AND st.status          = 'pending'
       )
       AND (
         v_is_admin
         OR dd.created_by = p_staff_id
         OR (dd.signer   IS NOT NULL AND v_staff_name IS NOT NULL
             AND LOWER(UNACCENT(dd.signer))   = LOWER(UNACCENT(v_staff_name)))
         OR (dd.approver IS NOT NULL AND v_staff_name IS NOT NULL
             AND LOWER(UNACCENT(dd.approver)) = LOWER(UNACCENT(v_staff_name)))
       )

    UNION ALL

    -- --------------------------------------------------------------------
    -- (3) Handling docs (HSCV) — signer là INT, match p_staff_id trực tiếp
    -- status IN (2,3) = đang xử lý / chờ duyệt (chưa đóng)
    -- --------------------------------------------------------------------
    SELECT ahd.id,
           'handling'::VARCHAR(20),
           ahd.file_name,
           hd.id,
           'handling_doc'::VARCHAR(20),
           ('HSCV: ' || COALESCE(hd.name, 'không tên'))::TEXT,
           NULL::INT,
           NULL::VARCHAR(100),
           ahd.created_at
      FROM edoc.attachment_handling_docs ahd
      JOIN edoc.handling_docs hd ON hd.id = ahd.handling_doc_id
     WHERE COALESCE(ahd.is_ca, FALSE) = FALSE
       AND LOWER(ahd.file_name) LIKE '%.pdf'
       AND NOT EXISTS (
         SELECT 1 FROM edoc.sign_transactions st
          WHERE st.attachment_id   = ahd.id
            AND st.attachment_type = 'handling'
            AND st.status          = 'pending'
       )
       AND (
         v_is_admin
         OR hd.created_by = p_staff_id
         OR hd.signer     = p_staff_id
       )
  )
  SELECT c.attachment_id,
         c.attachment_type,
         c.file_name,
         c.doc_id,
         c.doc_type,
         c.doc_label,
         c.doc_number,
         c.doc_notation,
         c.created_at,
         COUNT(*) OVER ()::BIGINT AS total_count
    FROM combined c
   ORDER BY c.created_at DESC
   LIMIT v_limit OFFSET v_offset;
END;
$$;


--
-- Name: fn_sign_transaction_complete(bigint, text, character varying); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_sign_transaction_complete(p_id bigint, p_signature_base64 text, p_signed_file_path character varying) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE edoc.sign_transactions
    SET "status" = 'completed',
        signature_base64 = p_signature_base64,
        signed_file_path = p_signed_file_path,
        completed_at = NOW()
    WHERE id = p_id AND "status" = 'pending';
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy giao dịch pending'::TEXT; RETURN;
  END IF;
  RETURN QUERY SELECT TRUE, 'Hoàn tất giao dịch ký số'::TEXT;
END;
$$;


--
-- Name: fn_sign_transaction_count_by_staff(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_sign_transaction_count_by_staff(p_staff_id integer) RETURNS TABLE(pending_count bigint, completed_count bigint, failed_count bigint)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    COUNT(*) FILTER (WHERE st."status" = 'pending')::BIGINT AS pending_count,
    COUNT(*) FILTER (WHERE st."status" = 'completed')::BIGINT AS completed_count,
    COUNT(*) FILTER (WHERE st."status" IN ('failed','expired','cancelled'))::BIGINT AS failed_count
  FROM edoc.sign_transactions st
  WHERE st.staff_id = p_staff_id;
END;
$$;


--
-- Name: fn_sign_transaction_create(integer, character varying, bigint, character varying, bigint, character varying, character varying); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_sign_transaction_create(p_staff_id integer, p_provider_code character varying, p_attachment_id bigint, p_attachment_type character varying, p_doc_id bigint, p_doc_type character varying, p_file_hash_sha256 character varying) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id BIGINT;
BEGIN
  IF p_attachment_type NOT IN ('incoming','outgoing','drafting','handling') THEN
    RETURN QUERY SELECT FALSE, 'Loại file đính kèm không hợp lệ'::TEXT, 0::BIGINT; RETURN;
  END IF;

  INSERT INTO edoc.sign_transactions (
    staff_id, provider_code, attachment_id, attachment_type, doc_id, doc_type,
    file_hash_sha256, "status", expires_at
  )
  VALUES (
    p_staff_id, p_provider_code, p_attachment_id, p_attachment_type, p_doc_id, p_doc_type,
    p_file_hash_sha256, 'pending', NOW() + INTERVAL '3 minutes'
  )
  RETURNING edoc.sign_transactions.id INTO v_id;

  RETURN QUERY SELECT TRUE, 'Tạo giao dịch ký số thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_sign_transaction_get_by_id(bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_sign_transaction_get_by_id(p_id bigint) RETURNS TABLE(id bigint, staff_id integer, provider_code character varying, provider_txn_id character varying, attachment_id bigint, attachment_type character varying, doc_id bigint, doc_type character varying, file_hash_sha256 character varying, signature_base64 text, signed_file_path character varying, status character varying, error_message text, retry_count integer, created_at timestamp with time zone, started_at timestamp with time zone, completed_at timestamp with time zone, expires_at timestamp with time zone)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
  RETURN QUERY
    SELECT t.id, t.staff_id, t.provider_code, t.provider_txn_id,
           t.attachment_id, t.attachment_type, t.doc_id, t.doc_type,
           t.file_hash_sha256, t.signature_base64, t.signed_file_path,
           t."status", t.error_message, t.retry_count,
           t.created_at, t.started_at, t.completed_at, t.expires_at
    FROM edoc.sign_transactions t
    WHERE t.id = p_id;
END;
$$;


--
-- Name: fn_sign_transaction_increment_retry(bigint); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_sign_transaction_increment_retry(p_id bigint) RETURNS TABLE(success boolean, new_retry_count integer)
    LANGUAGE plpgsql
    AS $$
DECLARE v_count INT;
BEGIN
  UPDATE edoc.sign_transactions AS t
    SET retry_count = t.retry_count + 1
    WHERE t.id = p_id AND t."status" = 'pending'
    RETURNING t.retry_count INTO v_count;
  IF v_count IS NULL THEN
    RETURN QUERY SELECT FALSE, 0; RETURN;
  END IF;
  RETURN QUERY SELECT TRUE, v_count;
END;
$$;


--
-- Name: fn_sign_transaction_list_by_staff(integer, character varying, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_sign_transaction_list_by_staff(p_staff_id integer, p_tab character varying, p_page integer, p_page_size integer) RETURNS TABLE(id bigint, provider_code character varying, provider_name character varying, attachment_id bigint, attachment_type character varying, file_name character varying, doc_id bigint, doc_type character varying, doc_label text, status character varying, error_message text, created_at timestamp with time zone, completed_at timestamp with time zone, total_count bigint)
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
  v_offset INT;
  v_page_size INT;
BEGIN
  v_page_size := GREATEST(COALESCE(p_page_size, 20), 1);
  v_offset := GREATEST(COALESCE(p_page, 1) - 1, 0) * v_page_size;

  RETURN QUERY
  SELECT
    st.id,
    st.provider_code,
    spc.provider_name,
    st.attachment_id,
    st.attachment_type,
    COALESCE(
      ao.file_name,
      ad.file_name,
      ah.file_name,
      ai.file_name
    ) AS file_name,
    st.doc_id,
    st.doc_type,
    CASE
      WHEN st.doc_type = 'outgoing_doc' AND od.id IS NOT NULL
        THEN ('VB đi số ' || COALESCE(od.number::TEXT, '?')
              || CASE WHEN od.notation IS NOT NULL THEN '/' || od.notation ELSE '' END)::TEXT
      WHEN st.doc_type = 'drafting_doc' AND dd.id IS NOT NULL
        THEN ('VB dự thảo: ' || COALESCE(LEFT(dd.abstract, 80), dd.document_code, '?'))::TEXT
      WHEN st.doc_type = 'handling_doc' AND hd.id IS NOT NULL
        THEN ('HSCV: ' || COALESCE(LEFT(hd.name, 80), '?'))::TEXT
      WHEN st.doc_type = 'incoming_doc' AND ind.id IS NOT NULL
        THEN ('VB đến số ' || COALESCE(ind.document_code, '?'))::TEXT
      ELSE NULL
    END AS doc_label,
    st."status",
    st.error_message,
    st.created_at,
    st.completed_at,
    COUNT(*) OVER()::BIGINT AS total_count
  FROM edoc.sign_transactions st
  LEFT JOIN public.signing_provider_config spc
    ON spc.provider_code = st.provider_code
  LEFT JOIN edoc.attachment_outgoing_docs ao
    ON st.attachment_type = 'outgoing' AND ao.id = st.attachment_id
  LEFT JOIN edoc.attachment_drafting_docs ad
    ON st.attachment_type = 'drafting' AND ad.id = st.attachment_id
  LEFT JOIN edoc.attachment_handling_docs ah
    ON st.attachment_type = 'handling' AND ah.id = st.attachment_id
  LEFT JOIN edoc.attachment_incoming_docs ai
    ON st.attachment_type = 'incoming' AND ai.id = st.attachment_id
  LEFT JOIN edoc.outgoing_docs od
    ON st.doc_type = 'outgoing_doc' AND od.id = st.doc_id
  LEFT JOIN edoc.drafting_docs dd
    ON st.doc_type = 'drafting_doc' AND dd.id = st.doc_id
  LEFT JOIN edoc.handling_docs hd
    ON st.doc_type = 'handling_doc' AND hd.id = st.doc_id
  LEFT JOIN edoc.incoming_docs ind
    ON st.doc_type = 'incoming_doc' AND ind.id = st.doc_id
  WHERE st.staff_id = p_staff_id
    AND (
      (p_tab = 'pending'   AND st."status" = 'pending')
      OR (p_tab = 'completed' AND st."status" = 'completed')
      OR (p_tab = 'failed'    AND st."status" IN ('failed','expired','cancelled'))
    )
  ORDER BY st.created_at DESC
  LIMIT v_page_size
  OFFSET v_offset;
END;
$$;


--
-- Name: fn_sign_transaction_set_provider_txn(bigint, character varying); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_sign_transaction_set_provider_txn(p_id bigint, p_provider_txn_id character varying) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE edoc.sign_transactions
    SET provider_txn_id = p_provider_txn_id, started_at = NOW()
    WHERE id = p_id AND "status" = 'pending';
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy giao dịch pending'::TEXT; RETURN;
  END IF;
  RETURN QUERY SELECT TRUE, 'Cập nhật provider_txn_id thành công'::TEXT;
END;
$$;


--
-- Name: fn_sign_transaction_update_status(bigint, character varying, text); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_sign_transaction_update_status(p_id bigint, p_status character varying, p_error_message text) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF p_status NOT IN ('failed','expired','cancelled') THEN
    RETURN QUERY SELECT FALSE, 'Trạng thái không hợp lệ'::TEXT; RETURN;
  END IF;
  UPDATE edoc.sign_transactions
    SET "status" = p_status,
        error_message = p_error_message,
        completed_at = NOW()
    WHERE id = p_id AND "status" = 'pending';
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy giao dịch pending'::TEXT; RETURN;
  END IF;
  RETURN QUERY SELECT TRUE, 'Cập nhật trạng thái thành công'::TEXT;
END;
$$;


--
-- Name: fn_signer_create(integer, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_signer_create(p_unit_id integer, p_department_id integer DEFAULT NULL::integer, p_staff_id integer DEFAULT NULL::integer) RETURNS TABLE(success boolean, message text, id integer)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id INT;
BEGIN
  IF p_staff_id IS NULL THEN
    RETURN QUERY SELECT FALSE, 'Vui lòng chọn nhân viên'::TEXT, 0;
    RETURN;
  END IF;

  -- Check staff exists
  IF NOT EXISTS(SELECT 1 FROM public.staff s WHERE s.id = p_staff_id AND s.is_deleted = FALSE) THEN
    RETURN QUERY SELECT FALSE, 'Nhân viên không tồn tại'::TEXT, 0;
    RETURN;
  END IF;

  -- Check unique
  IF EXISTS(SELECT 1 FROM edoc.signers WHERE unit_id = p_unit_id AND staff_id = p_staff_id) THEN
    RETURN QUERY SELECT FALSE, 'Nhân viên đã có trong danh sách người ký'::TEXT, 0;
    RETURN;
  END IF;

  INSERT INTO edoc.signers (unit_id, department_id, staff_id)
  VALUES (p_unit_id, p_department_id, p_staff_id)
  RETURNING signers.id INTO v_id;

  RETURN QUERY SELECT TRUE, 'Them nguoi ky thanh cong'::TEXT, v_id;
END;
$$;


--
-- Name: fn_signer_delete(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_signer_delete(p_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NOT EXISTS(SELECT 1 FROM edoc.signers WHERE id = p_id) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy người ký'::TEXT;
    RETURN;
  END IF;

  DELETE FROM edoc.signers WHERE id = p_id;
  RETURN QUERY SELECT TRUE, 'Xoa nguoi ky thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_signer_get_list(integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_signer_get_list(p_unit_id integer, p_department_id integer DEFAULT NULL::integer) RETURNS TABLE(id integer, unit_id integer, department_id integer, staff_id integer, staff_name character varying, position_name character varying, department_name character varying, sort_order integer)
    LANGUAGE sql STABLE
    AS $$
  SELECT sg.id, sg.unit_id, sg.department_id, sg.staff_id,
         s.full_name::VARCHAR AS staff_name,
         p.name::VARCHAR AS position_name,
         d.name::VARCHAR AS department_name,
         sg.sort_order
  FROM edoc.signers sg
    JOIN public.staff s ON s.id = sg.staff_id
    LEFT JOIN public.positions p ON p.id = s.position_id
    LEFT JOIN public.departments d ON d.id = sg.department_id
  WHERE sg.unit_id = p_unit_id
    AND (p_department_id IS NULL OR sg.department_id = p_department_id)
  ORDER BY sg.sort_order, s.full_name;
$$;


--
-- Name: fn_sms_template_create(integer, character varying, text, text, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_sms_template_create(p_unit_id integer, p_name character varying, p_content text, p_description text DEFAULT NULL::text, p_created_by integer DEFAULT NULL::integer) RETURNS TABLE(success boolean, message text, id integer)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id INT;
BEGIN
  IF p_name IS NULL OR TRIM(p_name) = '' THEN
    RETURN QUERY SELECT FALSE, 'Tên mẫu tin nhắn không được để trống'::TEXT, 0;
    RETURN;
  END IF;
  IF p_content IS NULL OR TRIM(p_content) = '' THEN
    RETURN QUERY SELECT FALSE, 'Nội dung mẫu tin nhắn không được để trống'::TEXT, 0;
    RETURN;
  END IF;
  IF LENGTH(p_name) > 200 THEN
    RETURN QUERY SELECT FALSE, 'Tên mẫu tin nhắn không được vượt quá 200 ký tự'::TEXT, 0;
    RETURN;
  END IF;

  INSERT INTO edoc.sms_templates (unit_id, name, content, description, created_by)
  VALUES (p_unit_id, TRIM(p_name), TRIM(p_content), p_description, p_created_by)
  RETURNING sms_templates.id INTO v_id;

  RETURN QUERY SELECT TRUE, 'Tao mau tin nhan thanh cong'::TEXT, v_id;
END;
$$;


--
-- Name: fn_sms_template_delete(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_sms_template_delete(p_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NOT EXISTS(SELECT 1 FROM edoc.sms_templates WHERE id = p_id) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy mẫu tin nhắn'::TEXT;
    RETURN;
  END IF;

  DELETE FROM edoc.sms_templates WHERE id = p_id;
  RETURN QUERY SELECT TRUE, 'Xoa mau tin nhan thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_sms_template_get_list(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_sms_template_get_list(p_unit_id integer) RETURNS TABLE(id integer, unit_id integer, name character varying, content text, description text, is_active boolean, created_by integer, created_at timestamp with time zone)
    LANGUAGE sql STABLE
    AS $$
  SELECT t.id, t.unit_id, t.name::VARCHAR, t.content,
         t.description, t.is_active, t.created_by, t.created_at
  FROM edoc.sms_templates t
  WHERE t.unit_id = p_unit_id
  ORDER BY t.name;
$$;


--
-- Name: fn_sms_template_update(integer, character varying, text, text, boolean); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_sms_template_update(p_id integer, p_name character varying DEFAULT NULL::character varying, p_content text DEFAULT NULL::text, p_description text DEFAULT NULL::text, p_is_active boolean DEFAULT NULL::boolean) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NOT EXISTS(SELECT 1 FROM edoc.sms_templates WHERE id = p_id) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy mẫu tin nhắn'::TEXT;
    RETURN;
  END IF;
  IF p_name IS NULL OR TRIM(p_name) = '' THEN
    RETURN QUERY SELECT FALSE, 'Tên mẫu tin nhắn không được để trống'::TEXT;
    RETURN;
  END IF;
  IF p_content IS NULL OR TRIM(p_content) = '' THEN
    RETURN QUERY SELECT FALSE, 'Nội dung mẫu tin nhắn không được để trống'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.sms_templates SET
    name        = TRIM(p_name),
    content     = TRIM(p_content),
    description = COALESCE(p_description, description),
    is_active   = COALESCE(p_is_active, is_active)
  WHERE id = p_id;

  RETURN QUERY SELECT TRUE, 'Cap nhat mau tin nhan thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_staff_note_get_list(integer, character varying); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_staff_note_get_list(p_staff_id integer, p_doc_type character varying DEFAULT 'incoming'::character varying) RETURNS TABLE(note_id bigint, doc_id bigint, note text, is_important boolean, created_at timestamp with time zone, doc_number integer, doc_notation character varying, doc_abstract text, doc_received_date timestamp with time zone, doc_publish_unit character varying)
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF p_doc_type = 'incoming' THEN
    RETURN QUERY
    SELECT sn.id, sn.doc_id, sn.note, sn.is_important, sn.created_at,
           d.number, d.notation, d.abstract, d.received_date, d.publish_unit
    FROM edoc.staff_notes sn
    JOIN edoc.incoming_docs d ON d.id = sn.doc_id
    WHERE sn.staff_id = p_staff_id AND sn.doc_type = 'incoming'
    ORDER BY sn.is_important DESC, sn.created_at DESC;

  ELSIF p_doc_type = 'outgoing' THEN
    RETURN QUERY
    SELECT sn.id, sn.doc_id, sn.note, sn.is_important, sn.created_at,
           d.number, d.notation, d.abstract, d.received_date,
           COALESCE(du.name, '')::VARCHAR
    FROM edoc.staff_notes sn
    JOIN edoc.outgoing_docs d ON d.id = sn.doc_id
    LEFT JOIN public.departments du ON du.id = d.drafting_unit_id
    WHERE sn.staff_id = p_staff_id AND sn.doc_type = 'outgoing'
    ORDER BY sn.is_important DESC, sn.created_at DESC;

  ELSIF p_doc_type = 'drafting' THEN
    RETURN QUERY
    SELECT sn.id, sn.doc_id, sn.note, sn.is_important, sn.created_at,
           d.number, d.notation, d.abstract, d.received_date,
           COALESCE(du.name, '')::VARCHAR
    FROM edoc.staff_notes sn
    JOIN edoc.drafting_docs d ON d.id = sn.doc_id
    LEFT JOIN public.departments du ON du.id = d.drafting_unit_id
    WHERE sn.staff_id = p_staff_id AND sn.doc_type = 'drafting'
    ORDER BY sn.is_important DESC, sn.created_at DESC;
  END IF;
END;
$$;


--
-- Name: fn_staff_note_toggle(character varying, bigint, integer, text, boolean); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_staff_note_toggle(p_doc_type character varying, p_doc_id bigint, p_staff_id integer, p_note text DEFAULT NULL::text, p_is_important boolean DEFAULT false) RETURNS TABLE(success boolean, message text, is_bookmarked boolean)
    LANGUAGE plpgsql
    AS $$
DECLARE v_exists BOOLEAN;
BEGIN
  SELECT TRUE INTO v_exists
  FROM edoc.staff_notes
  WHERE doc_type = p_doc_type AND doc_id = p_doc_id AND staff_id = p_staff_id;

  IF v_exists THEN
    DELETE FROM edoc.staff_notes
    WHERE doc_type = p_doc_type AND doc_id = p_doc_id AND staff_id = p_staff_id;
    RETURN QUERY SELECT TRUE, 'Đã bỏ đánh dấu'::TEXT, FALSE;
  ELSE
    INSERT INTO edoc.staff_notes (doc_type, doc_id, staff_id, note, is_important)
    VALUES (p_doc_type, p_doc_id, p_staff_id, NULLIF(TRIM(p_note), ''), COALESCE(p_is_important, FALSE));
    RETURN QUERY SELECT TRUE, 'Đã đánh dấu'::TEXT, TRUE;
  END IF;
END;
$$;


--
-- Name: fn_staff_note_update_important(character varying, bigint, integer, boolean); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_staff_note_update_important(p_doc_type character varying, p_doc_id bigint, p_staff_id integer, p_is_important boolean) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE edoc.staff_notes SET
    is_important = p_is_important
  WHERE doc_type = p_doc_type AND doc_id = p_doc_id AND staff_id = p_staff_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy đánh dấu'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT TRUE,
    CASE WHEN p_is_important THEN 'Đã đánh dấu quan trọng'::TEXT
    ELSE 'Đã bỏ đánh dấu quan trọng'::TEXT END;
END;
$$;


--
-- Name: fn_vote_answer_create(uuid, integer, character varying, integer, boolean); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_vote_answer_create(p_question_id uuid, p_room_schedule_id integer, p_name character varying, p_order_no integer, p_is_other boolean) RETURNS TABLE(success boolean, message text, id uuid)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_id UUID;
BEGIN
  IF TRIM(COALESCE(p_name, '')) = '' THEN
    RETURN QUERY SELECT false, 'Nội dung đáp án không được để trống'::TEXT, NULL::UUID;
    RETURN;
  END IF;

  INSERT INTO edoc.room_schedule_answers (
    room_schedule_question_id, room_schedule_id, name, order_no, is_other
  ) VALUES (
    p_question_id, p_room_schedule_id, p_name,
    COALESCE(p_order_no, 0), COALESCE(p_is_other, false)
  ) RETURNING edoc.room_schedule_answers.id INTO v_id;

  RETURN QUERY SELECT true, 'Tạo đáp án thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_vote_cast(uuid, uuid, integer, text); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_vote_cast(p_question_id uuid, p_answer_id uuid, p_staff_id integer, p_other_text text) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_q_status INT;
  v_room_schedule_id INT;
BEGIN
  SELECT q.status, q.room_schedule_id INTO v_q_status, v_room_schedule_id
  FROM edoc.room_schedule_questions q WHERE q.id = p_question_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy câu hỏi'::TEXT;
    RETURN;
  END IF;

  IF v_q_status <> 1 THEN
    RETURN QUERY SELECT false, 'Câu hỏi chưa mở biểu quyết'::TEXT;
    RETURN;
  END IF;

  INSERT INTO edoc.room_schedule_votes (room_schedule_id, question_id, answer_id, staff_id, other_text)
  VALUES (v_room_schedule_id, p_question_id, p_answer_id, p_staff_id, p_other_text)
  ON CONFLICT (question_id, staff_id) DO UPDATE SET
    answer_id  = EXCLUDED.answer_id,
    other_text = EXCLUDED.other_text,
    voted_at   = NOW();

  RETURN QUERY SELECT true, 'Biểu quyết thành công'::TEXT;
END;
$$;


--
-- Name: fn_vote_get_results(uuid); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_vote_get_results(p_question_id uuid) RETURNS TABLE(answer_id uuid, answer_name character varying, order_no integer, vote_count bigint, voter_names text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    a.id AS answer_id,
    a.name AS answer_name,
    a.order_no,
    COUNT(v.id) AS vote_count,
    STRING_AGG(
      (s.last_name || ' ' || s.first_name),
      ', ' ORDER BY s.last_name
    ) AS voter_names
  FROM edoc.room_schedule_answers a
  LEFT JOIN edoc.room_schedule_votes v ON v.answer_id = a.id AND v.question_id = p_question_id
  LEFT JOIN public.staff s ON s.id = v.staff_id
  WHERE a.room_schedule_question_id = p_question_id
  GROUP BY a.id, a.name, a.order_no
  ORDER BY a.order_no;
END;
$$;


--
-- Name: fn_vote_question_create(integer, character varying, integer, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_vote_question_create(p_room_schedule_id integer, p_name character varying, p_question_type integer, p_duration integer, p_order_no integer) RETURNS TABLE(success boolean, message text, id uuid)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_id UUID;
BEGIN
  IF TRIM(COALESCE(p_name, '')) = '' THEN
    RETURN QUERY SELECT false, 'Nội dung câu hỏi không được để trống'::TEXT, NULL::UUID;
    RETURN;
  END IF;

  INSERT INTO edoc.room_schedule_questions (
    room_schedule_id, name, question_type, duration, order_no
  ) VALUES (
    p_room_schedule_id, p_name, COALESCE(p_question_type, 0),
    COALESCE(p_duration, 60), COALESCE(p_order_no, 0)
  ) RETURNING edoc.room_schedule_questions.id INTO v_id;

  RETURN QUERY SELECT true, 'Tạo câu hỏi thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_vote_question_get_list(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_vote_question_get_list(p_room_schedule_id integer) RETURNS TABLE(id uuid, room_schedule_id integer, name character varying, start_time timestamp with time zone, stop_time timestamp with time zone, duration integer, status integer, question_type integer, order_no integer)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    q.id, q.room_schedule_id, q.name, q.start_time, q.stop_time,
    q.duration, q.status, q.question_type, q.order_no
  FROM edoc.room_schedule_questions q
  WHERE q.room_schedule_id = p_room_schedule_id
  ORDER BY q.order_no, q.start_time;
END;
$$;


--
-- Name: fn_vote_question_start(uuid); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_vote_question_start(p_question_id uuid) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_status INT;
BEGIN
  SELECT status INTO v_status FROM edoc.room_schedule_questions WHERE id = p_question_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy câu hỏi'::TEXT;
    RETURN;
  END IF;

  IF v_status <> 0 THEN
    RETURN QUERY SELECT false, 'Câu hỏi đã bắt đầu hoặc kết thúc'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.room_schedule_questions SET
    status     = 1,
    start_time = NOW()
  WHERE id = p_question_id;

  RETURN QUERY SELECT true, 'Bắt đầu biểu quyết thành công'::TEXT;
END;
$$;


--
-- Name: fn_vote_question_stop(uuid); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_vote_question_stop(p_question_id uuid) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_status INT;
BEGIN
  SELECT status INTO v_status FROM edoc.room_schedule_questions WHERE id = p_question_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy câu hỏi'::TEXT;
    RETURN;
  END IF;

  IF v_status <> 1 THEN
    RETURN QUERY SELECT false, 'Câu hỏi không đang trong trạng thái biểu quyết'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.room_schedule_questions SET
    status    = 2,
    stop_time = NOW()
  WHERE id = p_question_id;

  RETURN QUERY SELECT true, 'Kết thúc biểu quyết thành công'::TEXT;
END;
$$;


--
-- Name: fn_work_group_assign_members(integer, integer[]); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_work_group_assign_members(p_group_id integer, p_staff_ids integer[]) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NOT EXISTS(SELECT 1 FROM edoc.work_groups WHERE id = p_group_id AND is_deleted = FALSE) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy nhóm'::TEXT;
    RETURN;
  END IF;

  -- Delete old members
  DELETE FROM edoc.work_group_members WHERE group_id = p_group_id;

  -- Insert new members
  IF p_staff_ids IS NOT NULL AND array_length(p_staff_ids, 1) > 0 THEN
    INSERT INTO edoc.work_group_members (group_id, staff_id)
    SELECT p_group_id, unnest(p_staff_ids)
    ON CONFLICT (group_id, staff_id) DO NOTHING;
  END IF;

  RETURN QUERY SELECT TRUE, 'Cap nhat thanh vien thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_work_group_create(integer, character varying, text, integer, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_work_group_create(p_unit_id integer, p_name character varying, p_function text DEFAULT NULL::text, p_sort_order integer DEFAULT 0, p_created_by integer DEFAULT NULL::integer) RETURNS TABLE(success boolean, message text, id integer)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id INT;
BEGIN
  IF p_name IS NULL OR TRIM(p_name) = '' THEN
    RETURN QUERY SELECT FALSE, 'Tên nhóm không được để trống'::TEXT, 0;
    RETURN;
  END IF;
  IF LENGTH(p_name) > 200 THEN
    RETURN QUERY SELECT FALSE, 'Tên nhóm không được vượt quá 200 ký tự'::TEXT, 0;
    RETURN;
  END IF;

  -- Check unique name per unit
  IF EXISTS(
    SELECT 1 FROM edoc.work_groups
    WHERE unit_id = p_unit_id AND LOWER(TRIM(name)) = LOWER(TRIM(p_name))
      AND is_deleted = FALSE
  ) THEN
    RETURN QUERY SELECT FALSE, 'Tên nhóm đã tồn tại trong đơn vị'::TEXT, 0;
    RETURN;
  END IF;

  INSERT INTO edoc.work_groups (unit_id, name, function, sort_order, created_by)
  VALUES (p_unit_id, TRIM(p_name), p_function, p_sort_order, p_created_by)
  RETURNING work_groups.id INTO v_id;

  RETURN QUERY SELECT TRUE, 'Tao nhom thanh cong'::TEXT, v_id;
END;
$$;


--
-- Name: fn_work_group_delete(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_work_group_delete(p_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NOT EXISTS(SELECT 1 FROM edoc.work_groups WHERE id = p_id AND is_deleted = FALSE) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy nhóm'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.work_groups SET is_deleted = TRUE WHERE id = p_id;
  -- Also remove members
  DELETE FROM edoc.work_group_members WHERE group_id = p_id;

  RETURN QUERY SELECT TRUE, 'Xoa nhom thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_work_group_get_by_id(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_work_group_get_by_id(p_id integer) RETURNS TABLE(id integer, unit_id integer, name character varying, function text, sort_order integer, created_by integer, created_at timestamp with time zone)
    LANGUAGE sql STABLE
    AS $$
  SELECT g.id, g.unit_id, g.name::VARCHAR, g.function,
         g.sort_order, g.created_by, g.created_at
  FROM edoc.work_groups g
  WHERE g.id = p_id AND g.is_deleted = FALSE;
$$;


--
-- Name: fn_work_group_get_list(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_work_group_get_list(p_unit_id integer) RETURNS TABLE(id integer, unit_id integer, name character varying, function text, sort_order integer, member_count bigint, created_by integer, created_at timestamp with time zone)
    LANGUAGE sql STABLE
    AS $$
  SELECT g.id, g.unit_id, g.name::VARCHAR, g.function,
         g.sort_order,
         (SELECT COUNT(*) FROM edoc.work_group_members m WHERE m.group_id = g.id) AS member_count,
         g.created_by, g.created_at
  FROM edoc.work_groups g
  WHERE g.unit_id = p_unit_id AND g.is_deleted = FALSE
  ORDER BY g.sort_order, g.name;
$$;


--
-- Name: fn_work_group_get_members(integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_work_group_get_members(p_group_id integer) RETURNS TABLE(id integer, group_id integer, staff_id integer, staff_name character varying, position_name character varying, department_name character varying, created_at timestamp with time zone)
    LANGUAGE sql STABLE
    AS $$
  SELECT m.id, m.group_id, m.staff_id,
         s.full_name::VARCHAR AS staff_name,
         p.name::VARCHAR AS position_name,
         d.name::VARCHAR AS department_name,
         m.created_at
  FROM edoc.work_group_members m
    JOIN public.staff s ON s.id = m.staff_id
    LEFT JOIN public.positions p ON p.id = s.position_id
    LEFT JOIN public.departments d ON d.id = s.department_id
  WHERE m.group_id = p_group_id
  ORDER BY s.full_name;
$$;


--
-- Name: fn_work_group_update(integer, character varying, text, integer); Type: FUNCTION; Schema: edoc; Owner: -
--

CREATE OR REPLACE FUNCTION edoc.fn_work_group_update(p_id integer, p_name character varying DEFAULT NULL::character varying, p_function text DEFAULT NULL::text, p_sort_order integer DEFAULT NULL::integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_unit_id INT;
BEGIN
  SELECT unit_id INTO v_unit_id FROM edoc.work_groups WHERE id = p_id AND is_deleted = FALSE;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy nhóm'::TEXT;
    RETURN;
  END IF;

  IF p_name IS NULL OR TRIM(p_name) = '' THEN
    RETURN QUERY SELECT FALSE, 'Tên nhóm không được để trống'::TEXT;
    RETURN;
  END IF;
  IF LENGTH(p_name) > 200 THEN
    RETURN QUERY SELECT FALSE, 'Tên nhóm không được vượt quá 200 ký tự'::TEXT;
    RETURN;
  END IF;

  -- Check unique name (exclude self)
  IF EXISTS(
    SELECT 1 FROM edoc.work_groups
    WHERE unit_id = v_unit_id AND LOWER(TRIM(name)) = LOWER(TRIM(p_name))
      AND id <> p_id AND is_deleted = FALSE
  ) THEN
    RETURN QUERY SELECT FALSE, 'Tên nhóm đã tồn tại trong đơn vị'::TEXT;
    RETURN;
  END IF;

  UPDATE edoc.work_groups SET
    name       = TRIM(p_name),
    function   = COALESCE(p_function, function),
    sort_order = COALESCE(p_sort_order, sort_order)
  WHERE id = p_id;

  RETURN QUERY SELECT TRUE, 'Cap nhat nhom thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_borrow_request_approve(bigint, integer); Type: FUNCTION; Schema: esto; Owner: -
--

CREATE OR REPLACE FUNCTION esto.fn_borrow_request_approve(p_id bigint, p_modified_user_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_status INT;
BEGIN
  SELECT status INTO v_status FROM esto.borrow_requests WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy yêu cầu mượn'::TEXT;
    RETURN;
  END IF;

  IF v_status <> 0 THEN
    RETURN QUERY SELECT false, 'Yêu cầu không ở trạng thái chờ duyệt'::TEXT;
    RETURN;
  END IF;

  UPDATE esto.borrow_requests SET
    status           = 1,
    modified_user_id = p_modified_user_id,
    modified_date    = NOW()
  WHERE id = p_id;

  RETURN QUERY SELECT true, 'Duyệt yêu cầu thành công'::TEXT;
END;
$$;


--
-- Name: fn_borrow_request_checkout(bigint, integer); Type: FUNCTION; Schema: esto; Owner: -
--

CREATE OR REPLACE FUNCTION esto.fn_borrow_request_checkout(p_id bigint, p_modified_user_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_status INT;
BEGIN
  SELECT status INTO v_status FROM esto.borrow_requests WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy yêu cầu mượn'::TEXT;
    RETURN;
  END IF;

  IF v_status <> 1 THEN
    RETURN QUERY SELECT false, 'Yêu cầu chưa được duyệt'::TEXT;
    RETURN;
  END IF;

  UPDATE esto.borrow_requests SET
    status           = 2,
    modified_user_id = p_modified_user_id,
    modified_date    = NOW()
  WHERE id = p_id;

  RETURN QUERY SELECT true, 'Xác nhận mượn thành công'::TEXT;
END;
$$;


--
-- Name: fn_borrow_request_create(character varying, integer, integer, text, date, integer, integer[]); Type: FUNCTION; Schema: esto; Owner: -
--

CREATE OR REPLACE FUNCTION esto.fn_borrow_request_create(p_name character varying, p_unit_id integer, p_emergency integer, p_notice text, p_borrow_date date, p_created_user_id integer, p_record_ids integer[]) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_id BIGINT;
  v_record_id INT;
BEGIN
  IF TRIM(COALESCE(p_name, '')) = '' THEN
    RETURN QUERY SELECT false, 'Tên yêu cầu không được để trống'::TEXT, NULL::BIGINT;
    RETURN;
  END IF;

  INSERT INTO esto.borrow_requests (name, unit_id, emergency, notice, borrow_date, created_user_id, status)
  VALUES (p_name, p_unit_id, p_emergency, p_notice, p_borrow_date, p_created_user_id, 0)
  RETURNING esto.borrow_requests.id INTO v_id;

  IF p_record_ids IS NOT NULL THEN
    FOREACH v_record_id IN ARRAY p_record_ids LOOP
      INSERT INTO esto.borrow_request_records (borrow_request_id, record_id)
      VALUES (v_id, v_record_id)
      ON CONFLICT (borrow_request_id, record_id) DO NOTHING;
    END LOOP;
  END IF;

  RETURN QUERY SELECT true, 'Tạo yêu cầu mượn thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_borrow_request_get_by_id(bigint); Type: FUNCTION; Schema: esto; Owner: -
--

CREATE OR REPLACE FUNCTION esto.fn_borrow_request_get_by_id(p_id bigint) RETURNS TABLE(id bigint, name character varying, unit_id integer, emergency integer, notice text, borrow_date date, status integer, created_user_id integer, creator_name text, created_date timestamp with time zone, modified_user_id integer, modified_date timestamp with time zone, record_id bigint, record_title character varying, return_date date, actual_return_date date)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    br.id,
    br.name,
    br.unit_id,
    br.emergency,
    br.notice,
    br.borrow_date,
    br.status,
    br.created_user_id,
    (s.last_name || ' ' || s.first_name)::TEXT AS creator_name,
    br.created_date,
    br.modified_user_id,
    br.modified_date,
    r.id AS record_id,
    r.title AS record_title,
    brr.return_date,
    brr.actual_return_date
  FROM esto.borrow_requests br
  LEFT JOIN public.staff s ON s.id = br.created_user_id
  LEFT JOIN esto.borrow_request_records brr ON brr.borrow_request_id = br.id
  LEFT JOIN esto.records r ON r.id = brr.record_id
  WHERE br.id = p_id;
END;
$$;


--
-- Name: fn_borrow_request_get_list(integer, integer, text, integer, integer); Type: FUNCTION; Schema: esto; Owner: -
--

CREATE OR REPLACE FUNCTION esto.fn_borrow_request_get_list(p_unit_id integer, p_status integer, p_keyword text, p_page integer DEFAULT 1, p_page_size integer DEFAULT 20) RETURNS TABLE(id bigint, name character varying, unit_id integer, emergency integer, notice text, borrow_date date, status integer, created_user_id integer, creator_name text, created_date timestamp with time zone, record_count bigint, total_count bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_offset INT := (COALESCE(p_page, 1) - 1) * COALESCE(p_page_size, 20);
BEGIN
  RETURN QUERY
  WITH filtered AS (
    SELECT
      br.id,
      br.name,
      br.unit_id,
      br.emergency,
      br.notice,
      br.borrow_date,
      br.status,
      br.created_user_id,
      (s.last_name || ' ' || s.first_name)::TEXT AS creator_name,
      br.created_date,
      (SELECT COUNT(*) FROM esto.borrow_request_records brr WHERE brr.borrow_request_id = br.id) AS record_count
    FROM esto.borrow_requests br
    LEFT JOIN public.staff s ON s.id = br.created_user_id
    WHERE br.unit_id = p_unit_id
      AND (p_status IS NULL OR p_status = -99 OR br.status = p_status)
      AND (p_keyword IS NULL OR TRIM(p_keyword) = '' OR br.name ILIKE '%' || p_keyword || '%')
  )
  SELECT
    flt.*,
    COUNT(*) OVER() AS total_count
  FROM filtered flt
  ORDER BY flt.created_date DESC
  LIMIT p_page_size OFFSET v_offset;
END;
$$;


--
-- Name: fn_borrow_request_reject(bigint, integer, text); Type: FUNCTION; Schema: esto; Owner: -
--

CREATE OR REPLACE FUNCTION esto.fn_borrow_request_reject(p_id bigint, p_modified_user_id integer, p_notice text) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_status INT;
BEGIN
  SELECT status INTO v_status FROM esto.borrow_requests WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy yêu cầu mượn'::TEXT;
    RETURN;
  END IF;

  IF v_status <> 0 THEN
    RETURN QUERY SELECT false, 'Yêu cầu không ở trạng thái chờ duyệt'::TEXT;
    RETURN;
  END IF;

  UPDATE esto.borrow_requests SET
    status           = -1,
    notice           = COALESCE(p_notice, notice),
    modified_user_id = p_modified_user_id,
    modified_date    = NOW()
  WHERE id = p_id;

  RETURN QUERY SELECT true, 'Từ chối yêu cầu thành công'::TEXT;
END;
$$;


--
-- Name: fn_borrow_request_return(bigint, integer); Type: FUNCTION; Schema: esto; Owner: -
--

CREATE OR REPLACE FUNCTION esto.fn_borrow_request_return(p_id bigint, p_modified_user_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_status INT;
BEGIN
  SELECT status INTO v_status FROM esto.borrow_requests WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy yêu cầu mượn'::TEXT;
    RETURN;
  END IF;

  IF v_status <> 2 THEN
    RETURN QUERY SELECT false, 'Yêu cầu chưa ở trạng thái đang mượn'::TEXT;
    RETURN;
  END IF;

  UPDATE esto.borrow_requests SET
    status           = 3,
    modified_user_id = p_modified_user_id,
    modified_date    = NOW()
  WHERE id = p_id;

  UPDATE esto.borrow_request_records SET
    actual_return_date = CURRENT_DATE
  WHERE borrow_request_id = p_id;

  RETURN QUERY SELECT true, 'Xác nhận trả thành công'::TEXT;
END;
$$;


--
-- Name: fn_document_archive_create(character varying, bigint, integer, integer, bigint, character varying, character varying, integer, character varying, text, text, character varying, character varying, boolean, integer); Type: FUNCTION; Schema: esto; Owner: -
--

CREATE OR REPLACE FUNCTION esto.fn_document_archive_create(p_doc_type character varying, p_doc_id bigint, p_fond_id integer DEFAULT NULL::integer, p_warehouse_id integer DEFAULT NULL::integer, p_record_id bigint DEFAULT NULL::bigint, p_file_catalog character varying DEFAULT NULL::character varying, p_file_notation character varying DEFAULT NULL::character varying, p_doc_ordinal integer DEFAULT NULL::integer, p_language character varying DEFAULT 'Tiếng Việt'::character varying, p_autograph text DEFAULT NULL::text, p_keyword text DEFAULT NULL::text, p_format character varying DEFAULT 'Điện tử'::character varying, p_confidence_level character varying DEFAULT NULL::character varying, p_is_original boolean DEFAULT true, p_archived_by integer DEFAULT NULL::integer) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id BIGINT;
BEGIN
  IF p_doc_type NOT IN ('incoming', 'outgoing') THEN
    RETURN QUERY SELECT FALSE, 'Loại văn bản không hợp lệ'::TEXT, 0::BIGINT;
    RETURN;
  END IF;

  -- Kiểm tra VB tồn tại
  IF p_doc_type = 'incoming' AND NOT EXISTS (SELECT 1 FROM edoc.incoming_docs ind WHERE ind.id = p_doc_id) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản đến'::TEXT, 0::BIGINT; RETURN;
  END IF;
  IF p_doc_type = 'outgoing' AND NOT EXISTS (SELECT 1 FROM edoc.outgoing_docs od WHERE od.id = p_doc_id) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy văn bản đi'::TEXT, 0::BIGINT; RETURN;
  END IF;

  INSERT INTO esto.document_archives (
    doc_type, doc_id, fond_id, warehouse_id, record_id,
    file_catalog, file_notation, doc_ordinal, language,
    autograph, keyword, format, confidence_level, is_original, archived_by
  ) VALUES (
    p_doc_type, p_doc_id, p_fond_id, p_warehouse_id, p_record_id,
    NULLIF(TRIM(p_file_catalog), ''), NULLIF(TRIM(p_file_notation), ''), p_doc_ordinal,
    COALESCE(p_language, 'Tiếng Việt'),
    NULLIF(TRIM(p_autograph), ''), NULLIF(TRIM(p_keyword), ''),
    COALESCE(p_format, 'Điện tử'), NULLIF(TRIM(p_confidence_level), ''),
    COALESCE(p_is_original, true), p_archived_by
  )
  ON CONFLICT (doc_type, doc_id) DO UPDATE SET
    fond_id = EXCLUDED.fond_id, warehouse_id = EXCLUDED.warehouse_id,
    record_id = EXCLUDED.record_id, file_catalog = EXCLUDED.file_catalog,
    file_notation = EXCLUDED.file_notation, doc_ordinal = EXCLUDED.doc_ordinal,
    language = EXCLUDED.language, autograph = EXCLUDED.autograph,
    keyword = EXCLUDED.keyword, format = EXCLUDED.format,
    confidence_level = EXCLUDED.confidence_level, is_original = EXCLUDED.is_original,
    archived_by = EXCLUDED.archived_by, archive_date = NOW()
  RETURNING esto.document_archives.id INTO v_id;

  -- Cập nhật archive_status trên VB gốc
  IF p_doc_type = 'incoming' THEN
    UPDATE edoc.incoming_docs SET archive_status = true WHERE id = p_doc_id;
  ELSIF p_doc_type = 'outgoing' THEN
    UPDATE edoc.outgoing_docs SET archive_status = true WHERE id = p_doc_id;
  END IF;

  RETURN QUERY SELECT TRUE, 'Chuyển lưu trữ thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_document_archive_get_by_doc(character varying, bigint); Type: FUNCTION; Schema: esto; Owner: -
--

CREATE OR REPLACE FUNCTION esto.fn_document_archive_get_by_doc(p_doc_type character varying, p_doc_id bigint) RETURNS TABLE(id bigint, fond_id integer, fond_name character varying, warehouse_id integer, warehouse_name character varying, record_id bigint, record_name character varying, file_catalog character varying, file_notation character varying, doc_ordinal integer, language character varying, autograph text, keyword text, format character varying, confidence_level character varying, is_original boolean, archive_date timestamp with time zone, archived_by_name character varying)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT a.id, a.fond_id, f.name, a.warehouse_id, w.name,
         a.record_id, r.name, a.file_catalog, a.file_notation,
         a.doc_ordinal, a.language, a.autograph, a.keyword,
         a.format, a.confidence_level, a.is_original,
         a.archive_date, s.full_name
  FROM esto.document_archives a
  LEFT JOIN esto.fonds f ON f.id = a.fond_id
  LEFT JOIN esto.warehouses w ON w.id = a.warehouse_id
  LEFT JOIN esto.records r ON r.id = a.record_id
  LEFT JOIN public.staff s ON s.id = a.archived_by
  WHERE a.doc_type = p_doc_type AND a.doc_id = p_doc_id;
END;
$$;


--
-- Name: fn_fond_create(integer, integer, character varying, character varying, text, character varying, numeric, numeric, character varying, character varying, character varying, character varying, numeric, integer, text, numeric, integer); Type: FUNCTION; Schema: esto; Owner: -
--

CREATE OR REPLACE FUNCTION esto.fn_fond_create(p_unit_id integer, p_parent_id integer, p_fond_code character varying, p_fond_name character varying, p_fond_history text, p_archives_time character varying, p_paper_total numeric, p_paper_digital numeric, p_keys_group character varying, p_other_type character varying, p_language character varying, p_lookup_tools character varying, p_coppy_number numeric, p_status integer, p_description text, p_version numeric, p_created_user_id integer) RETURNS TABLE(success boolean, message text, id integer)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_id INT;
BEGIN
  IF TRIM(COALESCE(p_fond_name, '')) = '' THEN
    RETURN QUERY SELECT false, 'Tên phông không được để trống'::TEXT, NULL::INT;
    RETURN;
  END IF;

  INSERT INTO esto.fonds (
    unit_id, parent_id, fond_code, fond_name, fond_history, archives_time,
    paper_total, paper_digital, keys_group, other_type, language,
    lookup_tools, coppy_number, status, description, version, created_user_id
  ) VALUES (
    p_unit_id, COALESCE(p_parent_id, 0), NULLIF(TRIM(p_fond_code),''),
    p_fond_name, p_fond_history, p_archives_time, p_paper_total, p_paper_digital,
    p_keys_group, p_other_type, p_language, p_lookup_tools, p_coppy_number,
    COALESCE(p_status, 1), p_description, p_version, p_created_user_id
  ) RETURNING esto.fonds.id INTO v_id;

  RETURN QUERY SELECT true, 'Tạo phông thành công'::TEXT, v_id;
EXCEPTION
  WHEN unique_violation THEN
    RETURN QUERY SELECT false, 'Mã phông đã tồn tại trong đơn vị'::TEXT, NULL::INT;
END;
$$;


--
-- Name: fn_fond_delete(integer); Type: FUNCTION; Schema: esto; Owner: -
--

CREATE OR REPLACE FUNCTION esto.fn_fond_delete(p_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_count INT;
BEGIN
  SELECT COUNT(*) INTO v_count FROM esto.records WHERE fond_id = p_id;
  IF v_count > 0 THEN
    RETURN QUERY SELECT false, 'Phông đang có hồ sơ, không thể xóa'::TEXT;
    RETURN;
  END IF;

  SELECT COUNT(*) INTO v_count FROM esto.fonds WHERE parent_id = p_id;
  IF v_count > 0 THEN
    RETURN QUERY SELECT false, 'Phông đang có phông con, không thể xóa'::TEXT;
    RETURN;
  END IF;

  DELETE FROM esto.fonds WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy phông'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT true, 'Xóa phông thành công'::TEXT;
END;
$$;


--
-- Name: fn_fond_get_by_id(integer); Type: FUNCTION; Schema: esto; Owner: -
--

CREATE OR REPLACE FUNCTION esto.fn_fond_get_by_id(p_id integer) RETURNS TABLE(id integer, unit_id integer, parent_id integer, fond_code character varying, fond_name character varying, fond_history text, archives_time character varying, paper_total numeric, paper_digital numeric, keys_group character varying, other_type character varying, language character varying, lookup_tools character varying, coppy_number numeric, status integer, description text, version numeric, created_date timestamp with time zone, modified_user_id integer, modified_date timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    f.id, f.unit_id, f.parent_id, f.fond_code, f.fond_name,
    f.fond_history, f.archives_time, f.paper_total, f.paper_digital,
    f.keys_group, f.other_type, f.language, f.lookup_tools,
    f.coppy_number, f.status, f.description, f.version,
    f.created_date, f.modified_user_id, f.modified_date
  FROM esto.fonds f
  WHERE f.id = p_id;
END;
$$;


--
-- Name: fn_fond_get_tree(integer); Type: FUNCTION; Schema: esto; Owner: -
--

CREATE OR REPLACE FUNCTION esto.fn_fond_get_tree(p_unit_id integer) RETURNS TABLE(id integer, unit_id integer, parent_id integer, fond_code character varying, fond_name character varying, fond_history text, archives_time character varying, paper_total numeric, paper_digital numeric, keys_group character varying, other_type character varying, language character varying, lookup_tools character varying, coppy_number numeric, status integer, description text, version numeric, created_date timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    f.id,
    f.unit_id,
    f.parent_id,
    f.fond_code,
    f.fond_name,
    f.fond_history,
    f.archives_time,
    f.paper_total,
    f.paper_digital,
    f.keys_group,
    f.other_type,
    f.language,
    f.lookup_tools,
    f.coppy_number,
    f.status,
    f.description,
    f.version,
