--
-- Name: fn_fond_update(integer, integer, character varying, character varying, text, character varying, numeric, numeric, character varying, character varying, character varying, character varying, numeric, integer, text, numeric, integer); Type: FUNCTION; Schema: esto; Owner: -
--

CREATE OR REPLACE FUNCTION esto.fn_fond_update(p_id integer, p_parent_id integer, p_fond_code character varying, p_fond_name character varying, p_fond_history text, p_archives_time character varying, p_paper_total numeric, p_paper_digital numeric, p_keys_group character varying, p_other_type character varying, p_language character varying, p_lookup_tools character varying, p_coppy_number numeric, p_status integer, p_description text, p_version numeric, p_modified_user_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  IF TRIM(COALESCE(p_fond_name, '')) = '' THEN
    RETURN QUERY SELECT false, 'Tên phông không được để trống'::TEXT;
    RETURN;
  END IF;

  UPDATE esto.fonds SET
    parent_id        = COALESCE(p_parent_id, 0),
    fond_code        = NULLIF(TRIM(p_fond_code),''),
    fond_name        = p_fond_name,
    fond_history     = p_fond_history,
    archives_time    = p_archives_time,
    paper_total      = p_paper_total,
    paper_digital    = p_paper_digital,
    keys_group       = p_keys_group,
    other_type       = p_other_type,
    language         = p_language,
    lookup_tools     = p_lookup_tools,
    coppy_number     = p_coppy_number,
    status           = COALESCE(p_status, 1),
    description      = p_description,
    version          = p_version,
    modified_user_id = p_modified_user_id,
    modified_date    = NOW()
  WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy phông'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT true, 'Cập nhật thành công'::TEXT;
EXCEPTION
  WHEN unique_violation THEN
    RETURN QUERY SELECT false, 'Mã phông đã tồn tại trong đơn vị'::TEXT;
END;
$$;


--
-- Name: fn_get_fonds_list(integer); Type: FUNCTION; Schema: esto; Owner: -
--

CREATE OR REPLACE FUNCTION esto.fn_get_fonds_list(p_unit_id integer DEFAULT NULL::integer) RETURNS TABLE(id integer, name character varying, code character varying)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY SELECT f.id, f.name, f.code FROM esto.fonds f
  WHERE (p_unit_id IS NULL OR f.warehouse_id IN (SELECT w.id FROM esto.warehouses w WHERE w.unit_id = p_unit_id))
  ORDER BY f.name;
END;
$$;


--
-- Name: fn_get_warehouses_list(integer); Type: FUNCTION; Schema: esto; Owner: -
--

CREATE OR REPLACE FUNCTION esto.fn_get_warehouses_list(p_unit_id integer DEFAULT NULL::integer) RETURNS TABLE(id integer, name character varying, code character varying)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY SELECT w.id, w.name, w.code FROM esto.warehouses w
  WHERE (p_unit_id IS NULL OR w.unit_id = p_unit_id)
  ORDER BY w.name;
END;
$$;


--
-- Name: fn_record_create(integer, integer, integer, character varying, integer, character varying, character varying, character varying, character varying, character varying, date, date, integer, text, character varying, character varying, numeric, numeric, integer, date, integer, date, integer, character varying, boolean, integer, integer, integer); Type: FUNCTION; Schema: esto; Owner: -
--

CREATE OR REPLACE FUNCTION esto.fn_record_create(p_unit_id integer, p_fond_id integer, p_warehouse_id integer, p_file_code character varying, p_file_catalog integer, p_file_notation character varying, p_title character varying, p_maintenance character varying, p_rights character varying, p_language character varying, p_start_date date, p_complete_date date, p_total_doc integer, p_description text, p_infor_sign character varying, p_keyword character varying, p_total_paper numeric, p_page_number numeric, p_format integer, p_archive_date date, p_in_charge_staff_id integer, p_reception_date date, p_reception_from integer, p_transfer_staff character varying, p_is_document_original boolean, p_number_of_copy integer, p_doc_field_id integer, p_created_user_id integer) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_id BIGINT;
BEGIN
  IF TRIM(COALESCE(p_title, '')) = '' THEN
    RETURN QUERY SELECT false, 'Tiêu đề hồ sơ không được để trống'::TEXT, NULL::BIGINT;
    RETURN;
  END IF;

  INSERT INTO esto.records (
    unit_id, fond_id, warehouse_id, file_code, file_catalog, file_notation,
    title, maintenance, rights, language, start_date, complete_date, total_doc,
    description, infor_sign, keyword, total_paper, page_number, format,
    archive_date, in_charge_staff_id, reception_date, reception_from,
    transfer_staff, is_document_original, number_of_copy, doc_field_id,
    created_user_id
  ) VALUES (
    p_unit_id, p_fond_id, p_warehouse_id, p_file_code, p_file_catalog, p_file_notation,
    p_title, p_maintenance, p_rights, p_language, p_start_date, p_complete_date, p_total_doc,
    p_description, p_infor_sign, p_keyword, p_total_paper, p_page_number, COALESCE(p_format, 0),
    p_archive_date, p_in_charge_staff_id, p_reception_date, COALESCE(p_reception_from, 0),
    p_transfer_staff, p_is_document_original, p_number_of_copy, p_doc_field_id,
    p_created_user_id
  ) RETURNING esto.records.id INTO v_id;

  RETURN QUERY SELECT true, 'Tạo hồ sơ thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_record_delete(bigint); Type: FUNCTION; Schema: esto; Owner: -
--

CREATE OR REPLACE FUNCTION esto.fn_record_delete(p_id bigint) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_count INT;
BEGIN
  SELECT COUNT(*) INTO v_count FROM esto.borrow_request_records WHERE record_id = p_id;
  IF v_count > 0 THEN
    RETURN QUERY SELECT false, 'Hồ sơ đang có yêu cầu mượn, không thể xóa'::TEXT;
    RETURN;
  END IF;

  DELETE FROM esto.records WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy hồ sơ'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT true, 'Xóa hồ sơ thành công'::TEXT;
END;
$$;


--
-- Name: fn_record_get_by_id(bigint); Type: FUNCTION; Schema: esto; Owner: -
--

CREATE OR REPLACE FUNCTION esto.fn_record_get_by_id(p_id bigint) RETURNS TABLE(id bigint, unit_id integer, fond_id integer, fond_name character varying, file_code character varying, file_catalog integer, file_notation character varying, title character varying, maintenance character varying, rights character varying, language character varying, start_date date, complete_date date, total_doc integer, description text, infor_sign character varying, keyword character varying, total_paper numeric, page_number numeric, format integer, archive_date date, reception_archive_id integer, in_charge_staff_id integer, parent_id integer, warehouse_id integer, warehouse_name character varying, reception_date date, reception_from integer, transfer_staff character varying, is_document_original boolean, number_of_copy integer, doc_field_id integer, transfer_online_status boolean, created_user_id integer, created_date timestamp with time zone, modified_user_id integer, modified_date timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    r.id,
    r.unit_id,
    r.fond_id,
    f.fond_name,
    r.file_code,
    r.file_catalog,
    r.file_notation,
    r.title,
    r.maintenance,
    r.rights,
    r.language,
    r.start_date,
    r.complete_date,
    r.total_doc,
    r.description,
    r.infor_sign,
    r.keyword,
    r.total_paper,
    r.page_number,
    r.format,
    r.archive_date,
    r.reception_archive_id,
    r.in_charge_staff_id,
    r.parent_id,
    r.warehouse_id,
    w.name AS warehouse_name,
    r.reception_date,
    r.reception_from,
    r.transfer_staff,
    r.is_document_original,
    r.number_of_copy,
    r.doc_field_id,
    r.transfer_online_status,
    r.created_user_id,
    r.created_date,
    r.modified_user_id,
    r.modified_date
  FROM esto.records r
  LEFT JOIN esto.fonds f ON f.id = r.fond_id
  LEFT JOIN esto.warehouses w ON w.id = r.warehouse_id
  WHERE r.id = p_id;
END;
$$;


--
-- Name: fn_record_get_list(integer, integer, integer, text, integer, integer); Type: FUNCTION; Schema: esto; Owner: -
--

CREATE OR REPLACE FUNCTION esto.fn_record_get_list(p_unit_id integer, p_fond_id integer, p_warehouse_id integer, p_keyword text, p_page integer DEFAULT 1, p_page_size integer DEFAULT 20) RETURNS TABLE(id bigint, unit_id integer, fond_id integer, fond_name character varying, file_code character varying, file_catalog integer, file_notation character varying, title character varying, maintenance character varying, rights character varying, language character varying, start_date date, complete_date date, total_doc integer, description text, infor_sign character varying, keyword character varying, total_paper numeric, page_number numeric, format integer, archive_date date, in_charge_staff_id integer, warehouse_id integer, warehouse_name character varying, transfer_online_status boolean, created_date timestamp with time zone, total_count bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_offset INT := (COALESCE(p_page, 1) - 1) * COALESCE(p_page_size, 20);
BEGIN
  RETURN QUERY
  WITH filtered AS (
    SELECT
      r.id,
      r.unit_id,
      r.fond_id,
      f.fond_name,
      r.file_code,
      r.file_catalog,
      r.file_notation,
      r.title,
      r.maintenance,
      r.rights,
      r.language,
      r.start_date,
      r.complete_date,
      r.total_doc,
      r.description,
      r.infor_sign,
      r.keyword,
      r.total_paper,
      r.page_number,
      r.format,
      r.archive_date,
      r.in_charge_staff_id,
      r.warehouse_id,
      w.name AS warehouse_name,
      r.transfer_online_status,
      r.created_date
    FROM esto.records r
    LEFT JOIN esto.fonds f ON f.id = r.fond_id
    LEFT JOIN esto.warehouses w ON w.id = r.warehouse_id
    WHERE r.unit_id = p_unit_id
      AND (p_fond_id IS NULL OR r.fond_id = p_fond_id)
      AND (p_warehouse_id IS NULL OR r.warehouse_id = p_warehouse_id)
      AND (p_keyword IS NULL OR TRIM(p_keyword) = '' OR
           r.title ILIKE '%' || p_keyword || '%' OR
           r.file_code ILIKE '%' || p_keyword || '%')
  )
  SELECT
    flt.*,
    COUNT(*) OVER() AS total_count
  FROM filtered flt
  ORDER BY flt.created_date DESC
  LIMIT p_page_size OFFSET v_offset;
END;
$$;


--
-- Name: fn_record_update(bigint, integer, integer, character varying, integer, character varying, character varying, character varying, character varying, character varying, date, date, integer, text, character varying, character varying, numeric, numeric, integer, date, integer, date, integer, character varying, boolean, integer, integer, integer); Type: FUNCTION; Schema: esto; Owner: -
--

CREATE OR REPLACE FUNCTION esto.fn_record_update(p_id bigint, p_fond_id integer, p_warehouse_id integer, p_file_code character varying, p_file_catalog integer, p_file_notation character varying, p_title character varying, p_maintenance character varying, p_rights character varying, p_language character varying, p_start_date date, p_complete_date date, p_total_doc integer, p_description text, p_infor_sign character varying, p_keyword character varying, p_total_paper numeric, p_page_number numeric, p_format integer, p_archive_date date, p_in_charge_staff_id integer, p_reception_date date, p_reception_from integer, p_transfer_staff character varying, p_is_document_original boolean, p_number_of_copy integer, p_doc_field_id integer, p_modified_user_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  IF TRIM(COALESCE(p_title, '')) = '' THEN
    RETURN QUERY SELECT false, 'Tiêu đề hồ sơ không được để trống'::TEXT;
    RETURN;
  END IF;

  UPDATE esto.records SET
    fond_id               = p_fond_id,
    warehouse_id          = p_warehouse_id,
    file_code             = p_file_code,
    file_catalog          = p_file_catalog,
    file_notation         = p_file_notation,
    title                 = p_title,
    maintenance           = p_maintenance,
    rights                = p_rights,
    language              = p_language,
    start_date            = p_start_date,
    complete_date         = p_complete_date,
    total_doc             = p_total_doc,
    description           = p_description,
    infor_sign            = p_infor_sign,
    keyword               = p_keyword,
    total_paper           = p_total_paper,
    page_number           = p_page_number,
    format                = COALESCE(p_format, 0),
    archive_date          = p_archive_date,
    in_charge_staff_id    = p_in_charge_staff_id,
    reception_date        = p_reception_date,
    reception_from        = COALESCE(p_reception_from, 0),
    transfer_staff        = p_transfer_staff,
    is_document_original  = p_is_document_original,
    number_of_copy        = p_number_of_copy,
    doc_field_id          = p_doc_field_id,
    modified_user_id      = p_modified_user_id,
    modified_date         = NOW()
  WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy hồ sơ'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT true, 'Cập nhật thành công'::TEXT;
END;
$$;


--
-- Name: fn_warehouse_create(integer, integer, character varying, character varying, character varying, character varying, boolean, text, integer, boolean, integer, integer, character varying, integer); Type: FUNCTION; Schema: esto; Owner: -
--

CREATE OR REPLACE FUNCTION esto.fn_warehouse_create(p_unit_id integer, p_type_id integer, p_code character varying, p_name character varying, p_phone_number character varying, p_address character varying, p_status boolean, p_description text, p_parent_id integer, p_is_unit boolean, p_warehouse_level integer, p_limit_child integer, p_position character varying, p_created_user_id integer) RETURNS TABLE(success boolean, message text, id integer)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_id INT;
BEGIN
  IF TRIM(COALESCE(p_name, '')) = '' THEN
    RETURN QUERY SELECT false, 'Tên kho không được để trống'::TEXT, NULL::INT;
    RETURN;
  END IF;

  INSERT INTO esto.warehouses (
    unit_id, type_id, code, name, phone_number, address, status,
    description, parent_id, is_unit, warehouse_level, limit_child,
    "position", created_user_id
  ) VALUES (
    p_unit_id, p_type_id, NULLIF(TRIM(p_code),''), p_name, p_phone_number,
    p_address, COALESCE(p_status, true), p_description,
    COALESCE(p_parent_id, 0), COALESCE(p_is_unit, false),
    COALESCE(p_warehouse_level, 0), COALESCE(p_limit_child, 0),
    p_position, p_created_user_id
  ) RETURNING esto.warehouses.id INTO v_id;

  RETURN QUERY SELECT true, 'Tạo kho thành công'::TEXT, v_id;
EXCEPTION
  WHEN unique_violation THEN
    RETURN QUERY SELECT false, 'Mã kho đã tồn tại trong đơn vị'::TEXT, NULL::INT;
END;
$$;


--
-- Name: fn_warehouse_delete(integer); Type: FUNCTION; Schema: esto; Owner: -
--

CREATE OR REPLACE FUNCTION esto.fn_warehouse_delete(p_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_count INT;
BEGIN
  SELECT COUNT(*) INTO v_count FROM esto.records WHERE warehouse_id = p_id;
  IF v_count > 0 THEN
    RETURN QUERY SELECT false, 'Kho đang có hồ sơ, không thể xóa'::TEXT;
    RETURN;
  END IF;

  SELECT COUNT(*) INTO v_count FROM esto.warehouses WHERE parent_id = p_id AND is_deleted = false;
  IF v_count > 0 THEN
    RETURN QUERY SELECT false, 'Kho đang có kho con, không thể xóa'::TEXT;
    RETURN;
  END IF;

  UPDATE esto.warehouses SET is_deleted = true WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy kho'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT true, 'Xóa kho thành công'::TEXT;
END;
$$;


