    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    dc.id,
    dc.parent_id,
    dc.code,
    dc.name,
    dc.date_process,
    dc.status,
    dc.description,
    dc.version,
    dc.unit_id,
    dc.created_date
  FROM iso.document_categories dc
  WHERE (dc.unit_id IS NULL OR dc.unit_id = p_unit_id)
    AND dc.status = 1
  ORDER BY dc.parent_id, dc.name;
END;
$$;


