--
-- Name: fn_document_get_by_id(bigint); Type: FUNCTION; Schema: iso; Owner: -
--

CREATE OR REPLACE FUNCTION iso.fn_document_get_by_id(p_id bigint) RETURNS TABLE(id bigint, unit_id integer, category_id integer, category_name character varying, title character varying, description text, file_name character varying, file_path character varying, file_size bigint, mime_type character varying, keyword character varying, status integer, created_user_id integer, creator_name text, created_date timestamp with time zone, modified_user_id integer, modified_date timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    d.id, d.unit_id, d.category_id, dc.name AS category_name,
    d.title, d.description, d.file_name, d.file_path, d.file_size,
    d.mime_type, d.keyword, d.status, d.created_user_id,
    (s.last_name || ' ' || s.first_name)::TEXT AS creator_name,
    d.created_date, d.modified_user_id, d.modified_date
  FROM iso.documents d
  LEFT JOIN iso.document_categories dc ON dc.id = d.category_id
  LEFT JOIN public.staff s ON s.id = d.created_user_id
  WHERE d.id = p_id AND d.is_deleted = false;
END;
$$;


--
-- Name: fn_document_get_list(integer, integer, text, integer, integer); Type: FUNCTION; Schema: iso; Owner: -
--

CREATE OR REPLACE FUNCTION iso.fn_document_get_list(p_unit_id integer, p_category_id integer, p_keyword text, p_page integer DEFAULT 1, p_page_size integer DEFAULT 20) RETURNS TABLE(id bigint, unit_id integer, category_id integer, category_name character varying, title character varying, description text, file_name character varying, file_path character varying, file_size bigint, mime_type character varying, keyword character varying, status integer, created_user_id integer, creator_name text, created_date timestamp with time zone, total_count bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_offset INT := (COALESCE(p_page, 1) - 1) * COALESCE(p_page_size, 20);
BEGIN
  RETURN QUERY
  WITH filtered AS (
    SELECT
      d.id,
      d.unit_id,
      d.category_id,
      dc.name AS category_name,
      d.title,
      d.description,
      d.file_name,
      d.file_path,
      d.file_size,
      d.mime_type,
      d.keyword,
      d.status,
      d.created_user_id,
      (s.last_name || ' ' || s.first_name)::TEXT AS creator_name,
      d.created_date
    FROM iso.documents d
    LEFT JOIN iso.document_categories dc ON dc.id = d.category_id
    LEFT JOIN public.staff s ON s.id = d.created_user_id
    WHERE d.unit_id = p_unit_id
      AND d.is_deleted = false
      AND (p_category_id IS NULL OR d.category_id = p_category_id)
      AND (p_keyword IS NULL OR TRIM(p_keyword) = '' OR
           d.title ILIKE '%' || p_keyword || '%' OR
           d.keyword ILIKE '%' || p_keyword || '%')
  )
  SELECT
    flt.*,
    COUNT(*) OVER() AS total_count
  FROM filtered flt
  ORDER BY flt.created_date DESC
  LIMIT p_page_size OFFSET v_offset;
END;
$$;


--
-- Name: fn_document_update(bigint, integer, character varying, text, character varying, character varying, bigint, character varying, character varying, integer, integer); Type: FUNCTION; Schema: iso; Owner: -
--

CREATE OR REPLACE FUNCTION iso.fn_document_update(p_id bigint, p_category_id integer, p_title character varying, p_description text, p_file_name character varying, p_file_path character varying, p_file_size bigint, p_mime_type character varying, p_keyword character varying, p_status integer, p_modified_user_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  IF TRIM(COALESCE(p_title, '')) = '' THEN
    RETURN QUERY SELECT false, 'Tiêu đề tài liệu không được để trống'::TEXT;
    RETURN;
  END IF;

  UPDATE iso.documents SET
    category_id      = p_category_id,
    title            = p_title,
    description      = p_description,
    file_name        = COALESCE(p_file_name, file_name),
    file_path        = COALESCE(p_file_path, file_path),
    file_size        = COALESCE(p_file_size, file_size),
    mime_type        = COALESCE(p_mime_type, mime_type),
    keyword          = p_keyword,
    status           = COALESCE(p_status, status),
    modified_user_id = p_modified_user_id,
    modified_date    = NOW()
  WHERE id = p_id AND is_deleted = false;

  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'Không tìm thấy tài liệu'::TEXT;
    RETURN;
  END IF;

  RETURN QUERY SELECT true, 'Cập nhật thành công'::TEXT;
END;
$$;


--
-- Name: fn_auth_cleanup_expired_tokens(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_auth_cleanup_expired_tokens() RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_count INT;
BEGIN
  DELETE FROM public.refresh_tokens
  WHERE expires_at < NOW() OR revoked_at IS NOT NULL;

  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$$;


--
-- Name: fn_auth_get_me(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_auth_get_me(p_staff_id integer) RETURNS TABLE(staff_id integer, username character varying, full_name character varying, email character varying, phone character varying, image character varying, is_admin boolean, gender smallint, birth_date date, address text, department_id integer, unit_id integer, position_id integer, position_name character varying, department_name character varying, unit_name character varying, roles text, last_login_at timestamp with time zone, created_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    s.id              AS staff_id,
    s.username,
    s.full_name::VARCHAR,
    s.email::VARCHAR,
    COALESCE(s.phone, s.mobile)::VARCHAR AS phone,
    s.image::VARCHAR,
    s.is_admin,
    s.gender,
    s.birth_date,
    s.address,
    s.department_id,
    s.unit_id,
    s.position_id,
    p.name::VARCHAR   AS position_name,
    d.name::VARCHAR   AS department_name,
    u.name::VARCHAR   AS unit_name,
    COALESCE(
      (SELECT string_agg(r.name, ',')
       FROM public.role_of_staff ros
       JOIN public.roles r ON r.id = ros.role_id
       WHERE ros.staff_id = s.id),
      ''
    )::TEXT AS roles,
    s.last_login_at,
    s.created_at
  FROM public.staff s
  LEFT JOIN public.positions p ON p.id = s.position_id
  LEFT JOIN public.departments d ON d.id = s.department_id
  LEFT JOIN public.departments u ON u.id = s.unit_id
  WHERE s.id = p_staff_id
    AND s.is_deleted = FALSE
    AND s.is_locked = FALSE;
END;
$$;


--
-- Name: fn_auth_log_login(integer, character varying, character varying, text, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_auth_log_login(p_staff_id integer, p_username character varying, p_ip_address character varying, p_user_agent text, p_success boolean) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
  INSERT INTO public.login_history (staff_id, username, ip_address, user_agent, success)
  VALUES (p_staff_id, p_username, p_ip_address, p_user_agent, p_success);

  -- Cập nhật last_login_at nếu thành công
  IF p_success AND p_staff_id IS NOT NULL THEN
    UPDATE public.staff SET last_login_at = NOW() WHERE id = p_staff_id;
  END IF;
END;
$$;


--
-- Name: fn_auth_login(character varying, character varying, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_auth_login(p_username character varying, p_ip_address character varying DEFAULT NULL::character varying, p_user_agent text DEFAULT NULL::text) RETURNS TABLE(staff_id integer, username character varying, password_hash character varying, full_name character varying, email character varying, phone character varying, image character varying, is_admin boolean, is_locked boolean, is_deleted boolean, department_id integer, unit_id integer, position_name character varying, department_name character varying, unit_name character varying, roles text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    s.id              AS staff_id,
    s.username,
    s.password_hash,
    s.full_name::VARCHAR,
    s.email::VARCHAR,
    COALESCE(s.phone, s.mobile)::VARCHAR AS phone,
    s.image::VARCHAR,
    s.is_admin,
    s.is_locked,
    s.is_deleted,
    s.department_id,
    s.unit_id,
    p.name::VARCHAR   AS position_name,
    d.name::VARCHAR   AS department_name,
    u.name::VARCHAR   AS unit_name,
    COALESCE(
      (SELECT string_agg(r.name, ',')
       FROM public.role_of_staff ros
       JOIN public.roles r ON r.id = ros.role_id
       WHERE ros.staff_id = s.id),
      ''
    )::TEXT AS roles
  FROM public.staff s
  LEFT JOIN public.positions p ON p.id = s.position_id
  LEFT JOIN public.departments d ON d.id = s.department_id
  LEFT JOIN public.departments u ON u.id = s.unit_id
  WHERE s.username = p_username;
END;
$$;


--
-- Name: fn_auth_logout(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_auth_logout(p_token_hash character varying) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE public.refresh_tokens
  SET revoked_at = NOW()
  WHERE token_hash = p_token_hash AND revoked_at IS NULL;
END;
$$;


--
-- Name: fn_auth_logout_all(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_auth_logout_all(p_staff_id integer) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE public.refresh_tokens
  SET revoked_at = NOW()
  WHERE staff_id = p_staff_id AND revoked_at IS NULL;
END;
$$;


--
-- Name: fn_auth_save_refresh_token(integer, character varying, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_auth_save_refresh_token(p_staff_id integer, p_token_hash character varying, p_expires_at timestamp with time zone) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- Revoke tất cả refresh token cũ của user (single session)
  UPDATE public.refresh_tokens
  SET revoked_at = NOW()
  WHERE staff_id = p_staff_id AND revoked_at IS NULL;

  -- Tạo token mới
  INSERT INTO public.refresh_tokens (staff_id, token_hash, expires_at)
  VALUES (p_staff_id, p_token_hash, p_expires_at);
END;
$$;


--
-- Name: fn_auth_verify_refresh_token(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_auth_verify_refresh_token(p_token_hash character varying) RETURNS TABLE(staff_id integer, username character varying, full_name character varying, email character varying, phone character varying, image character varying, is_admin boolean, is_locked boolean, is_deleted boolean, department_id integer, unit_id integer, position_name character varying, department_name character varying, unit_name character varying, roles text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    s.id              AS staff_id,
    s.username,
    s.full_name::VARCHAR,
    s.email::VARCHAR,
    COALESCE(s.phone, s.mobile)::VARCHAR AS phone,
    s.image::VARCHAR,
    s.is_admin,
    s.is_locked,
    s.is_deleted,
    s.department_id,
    s.unit_id,
    p.name::VARCHAR   AS position_name,
    d.name::VARCHAR   AS department_name,
    u.name::VARCHAR   AS unit_name,
    COALESCE(
      (SELECT string_agg(r.name, ',')
       FROM public.role_of_staff ros
       JOIN public.roles r ON r.id = ros.role_id
       WHERE ros.staff_id = s.id),
      ''
    )::TEXT AS roles
  FROM public.refresh_tokens rt
  JOIN public.staff s ON s.id = rt.staff_id
  LEFT JOIN public.positions p ON p.id = s.position_id
  LEFT JOIN public.departments d ON d.id = s.department_id
  LEFT JOIN public.departments u ON u.id = s.unit_id
  WHERE rt.token_hash = p_token_hash
    AND rt.revoked_at IS NULL
    AND rt.expires_at > NOW();
END;
$$;


--
-- Name: fn_calendar_event_create(character varying, text, timestamp without time zone, timestamp without time zone, boolean, character varying, character varying, character varying, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_calendar_event_create(p_title character varying, p_description text, p_start_time timestamp without time zone, p_end_time timestamp without time zone, p_all_day boolean, p_color character varying, p_repeat_type character varying, p_scope character varying, p_unit_id integer, p_created_by integer) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_new_id BIGINT;
BEGIN
  -- Validate title
  IF p_title IS NULL OR TRIM(p_title) = '' THEN
    RETURN QUERY SELECT FALSE, 'Tiêu đề sự kiện là bắt buộc'::TEXT, NULL::BIGINT;
    RETURN;
  END IF;
  -- Validate times
  IF p_end_time < p_start_time THEN
    RETURN QUERY SELECT FALSE, 'Thời gian kết thúc phải sau thời gian bắt đầu'::TEXT, NULL::BIGINT;
    RETURN;
  END IF;
  -- Validate scope
  IF p_scope NOT IN ('personal', 'unit', 'leader') THEN
    RETURN QUERY SELECT FALSE, 'Phạm vi sự kiện không hợp lệ'::TEXT, NULL::BIGINT;
    RETURN;
  END IF;

  INSERT INTO public.calendar_events (
    title, description, start_time, end_time, all_day,
    color, repeat_type, scope, unit_id, created_by
  ) VALUES (
    TRIM(p_title), p_description,
    p_start_time, p_end_time, COALESCE(p_all_day, FALSE),
    COALESCE(p_color, '#1B3A5C'), COALESCE(p_repeat_type, 'none'),
    p_scope, p_unit_id, p_created_by
  ) RETURNING calendar_events.id INTO v_new_id;

  RETURN QUERY SELECT TRUE, 'Tạo sự kiện thành công'::TEXT, v_new_id;
END;
$$;


--
-- Name: fn_calendar_event_delete(bigint, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_calendar_event_delete(p_id bigint, p_staff_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_event public.calendar_events%ROWTYPE;
BEGIN
  SELECT * INTO v_event FROM public.calendar_events WHERE id = p_id AND is_deleted = FALSE;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy sự kiện'::TEXT;
    RETURN;
  END IF;
  -- Ownership check for personal scope
  IF v_event.scope = 'personal' AND v_event.created_by != p_staff_id THEN
    RETURN QUERY SELECT FALSE, 'Bạn không có quyền xóa sự kiện này'::TEXT;
    RETURN;
  END IF;

  UPDATE public.calendar_events SET is_deleted = TRUE, updated_at = NOW() WHERE id = p_id;
  RETURN QUERY SELECT TRUE, 'Xóa sự kiện thành công'::TEXT;
END;
$$;


--
-- Name: fn_calendar_event_get_by_id(bigint); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_calendar_event_get_by_id(p_id bigint) RETURNS TABLE(id bigint, title character varying, description text, start_time timestamp without time zone, end_time timestamp without time zone, all_day boolean, color character varying, repeat_type character varying, scope character varying, unit_id integer, created_by integer, creator_name character varying, created_at timestamp without time zone, updated_at timestamp without time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    ce.id,
    ce.title,
    ce.description,
    ce.start_time,
    ce.end_time,
    ce.all_day,
    ce.color,
    ce.repeat_type,
    ce.scope,
    ce.unit_id,
    ce.created_by,
    (s.last_name || ' ' || s.first_name)::VARCHAR AS creator_name,
    ce.created_at,
    ce.updated_at
  FROM public.calendar_events ce
  LEFT JOIN public.staff s ON s.id = ce.created_by
  WHERE ce.id = p_id
    AND ce.is_deleted = FALSE;
END;
$$;


--
-- Name: fn_calendar_event_get_list(character varying, integer, integer, timestamp without time zone, timestamp without time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_calendar_event_get_list(p_scope character varying, p_unit_id integer, p_staff_id integer, p_start timestamp without time zone, p_end timestamp without time zone) RETURNS TABLE(id bigint, title character varying, description text, start_time timestamp without time zone, end_time timestamp without time zone, all_day boolean, color character varying, repeat_type character varying, scope character varying, unit_id integer, created_by integer, creator_name character varying, created_at timestamp without time zone, updated_at timestamp without time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    ce.id,
    ce.title,
    ce.description,
    ce.start_time,
    ce.end_time,
    ce.all_day,
    ce.color,
    ce.repeat_type,
    ce.scope,
    ce.unit_id,
    ce.created_by,
    (s.last_name || ' ' || s.first_name)::VARCHAR AS creator_name,
    ce.created_at,
    ce.updated_at
  FROM public.calendar_events ce
  LEFT JOIN public.staff s ON s.id = ce.created_by
  WHERE ce.is_deleted = FALSE
    AND ce.scope = p_scope
    AND (
      CASE
        WHEN p_scope = 'personal' THEN ce.created_by = p_staff_id
        ELSE ce.unit_id = p_unit_id
      END
    )
    AND ce.start_time >= p_start
    AND ce.start_time <= p_end
  ORDER BY ce.start_time ASC;
END;
$$;


--
-- Name: fn_calendar_event_update(bigint, character varying, text, timestamp without time zone, timestamp without time zone, boolean, character varying, character varying, character varying, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_calendar_event_update(p_id bigint, p_title character varying, p_description text, p_start_time timestamp without time zone, p_end_time timestamp without time zone, p_all_day boolean, p_color character varying, p_repeat_type character varying, p_scope character varying, p_unit_id integer, p_staff_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_event public.calendar_events%ROWTYPE;
BEGIN
  SELECT * INTO v_event FROM public.calendar_events WHERE id = p_id AND is_deleted = FALSE;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy sự kiện'::TEXT;
    RETURN;
  END IF;
  -- Ownership check for personal scope
  IF v_event.scope = 'personal' AND v_event.created_by != p_staff_id THEN
    RETURN QUERY SELECT FALSE, 'Bạn không có quyền chỉnh sửa sự kiện này'::TEXT;
    RETURN;
  END IF;
  -- Validate times
  IF p_end_time < p_start_time THEN
    RETURN QUERY SELECT FALSE, 'Thời gian kết thúc phải sau thời gian bắt đầu'::TEXT;
    RETURN;
  END IF;

  UPDATE public.calendar_events SET
    title       = TRIM(p_title),
    description = p_description,
    start_time  = p_start_time,
    end_time    = p_end_time,
    all_day     = COALESCE(p_all_day, FALSE),
    color       = COALESCE(p_color, '#1B3A5C'),
    repeat_type = COALESCE(p_repeat_type, 'none'),
    scope       = p_scope,
    unit_id     = p_unit_id,
    updated_at  = NOW()
  WHERE id = p_id;

  RETURN QUERY SELECT TRUE, 'Cập nhật sự kiện thành công'::TEXT;
END;
$$;


--
-- Name: fn_commune_create(integer, character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_commune_create(p_district_id integer, p_name character varying, p_code character varying DEFAULT NULL::character varying) RETURNS TABLE(success boolean, message text, id integer)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id INT;
BEGIN
  IF p_name IS NULL OR TRIM(p_name) = '' THEN
    RETURN QUERY SELECT FALSE, 'Tên phường/xã không được để trống'::TEXT, 0;
    RETURN;
  END IF;
  IF NOT EXISTS(SELECT 1 FROM public.districts ds WHERE ds.id = p_district_id) THEN
    RETURN QUERY SELECT FALSE, 'Quận/huyện không tồn tại'::TEXT, 0;
    RETURN;
  END IF;
  IF p_code IS NOT NULL AND LENGTH(p_code) > 10 THEN
    RETURN QUERY SELECT FALSE, 'Mã phường/xã không được vượt quá 10 ký tự'::TEXT, 0;
    RETURN;
  END IF;

  -- Check unique code within district
  IF p_code IS NOT NULL AND EXISTS(
    SELECT 1 FROM public.communes
    WHERE district_id = p_district_id AND LOWER(TRIM(code)) = LOWER(TRIM(p_code))
  ) THEN
    RETURN QUERY SELECT FALSE, 'Mã phường/xã đã tồn tại trong quận/huyện'::TEXT, 0;
    RETURN;
  END IF;

  INSERT INTO public.communes (district_id, name, code)
  VALUES (p_district_id, TRIM(p_name), TRIM(p_code))
  RETURNING communes.id INTO v_id;

  RETURN QUERY SELECT TRUE, 'Tao phuong/xa thanh cong'::TEXT, v_id;
END;
$$;


--
-- Name: fn_commune_delete(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_commune_delete(p_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NOT EXISTS(SELECT 1 FROM public.communes WHERE id = p_id) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy phường/xã'::TEXT;
    RETURN;
  END IF;

  DELETE FROM public.communes WHERE id = p_id;
  RETURN QUERY SELECT TRUE, 'Xoa phuong/xa thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_commune_get_list(integer, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_commune_get_list(p_district_id integer DEFAULT NULL::integer, p_keyword character varying DEFAULT NULL::character varying) RETURNS TABLE(id integer, district_id integer, name character varying, code character varying, is_active boolean)
    LANGUAGE sql STABLE
    AS $$
  SELECT c.id, c.district_id, c.name::VARCHAR, c.code::VARCHAR, c.is_active
  FROM public.communes c
  WHERE (p_district_id IS NULL OR c.district_id = p_district_id)
    AND (p_keyword IS NULL OR c.name ILIKE '%' || p_keyword || '%'
         OR c.code ILIKE '%' || p_keyword || '%')
  ORDER BY c.name;
$$;


--
-- Name: fn_commune_update(integer, character varying, character varying, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_commune_update(p_id integer, p_name character varying, p_code character varying DEFAULT NULL::character varying, p_is_active boolean DEFAULT true) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_district_id INT;
BEGIN
  SELECT district_id INTO v_district_id FROM public.communes WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy phường/xã'::TEXT;
    RETURN;
  END IF;
  IF p_name IS NULL OR TRIM(p_name) = '' THEN
    RETURN QUERY SELECT FALSE, 'Tên phường/xã không được để trống'::TEXT;
    RETURN;
  END IF;

  -- Check unique code (exclude self)
  IF p_code IS NOT NULL AND EXISTS(
    SELECT 1 FROM public.communes
    WHERE district_id = v_district_id AND LOWER(TRIM(code)) = LOWER(TRIM(p_code))
      AND id <> p_id
  ) THEN
    RETURN QUERY SELECT FALSE, 'Mã phường/xã đã tồn tại trong quận/huyện'::TEXT;
    RETURN;
  END IF;

  UPDATE public.communes SET name = TRIM(p_name), code = TRIM(p_code), is_active = p_is_active WHERE id = p_id;
  RETURN QUERY SELECT TRUE, 'Cap nhat thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_config_get_list(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_config_get_list(p_unit_id integer DEFAULT NULL::integer) RETURNS TABLE(id integer, unit_id integer, key character varying, value text, description text)
    LANGUAGE sql STABLE
    AS $$
  SELECT c.id, c.unit_id, c.key::VARCHAR, c.value, c.description
  FROM public.configurations c
  WHERE (p_unit_id IS NULL OR c.unit_id = p_unit_id)
  ORDER BY c.key;
$$;


--
-- Name: fn_config_upsert(integer, character varying, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_config_upsert(p_unit_id integer, p_key character varying, p_value text DEFAULT NULL::text, p_description text DEFAULT NULL::text) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF p_key IS NULL OR TRIM(p_key) = '' THEN
    RETURN QUERY SELECT FALSE, 'Key cấu hình không được để trống'::TEXT;
    RETURN;
  END IF;
  IF LENGTH(p_key) > 100 THEN
    RETURN QUERY SELECT FALSE, 'Key cấu hình không được vượt quá 100 ký tự'::TEXT;
    RETURN;
  END IF;

  INSERT INTO public.configurations (unit_id, key, value, description)
  VALUES (p_unit_id, TRIM(p_key), p_value, p_description)
  ON CONFLICT (unit_id, key) DO UPDATE SET
    value       = EXCLUDED.value,
    description = COALESCE(EXCLUDED.description, configurations.description);

  RETURN QUERY SELECT TRUE, 'Cap nhat cau hinh thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_department_create(integer, character varying, character varying, character varying, character varying, character varying, boolean, integer, integer, character varying, character varying, character varying, text, boolean, text, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_department_create(p_parent_id integer, p_code character varying, p_name character varying, p_name_en character varying, p_short_name character varying, p_abb_name character varying, p_is_unit boolean, p_level integer, p_sort_order integer, p_phone character varying, p_fax character varying, p_email character varying, p_address text, p_allow_doc_book boolean, p_description text, p_created_by integer) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE v_id INT;
BEGIN
  INSERT INTO public.departments (
    parent_id, code, name, name_en, short_name, abb_name, is_unit,
    level, sort_order, phone, fax, email, address, allow_doc_book,
    description, created_by
  ) VALUES (
    p_parent_id, p_code, p_name, p_name_en, p_short_name, p_abb_name, p_is_unit,
    p_level, p_sort_order, p_phone, p_fax, p_email, p_address, p_allow_doc_book,
    p_description, p_created_by
  ) RETURNING id INTO v_id;
  RETURN v_id;
END;
$$;


--
-- Name: fn_department_delete(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_department_delete(p_id integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_staff_count INT; v_child_count INT;
BEGIN
  SELECT COUNT(*) INTO v_child_count FROM public.departments WHERE parent_id = p_id AND is_deleted = FALSE;
  IF v_child_count > 0 THEN
    RETURN QUERY SELECT FALSE, 'Không thể xóa: còn '|| v_child_count ||' phòng ban con';
    RETURN;
  END IF;

  SELECT COUNT(*) INTO v_staff_count FROM public.staff WHERE department_id = p_id AND is_deleted = FALSE;
  IF v_staff_count > 0 THEN
    RETURN QUERY SELECT FALSE, 'Không thể xóa: còn '|| v_staff_count ||' nhân viên thuộc phòng ban này';
    RETURN;
  END IF;

  UPDATE public.departments SET is_deleted = TRUE WHERE id = p_id;
  RETURN QUERY SELECT TRUE, 'Xóa thành công'::TEXT;
END;
$$;


--
-- Name: fn_department_get_by_id(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_department_get_by_id(p_id integer) RETURNS TABLE(id integer, parent_id integer, code character varying, name character varying, name_en character varying, short_name character varying, abb_name character varying, is_unit boolean, level integer, sort_order integer, phone character varying, fax character varying, email character varying, address text, allow_doc_book boolean, description text, is_locked boolean, lgsp_system_id character varying, lgsp_secret_key character varying, created_at timestamp with time zone, updated_at timestamp with time zone)
    LANGUAGE sql STABLE
    AS $$
  SELECT d.id, d.parent_id, d.code::VARCHAR, d.name::VARCHAR, d.name_en::VARCHAR,
    d.short_name::VARCHAR, d.abb_name::VARCHAR, d.is_unit, d.level,
    d.sort_order, d.phone::VARCHAR, d.fax::VARCHAR, d.email::VARCHAR, d.address,
    d.allow_doc_book, d.description, d.is_locked,
    d.lgsp_system_id::VARCHAR, d.lgsp_secret_key::VARCHAR,
    d.created_at, d.updated_at
  FROM public.departments d WHERE d.id = p_id AND d.is_deleted = FALSE;
$$;


--
-- Name: fn_department_get_tree(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_department_get_tree(p_unit_id integer DEFAULT NULL::integer) RETURNS TABLE(id integer, parent_id integer, code character varying, name character varying, name_en character varying, short_name character varying, abb_name character varying, is_unit boolean, level integer, sort_order integer, phone character varying, fax character varying, email character varying, address text, allow_doc_book boolean, is_locked boolean, staff_count bigint)
    LANGUAGE sql STABLE
    AS $$
  SELECT
    d.id, d.parent_id, d.code::VARCHAR, d.name::VARCHAR, d.name_en::VARCHAR,
    d.short_name::VARCHAR, d.abb_name::VARCHAR, d.is_unit, d.level,
    d.sort_order, d.phone::VARCHAR, d.fax::VARCHAR, d.email::VARCHAR, d.address,
    d.allow_doc_book, d.is_locked,
    (SELECT COUNT(*) FROM public.staff s WHERE s.department_id = d.id AND s.is_deleted = FALSE) AS staff_count
  FROM public.departments d
  WHERE d.is_deleted = FALSE
    AND (p_unit_id IS NULL OR d.id = p_unit_id OR d.parent_id = p_unit_id
         OR d.parent_id IN (SELECT dd.id FROM public.departments dd WHERE dd.parent_id = p_unit_id AND dd.is_deleted = FALSE))
  ORDER BY d.sort_order, d.name;
$$;


