--

CREATE OR REPLACE FUNCTION public.fn_department_update(p_id integer, p_parent_id integer, p_code character varying, p_name character varying, p_name_en character varying, p_short_name character varying, p_abb_name character varying, p_is_unit boolean, p_level integer, p_sort_order integer, p_phone character varying, p_fax character varying, p_email character varying, p_address text, p_allow_doc_book boolean, p_description text, p_updated_by integer) RETURNS boolean
