CREATE OR REPLACE FUNCTION public.fn_position_get_by_id(p_id integer) RETURNS TABLE(id integer, name character varying, code character varying, sort_order integer, description text, is_active boolean, is_leader boolean, is_handle_document boolean)
    LANGUAGE sql STABLE
    AS $$
  SELECT p.id, p.name::VARCHAR, p.code::VARCHAR, p.sort_order, p.description, p.is_active, p.is_leader, p.is_handle_document
