    LANGUAGE plpgsql
    AS $$
DECLARE v_id INT;
BEGIN
  INSERT INTO public.rights (parent_id, name, name_of_menu, action_link, icon,
    sort_order, show_menu, default_page, show_in_app, description)
  VALUES (p_parent_id, p_name, p_name_of_menu, p_action_link, p_icon,
