    LANGUAGE sql STABLE
    AS $$
  SELECT r.id, r.parent_id, r.name::VARCHAR, r.name_of_menu::VARCHAR,
    r.action_link::VARCHAR, r.icon::VARCHAR, r.sort_order,
    r.show_menu, r.default_page, r.show_in_app,
    r.description, r.is_locked
  FROM public.rights r WHERE r.id = p_id;
$$;


--
-- Name: fn_right_get_by_staff(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_right_get_by_staff(p_staff_id integer) RETURNS TABLE(id integer, parent_id integer, name character varying, name_of_menu character varying, action_link character varying, icon character varying, sort_order integer, show_menu boolean, default_page boolean, show_in_app boolean)
    LANGUAGE sql STABLE
    AS $$
  SELECT r.id, r.parent_id, r.name::VARCHAR, r.name_of_menu::VARCHAR,
    r.action_link::VARCHAR, r.icon::VARCHAR, r.sort_order,
    r.show_menu, r.default_page, r.show_in_app
  FROM public.rights r
  WHERE r.show_menu = TRUE
    AND (
      EXISTS (
        SELECT 1 FROM public.action_of_role aor
        JOIN public.role_of_staff ros ON ros.role_id = aor.role_id
        WHERE aor.right_id = r.id AND ros.staff_id = p_staff_id
      )
      OR EXISTS (
        SELECT 1 FROM public.staff s WHERE s.id = p_staff_id AND s.is_admin = TRUE
      )
    )
  ORDER BY r.sort_order, r.name;
$$;


--
-- Name: fn_right_get_tree(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_right_get_tree() RETURNS TABLE(id integer, parent_id integer, name character varying, name_of_menu character varying, action_link character varying, icon character varying, sort_order integer, show_menu boolean, default_page boolean, show_in_app boolean, description text, is_locked boolean)
    LANGUAGE sql STABLE
    AS $$
  SELECT r.id, r.parent_id, r.name::VARCHAR, r.name_of_menu::VARCHAR,
    r.action_link::VARCHAR, r.icon::VARCHAR, r.sort_order,
    r.show_menu, r.default_page, r.show_in_app,
    r.description, r.is_locked
  FROM public.rights r
  ORDER BY r.sort_order, r.name;
$$;


