-- Name: fn_role_create(integer, character varying, text, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_role_create(p_unit_id integer, p_name character varying, p_description text, p_created_by integer) RETURNS integer
    LANGUAGE plpgsql
    AS $$
