--
-- Name: fn_signing_provider_config_list(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_signing_provider_config_list() RETURNS TABLE(id bigint, provider_code character varying, provider_name character varying, base_url character varying, client_id character varying, profile_id character varying, extra_config jsonb, is_active boolean, last_tested_at timestamp with time zone, test_result text, created_at timestamp with time zone, updated_at timestamp with time zone)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
  RETURN QUERY
    SELECT c.id, c.provider_code, c.provider_name, c.base_url, c.client_id,
           c.profile_id, c.extra_config, c.is_active, c.last_tested_at, c.test_result,
           c.created_at, c.updated_at
    FROM public.signing_provider_config c
    ORDER BY c.is_active DESC, c.provider_code ASC;
END;
$$;


--
-- Name: fn_signing_provider_config_set_active(character varying, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_signing_provider_config_set_active(p_provider_code character varying, p_updated_by integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
DECLARE v_exists BOOLEAN;
BEGIN
  SELECT EXISTS(SELECT 1 FROM public.signing_provider_config WHERE provider_code = p_provider_code)
    INTO v_exists;
  IF NOT v_exists THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy provider'::TEXT; RETURN;
  END IF;

  -- Deactivate all (respects partial unique index)
  UPDATE public.signing_provider_config
    SET is_active = FALSE, updated_at = NOW(), updated_by = p_updated_by
    WHERE is_active = TRUE;

  -- Activate chosen
  UPDATE public.signing_provider_config
    SET is_active = TRUE, updated_at = NOW(), updated_by = p_updated_by
    WHERE provider_code = p_provider_code;

  RETURN QUERY SELECT TRUE, 'Kích hoạt provider thành công'::TEXT;
END;
$$;


--
-- Name: fn_signing_provider_config_upsert(character varying, character varying, character varying, character varying, bytea, character varying, jsonb, timestamp with time zone, text, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_signing_provider_config_upsert(p_provider_code character varying, p_provider_name character varying, p_base_url character varying, p_client_id character varying, p_client_secret bytea, p_profile_id character varying, p_extra_config jsonb, p_last_tested_at timestamp with time zone, p_test_result text, p_updated_by integer) RETURNS TABLE(success boolean, message text, id bigint)
    LANGUAGE plpgsql
    AS $$
DECLARE v_id BIGINT;
BEGIN
  INSERT INTO public.signing_provider_config (
    provider_code, provider_name, base_url, client_id, client_secret,
    profile_id, extra_config, last_tested_at, test_result, created_by, updated_by
  )
  VALUES (
    p_provider_code, p_provider_name, p_base_url, p_client_id, p_client_secret,
    p_profile_id, COALESCE(p_extra_config, '{}'::jsonb), p_last_tested_at, p_test_result, p_updated_by, p_updated_by
  )
  ON CONFLICT (provider_code) DO UPDATE SET
    provider_name   = EXCLUDED.provider_name,
    base_url        = EXCLUDED.base_url,
    client_id       = EXCLUDED.client_id,
    client_secret   = EXCLUDED.client_secret,
    profile_id      = EXCLUDED.profile_id,
    extra_config    = EXCLUDED.extra_config,
    last_tested_at  = EXCLUDED.last_tested_at,
    test_result     = EXCLUDED.test_result,
    updated_by      = EXCLUDED.updated_by,
    updated_at      = NOW()
  RETURNING public.signing_provider_config.id INTO v_id;

  RETURN QUERY SELECT TRUE, 'Lưu cấu hình provider thành công'::TEXT, v_id;
END;
$$;


--
-- Name: fn_signing_stats(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_signing_stats(p_provider_code character varying) RETURNS TABLE(total_users integer, verified_users integer, monthly_transactions integer, monthly_completed integer, monthly_failed integer)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    COALESCE((
      SELECT COUNT(*)::INT
        FROM public.staff_signing_config
       WHERE provider_code = p_provider_code
    ), 0),
    COALESCE((
      SELECT COUNT(*)::INT
        FROM public.staff_signing_config
       WHERE provider_code = p_provider_code
         AND is_verified = TRUE
    ), 0),
    COALESCE((
      SELECT COUNT(*)::INT
        FROM edoc.sign_transactions
       WHERE provider_code = p_provider_code
         AND created_at >= date_trunc('month', NOW())
    ), 0),
    COALESCE((
      SELECT COUNT(*)::INT
        FROM edoc.sign_transactions
       WHERE provider_code = p_provider_code
         AND "status" = 'completed'
         AND created_at >= date_trunc('month', NOW())
    ), 0),
    COALESCE((
      SELECT COUNT(*)::INT
        FROM edoc.sign_transactions
       WHERE provider_code = p_provider_code
         AND "status" IN ('failed', 'expired', 'cancelled')
         AND created_at >= date_trunc('month', NOW())
    ), 0);
END;
$$;


