  RETURN FOUND;
END;
$$;


--
-- Name: fn_staff_generate_code(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_staff_generate_code() RETURNS character varying
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN 'NV' || LPAD(nextval('seq_staff_code')::TEXT, 6, '0');
END;
$$;


--
-- Name: fn_staff_get_by_id(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_staff_get_by_id(p_id integer) RETURNS TABLE(id integer, code character varying, username character varying, full_name character varying, first_name character varying, last_name character varying, email character varying, phone character varying, mobile character varying, image character varying, gender smallint, birth_date date, address text, id_card character varying, id_card_date date, id_card_place character varying, department_id integer, department_name character varying, unit_id integer, unit_name character varying, position_id integer, position_name character varying, is_admin boolean, is_locked boolean, is_represent_unit boolean, is_represent_department boolean, password_changed boolean, sign_phone character varying, sign_ca text, sign_image character varying, last_login_at timestamp with time zone, created_at timestamp with time zone, roles text)
    LANGUAGE sql STABLE
    AS $$
  SELECT
    s.id, s.code::VARCHAR, s.username::VARCHAR, s.full_name::VARCHAR, s.first_name::VARCHAR, s.last_name::VARCHAR,
    s.email::VARCHAR, s.phone::VARCHAR, s.mobile::VARCHAR, s.image::VARCHAR,
    s.gender, s.birth_date, s.address,
    s.id_card::VARCHAR, s.id_card_date, s.id_card_place::VARCHAR,
    s.department_id, d.name::VARCHAR, s.unit_id, u.name::VARCHAR,
    s.position_id, p.name::VARCHAR,
    s.is_admin, s.is_locked, s.is_represent_unit, s.is_represent_department,
    s.password_changed,
    s.sign_phone::VARCHAR, s.sign_ca, s.sign_image::VARCHAR,
    s.last_login_at, s.created_at,
    COALESCE((SELECT string_agg(r.name, ',') FROM public.role_of_staff ros JOIN public.roles r ON r.id = ros.role_id WHERE ros.staff_id = s.id), '')::TEXT AS roles
  FROM public.staff s
  LEFT JOIN public.departments d ON d.id = s.department_id
  LEFT JOIN public.departments u ON u.id = s.unit_id
  LEFT JOIN public.positions p ON p.id = s.position_id
  WHERE s.id = p_id AND s.is_deleted = FALSE;
$$;


--
-- Name: fn_staff_get_list(integer, integer, character varying, boolean, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_staff_get_list(p_unit_id integer DEFAULT NULL::integer, p_department_id integer DEFAULT NULL::integer, p_keyword character varying DEFAULT NULL::character varying, p_is_locked boolean DEFAULT NULL::boolean, p_page integer DEFAULT 1, p_page_size integer DEFAULT 20) RETURNS TABLE(id integer, code character varying, username character varying, full_name character varying, first_name character varying, last_name character varying, email character varying, phone character varying, image character varying, gender smallint, department_id integer, department_name character varying, unit_id integer, unit_name character varying, position_id integer, position_name character varying, is_admin boolean, is_locked boolean, is_represent_unit boolean, is_represent_department boolean, password_changed boolean, last_login_at timestamp with time zone, created_at timestamp with time zone, total_count bigint)
    LANGUAGE sql STABLE
    AS $$
  SELECT
    s.id, s.code::VARCHAR, s.username::VARCHAR, s.full_name::VARCHAR, s.first_name::VARCHAR, s.last_name::VARCHAR,
    s.email::VARCHAR, COALESCE(s.phone, s.mobile)::VARCHAR AS phone, s.image::VARCHAR, s.gender,
    s.department_id, d.name::VARCHAR AS department_name,
    s.unit_id, u.name::VARCHAR AS unit_name,
    s.position_id, p.name::VARCHAR AS position_name,
    s.is_admin, s.is_locked, s.is_represent_unit, s.is_represent_department,
    s.password_changed,
    s.last_login_at, s.created_at,
    COUNT(*) OVER() AS total_count
  FROM public.staff s
  LEFT JOIN public.departments d ON d.id = s.department_id
  LEFT JOIN public.departments u ON u.id = s.unit_id
  LEFT JOIN public.positions p ON p.id = s.position_id
  WHERE s.is_deleted = FALSE
    AND (p_unit_id IS NULL OR s.unit_id = p_unit_id)
    AND (p_department_id IS NULL OR s.department_id = p_department_id)
    AND (p_keyword IS NULL OR s.full_name ILIKE '%' || p_keyword || '%'
         OR s.username ILIKE '%' || p_keyword || '%'
         OR s.email ILIKE '%' || p_keyword || '%'
         OR s.code ILIKE '%' || p_keyword || '%')
    AND (p_is_locked IS NULL OR s.is_locked = p_is_locked)
  ORDER BY s.last_name, s.first_name
  OFFSET (p_page - 1) * p_page_size LIMIT p_page_size;
$$;


--
-- Name: fn_staff_get_roles(integer); Type: FUNCTION; Schema: public; Owner: -
