--
-- Name: fn_staff_signing_config_list_by_staff(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_staff_signing_config_list_by_staff(p_staff_id integer) RETURNS TABLE(staff_id integer, provider_code character varying, user_id character varying, credential_id character varying, certificate_subject character varying, certificate_serial character varying, is_verified boolean, last_verified_at timestamp with time zone, last_error text, created_at timestamp with time zone, updated_at timestamp with time zone)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
  RETURN QUERY
    SELECT c.staff_id, c.provider_code, c.user_id, c.credential_id,
           c.certificate_subject, c.certificate_serial, c.is_verified,
           c.last_verified_at, c.last_error, c.created_at, c.updated_at
    FROM public.staff_signing_config c
    WHERE c.staff_id = p_staff_id
    ORDER BY c.provider_code;
END;
$$;


--
-- Name: fn_staff_signing_config_upsert(integer, character varying, character varying, character varying, text, character varying, character varying, boolean, timestamp with time zone, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_staff_signing_config_upsert(p_staff_id integer, p_provider_code character varying, p_user_id character varying, p_credential_id character varying, p_certificate_data text, p_certificate_subject character varying, p_certificate_serial character varying, p_is_verified boolean, p_last_verified_at timestamp with time zone, p_last_error text) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  INSERT INTO public.staff_signing_config (
    staff_id, provider_code, user_id, credential_id, certificate_data,
    certificate_subject, certificate_serial, is_verified, last_verified_at, last_error
  )
  VALUES (
    p_staff_id, p_provider_code, p_user_id, p_credential_id, p_certificate_data,
    p_certificate_subject, p_certificate_serial, COALESCE(p_is_verified, FALSE),
    p_last_verified_at, p_last_error
  )
  ON CONFLICT (staff_id, provider_code) DO UPDATE SET
    user_id             = EXCLUDED.user_id,
    credential_id       = EXCLUDED.credential_id,
    certificate_data    = COALESCE(EXCLUDED.certificate_data, public.staff_signing_config.certificate_data),
    certificate_subject = COALESCE(EXCLUDED.certificate_subject, public.staff_signing_config.certificate_subject),
    certificate_serial  = COALESCE(EXCLUDED.certificate_serial, public.staff_signing_config.certificate_serial),
    is_verified         = EXCLUDED.is_verified,
    last_verified_at    = EXCLUDED.last_verified_at,
    last_error          = EXCLUDED.last_error,
    updated_at          = NOW();

  RETURN QUERY SELECT TRUE, 'Lưu cấu hình ký số cá nhân thành công'::TEXT;
END;
$$;


--
-- Name: fn_staff_toggle_lock(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_staff_toggle_lock(p_id integer) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE public.staff SET is_locked = NOT is_locked WHERE id = p_id AND is_deleted = FALSE;
  RETURN FOUND;
END;
$$;


--
-- Name: fn_staff_update(integer, integer, integer, integer, character varying, character varying, smallint, date, character varying, character varying, character varying, text, character varying, date, character varying, boolean, boolean, boolean, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_staff_update(p_id integer, p_department_id integer, p_unit_id integer, p_position_id integer, p_first_name character varying, p_last_name character varying, p_gender smallint, p_birth_date date, p_email character varying, p_phone character varying, p_mobile character varying, p_address text, p_id_card character varying, p_id_card_date date, p_id_card_place character varying, p_is_admin boolean, p_is_represent_unit boolean, p_is_represent_department boolean, p_updated_by integer) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE public.staff SET
    department_id = p_department_id, unit_id = p_unit_id, position_id = p_position_id,
    first_name = p_first_name, last_name = p_last_name, gender = p_gender,
    birth_date = p_birth_date, email = p_email, phone = p_phone, mobile = p_mobile,
    address = p_address, id_card = p_id_card, id_card_date = p_id_card_date,
    id_card_place = p_id_card_place, is_admin = p_is_admin,
    is_represent_unit = p_is_represent_unit, is_represent_department = p_is_represent_department,
    updated_by = p_updated_by
  WHERE id = p_id AND is_deleted = FALSE;
  RETURN FOUND;
END;
$$;


--
-- Name: fn_staff_update_avatar(integer, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_staff_update_avatar(p_id integer, p_image_path character varying) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE public.staff SET image = p_image_path WHERE id = p_id AND is_deleted = FALSE;
  RETURN FOUND;
END;
$$;


--
-- Name: fn_update_timestamp(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_update_timestamp() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$;


--
-- Name: fn_work_calendar_get(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_work_calendar_get(p_year integer) RETURNS TABLE(id integer, date date, description character varying, is_holiday boolean, created_by integer, created_at timestamp with time zone)
    LANGUAGE sql STABLE
    AS $$
  SELECT wc.id, wc.date, wc.description::VARCHAR, wc.is_holiday,
         wc.created_by, wc.created_at
  FROM public.work_calendar wc
  WHERE EXTRACT(YEAR FROM wc.date) = p_year
  ORDER BY wc.date;
$$;


--
-- Name: fn_work_calendar_remove_holiday(date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_work_calendar_remove_holiday(p_date date) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NOT EXISTS(SELECT 1 FROM public.work_calendar WHERE date = p_date) THEN
    RETURN QUERY SELECT FALSE, 'Không tìm thấy ngày nghỉ'::TEXT;
    RETURN;
  END IF;

  DELETE FROM public.work_calendar WHERE date = p_date;
  RETURN QUERY SELECT TRUE, 'Xoa ngay nghi thanh cong'::TEXT;
END;
$$;


--
-- Name: fn_work_calendar_set_holiday(date, character varying, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.fn_work_calendar_set_holiday(p_date date, p_description character varying DEFAULT NULL::character varying, p_created_by integer DEFAULT NULL::integer) RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF p_date IS NULL THEN
    RETURN QUERY SELECT FALSE, 'Ngày không được để trống'::TEXT;
    RETURN;
  END IF;
  IF p_description IS NOT NULL AND LENGTH(p_description) > 200 THEN
    RETURN QUERY SELECT FALSE, 'Mô tả không được vượt quá 200 ký tự'::TEXT;
    RETURN;
  END IF;

  INSERT INTO public.work_calendar (date, description, is_holiday, created_by)
  VALUES (p_date, p_description, TRUE, p_created_by)
  ON CONFLICT (date) DO UPDATE SET
    description = EXCLUDED.description,
    is_holiday  = TRUE,
    created_by  = EXCLUDED.created_by;

  RETURN QUERY SELECT TRUE, 'Cap nhat lich thanh cong'::TEXT;
END;
$$;


--
-- Name: sp_auth_cleanup_expired_tokens(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.sp_auth_cleanup_expired_tokens() RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_count INT;
BEGIN
  DELETE FROM public.refresh_tokens
  WHERE expires_at < NOW() OR revoked_at IS NOT NULL;

  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$$;


--
-- Name: sp_auth_get_me(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.sp_auth_get_me(p_staff_id integer) RETURNS TABLE(staff_id integer, username character varying, full_name character varying, email character varying, phone character varying, image character varying, is_admin boolean, gender smallint, birth_date date, address text, department_id integer, unit_id integer, position_id integer, position_name character varying, department_name character varying, unit_name character varying, roles text, last_login_at timestamp with time zone, created_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    s.id              AS staff_id,
    s.username,
    s.full_name::VARCHAR,
    s.email::VARCHAR,
    COALESCE(s.phone, s.mobile)::VARCHAR AS phone,
    s.image::VARCHAR,
    s.is_admin,
    s.gender,
    s.birth_date,
    s.address,
    s.department_id,
    s.unit_id,
    s.position_id,
    p.name::VARCHAR   AS position_name,
    d.name::VARCHAR   AS department_name,
    u.name::VARCHAR   AS unit_name,
    COALESCE(
      (SELECT string_agg(r.name, ',')
       FROM public.role_of_staff ros
       JOIN public.roles r ON r.id = ros.role_id
       WHERE ros.staff_id = s.id),
      ''
    )::TEXT AS roles,
    s.last_login_at,
    s.created_at
  FROM public.staff s
  LEFT JOIN public.positions p ON p.id = s.position_id
  LEFT JOIN public.departments d ON d.id = s.department_id
  LEFT JOIN public.departments u ON u.id = s.unit_id
  WHERE s.id = p_staff_id
    AND s.is_deleted = FALSE
    AND s.is_locked = FALSE;
END;
$$;


--
-- Name: sp_auth_log_login(integer, character varying, character varying, text, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.sp_auth_log_login(p_staff_id integer, p_username character varying, p_ip_address character varying, p_user_agent text, p_success boolean) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
  INSERT INTO public.login_history (staff_id, username, ip_address, user_agent, success)
  VALUES (p_staff_id, p_username, p_ip_address, p_user_agent, p_success);

  -- Cập nhật last_login_at nếu thành công
  IF p_success AND p_staff_id IS NOT NULL THEN
    UPDATE public.staff SET last_login_at = NOW() WHERE id = p_staff_id;
  END IF;
END;
$$;


--
-- Name: sp_auth_login(character varying, character varying, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.sp_auth_login(p_username character varying, p_ip_address character varying DEFAULT NULL::character varying, p_user_agent text DEFAULT NULL::text) RETURNS TABLE(staff_id integer, username character varying, password_hash character varying, full_name character varying, email character varying, phone character varying, image character varying, is_admin boolean, is_locked boolean, is_deleted boolean, department_id integer, unit_id integer, position_name character varying, department_name character varying, unit_name character varying, roles text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    s.id              AS staff_id,
    s.username,
    s.password_hash,
    s.full_name::VARCHAR,
    s.email::VARCHAR,
    COALESCE(s.phone, s.mobile)::VARCHAR AS phone,
    s.image::VARCHAR,
    s.is_admin,
    s.is_locked,
    s.is_deleted,
    s.department_id,
    s.unit_id,
    p.name::VARCHAR   AS position_name,
    d.name::VARCHAR   AS department_name,
    u.name::VARCHAR   AS unit_name,
    COALESCE(
      (SELECT string_agg(r.name, ',')
       FROM public.role_of_staff ros
       JOIN public.roles r ON r.id = ros.role_id
       WHERE ros.staff_id = s.id),
      ''
    )::TEXT AS roles
  FROM public.staff s
  LEFT JOIN public.positions p ON p.id = s.position_id
  LEFT JOIN public.departments d ON d.id = s.department_id
  LEFT JOIN public.departments u ON u.id = s.unit_id
  WHERE s.username = p_username;
END;
$$;


--
-- Name: sp_auth_logout(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.sp_auth_logout(p_token_hash character varying) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE public.refresh_tokens
  SET revoked_at = NOW()
  WHERE token_hash = p_token_hash AND revoked_at IS NULL;
END;
$$;


--
-- Name: sp_auth_logout_all(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.sp_auth_logout_all(p_staff_id integer) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
  UPDATE public.refresh_tokens
  SET revoked_at = NOW()
  WHERE staff_id = p_staff_id AND revoked_at IS NULL;
END;
$$;


--
-- Name: sp_auth_save_refresh_token(integer, character varying, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.sp_auth_save_refresh_token(p_staff_id integer, p_token_hash character varying, p_expires_at timestamp with time zone) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- Revoke tất cả refresh token cũ của user (single session)
  UPDATE public.refresh_tokens
  SET revoked_at = NOW()
  WHERE staff_id = p_staff_id AND revoked_at IS NULL;

  -- Tạo token mới
  INSERT INTO public.refresh_tokens (staff_id, token_hash, expires_at)
  VALUES (p_staff_id, p_token_hash, p_expires_at);
END;
$$;


--
-- Name: sp_auth_verify_refresh_token(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE OR REPLACE FUNCTION public.sp_auth_verify_refresh_token(p_token_hash character varying) RETURNS TABLE(staff_id integer, username character varying, full_name character varying, email character varying, phone character varying, image character varying, is_admin boolean, is_locked boolean, is_deleted boolean, department_id integer, unit_id integer, position_name character varying, department_name character varying, unit_name character varying, roles text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    s.id              AS staff_id,
    s.username,
    s.full_name::VARCHAR,
    s.email::VARCHAR,
    COALESCE(s.phone, s.mobile)::VARCHAR AS phone,
    s.image::VARCHAR,
    s.is_admin,
    s.is_locked,
    s.is_deleted,
    s.department_id,
    s.unit_id,
    p.name::VARCHAR   AS position_name,
    d.name::VARCHAR   AS department_name,
    u.name::VARCHAR   AS unit_name,
    COALESCE(
      (SELECT string_agg(r.name, ',')
       FROM public.role_of_staff ros
       JOIN public.roles r ON r.id = ros.role_id
       WHERE ros.staff_id = s.id),
      ''
    )::TEXT AS roles
  FROM public.refresh_tokens rt
  JOIN public.staff s ON s.id = rt.staff_id
  LEFT JOIN public.positions p ON p.id = s.position_id
  LEFT JOIN public.departments d ON d.id = s.department_id
  LEFT JOIN public.departments u ON u.id = s.unit_id
  WHERE rt.token_hash = p_token_hash
    AND rt.revoked_at IS NULL
    AND rt.expires_at > NOW();
END;
$$;


