)
RETURNS TABLE (success BOOLEAN, message TEXT, id INT)
LANGUAGE plpgsql
AS $$
DECLARE v_id INT; v_unit_id INT;
BEGIN
  v_unit_id := public.fn_get_ancestor_unit(COALESCE(p_department_id, p_unit_id));

  IF p_staff_id IS NULL THEN
