-- 8. CREATE TABLE edoc.outgoing_doc_recipients
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS edoc.outgoing_doc_recipients (
  id                          BIGSERIAL PRIMARY KEY,
  outgoing_doc_id             BIGINT NOT NULL,
  recipient_type              edoc.recipient_type_enum NOT NULL,
  recipient_unit_id           INTEGER NULL,
  recipient_org_id            BIGINT NULL,
  sent_at                     TIMESTAMPTZ NULL,
  sent_status                 VARCHAR(20) NOT NULL DEFAULT 'pending',
  error_message               TEXT NULL,
  generated_incoming_doc_id   BIGINT NULL,
  generated_lgsp_tracking_id  BIGINT NULL,
  created_at                  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

DO $$ BEGIN
  ALTER TABLE edoc.outgoing_doc_recipients ADD CONSTRAINT fk_recipients_outgoing
    FOREIGN KEY (outgoing_doc_id) REFERENCES edoc.outgoing_docs(id) ON DELETE CASCADE;
EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DO $$ BEGIN
  ALTER TABLE edoc.outgoing_doc_recipients ADD CONSTRAINT fk_recipients_unit
    FOREIGN KEY (recipient_unit_id) REFERENCES public.departments(id) ON DELETE RESTRICT;
EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DO $$ BEGIN
  ALTER TABLE edoc.outgoing_doc_recipients ADD CONSTRAINT fk_recipients_inter_org
    FOREIGN KEY (recipient_org_id) REFERENCES edoc.inter_organizations(id) ON DELETE RESTRICT;
EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DO $$ BEGIN
  ALTER TABLE edoc.outgoing_doc_recipients ADD CONSTRAINT fk_recipients_gen_incoming
    FOREIGN KEY (generated_incoming_doc_id) REFERENCES edoc.incoming_docs(id) ON DELETE SET NULL;
EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DO $$ BEGIN
  ALTER TABLE edoc.outgoing_doc_recipients ADD CONSTRAINT fk_recipients_gen_lgsp
    FOREIGN KEY (generated_lgsp_tracking_id) REFERENCES edoc.lgsp_tracking(id) ON DELETE SET NULL;
EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DO $$ BEGIN
  ALTER TABLE edoc.outgoing_doc_recipients ADD CONSTRAINT chk_recipient_xor
    CHECK (
      (recipient_type = 'internal_unit' AND recipient_unit_id IS NOT NULL AND recipient_org_id IS NULL) OR
      (recipient_type = 'external_org'  AND recipient_org_id  IS NOT NULL AND recipient_unit_id IS NULL)
    );
EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DO $$ BEGIN
  ALTER TABLE edoc.outgoing_doc_recipients ADD CONSTRAINT chk_recipient_sent_status
    CHECK (sent_status IN ('pending', 'sent', 'failed'));
EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- ----------------------------------------------------------------------------
-- 9. CREATE INDEXES
-- ----------------------------------------------------------------------------
CREATE INDEX IF NOT EXISTS idx_incoming_docs_source_type ON edoc.incoming_docs(source_type);
CREATE INDEX IF NOT EXISTS idx_incoming_docs_previous_outgoing ON edoc.incoming_docs(previous_outgoing_doc_id) WHERE previous_outgoing_doc_id IS NOT NULL;
CREATE UNIQUE INDEX IF NOT EXISTS idx_incoming_docs_external_dedupe ON edoc.incoming_docs(external_doc_id) WHERE external_doc_id IS NOT NULL AND source_type = 'external_lgsp';

CREATE INDEX IF NOT EXISTS idx_outgoing_docs_status ON edoc.outgoing_docs(unit_id, status, is_released);
CREATE INDEX IF NOT EXISTS idx_outgoing_docs_previous ON edoc.outgoing_docs(previous_outgoing_doc_id) WHERE previous_outgoing_doc_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_drafting_docs_status ON edoc.drafting_docs(unit_id, status, is_released);
CREATE INDEX IF NOT EXISTS idx_drafting_docs_previous ON edoc.drafting_docs(previous_outgoing_doc_id) WHERE previous_outgoing_doc_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_outgoing_recipients_doc ON edoc.outgoing_doc_recipients(outgoing_doc_id);
CREATE INDEX IF NOT EXISTS idx_outgoing_recipients_pending ON edoc.outgoing_doc_recipients(sent_status, recipient_type) WHERE sent_status = 'pending';
CREATE INDEX IF NOT EXISTS idx_outgoing_recipients_unit ON edoc.outgoing_doc_recipients(recipient_unit_id) WHERE recipient_unit_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_outgoing_recipients_org ON edoc.outgoing_doc_recipients(recipient_org_id) WHERE recipient_org_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_inter_org_lgsp_id ON edoc.inter_organizations(lgsp_organ_id) WHERE lgsp_organ_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_inter_org_parent ON edoc.inter_organizations(parent_id);
CREATE INDEX IF NOT EXISTS idx_inter_org_active ON edoc.inter_organizations(is_active) WHERE is_active = TRUE;

-- ----------------------------------------------------------------------------
-- 10. RECREATE 5 SPs với schema mới
-- ----------------------------------------------------------------------------

CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_get_by_id(p_id bigint, p_staff_id integer)
RETURNS TABLE(
  id bigint, unit_id integer, received_date timestamptz, "number" integer,
  notation varchar, document_code varchar, abstract text,
  publish_unit varchar, publish_date timestamptz, signer varchar, sign_date timestamptz,
  doc_book_id integer, doc_type_id integer, doc_field_id integer,
  secret_id smallint, urgent_id smallint,
  number_paper integer, number_copies integer, expired_date timestamptz,
  recipients text, sents text,
  approver varchar, approved boolean, approved_at timestamptz,
  is_received_paper boolean, received_paper_date timestamptz,
  archive_status boolean,
  source_type edoc.doc_source_type, is_unit_send boolean, unit_send varchar,
  previous_outgoing_doc_id bigint, external_doc_id varchar,
  recall_reason text, recall_requested_at timestamptz, recall_response text, recall_responded_at timestamptz, status_before_recall varchar,
  created_by integer, created_at timestamptz, updated_by integer, updated_at timestamptz,
  doc_book_name varchar, doc_type_name varchar, doc_type_code varchar, doc_field_name varchar,
  created_by_name varchar, is_read boolean
)
LANGUAGE plpgsql AS $$
BEGIN
  RETURN QUERY
  SELECT
    d.id, d.unit_id, d.received_date, d.number, d.notation, d.document_code, d.abstract,
    d.publish_unit, d.publish_date, d.signer, d.sign_date,
    d.doc_book_id, d.doc_type_id, d.doc_field_id, d.secret_id, d.urgent_id,
    d.number_paper, d.number_copies, d.expired_date,
    d.recipients, d.sents,
    d.approver, d.approved, d.approved_at,
    d.is_received_paper, d.received_paper_date,
    d.archive_status,
    d.source_type, d.is_unit_send, d.unit_send,
    d.previous_outgoing_doc_id, d.external_doc_id,
    d.recall_reason, d.recall_requested_at, d.recall_response, d.recall_responded_at, d.status_before_recall,
    d.created_by, d.created_at, d.updated_by, d.updated_at,
    db.name::varchar AS doc_book_name,
    dt.name::varchar AS doc_type_name,
    dt.code::varchar AS doc_type_code,
    df.name::varchar AS doc_field_name,
    s.full_name::varchar AS created_by_name,
    EXISTS(SELECT 1 FROM edoc.user_incoming_docs uid WHERE uid.incoming_doc_id = d.id AND uid.staff_id = p_staff_id AND uid.read_at IS NOT NULL) AS is_read
  FROM edoc.incoming_docs d
  LEFT JOIN edoc.doc_books db ON d.doc_book_id = db.id
  LEFT JOIN edoc.doc_types dt ON d.doc_type_id = dt.id
  LEFT JOIN edoc.doc_fields df ON d.doc_field_id = df.id
  LEFT JOIN public.staff s ON d.created_by = s.id
  WHERE d.id = p_id;
END;
$$;

CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_get_list(
  p_unit_id integer, p_staff_id integer,
  p_doc_book_id integer DEFAULT NULL, p_doc_type_id integer DEFAULT NULL, p_doc_field_id integer DEFAULT NULL,
  p_urgent_id smallint DEFAULT NULL, p_is_read boolean DEFAULT NULL, p_approved boolean DEFAULT NULL,
  p_from_date timestamptz DEFAULT NULL, p_to_date timestamptz DEFAULT NULL,
  p_keyword text DEFAULT NULL, p_signer text DEFAULT NULL,
  p_from_number integer DEFAULT NULL, p_to_number integer DEFAULT NULL,
  p_page integer DEFAULT 1, p_page_size integer DEFAULT 20,
  p_source_type edoc.doc_source_type DEFAULT NULL
) RETURNS TABLE(
  id bigint, unit_id integer, received_date timestamptz, "number" integer,
  notation varchar, document_code varchar, abstract text,
  publish_unit varchar, publish_date timestamptz, signer varchar, sign_date timestamptz,
  doc_book_id integer, doc_type_id integer, doc_field_id integer,
  secret_id smallint, urgent_id smallint,
  number_paper integer, number_copies integer, expired_date timestamptz,
  recipients text, sents text,
  approver varchar, approved boolean,
  is_received_paper boolean, archive_status boolean,
  source_type edoc.doc_source_type, is_unit_send boolean, unit_send varchar, external_doc_id varchar,
  created_by integer, created_at timestamptz,
  doc_book_name varchar, doc_type_name varchar, doc_type_code varchar, doc_field_name varchar,
  created_by_name varchar,
  is_read boolean, read_at timestamptz, attachment_count bigint, total_count bigint
)
LANGUAGE plpgsql AS $$
DECLARE
  v_offset INTEGER := (p_page - 1) * p_page_size;
  v_total  BIGINT;
BEGIN
  SELECT count(*) INTO v_total FROM edoc.incoming_docs f
  WHERE f.unit_id = p_unit_id
    AND (p_doc_book_id IS NULL OR f.doc_book_id = p_doc_book_id)
    AND (p_doc_type_id IS NULL OR f.doc_type_id = p_doc_type_id)
    AND (p_doc_field_id IS NULL OR f.doc_field_id = p_doc_field_id)
    AND (p_urgent_id IS NULL OR f.urgent_id = p_urgent_id)
    AND (p_approved IS NULL OR f.approved = p_approved)
    AND (p_from_date IS NULL OR f.received_date >= p_from_date)
    AND (p_to_date IS NULL OR f.received_date <= p_to_date)
    AND (p_keyword IS NULL OR f.abstract ILIKE '%' || p_keyword || '%' OR f.notation ILIKE '%' || p_keyword || '%' OR f.document_code ILIKE '%' || p_keyword || '%')
    AND (p_signer IS NULL OR f.signer ILIKE '%' || p_signer || '%')
    AND (p_from_number IS NULL OR f.number >= p_from_number)
    AND (p_to_number IS NULL OR f.number <= p_to_number)
    AND (p_source_type IS NULL OR f.source_type = p_source_type);

  RETURN QUERY
  SELECT
    f.id, f.unit_id, f.received_date, f.number, f.notation, f.document_code, f.abstract,
    f.publish_unit, f.publish_date, f.signer, f.sign_date,
    f.doc_book_id, f.doc_type_id, f.doc_field_id, f.secret_id, f.urgent_id,
    f.number_paper, f.number_copies, f.expired_date,
    f.recipients, f.sents, f.approver, f.approved,
    f.is_received_paper, f.archive_status,
    f.source_type, f.is_unit_send, f.unit_send, f.external_doc_id,
    f.created_by, f.created_at,
    db.name::varchar AS doc_book_name,
    dt.name::varchar AS doc_type_name,
    dt.code::varchar AS doc_type_code,
    df.name::varchar AS doc_field_name,
    s.full_name::varchar AS created_by_name,
    EXISTS(SELECT 1 FROM edoc.user_incoming_docs uid WHERE uid.incoming_doc_id = f.id AND uid.staff_id = p_staff_id AND uid.read_at IS NOT NULL) AS is_read,
    (SELECT max(uid2.read_at) FROM edoc.user_incoming_docs uid2 WHERE uid2.incoming_doc_id = f.id AND uid2.staff_id = p_staff_id) AS read_at,
    (SELECT count(*) FROM edoc.attachment_incoming_docs a WHERE a.incoming_doc_id = f.id) AS attachment_count,
    v_total AS total_count
  FROM edoc.incoming_docs f
  LEFT JOIN edoc.doc_books db ON f.doc_book_id = db.id
  LEFT JOIN edoc.doc_types dt ON f.doc_type_id = dt.id
  LEFT JOIN edoc.doc_fields df ON f.doc_field_id = df.id
  LEFT JOIN public.staff s ON f.created_by = s.id
  WHERE f.unit_id = p_unit_id
    AND (p_doc_book_id IS NULL OR f.doc_book_id = p_doc_book_id)
    AND (p_doc_type_id IS NULL OR f.doc_type_id = p_doc_type_id)
    AND (p_doc_field_id IS NULL OR f.doc_field_id = p_doc_field_id)
    AND (p_urgent_id IS NULL OR f.urgent_id = p_urgent_id)
    AND (p_approved IS NULL OR f.approved = p_approved)
    AND (p_from_date IS NULL OR f.received_date >= p_from_date)
    AND (p_to_date IS NULL OR f.received_date <= p_to_date)
    AND (p_keyword IS NULL OR f.abstract ILIKE '%' || p_keyword || '%' OR f.notation ILIKE '%' || p_keyword || '%' OR f.document_code ILIKE '%' || p_keyword || '%')
    AND (p_signer IS NULL OR f.signer ILIKE '%' || p_signer || '%')
    AND (p_from_number IS NULL OR f.number >= p_from_number)
    AND (p_to_number IS NULL OR f.number <= p_to_number)
    AND (p_source_type IS NULL OR f.source_type = p_source_type)
  ORDER BY f.received_date DESC NULLS LAST, f.id DESC
  LIMIT p_page_size OFFSET v_offset;
END;
$$;

CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_create(
  p_unit_id integer, p_received_date timestamptz, p_doc_book_id integer,
  p_notation varchar, p_document_code varchar, p_abstract text,
  p_publish_unit varchar, p_publish_date timestamptz, p_signer varchar, p_sign_date timestamptz,
  p_doc_type_id integer, p_doc_field_id integer,
  p_secret_id smallint, p_urgent_id smallint,
  p_number_paper integer, p_number_copies integer,
  p_expired_date timestamptz, p_recipients text, p_sents text,
  p_approved boolean, p_created_by integer,
  p_source_type edoc.doc_source_type DEFAULT 'manual',
  p_is_unit_send boolean DEFAULT FALSE,
  p_unit_send varchar DEFAULT NULL,
  p_previous_outgoing_doc_id bigint DEFAULT NULL,
  p_external_doc_id varchar DEFAULT NULL
) RETURNS TABLE(success boolean, message text, id bigint)
LANGUAGE plpgsql AS $$
DECLARE
  v_id bigint;
  v_number integer;
BEGIN
  SELECT COALESCE(max(d.number), 0) + 1 INTO v_number
  FROM edoc.incoming_docs d
  WHERE d.unit_id = p_unit_id
    AND (p_doc_book_id IS NULL OR d.doc_book_id = p_doc_book_id);

  INSERT INTO edoc.incoming_docs (
    unit_id, received_date, "number", notation, document_code, abstract,
    publish_unit, publish_date, signer, sign_date,
    doc_book_id, doc_type_id, doc_field_id,
    secret_id, urgent_id, number_paper, number_copies,
    expired_date, recipients, sents,
    approved, archive_status,
    source_type, is_unit_send, unit_send,
    previous_outgoing_doc_id, external_doc_id,
    created_by, created_at, updated_at
  ) VALUES (
    p_unit_id, p_received_date, v_number, p_notation, p_document_code, p_abstract,
    p_publish_unit, p_publish_date, p_signer, p_sign_date,
    p_doc_book_id, p_doc_type_id, p_doc_field_id,
    p_secret_id, p_urgent_id, p_number_paper, p_number_copies,
    p_expired_date, p_recipients, p_sents,
    p_approved, FALSE,
    p_source_type, p_is_unit_send, p_unit_send,
    p_previous_outgoing_doc_id, p_external_doc_id,
    p_created_by, NOW(), NOW()
  ) RETURNING incoming_docs.id INTO v_id;

  RETURN QUERY SELECT TRUE, 'Tao van ban den thanh cong'::text, v_id;
EXCEPTION WHEN others THEN
  RETURN QUERY SELECT FALSE, SQLERRM::text, NULL::bigint;
END;
$$;

CREATE OR REPLACE FUNCTION edoc.fn_outgoing_doc_get_by_id(p_id bigint, p_staff_id integer)
RETURNS TABLE(
  id bigint, unit_id integer, received_date timestamptz, "number" integer,
  sub_number varchar, notation varchar, document_code varchar, abstract text,
  drafting_unit_id integer, drafting_user_id integer, publish_unit_id integer, publish_date timestamptz,
  signer varchar, sign_date timestamptz, expired_date timestamptz,
  doc_book_id integer, doc_type_id integer, doc_field_id integer,
  secret_id smallint, urgent_id smallint, number_paper integer, number_copies integer,
  recipients text,
  approver varchar, approved boolean, approved_at timestamptz,
  status varchar, is_released boolean, released_date timestamptz, previous_outgoing_doc_id bigint,
  archive_status boolean, is_digital_signed smallint,
  created_by integer, created_at timestamptz, updated_by integer, updated_at timestamptz,
  doc_book_name varchar, doc_type_name varchar, doc_type_code varchar, doc_field_name varchar,
  drafting_unit_name varchar, drafting_user_name varchar, publish_unit_name varchar,
  created_by_name varchar, is_read boolean
)
LANGUAGE plpgsql AS $$
BEGIN
  RETURN QUERY
  SELECT
    d.id, d.unit_id, d.received_date, d.number, d.sub_number, d.notation, d.document_code, d.abstract,
    d.drafting_unit_id, d.drafting_user_id, d.publish_unit_id, d.publish_date,
    d.signer, d.sign_date, d.expired_date,
    d.doc_book_id, d.doc_type_id, d.doc_field_id, d.secret_id, d.urgent_id,
    d.number_paper, d.number_copies, d.recipients,
    d.approver, d.approved, d.approved_at,
    d.status, d.is_released, d.released_date, d.previous_outgoing_doc_id,
    d.archive_status, d.is_digital_signed,
    d.created_by, d.created_at, d.updated_by, d.updated_at,
    db.name::varchar AS doc_book_name,
    dt.name::varchar AS doc_type_name,
    dt.code::varchar AS doc_type_code,
    df.name::varchar AS doc_field_name,
    du.name::varchar AS drafting_unit_name,
    duser.full_name::varchar AS drafting_user_name,
    pu.name::varchar AS publish_unit_name,
    s.full_name::varchar AS created_by_name,
    EXISTS(SELECT 1 FROM edoc.user_outgoing_docs uod WHERE uod.outgoing_doc_id = d.id AND uod.staff_id = p_staff_id AND uod.read_at IS NOT NULL) AS is_read
  FROM edoc.outgoing_docs d
  LEFT JOIN edoc.doc_books db ON d.doc_book_id = db.id
  LEFT JOIN edoc.doc_types dt ON d.doc_type_id = dt.id
  LEFT JOIN edoc.doc_fields df ON d.doc_field_id = df.id
  LEFT JOIN public.departments du ON d.drafting_unit_id = du.id
  LEFT JOIN public.staff duser ON d.drafting_user_id = duser.id
  LEFT JOIN public.departments pu ON d.publish_unit_id = pu.id
  LEFT JOIN public.staff s ON d.created_by = s.id
  WHERE d.id = p_id;
END;
$$;

CREATE OR REPLACE FUNCTION edoc.fn_outgoing_doc_get_list(
  p_unit_id integer, p_staff_id integer,
  p_doc_book_id integer DEFAULT NULL, p_doc_type_id integer DEFAULT NULL, p_doc_field_id integer DEFAULT NULL,
  p_urgent_id smallint DEFAULT NULL, p_approved boolean DEFAULT NULL,
  p_from_date timestamptz DEFAULT NULL, p_to_date timestamptz DEFAULT NULL,
  p_keyword text DEFAULT NULL, p_page integer DEFAULT 1, p_page_size integer DEFAULT 20,
  p_status varchar DEFAULT NULL, p_is_released boolean DEFAULT NULL
) RETURNS TABLE(
  id bigint, unit_id integer, received_date timestamptz, "number" integer,
  sub_number varchar, notation varchar, document_code varchar, abstract text,
  drafting_unit_id integer, drafting_user_id integer, publish_unit_id integer, publish_date timestamptz,
  signer varchar, sign_date timestamptz, expired_date timestamptz,
  doc_book_id integer, doc_type_id integer, doc_field_id integer,
  secret_id smallint, urgent_id smallint, number_paper integer, number_copies integer,
  recipients text, approver varchar, approved boolean,
  status varchar, is_released boolean, released_date timestamptz,
  archive_status boolean,
  created_by integer, created_at timestamptz,
  doc_book_name varchar, doc_type_name varchar, doc_type_code varchar, doc_field_name varchar,
  drafting_unit_name varchar, drafting_user_name varchar,
  created_by_name varchar,
  is_read boolean, read_at timestamptz, attachment_count bigint, total_count bigint
)
LANGUAGE plpgsql AS $$
DECLARE
  v_offset INTEGER := (p_page - 1) * p_page_size;
  v_total  BIGINT;
BEGIN
  SELECT count(*) INTO v_total FROM edoc.outgoing_docs f
  WHERE f.unit_id = p_unit_id
    AND (p_doc_book_id IS NULL OR f.doc_book_id = p_doc_book_id)
    AND (p_doc_type_id IS NULL OR f.doc_type_id = p_doc_type_id)
    AND (p_doc_field_id IS NULL OR f.doc_field_id = p_doc_field_id)
    AND (p_urgent_id IS NULL OR f.urgent_id = p_urgent_id)
    AND (p_approved IS NULL OR f.approved = p_approved)
    AND (p_status IS NULL OR f.status = p_status)
    AND (p_is_released IS NULL OR f.is_released = p_is_released)
    AND (p_from_date IS NULL OR f.received_date >= p_from_date)
    AND (p_to_date IS NULL OR f.received_date <= p_to_date)
    AND (p_keyword IS NULL OR f.abstract ILIKE '%' || p_keyword || '%' OR f.notation ILIKE '%' || p_keyword || '%' OR f.document_code ILIKE '%' || p_keyword || '%');

  RETURN QUERY
  SELECT
    f.id, f.unit_id, f.received_date, f.number, f.sub_number, f.notation, f.document_code, f.abstract,
    f.drafting_unit_id, f.drafting_user_id, f.publish_unit_id, f.publish_date,
    f.signer, f.sign_date, f.expired_date,
    f.doc_book_id, f.doc_type_id, f.doc_field_id, f.secret_id, f.urgent_id,
    f.number_paper, f.number_copies, f.recipients, f.approver, f.approved,
    f.status, f.is_released, f.released_date,
    f.archive_status,
    f.created_by, f.created_at,
    db.name::varchar AS doc_book_name,
    dt.name::varchar AS doc_type_name,
    dt.code::varchar AS doc_type_code,
    df.name::varchar AS doc_field_name,
    du.name::varchar AS drafting_unit_name,
    duser.full_name::varchar AS drafting_user_name,
    s.full_name::varchar AS created_by_name,
    EXISTS(SELECT 1 FROM edoc.user_outgoing_docs uod WHERE uod.outgoing_doc_id = f.id AND uod.staff_id = p_staff_id AND uod.read_at IS NOT NULL) AS is_read,
    (SELECT max(uod2.read_at) FROM edoc.user_outgoing_docs uod2 WHERE uod2.outgoing_doc_id = f.id AND uod2.staff_id = p_staff_id) AS read_at,
    (SELECT count(*) FROM edoc.attachment_outgoing_docs a WHERE a.outgoing_doc_id = f.id) AS attachment_count,
    v_total AS total_count
  FROM edoc.outgoing_docs f
  LEFT JOIN edoc.doc_books db ON f.doc_book_id = db.id
  LEFT JOIN edoc.doc_types dt ON f.doc_type_id = dt.id
  LEFT JOIN edoc.doc_fields df ON f.doc_field_id = df.id
  LEFT JOIN public.departments du ON f.drafting_unit_id = du.id
  LEFT JOIN public.staff duser ON f.drafting_user_id = duser.id
  LEFT JOIN public.staff s ON f.created_by = s.id
  WHERE f.unit_id = p_unit_id
    AND (p_doc_book_id IS NULL OR f.doc_book_id = p_doc_book_id)
    AND (p_doc_type_id IS NULL OR f.doc_type_id = p_doc_type_id)
    AND (p_doc_field_id IS NULL OR f.doc_field_id = p_doc_field_id)
    AND (p_urgent_id IS NULL OR f.urgent_id = p_urgent_id)
    AND (p_approved IS NULL OR f.approved = p_approved)
    AND (p_status IS NULL OR f.status = p_status)
    AND (p_is_released IS NULL OR f.is_released = p_is_released)
    AND (p_from_date IS NULL OR f.received_date >= p_from_date)
    AND (p_to_date IS NULL OR f.received_date <= p_to_date)
    AND (p_keyword IS NULL OR f.abstract ILIKE '%' || p_keyword || '%' OR f.notation ILIKE '%' || p_keyword || '%' OR f.document_code ILIKE '%' || p_keyword || '%')
  ORDER BY f.received_date DESC NULLS LAST, f.id DESC
  LIMIT p_page_size OFFSET v_offset;
END;
$$;

