-- CREATE lại với signature ĐÚNG (match repository call positional 22 args)
CREATE OR REPLACE FUNCTION edoc.fn_incoming_doc_create(
  p_unit_id              integer,
  p_received_date        timestamp with time zone,
  p_number               integer,
  p_notation             character varying,
  p_document_code        character varying,
  p_abstract             text,
  p_publish_unit         character varying,
  p_publish_date         timestamp with time zone,
  p_signer               character varying,
  p_sign_date            timestamp with time zone,
  p_doc_book_id          integer,
  p_doc_type_id          integer,
  p_doc_field_id         integer,
  p_secret_id            smallint DEFAULT 1,
  p_urgent_id            smallint DEFAULT 1,
  p_number_paper         integer DEFAULT 1,
  p_number_copies        integer DEFAULT 1,
  p_expired_date         timestamp with time zone DEFAULT NULL,
  p_recipients           text DEFAULT NULL,
  p_is_received_paper    boolean DEFAULT FALSE,
  p_created_by           integer DEFAULT NULL,
  p_department_id        integer DEFAULT NULL,
  p_source_type          edoc.doc_source_type DEFAULT 'manual',
  p_is_unit_send         boolean DEFAULT FALSE,
  p_unit_send            character varying DEFAULT NULL,
  p_previous_outgoing_doc_id bigint DEFAULT NULL,
  p_external_doc_id      character varying DEFAULT NULL
) RETURNS TABLE(success boolean, message text, id bigint)
LANGUAGE plpgsql AS $$
DECLARE
  v_id bigint;
  v_number integer;
BEGIN
  IF p_number IS NULL THEN
    SELECT COALESCE(max(d.number), 0) + 1 INTO v_number
    FROM edoc.incoming_docs d
    WHERE d.unit_id = p_unit_id
      AND (p_doc_book_id IS NULL OR d.doc_book_id = p_doc_book_id);
  ELSE
    v_number := p_number;
  END IF;

  INSERT INTO edoc.incoming_docs (
    unit_id, received_date, "number", notation, document_code, abstract,
    publish_unit, publish_date, signer, sign_date,
    doc_book_id, doc_type_id, doc_field_id,
    secret_id, urgent_id, number_paper, number_copies,
    expired_date, recipients,
    is_received_paper, archive_status,
    source_type, is_unit_send, unit_send,
    previous_outgoing_doc_id, external_doc_id,
    department_id, created_by, created_at, updated_at
  ) VALUES (
    p_unit_id, p_received_date, v_number, p_notation, p_document_code, p_abstract,
    p_publish_unit, p_publish_date, p_signer, p_sign_date,
    p_doc_book_id, p_doc_type_id, p_doc_field_id,
    p_secret_id, p_urgent_id, p_number_paper, p_number_copies,
    p_expired_date, p_recipients,
    p_is_received_paper, FALSE,
    p_source_type, p_is_unit_send, p_unit_send,
    p_previous_outgoing_doc_id, p_external_doc_id,
    p_department_id, p_created_by, NOW(), NOW()
  ) RETURNING incoming_docs.id INTO v_id;

  RETURN QUERY SELECT TRUE, 'Tao van ban den thanh cong'::text, v_id;
EXCEPTION WHEN others THEN
  RETURN QUERY SELECT FALSE, SQLERRM::text, NULL::bigint;
END;
$$;
